/* ── API EQUIPOS ─────────────────────────────────────────────
   URL de la API PHP en el mismo servidor
   ─────────────────────────────────────────────────────────── */
const API_EQUIPOS_URL = '/api_2026ia.php';
const API_IA_URL      = '/api_ia.php';

// NOTA: Ya no se envían secrets desde el frontend.
// La autenticación se hace con la cookie de sesión PHP.

async function apiEquipos(action, body = {}) {
  try {
    const res = await fetch(`${API_EQUIPOS_URL}?action=${action}`, {
      credentials: 'same-origin',
      credentials: 'same-origin',
      method : 'POST',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'same-origin',
      body   : JSON.stringify(body)
    });
    const data = await res.json();
    if (res.status === 401) {
      // Sesión expirada — redirigir a login
      showToast('Sesión expirada. Redirigiendo...', 'error');
      setTimeout(() => window.location.href = 'login.php', 1500);
      return null;
    }
    if (!res.ok) { console.warn('API error:', data.error); return null; }
    return data;
  } catch(e) {
    console.warn('API no disponible (modo offline):', e.message);
    showToast('Sin conexión con el servidor', 'error');
    return null;
  }
}

/**
 * Carga la lista de cámaras activas desde MySQL al iniciar la app.
 * Si falla (offline / error), conserva la lista hardcodeada como fallback.
 */
async function cargarCamarasDesdeDB() {
  try {
    const res  = await fetch(`${API_EQUIPOS_URL}?action=camaras`, {credentials:'same-origin'});
    const data = await res.json();
    if (!Array.isArray(data) || !data.length) {
      console.warn('Cámaras: respuesta vacía desde DB');
      return;
    }

    // ── Guardar datos completos ──────────────────────────────
    camarasDB = data;

    // ── PR6_CAMARAS: lista de nombres para chips y selects ───
    // Solo cámaras activas, ordenadas por número
    PR6_CAMARAS = data
      .filter(c => parseInt(c.activo) === 1)
      .sort((a,b) => a.CamaraNumero - b.CamaraNumero)
      .map(c => c.nombre_display);

    // ── PR100_CAMARAS: solo TiposCamaraID=2 (cámaras de descongelado) ──
    PR100_CAMARAS = data
      .filter(c => parseInt(c.activo) === 1 && parseInt(c.TiposCamaraID) === 2)
      .sort((a,b) => a.CamaraNumero - b.CamaraNumero)
      .map(c => ({ id: c.CamaraID, numero: c.CamaraNumero, nombre: c.nombre_display }));

    // ── dashboardLogisticaNacionalData: solo cámaras es_dashboard=true ──
    dashboardLogisticaNacionalData.length = 0;
    data
      .filter(c => parseInt(c.activo) === 1 && c.es_dashboard)
      .sort((a,b) => {
        const orden = t => {
          const tl = (t||'').toLowerCase();
          if (tl.includes('tunel') || tl.includes('túnel')) return 0;
          if (tl.includes('antecamara') || tl.includes('antecámara')) return 2;
          if (tl === 'anden norte' || tl === 'anden sur') return 3;
          return 1; // cámara normal
        };
        const oa = orden(a.tipo_nombre), ob = orden(b.tipo_nombre);
        if (oa !== ob) return oa - ob;
        return a.CamaraNumero - b.CamaraNumero;
      })
      .forEach(c => {
        const esTunel   = (c.tipo_nombre||'').toLowerCase().includes('tunel');
        const capacidad = (c.CamaraCalles||0) * (c.CamaraFilas||0) * (c.CamaraNiveles||1);
        const tipoNombreLow = (c.tipo_nombre || '').toLowerCase();
        let tipoCard = 'CAMARA';
        if (tipoNombreLow.includes('tunel') || tipoNombreLow.includes('túnel')) tipoCard = 'TUNEL';
        else if (tipoNombreLow.includes('antecamara') || tipoNombreLow.includes('antecámara')) tipoCard = 'ANTECAMARA';
        else if (tipoNombreLow === 'anden norte') tipoCard = 'ANDEN_NORTE';
        else if (tipoNombreLow === 'anden sur')   tipoCard = 'ANDEN_SUR';
        dashboardLogisticaNacionalData.push({
          tipo          : tipoCard,
          nombre        : String(c.CamaraNumero),
          nombre_display: c.nombre_display,
          camara_id     : c.CamaraID,
          estibas       : 0,
          capacidad     : capacidad,
          calles        : c.CamaraCalles  || 0,
          filas         : c.CamaraFilas   || 0,
          niveles       : c.CamaraNiveles || 0,
          temperatura   : c.temp_actual !== null && c.temp_actual !== undefined
                          ? parseFloat(c.temp_actual) : null,
          temp_fecha    : c.temp_fecha || null,
          temp_hora     : c.temp_hora  || null,
          estado_camara : c.temp_estado || null,
          clientes      : [],
          extra         : 0,
          puerta        : null,   // se actualiza desde camara_puerta_registro vía header_tiles
          ventilador    : true,
        });
      });

    console.log(`✓ ${PR6_CAMARAS.length} cámaras activas cargadas desde DB`);

    // Temperaturas ya vienen incluidas en el endpoint camaras
    console.log(`✓ Dashboard logística: ${dashboardLogisticaNacionalData.length} cámaras`);

    // Cargar maquinistas desde tabla persona
    try {
      const resMaq = await fetch(`${API_EQUIPOS_URL}?action=maquinistas`, {credentials:'same-origin'});
      const maqData = await resMaq.json();
      if (Array.isArray(maqData) && maqData.length) {
        PR6_MAQUINISTAS.length = 0;
        maqData.forEach(m => PR6_MAQUINISTAS.push(m));
        console.log(`✓ ${PR6_MAQUINISTAS.length} maquinistas cargados desde DB`);
      }
    } catch(e) { console.warn('Maquinistas: error al cargar', e.message); }

  } catch(e) {
    console.warn('Cámaras: error al cargar desde DB:', e.message);
    // Fallback mínimo para que la app no quede en blanco
    if (PR6_CAMARAS.length === 0) {
      PR6_CAMARAS = ['CÁMARA 1','CÁMARA 2','CÁMARA 3','CÁMARA 4','CÁMARA 5',
                     'CÁMARA 6','CÁMARA 7','CÁMARA 8','ANTECÁMARA'];
    }
  }
}
