/* ── HELPERS GENERALES ──────────────────────────────────────── */
function setHeader(title) {
  screenTitle.textContent    = title;
  screenSubtitle.textContent = perfilData?.usuario || USER_NAME;
}

function syncBackBtn() {
  backBtn.disabled = historyStack.length === 0;
}

/* Detiene el auto-refresh del dashboard logística nacional */
function stopDashNacRefresh() {
  if (_dashNacTimer)    { clearInterval(_dashNacTimer);    _dashNacTimer    = null; }
  if (_dashNacCountdown){ clearInterval(_dashNacCountdown); _dashNacCountdown = null; }
  const ind = document.getElementById('dashNacRefreshInd');
  if (ind) ind.remove();
}

/* Muestra / oculta la tira de datos superior */
function showMetaPanel(visible) {
  // Usuarios cliente portal NUNCA ven el meta-panel
  if (visible && typeof esClientePortal === 'function' && esClientePortal()) return;
  metaPanel.style.display = visible ? 'block' : 'none';
}

/* Modo "expandido" para formularios y vistas de detalle */
function setExpandedMode(enabled) {
  menuWrap.classList.toggle('expanded', enabled);
}

function getTextInitials(text) {
  return text.split(/\s+/).filter(Boolean).slice(0, 2).map(w => w[0]).join('').toUpperCase();
}

function getCustomTileHTML(item) {
  // MAPA DE BOXES: vehículos en planta
  if (item.title === 'MAPA DE BOXES') {
    const veh = dashboardEquipamientoData.length
      ? null   // dato del tile de header_tiles (vehiculos-planta)
      : null;
    const vehiculosEl = document.getElementById('vehiculos-planta');
    const vehiculos   = vehiculosEl ? vehiculosEl.textContent.trim() : '—';
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge" style="background:rgba(54,176,201,.18);color:#36B0C9;border-color:rgba(54,176,201,.35)">BOX</span></div>
        <div style="font-size:1.8rem;line-height:1;margin:2px 0">🗺️</div>
        <div class="tile-kpi-value tile-kpi-value--lg" style="color:#22C55E">${vehiculos}</div>
        <div class="tile-kpi-sublabel">VEHÍCULOS EN PLANTA</div>
        <div class="tile-title one-line tile-label">MAPA DE BOXES</div>
      </div>`;
  }

  // MANTENIMIENTO GENERAL: grilla 4×2 — ícono + badge fallas
  if (item.title === 'MANTENIMIENTO GENERAL') {
    const totalFallas = mantEquiposCache.filter(e => e.estado === 'En falla').length;

    const celdas = MANT_CATEGORIAS.map(cat => {
      const fallas = mantEquiposCache.filter(e => e.categoria === cat.id && e.estado === 'En falla').length;
      return `
        <div class="mant-icon-cell${fallas > 0 ? ' mant-icon-cell--falla' : ''}" title="${cat.label}">
          <span class="mant-icon-cell-emoji">${cat.icon}</span>
          ${fallas > 0 ? `<span class="mant-icon-cell-badge">${fallas}</span>` : ''}
        </div>`;
    }).join('');

    return `
      <div class="tile-kpi-wrap mant-gen-tile">
        <div class="tile-kpi-top">
          <span class="tile-kpi-badge" style="background:rgba(15,118,110,.25);color:#2dd4bf;border-color:rgba(15,118,110,.5)">MG</span>
          ${totalFallas > 0
            ? `<span class="mant-total-fallas">${totalFallas} FALLA${totalFallas !== 1 ? 'S' : ''}</span>`
            : `<span class="mant-total-ok">✓ TODO OK</span>`}
        </div>
        <div class="mant-icon-grid">${celdas}</div>
        <div class="tile-title one-line tile-label">MANTENIMIENTO GENERAL</div>
      </div>`;
  }

  // DASHBOARD LOGISTICA NACIONAL: estibas + % ocupación
  if (item.title === 'DASHBOARD LOGISTICA NACIONAL') {
    const estibasEl = document.getElementById('estibas-en-planta');
    const estibas   = estibasEl ? estibasEl.textContent.trim() : '—';
    const pct       = dashTileOcupacion.pct;
    const pctStr    = pct !== null ? pct + '%' : '—';
    const pctColor  = pct === null ? 'rgba(255,255,255,.6)'
                    : pct >= 90   ? '#EF4444'
                    : pct >= 70   ? '#F97316'
                    : '#22C55E';
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge">DL</span></div>
        <div class="tile-kpi-value tile-kpi-value--md" style="color:#36B0C9">${estibas}</div>
        <div class="tile-kpi-sublabel">ESTIBAS EN PLANTA</div>
        <div style="font-size:.95rem;font-weight:800;color:${pctColor};margin:3px 0 1px;line-height:1">${pctStr}</div>
        <div class="tile-kpi-sublabel">OCUPACIÓN TOTAL</div>
        <div class="tile-title one-line tile-label">DASHBOARD LOGÍSTICA</div>
      </div>`;
  }

  // DASHBOARD EQUIPAMIENTO: resumen de estados de equipos de mantenimiento
  if (item.title === 'DASHBOARD EQUIPAMIENTO') {
    const colorEstado = {
      'Operativo':         '#22C55E',
      'En mantenimiento':  '#FACC15',
      'En falla':          '#EF4444',
      'Fuera de servicio': '#64748B',
    };
    const porEstado = dashTileEquipMant.porEstado;
    const total     = dashTileEquipMant.total;
    const tieneData = total !== null && Object.keys(porEstado).length > 0;

    if (!tieneData) {
      return `
        <div class="tile-kpi-wrap">
          <div class="tile-kpi-top"><span class="tile-kpi-badge">DE</span></div>
          <div style="font-size:1.8rem;line-height:1;margin:4px 0">🏭</div>
          <div class="tile-kpi-sublabel">EQUIPAMIENTO</div>
          <div class="tile-title one-line tile-label">DASHBOARD EQUIPAMIENTO</div>
        </div>`;
    }

    const pills = Object.entries(porEstado).map(([estado, n]) => {
      const col = colorEstado[estado] || '#64748B';
      return `<div style="display:flex;flex-direction:column;align-items:center;gap:1px;padding:3px 7px;border-radius:6px;border:1px solid ${col}33;background:${col}11">
        <span style="font-size:.95rem;font-weight:800;color:${col};line-height:1">${n}</span>
        <span style="font-size:.5rem;font-weight:700;color:${col};opacity:.8;text-transform:uppercase;letter-spacing:.04em;text-align:center">${estado.replace('En ','')}</span>
      </div>`;
    }).join('');

    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge">DE</span></div>
        <div style="display:flex;gap:5px;flex-wrap:wrap;justify-content:center;margin:4px 0 2px">${pills}</div>
        <div class="tile-kpi-sublabel">${total} equipos totales</div>
        <div class="tile-title one-line tile-label">DASHBOARD EQUIPAMIENTO</div>
      </div>`;
  }

  // CARGAS I-2: mostrar % cumplimiento actual
  if (item.title === 'CARGAS I-2') {
    const pct   = Math.round((cargasI2Data.cumplidas / (cargasI2Data.planificadas || 1)) * 100);
    const color = pct >= 80 ? '#00A887' : pct >= 60 ? '#F97316' : '#DC2626';
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top">
          <span class="tile-kpi-badge">I-2</span>
        </div>
        <div class="tile-kpi-value tile-kpi-value--lg" style="color:${color}">${pct}<span class="tile-kpi-sym">%</span></div>
        <div class="tile-kpi-sublabel">CUMPLIMIENTO</div>
        <div class="tile-title one-line tile-label">CARGAS</div>
      </div>`;
  }
  // ALMACENAMIENTO DE POSICIONES I-36: mostrar valor actual del contenedor 5
  if (item.title === 'ALMACENAMIENTO DE POSICIONES') {
    const estEl  = document.getElementById('estibas-en-planta');
    const actual = estEl ? parseInt(estEl.textContent.replace(/\D/g,'')) || 6500 : 6500;
    const color  = actual >= 6200 ? '#00A887' : actual >= 5500 ? '#36B0C9' : '#F97316';
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top">
          <span class="tile-kpi-badge">I-36</span>
        </div>
        <div class="tile-kpi-value tile-kpi-value--md" style="color:${color}">${actual.toLocaleString('es-AR')}</div>
        <div class="tile-kpi-sublabel">POSICIONES</div>
        <div class="tile-title one-line tile-label">ALMACENAMIENTO</div>
      </div>`;
  }
  // POSICIONES INGRESADAS/EGRESADAS: dos valores verde/rojo con barra
  if (item.title === 'POSICIONES INGRESADAS EGRESADAS') {
    const inVal  = ingEgrTile.in  > 0 ? ingEgrTile.in.toLocaleString('es-AR')  : '—';
    const outVal = ingEgrTile.out > 0 ? ingEgrTile.out.toLocaleString('es-AR') : '—';
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge">I/E</span></div>
        <div class="tile-kpi-dual">
          <div class="tile-kpi-dual-item green">
            <span class="tile-kpi-dual-val">${inVal}</span>
            <span class="tile-kpi-dual-lbl">INGR.</span>
          </div>
          <div class="tile-kpi-dual-sep"></div>
          <div class="tile-kpi-dual-item red">
            <span class="tile-kpi-dual-val">${outVal}</span>
            <span class="tile-kpi-dual-lbl">EGR.</span>
          </div>
        </div>
        <div class="tile-title one-line tile-label">POS. INGR / EGR</div>
      </div>`;
  }
  // CLIENTES QUE OPERARON: cantidad real del mes actual
  if (item.title === 'CLIENTES QUE OPERARON') {
    const n = clientesTileData.total > 0 ? clientesTileData.total : clientesOperaron.length;
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge">CLI</span></div>
        <div class="tile-kpi-value tile-kpi-value--lg" style="color:#36B0C9">${n}</div>
        <div class="tile-kpi-sublabel">CLIENTES</div>
        <div class="tile-title one-line tile-label">QUE OPERARON</div>
      </div>`;
  }
  // MOVIMIENTOS (dentro de INDICADORES): tiempos reales vs objetivo
  if (item.title === 'MOVIMIENTOS') {
    const veh = MOV_VEHICULOS.filter(v => v.id !== 'todos'); // sin "todos" en el tile
    return `
      <div class="tile-kpi-wrap tile-mov-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge">MOV</span></div>
        <div class="tile-mov-grid">
          ${veh.map(v => {
            const min     = movTileData[v.id] ?? null;
            const obj     = MOV_OBJETIVOS[v.id];
            const enRojo  = min !== null && obj !== null && min > obj;
            const color   = min === null ? 'rgba(255,255,255,.35)'
                          : enRojo       ? '#EF4444'
                          :                '#22C55E';
            const txt     = min !== null ? min + 'm' : '—';
            return `
              <div class="tile-mov-item">
                <span class="tile-mov-code">${v.code}</span>
                <span class="tile-mov-val" style="color:${color}">${txt}</span>
              </div>`;
          }).join('')}
        </div>
        <div class="tile-title one-line tile-label">MOVIMIENTOS</div>
      </div>`;
  }
  // AJUSTES DE STOCK: I-3 y I-4 con 2 números
  if (item.title === 'AJUSTES DE STOCK') {
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge">AJS</span></div>
        <div class="tile-adj-dual">
          <div class="tile-adj-row"><span class="tile-adj-code">I-3</span><span class="tile-adj-val">1</span></div>
          <div class="tile-adj-row"><span class="tile-adj-code">I-49</span><span class="tile-adj-val">2</span></div>
        </div>
        <div class="tile-title one-line tile-label">AJUSTES STOCK</div>
      </div>`;
  }
  // ESTADISTICAS DE PERSONAL: usuarios online en este momento
  if (item.title === 'ESTADISTICAS DE PERSONAL') {
    const online = rrhhTileData.online ?? '—';
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge">RRHH</span></div>
        <div class="tile-kpi-value tile-kpi-value--lg" style="color:#A78BFA">${online}</div>
        <div class="tile-kpi-sublabel">ONLINE AHORA</div>
        <div class="tile-title one-line tile-label">ESTADÍSTICAS</div>
      </div>`;
  }
  // USO DE EQUIPOS
  if (item.title === 'USO DE EQUIPOS') {
    const ue = usoEquiposData;
    const mes = ue.meses[ue.meses.length-1];
    return `
      <div class="tile-kpi-wrap tile-mov-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge">EQP</span></div>
        <div class="tile-mov-grid">
          <div class="tile-mov-item"><span class="tile-mov-code">BOX</span><span class="tile-mov-val" style="color:#36B0C9">${mes.boxes}h</span></div>
          <div class="tile-mov-item"><span class="tile-mov-code">TRON</span><span class="tile-mov-val" style="color:#36B0C9">${mes.troneras}h</span></div>
          <div class="tile-mov-item"><span class="tile-mov-code">AE</span><span class="tile-mov-val" style="color:#36B0C9">${mes.autoelevadores}h</span></div>
          <div class="tile-mov-item"><span class="tile-mov-code">CAM</span><span class="tile-mov-val" style="color:#36B0C9">${mes.camion}h</span></div>
          <div class="tile-mov-item"><span class="tile-mov-code">LIM</span><span class="tile-mov-val" style="color:#36B0C9">${mes.limpieza}h</span></div>
        </div>
        <div class="tile-title one-line tile-label">USO EQUIPOS</div>
      </div>`;
  }
  // ESTIBAS CONGELADAS: valor del mes en curso desde DB
  if (item.title === 'ESTIBAS CONGELADAS') {
    const total = tunelesTileData.total > 0 ? tunelesTileData.total.toLocaleString('es-AR') : '—';
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge">❄</span></div>
        <div class="tile-kpi-value tile-kpi-value--md" style="color:#60c8e0">${total}</div>
        <div class="tile-kpi-sublabel">ESTIBAS MES</div>
        <div class="tile-title one-line tile-label">CONGELADAS</div>
      </div>`;
  }
  // FACTURACIÓN
  if (item.title === 'FACTURACION') {
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge" style="background:rgba(249,115,22,.2);color:#F97316;border-color:rgba(249,115,22,.4)">FAC</span></div>
        <div style="font-size:2rem;line-height:1">🧾</div>
        <div class="tile-kpi-sublabel">RESÚMENES</div>
        <div class="tile-title one-line tile-label">FACTURACIÓN</div>
      </div>`;
  }
  // REMITOS
  if (item.title === 'REMITOS') {
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge" style="background:rgba(167,139,250,.2);color:#A78BFA;border-color:rgba(167,139,250,.4)">REM</span></div>
        <div style="font-size:2rem;line-height:1">📋</div>
        <div class="tile-kpi-sublabel">DESCARGA</div>
        <div class="tile-title one-line tile-label">REMITOS</div>
      </div>`;
  }
  // COMPRAS
  if (item.title === 'COMPRAS') {
    const pendientes = (typeof comprasDB !== 'undefined') ? comprasDB.ordenes.filter(o => o.estado === 'PENDIENTE').length : 0;
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge" style="background:rgba(250,204,21,.15);color:#FACC15;border-color:rgba(250,204,21,.3)">OC</span></div>
        <div class="tile-kpi-value tile-kpi-value--lg" style="color:#FACC15">${pendientes > 0 ? pendientes : '—'}</div>
        <div class="tile-kpi-sublabel">${pendientes > 0 ? 'PENDIENTES' : 'ÓRDENES'}</div>
        <div class="tile-title one-line tile-label">COMPRAS</div>
      </div>`;
  }

  // SALIDAS: imagen personalizada + cantidad del mes
  if (item.title === 'SALIDAS') {
    const totalMes = logModData.salidas.length; // en producción vendría del server
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top"><span class="tile-kpi-badge" style="background:rgba(0,168,135,.18);color:#00A887;border-color:rgba(0,168,135,.4)">SAL</span></div>
        <img src="img/salidassimbolo.png" class="tile-custom-img" alt="Salidas" onerror="this.style.display='none';this.nextElementSibling.style.display='block'">
        <div style="font-size:1.6rem;display:none">📤</div>
        <div class="tile-kpi-value tile-kpi-value--lg" style="color:#00A887">${totalMes}</div>
        <div class="tile-kpi-sublabel">SALIDAS DEL MES</div>
        <div class="tile-title one-line tile-label">SALIDAS</div>
      </div>`;
  }
  // PR 6 CONTRASTE DE TERMÓMETROS: grilla de 20 recuadros con estado por cámara
  if (item.title === 'PR 6 CONTRASTE DE TERMOMETROS') {
    const hoy     = new Date();
    const TOTAL   = 20;

    // Para cada cámara buscar el registro más reciente (DB primero, fallback a memoria)
    const estadoCamaras = PR6_CAMARAS.map(cam => {
      const camaraObj = camarasDB.find(c => c.nombre_display === cam);
      const camaraNum = camaraObj ? camaraObj.CamaraNumero : null;
      if (pr6EstadoCamarasDB.length && camaraNum) {
        const dbRow = pr6EstadoCamarasDB.find(r => parseInt(r.camara) === camaraNum);
        if (dbRow) {
          const dias = parseInt(dbRow.dias_desde_ultimo);
          return { cam, estado: dias <= 30 ? 'ok' : 'vencido', dias };
        }
      }
      const registrosConCam = pr6Registros.filter(r =>
        r.detalles && r.detalles.some(d => d.camara_nombre === cam || d.camara === cam)
      );
      if (!registrosConCam.length) return { cam, estado: 'sin-dato' };
      const fechas = registrosConCam.map(r => new Date(r.fecha));
      const ultima = new Date(Math.max(...fechas));
      const dias   = Math.floor((hoy - ultima) / (1000 * 60 * 60 * 24));
      return { cam, estado: dias <= 30 ? 'ok' : 'vencido', dias };
    });

    // Generar los 20 recuadros: 11 cámaras reales + 9 vacíos
    const recuadros = [];
    for (let i = 0; i < TOTAL; i++) {
      if (i < PR6_CAMARAS.length) {
        const { cam, estado, dias } = estadoCamaras[i];
        const label = cam
          .replace('CÁMARA ', 'C')
          .replace('ANTECÁMARA', 'AC')
          .replace('SALA DE MÁQUINAS', 'SM')
          .replace('EXTERIOR', 'EXT');
        recuadros.push(`<div class="pr6-tile-cam pr6-cam-${estado}" title="${cam}: ${dias != null ? dias+' días' : 'sin dato'}"></div>`);
      } else {
        recuadros.push(`<div class="pr6-tile-cam pr6-cam-empty"></div>`);
      }
    }

    return `
      <div class="pr6-tile-wrap">
        <div class="pr6-tile-grid">${recuadros.join('')}</div>
        <div class="pr6-tile-footer">
          <span class="pr6-tile-badge">PR-06</span>
          <span class="pr6-tile-name">Contraste de Termómetros</span>
        </div>
      </div>`;
  }

  // PR 9 SEMANAL — muestra fecha, cámaras y usuario del último registro
  if (item.title === 'PR 9 SEMANAL') {
    const reg   = _pr9UltimoReg;
    const fecha = reg?.fecha ? reg.fecha.split('-').reverse().join('/') : null;
    const hora  = reg?.hora  ? reg.hora.slice(0,5) : null;
    const maq   = reg?.maquinista || null;
    const cams  = reg?.camaras_nombres || null;
    const camCount = reg?.camaras_count || null;
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top">
          <span class="tile-kpi-badge" style="background:rgba(54,176,201,.18);color:#36B0C9;border-color:rgba(54,176,201,.35)">PR-09</span>
        </div>
        ${fecha ? `
          <div style="font-size:.72rem;font-weight:700;color:rgba(255,255,255,.45);text-transform:uppercase;letter-spacing:.5px;margin-top:4px">Último registro</div>
          <div style="font-size:.92rem;font-weight:900;color:#36B0C9;line-height:1.2;margin-top:3px">${fecha}${hora ? ' · ' + hora : ''}</div>
          ${maq ? `<div style="font-size:.72rem;color:rgba(255,255,255,.55);font-weight:600;margin-top:2px">👤 ${maq}</div>` : ''}
          ${cams  ? `<div style="font-size:.68rem;color:rgba(255,255,255,.45);margin-top:2px;line-height:1.3">❄️ ${cams}</div>`
                  : camCount ? `<div style="font-size:.68rem;color:rgba(255,255,255,.45);margin-top:2px">❄️ ${camCount} cámara${camCount !== 1 ? 's' : ''}</div>` : ''}
        ` : `
          <div style="font-size:1.8rem;line-height:1;margin:4px 0">📋</div>
          <div style="font-size:.72rem;color:rgba(255,255,255,.35);margin-top:2px">Sin registros aún</div>
        `}
        <div class="tile-title one-line tile-label" style="margin-top:6px">PR-09 SEMANAL</div>
      </div>`;
  }

  // PR 22 LIMPIEZA DE TANQUES
  if (item.title === 'PR 22 LIMPIEZA TANQUES') {
    const hoy = new Date();
    const getEstado = (tanque) => {
      const regs = pr22Registros.filter(r => r.tanques && r.tanques[tanque]);
      if (!regs.length) return 'sin';
      const fechas = regs.map(r => new Date(r.fecha));
      const ultima = new Date(Math.max(...fechas));
      const dias   = Math.floor((hoy - ultima) / (1000 * 60 * 60 * 24));
      return dias <= 30 ? 'ok' : 'vencido';
    };
    const estNorte = getEstado('norte');
    const estSur   = getEstado('sur');
    const labelNorte = estNorte === 'ok' ? '≤30 días' : estNorte === 'vencido' ? '>30 días' : 'Sin dato';
    const labelSur   = estSur   === 'ok' ? '≤30 días' : estSur   === 'vencido' ? '>30 días' : 'Sin dato';
    return `
      <div class="pr22-tile-wrap">
        <div class="pr22-tile-tanques">
          <div class="pr22-tile-tanque">
            <div class="pr22-tile-drum">🛢️</div>
            <div class="pr22-tile-label">Norte</div>
            <div class="pr22-tile-estado pr22-estado-${estNorte}">${labelNorte}</div>
          </div>
          <div class="pr22-tile-sep"></div>
          <div class="pr22-tile-tanque">
            <div class="pr22-tile-drum">🛢️</div>
            <div class="pr22-tile-label">Sur</div>
            <div class="pr22-tile-estado pr22-estado-${estSur}">${labelSur}</div>
          </div>
        </div>
        <div class="pr22-tile-footer">
          <span class="pr22-tile-badge">PR-22</span>
          <span class="pr22-tile-name">Limpieza de Tanques</span>
        </div>
      </div>`;
  }

  // PR 80 PARADA DE CAMARAS — muestra cantidad de cámaras Sin inyección
  if (item.title === 'PR 80 PARADA DE CAMARAS') {
    let countSinIny = 0;
    let namesSinIny = [];
    if (_sdmCamaras.length) {
      _sdmCamaras.forEach(function(c) {
        if (c.btn_color === 'gray') {
          countSinIny++;
          namesSinIny.push(c.nombre_display || ('C' + c.CamaraNumero));
        }
      });
    } else {
      dashboardLogisticaNacionalData.forEach(function(c) {
        var est = (c.estado_camara || c.estado || '').toLowerCase();
        if (est.includes('sin') || est.includes('no iny')) {
          countSinIny++;
          namesSinIny.push((c.nombre_display || '').replace('Cámara ','C').replace('Túnel ','T').replace('Antecámara ','AC'));
        }
      });
    }
    const subLabel = countSinIny > 0
      ? namesSinIny.slice(0,3).join(', ') + (namesSinIny.length > 3 ? ' +' + (namesSinIny.length - 3) : '')
      : 'Todas inyectando';
    const countColor = countSinIny > 0 ? '#ef4444' : '#22c55e';
    return `
      <div class="tile-kpi-wrap">
        <div class="tile-kpi-top">
          <span class="tile-kpi-badge" style="background:rgba(239,68,68,.18);color:#f87171;border-color:rgba(239,68,68,.35)">PR-80</span>
        </div>
        <div style="font-size:1.6rem;font-weight:900;color:${countColor};line-height:1;margin:4px 0">${countSinIny}</div>
        <div style="font-size:.68rem;font-weight:700;color:${countColor};text-transform:uppercase;letter-spacing:.5px">${countSinIny > 0 ? 'Sin inyección' : 'Sin inyección'}</div>
        ${countSinIny > 0 ? `<div style="font-size:.62rem;color:rgba(255,255,255,.4);margin-top:3px;line-height:1.3;max-width:100%;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${subLabel}</div>` : ''}
        <div class="tile-title one-line tile-label" style="margin-top:6px">PR-80 PARADA DE CÁMARAS</div>
      </div>`;
  }

  // PR 100 DESCONGELADO
  if (item.title === 'PR 100 DESCONGELADO') {
    // Contar cámaras en deshelo: primero desde _sdmCamaras (btn_color=yellow), si no desde dashboardLogisticaNacionalData
    let countDeshelo = 0;
    let namesDeshelo = [];
    if (_sdmCamaras.length) {
      _sdmCamaras.forEach(function(c) {
        if (c.btn_color === 'yellow') {
          countDeshelo++;
          namesDeshelo.push(c.nombre_display || ('C' + c.CamaraNumero));
        }
      });
    } else {
      dashboardLogisticaNacionalData.forEach(function(c) {
        var est = (c.estado_camara || c.estado || '').toLowerCase();
        if (est.includes('desh') || est.includes('descongelad')) {
          countDeshelo++;
          namesDeshelo.push((c.nombre_display || '').replace('Cámara ','C').replace('Túnel ','T').replace('Antecámara ','AC'));
        }
      });
    }
    const subLabel = countDeshelo > 0
      ? namesDeshelo.slice(0,3).join(', ') + (namesDeshelo.length > 3 ? ' +' + (namesDeshelo.length - 3) : '')
      : 'Sin cámaras en desheló';
    const countColor = countDeshelo > 0 ? '#facc15' : 'rgba(255,255,255,.35)';
    return `
      <div class="pr100-tile-wrap">
        <div class="pr100-tile-footer" style="flex-direction:column;gap:4px;padding:14px 10px">
          <span class="pr100-tile-badge">PR-100</span>
          <span class="pr100-tile-name" style="font-size:.75rem;font-weight:700">Descongelado de Cámaras</span>
          <div style="font-size:1.6rem;font-weight:900;color:${countColor};line-height:1">${countDeshelo}</div>
          <span style="font-size:.65rem;color:${countColor};font-weight:600;opacity:.85">${countDeshelo > 0 ? 'En desheló ahora' : 'En desheló ahora'}</span>
          ${countDeshelo > 0 ? `<span style="font-size:.6rem;color:rgba(255,255,255,.4);line-height:1.3;max-width:100%;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${subLabel}</span>` : ''}
        </div>
      </div>`;
  }

  return null; // usar HTML por defecto
}

function getIconMarkup(title) {
  const imageMap = {
    'SISTEMA DE GESTION': 'img/iso_logo.png',
    'SENASA':             'img/senasa_logo.png'
  };
  if (imageMap[title]) {
    return `<img src="${imageMap[title]}" alt="${title}" onerror="this.style.display='none';this.parentElement.textContent='${getTextInitials(title)}';">`;
  }
  const symbolMap = {
    'LOGISTICA NACIONAL':     '🚛',
    'LOGISTICA FISCAL':       '📦',
    'CALIDAD':                '🌡',
    'PORTERIA':               '🚪',
    'TRANSPORTE':             '🚚',
    'INDICADORES':            '📊',
    'REPORTES':               '📑',
    'DASHBOARD':              '🖥',
    'ADMINISTRACION':         '🗂',
    'RRHH':                   '👥',
    'MANTENIMIENTO':          '🔧',
    'PAÑOL':                  '🔩',
    'CONFIGURACION':          '⚙',
    'PRODUCTOS':              '📦',
    'OTROS SISTEMAS':         '🧩',
    'INFORMACION DOCUMENTADA':'📚',
    'REGISTRO PR 44':         '🗂',
    'FORMACION':              '👨‍🏫',
    'MAPA DE BOXES':          '🗺',
    'USUARIOS':               '👤',
    'ROLES':                  '🔑'
  };
  return symbolMap[title] || getTextInitials(title);
}

function getEquipmentIconMarkup(item) {
  if (item.isImage) {
    return `<img src="${item.icono}" alt="${item.tipo}" onerror="this.style.display='none';this.parentElement.textContent='🛗';">`;
  }
  return item.icono;
}

function getGridLayout(count) {
  // Returns a CSS class and also sets a data-count attribute on menuGrid
  // so CSS can use the right tile size
  if (count === 1)  return 'layout-1';
  if (count === 2)  return 'layout-2';
  if (count === 3)  return 'layout-3';
  if (count <= 4)   return 'layout-4';
  if (count <= 5)   return 'layout-5';
  if (count <= 6)   return 'layout-6';
  if (count <= 8)   return 'layout-8';
  if (count <= 9)   return 'layout-9';
  if (count <= 12)  return 'layout-12';
  if (count <= 14)  return 'layout-14';
  return 'layout-16';
}

function formatTitle(title) {
  const words = title.trim().split(/\s+/);
  if (words.length <= 1) return title;
  if (words.length === 2) return `${words[0]}<br>${words[1]}`;
  const mid = Math.ceil(words.length / 2);
  return `${words.slice(0, mid).join(' ')}<br>${words.slice(mid).join(' ')}`;
}

function titleClass(title) {
  return title.trim().split(/\s+/).length >= 2 ? 'two-lines' : 'one-line';
}

function openModule(url) {
  // Si es URL del sistema interno CINA, embeber en iframe
  if (url && url.includes('sistema.cinafrio.com')) {
    renderIframe(url);
    return;
  }
  window.open(url, '_blank', 'noopener,noreferrer');
}

/* ── IFRAME EMBEBIDO ─────────────────────────────────────────
   Carga páginas internas del sistema dentro del workspace,
   ocultando el sidebar y el botón de toggle de AdminLTE.
   ──────────────────────────────────────────────────────────── */
function renderIframe(url) {
  showMetaPanel(true);
  setExpandedMode(false);

  workspace.innerHTML = `
    <div class="iframe-wrap">
      <div class="iframe-toolbar">
        <span class="iframe-url-label">🌐 sistema.cinafrio.com</span>
        <a class="iframe-open-btn" href="${url}" target="_blank" title="Abrir en pestaña nueva">
          ↗ Nueva pestaña
        </a>
      </div>
      <iframe
        id="cinaFrame"
        src="${url}"
        class="cina-iframe"
        frameborder="0"
      ></iframe>
    </div>
  `;

  // Inyectar CSS en el iframe para ocultar sidebar AdminLTE
  const frame = document.getElementById('cinaFrame');
  if (frame) {
    frame.addEventListener('load', () => {
      try {
        const doc = frame.contentDocument || frame.contentWindow.document;
        const style = doc.createElement('style');
        style.textContent = `
          .main-sidebar { display: none !important; }
          .sidebar-toggle { display: none !important; }
          .content-wrapper { margin-left: 0 !important; }
          .main-header .logo { display: none !important; }
          .main-header .navbar { margin-left: 0 !important; }
          body { overflow-y: auto !important; }
          .main-footer { display: none !important; }
        `;
        doc.head.appendChild(style);
        // También ocultar via DOM directo
        ['aside.main-sidebar', '.sidebar-toggle', '.logo'].forEach(sel => {
          const el = doc.querySelector(sel);
          if (el) el.style.cssText += 'display:none!important';
        });
        const cw = doc.querySelector('.content-wrapper');
        if (cw) cw.style.marginLeft = '0';
        const nav = doc.querySelector('.navbar');
        if (nav) nav.style.marginLeft = '0';
      } catch(e) {
        // Cross-origin: no se puede modificar — igualmente el iframe carga
        console.warn('iframe cross-origin, no se pudo inyectar CSS:', e);
      }
    });
  }

  historyStack.push({ title: 'INICIO', children: menuTree });
  syncBackBtn();
}

function darkenColor(hex, amount) {
  let color = hex.replace('#', '');
  if (color.length === 3) color = color.split('').map(c => c + c).join('');
  let r = parseInt(color.substring(0, 2), 16);
  let g = parseInt(color.substring(2, 4), 16);
  let b = parseInt(color.substring(4, 6), 16);
  r = Math.max(0, Math.min(255, r + amount));
  g = Math.max(0, Math.min(255, g + amount));
  b = Math.max(0, Math.min(255, b + amount));
  return '#' + [r, g, b].map(v => v.toString(16).padStart(2, '0')).join('');
}

function getTileColors(item, level) {
  const base = level === 0 ? (mainColorMap[item.title] || '#001F60') : '#163A7A';
  return { start: base, end: darkenColor(base, -28) };
}

function buildClientSlots(clientes) {
  // Solo mostrar clientes que tienen mercadería en una cámara NO asignada → badge rojo
  const alertas = clientes.filter(c => c.camara_asignada === false);
  const total   = 6;
  const filled  = alertas.slice(0, total);
  const slots   = filled.map(c => {
    const title = `${c.nombre || c.siglas} ⚠️ Cámara no asignada`;
    return `<div class="client-badge" title="${title}"
      style="background:rgba(239,68,68,.35);border-color:rgba(239,68,68,.7);color:#fff">${c.siglas || '?'}</div>`;
  });
  for (let i = slots.length; i < total; i++) slots.push('<div class="client-badge empty"></div>');
  return slots.join('');
}

function getTemperatureStyle(temp) {
  if (temp >= 0)   return 'linear-gradient(135deg,#16a34a,#22c55e)';
  if (temp > -10)  return 'linear-gradient(135deg,#0891b2,#06b6d4)';
  if (temp > -20)  return 'linear-gradient(135deg,#2563eb,#3b82f6)';
  if (temp > -25)  return 'linear-gradient(135deg,#4338ca,#6366f1)';
  return 'linear-gradient(135deg,#7e22ce,#a855f7)';
}

function buildStatusRow(item) {
  // ── Puerta: color según estado real desde camara_puerta_registro ──
  let puertaColor, puertaTitle;
  if (item.puerta === 'Cerrada') {
    puertaColor = '#22C55E'; puertaTitle = 'Puerta cerrada';   // verde
  } else if (item.puerta === 'Abierta') {
    puertaColor = '#EF4444'; puertaTitle = 'Puerta abierta';   // rojo
  } else {
    puertaColor = 'rgba(255,255,255,0.15)'; puertaTitle = 'Sin datos de puerta';
  }

  // ── Ventilador: color según estado SCADA ──────────────────────
  const estadoCamara = (item.estado_camara || '').toLowerCase();
  let fanColor, fanTitle;
  if (estadoCamara.includes('desh')) {
    fanColor = '#FACC15'; fanTitle = 'En desheló';
  } else if (estadoCamara.includes('sin')) {
    fanColor = '#EF4444'; fanTitle = 'Sin inyección';
  } else if (estadoCamara.includes('inye')) {
    fanColor = '#22C55E'; fanTitle = 'Inyectando';
  } else if (estadoCamara.includes('normal')) {
    fanColor = '#86EFAC'; fanTitle = 'Normal';
  } else {
    fanColor = 'rgba(255,255,255,0.15)'; fanTitle = 'Sin datos';
  }

  return `
    <div class="dashboard-status-row">
      <div class="status-box" title="${puertaTitle}"
           style="background:${puertaColor};border-color:${puertaColor};filter:brightness(1.1)">🚪</div>
      <div class="status-box" title="${fanTitle}"
           style="background:${fanColor};border-color:${fanColor};filter:brightness(1.1)">🌀</div>
    </div>`;
}

function getEquipmentCardClass(estado) {
  if (estado === 'En marcha') return 'state-running-card';
  if (estado === 'Cargando')  return 'state-charging-card';
  return 'state-failure-card';
}

/* ── MODAL DE EDICIÓN DE EQUIPO ─────────────────────────────── */
function openEquipmentModal(index) {
  const item = dashboardEquipamientoData[index];

  // Eliminar modal previo si existe
  document.getElementById('equipModal')?.remove();

  const modal = document.createElement('div');
  modal.id = 'equipModal';
  modal.className = 'equip-modal-overlay';

  modal.innerHTML = `
    <div class="equip-modal">
      <div class="equip-modal-header">
        <div class="equip-modal-title">
          <span class="equip-modal-denom">${item.denominacion}</span>
          <span class="equip-modal-type">${item.tipo}</span>
        </div>
        <button class="equip-modal-close" id="equipModalClose">✕</button>
      </div>

      <div class="equip-modal-body">

        <div class="equip-modal-field">
          <label class="equip-modal-label" for="em_estado">Estado</label>
          <div class="equip-modal-select-wrap">
            ${ESTADOS_EQUIPO.map(e => `
              <label class="equip-state-opt ${e === item.estado ? 'selected' : ''} state-opt-${e.toLowerCase().replace(/ /g,'-')}">
                <input type="radio" name="em_estado" value="${e}" ${e === item.estado ? 'checked' : ''}>
                ${e}
              </label>`).join('')}
          </div>
        </div>

        <div class="equip-modal-field">
          <label class="equip-modal-label" for="em_planta">Planta</label>
          <select id="em_planta" class="equip-modal-select">
            ${PLANTAS_EQUIPO.map(p => `<option value="${p}" ${p === item.planta ? 'selected' : ''}>${p}</option>`).join('')}
          </select>
        </div>

        <div class="equip-modal-field">
          <label class="equip-modal-label" for="em_usuario">Usuario</label>
          <input id="em_usuario" class="equip-modal-input" type="text" value="${perfilData.usuario}" placeholder="Nombre de usuario">
        </div>

        <div class="equip-modal-field">
          <label class="equip-modal-label" for="em_horas">Horas en estado</label>
          <input id="em_horas" class="equip-modal-input" type="text" value="${item.horas}" placeholder="Ej: 01:30hs">
        </div>

      </div>

      <div class="equip-modal-footer">
        <button class="equip-modal-btn cancel" id="equipModalCancel">Cancelar</button>
        <button class="equip-modal-btn save"   id="equipModalSave">💾 Guardar cambios</button>
      </div>
    </div>
  `;

  document.body.appendChild(modal);

  /* Resaltar opción de estado al hacer click */
  modal.querySelectorAll('input[name="em_estado"]').forEach(radio => {
    radio.addEventListener('change', () => {
      modal.querySelectorAll('.equip-state-opt').forEach(l => l.classList.remove('selected'));
      radio.parentElement.classList.add('selected');
    });
  });

  /* Cerrar al click fuera */
  modal.addEventListener('click', e => { if (e.target === modal) closeModal(); });

  document.getElementById('equipModalClose').addEventListener('click', closeModal);
  document.getElementById('equipModalCancel').addEventListener('click', closeModal);

  document.getElementById('equipModalSave').addEventListener('click', () => {
    const nuevoEstado  = modal.querySelector('input[name="em_estado"]:checked')?.value || item.estado;
    const nuevaPlanta  = document.getElementById('em_planta').value.trim();
    const nuevoUsuario = document.getElementById('em_usuario').value.trim();
    const nuevasHoras  = document.getElementById('em_horas').value.trim();

    // Validaciones básicas
    if (!nuevoUsuario) { showModalError('El campo usuario no puede estar vacío.'); return; }
    if (!nuevasHoras)  { showModalError('El campo horas no puede estar vacío.');  return; }

    // Persistir en el array fuente
    dashboardEquipamientoData[index].estado  = nuevoEstado;
    dashboardEquipamientoData[index].planta  = nuevaPlanta;
    dashboardEquipamientoData[index].usuario = nuevoUsuario;
    dashboardEquipamientoData[index].horas   = nuevasHoras;

    closeModal();

    // Re-renderizar el dashboard con los datos actualizados
    renderDashboardEquipamiento();

    showToast(`✓ ${item.denominacion} actualizado correctamente`);
  });

  // Animar entrada
  requestAnimationFrame(() => modal.classList.add('visible'));

  function closeModal() {
    modal.classList.remove('visible');
    setTimeout(() => modal.remove(), 220);
  }

  function showModalError(msg) {
    let err = modal.querySelector('.equip-modal-error');
    if (!err) {
      err = document.createElement('p');
      err.className = 'equip-modal-error';
      modal.querySelector('.equip-modal-footer').prepend(err);
    }
    err.textContent = msg;
  }
}

/* Toast de confirmación */
function showToast(msg) {
  document.getElementById('cinaToast')?.remove();
  const toast = document.createElement('div');
  toast.id = 'cinaToast';
  toast.className = 'cina-toast';
  toast.textContent = msg;
  document.body.appendChild(toast);
  requestAnimationFrame(() => toast.classList.add('visible'));
  setTimeout(() => {
    toast.classList.remove('visible');
    setTimeout(() => toast.remove(), 300);
  }, 2800);
}

/* ── RENDERS ────────────────────────────────────────────────── */
function renderDashboardLogisticaNacional() {
  setHeader('DASHBOARD LOGISTICA NACIONAL');
  setExpandedMode(false);
  showMetaPanel(true);
  menuGrid.className = '';
  menuGrid.innerHTML = '';

  const grid = document.createElement('div');
  grid.className = 'dashboard-grid';

  dashboardLogisticaNacionalData.forEach(item => {
    const card = document.createElement('button');
    const tipoClass = {
      'TUNEL'      : 'dashboard-card-tunel',
      'ANTECAMARA' : 'dashboard-card-antecamara',
      'ANDEN_NORTE': 'dashboard-card-anden-norte',
      'ANDEN_SUR'  : 'dashboard-card-anden-sur',
    }[item.tipo] || '';

    // ── Color de borde según estado temperatura (igual que parada de cámaras) ──
    const estadoLow = (item.estado_camara || '').toLowerCase().trim();
    let colorClass = '';
    if (estadoLow.includes('deshel') || estadoLow.includes('descongelad')) {
      colorClass = 'dashboard-card-deshelo';   // amarillo
    } else if (estadoLow === 'sin inyección' || estadoLow === 'sin inyeccion' ||
               estadoLow === 'no inyectando' || estadoLow === 'parada') {
      colorClass = 'dashboard-card-parada';    // gris/rojo
    } else if (item.temperatura !== null) {
      colorClass = 'dashboard-card-marcha';    // verde
    }

    card.className = 'dashboard-card' + (tipoClass ? ' ' + tipoClass : '') + (colorClass ? ' ' + colorClass : '');
    card.type = 'button';

    // ── Borde por sector según CamaraID (misma lógica que sala de máquinas) ──
    const sectorDash = sdmGetSector(item.camara_id);
    card.classList.add('dashboard-border-' + sectorDash);
    card.innerHTML = `
      <div class="dashboard-left">
        <div class="dashboard-temp" style="background:${getTemperatureStyle(item.temperatura)}">
          <div class="dashboard-temp-label">Temp.</div>
          <div class="dashboard-temp-value">${item.temperatura !== null ? item.temperatura+'°C' : '—'}</div>
          ${item.temp_hora ? `<div style="font-size:.55rem;opacity:.6;margin-top:2px">${item.temp_hora.slice(0,5)}</div>` : ''}
        </div>
        <div class="dashboard-alert">
          <div class="dashboard-alert-value">${item.extra || 0}</div>
          <div class="dashboard-alert-label">SIN POS.</div>
        </div>
        <div class="dashboard-alert dashboard-alert-venc">
          <div class="dashboard-alert-value dashboard-venc-value">${item.vencidas || 0}</div>
          <div class="dashboard-alert-label">VENCIDAS</div>
        </div>
      </div>
      <div class="dashboard-main">
        <div class="dashboard-title">${item.nombre_display || (item.tipo+' '+item.nombre)}</div>
        <div class="dashboard-number">${item.capacidad > 0 ? Math.round((item.estibas || 0) / item.capacidad * 100) + '%' : '—'}</div>
        <div class="dashboard-sub">${item.estibas || 0} ESTIBAS</div>
        ${item.tipo === 'TUNEL' && item.tunel_fecha ? `<div class="dashboard-tunel-fecha">${item.tunel_fecha}</div>` : ''}
        ${buildStatusRow(item)}
      </div>
      <div class="dashboard-clients">${buildClientSlots(item.clientes||[])}</div>`;
    card.addEventListener('click', () => renderHistorialCamara(item));
    grid.appendChild(card);
  });

  menuGrid.appendChild(grid);

  // ── Leyenda del ventilador ────────────────────────────────────
  const leyenda = document.createElement('div');
  leyenda.style.cssText = `
    display:flex;align-items:center;justify-content:center;
    gap:18px;flex-wrap:wrap;
    padding:7px 16px;margin-top:4px;
    font-size:.65rem;font-weight:600;letter-spacing:.04em;
    color:rgba(255,255,255,.5);user-select:none;`;
  leyenda.innerHTML = [
    { icon: '🚪', color: '#22C55E', label: 'Cerrada'        },
    { icon: '🚪', color: '#EF4444', label: 'Abierta'        },
    { icon: '🌀', color: '#FACC15', label: 'Descongelando'  },
    { icon: '🌀', color: '#EF4444', label: 'Detenida'       },
    { icon: '🌀', color: '#22C55E', label: 'Funcionando'    },
    { icon: '🌀', color: '#86EFAC', label: 'En temperatura' },
  ].map(({icon, color, label}) => `
    <span style="display:inline-flex;align-items:center;gap:5px">
      <span style="
        display:inline-flex;align-items:center;justify-content:center;
        width:18px;height:18px;border-radius:4px;
        background:${color};font-size:.75rem;line-height:1">${icon}</span>
      ${label}
    </span>`).join('');
  menuGrid.appendChild(leyenda);

  syncBackBtn();

  // Actualizar tiles desde DB
  cargarHeaderTiles();

  // ── Auto-refresh cada 60s mientras el dashboard esté abierto ──
  stopDashNacRefresh(); // limpiar timer previo si existiera

  // Indicador visual de countdown en el header
  const REFRESH_SEG = 300;
  let segsRestantes = REFRESH_SEG;

  const ind = document.createElement('span');
  ind.id = 'dashNacRefreshInd';
  ind.title = 'Actualización automática cada 5 minutos';
  ind.style.cssText = `
    display:inline-flex;align-items:center;gap:5px;
    font-size:.65rem;font-weight:600;letter-spacing:.04em;
    color:rgba(255,255,255,.45);margin-left:12px;
    vertical-align:middle;user-select:none;`;
  ind.innerHTML = `<span class="dash-ref-dot" style="
    width:6px;height:6px;border-radius:50%;
    background:#36B0C9;display:inline-block;
    animation:dashRefPulse 2s ease-in-out infinite;"></span>
    <span id="dashNacCountTxt">↻ ${REFRESH_SEG}s</span>`;

  // Inyectar estilos de animación si no existen
  if (!document.getElementById('dashRefStyle')) {
    const st = document.createElement('style');
    st.id = 'dashRefStyle';
    st.textContent = `@keyframes dashRefPulse{0%,100%{opacity:.4}50%{opacity:1}}
    @keyframes dashRefSpin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}`;
    document.head.appendChild(st);
  }

  const titleEl = document.getElementById('screenTitle');
  if (titleEl) titleEl.after(ind);

  // Countdown visual cada segundo
  _dashNacCountdown = setInterval(() => {
    segsRestantes--;
    const txt = document.getElementById('dashNacCountTxt');
    if (txt) txt.textContent = `↻ ${segsRestantes}s`;
  }, 1000);

  // Refresh real cada 5 minutos — recarga datos y actualiza DOM in-place
  _dashNacTimer = setInterval(async () => {
    segsRestantes = REFRESH_SEG;
    const txt = document.getElementById('dashNacCountTxt');
    const dot = ind.querySelector('.dash-ref-dot');
    if (txt) txt.textContent = '↻ ...';
    if (dot) dot.style.background = '#facc15';

    // 1. Recargar temperaturas desde DB
    await cargarCamarasDesdeDB();

    // 2. Actualizar cada card in-place sin re-renderizar toda la pantalla
    const grid = menuGrid.querySelector('.dashboard-grid');
    if (grid) {
      grid.querySelectorAll('.dashboard-card').forEach((card, i) => {
        const item = dashboardLogisticaNacionalData[i];
        if (!item) return;
        const tempEl = card.querySelector('.dashboard-temp-value');
        const horaEl = card.querySelector('.dashboard-temp > div:last-child');
        const numEl  = card.querySelector('.dashboard-number');
        const subEl  = card.querySelector('.dashboard-sub');
        const fanEl  = card.querySelector('.dashboard-status-row');
        if (tempEl) tempEl.textContent = item.temperatura !== null ? item.temperatura + '°C' : '—';
        if (horaEl && item.temp_hora) horaEl.textContent = item.temp_hora.slice(0, 5);
        if (numEl)  numEl.textContent  = item.capacidad > 0
          ? Math.round((item.estibas || 0) / item.capacidad * 100) + '%' : '—';
        if (subEl)  subEl.textContent  = (item.estibas || 0) + ' ESTIBAS';
        if (fanEl)  fanEl.outerHTML    = buildStatusRow(item);
        // Actualizar clase de color según estado temperatura
        card.classList.remove('dashboard-card-marcha','dashboard-card-deshelo','dashboard-card-parada');
        const eL = (item.estado_camara||'').toLowerCase().trim();
        if (eL.includes('deshel')||eL.includes('descongelad')) card.classList.add('dashboard-card-deshelo');
        else if (eL==='sin inyección'||eL==='sin inyeccion'||eL==='no inyectando'||eL==='parada') card.classList.add('dashboard-card-parada');
        else if (item.temperatura!==null) card.classList.add('dashboard-card-marcha');
        // Actualizar borde de cliente dominante
        const cd = (item.clientes||[]).find(c => c.camara_asignada !== false);
        if (cd?.color) { card.style.setProperty('--client-border', cd.color); card.classList.add('dashboard-card-cliente'); }
        else { card.classList.remove('dashboard-card-cliente'); card.style.removeProperty('--client-border'); }
      });
    }

    // 3. Actualizar estibas, sin posición y clientes por cámara
    cargarHeaderTiles();

    if (txt) txt.textContent = `↻ ${REFRESH_SEG}s`;
    if (dot) dot.style.background = '#36B0C9';
  }, REFRESH_SEG * 1000);
}

function renderDashboardEquipamiento() {
  setHeader('DASHBOARD EQUIPAMIENTO');
  setExpandedMode(false);
  showMetaPanel(true);
  menuGrid.className = '';
  menuGrid.innerHTML = '';

  const wrapper = document.createElement('div');
  wrapper.style.cssText = 'width:100%;box-sizing:border-box;padding:0 4px;';

  const grid = document.createElement('div');
  grid.className = 'equipment-grid';

  dashboardEquipamientoData.forEach((item, index) => {
    const card = document.createElement('div');
    card.className = `equipment-card ${getEquipmentCardClass(item.estado)}`;

    card.innerHTML = `
      <div class="equipment-header">
        <div class="equipment-icon">${getEquipmentIconMarkup(item)}</div>
        <div class="equipment-title-wrap">
          <div class="equipment-type">${item.tipo}</div>
          <div class="equipment-name">${item.denominacion}</div>
        </div>
        <button class="equipment-edit-btn" title="Editar equipo" data-index="${index}">✏️</button>
      </div>
      <div class="equipment-row">
        <div class="equipment-label">Estado</div>
        <div class="equipment-value"><span class="state-badge">${item.estado}</span></div>
      </div>
      <div class="equipment-row">
        <div class="equipment-label">Marca / Modelo</div>
        <div class="equipment-value" style="font-size:.7rem">${item.marca||''} ${item.modelo||''}</div>
      </div>
      <div class="equipment-row">
        <div class="equipment-label">Horómetro</div>
        <div class="equipment-value"><strong>${(item.horasActual||item.horasBase||0).toLocaleString('es-AR')}</strong> hs</div>
      </div>
      <div class="equipment-row">
        <div class="equipment-label">Planta</div>
        <div class="equipment-value"><span class="plant-badge">${item.planta}</span></div>
      </div>
      <div class="equipment-row">
        <div class="equipment-label">Usuario</div>
        <div class="equipment-value">${item.usuario}</div>
      </div>`;

    // Botón editar dentro de la card → editor completo
    card.querySelector('.equipment-edit-btn').addEventListener('click', e => {
      e.stopPropagation();
      openEquipmentEditFull(index);
    });

    // Click en la card según estado
    card.addEventListener('click', () => {
      if (item.estado === 'Cargando')    openChecklistEnMarcha(index);   // lista para poner en marcha
      else if (item.estado === 'Falla')  openCambioEstadoEquipo(index);  // solo pasar a Cargando
      else if (item.estado === 'En marcha') openCambioEstadoEquipo(index); // pasar a Falla o Cargando
    });
    card.style.cursor = 'pointer';

    grid.appendChild(card);
  });

  wrapper.appendChild(grid);

  // Botón "+ Nuevo equipo"
  const btnNuevo = document.createElement('div');
  btnNuevo.style.cssText = 'display:flex;justify-content:flex-end;padding:10px 4px 4px;';
  btnNuevo.innerHTML = '<button id="equipNuevoBtn" style="padding:9px 20px;border-radius:10px;border:1px solid rgba(54,176,201,.4);background:rgba(54,176,201,.12);color:#7dd3fc;font-size:.82rem;font-weight:700;cursor:pointer;transition:background .15s">➕ Nuevo equipo</button>';
  wrapper.appendChild(btnNuevo);
  menuGrid.appendChild(wrapper);
  document.getElementById('equipNuevoBtn')?.addEventListener('click', () => openEquipmentEditFull(null));
  syncBackBtn();
}


