async function precargarTileIngEgr() {
  try {
    const res  = await fetch(`${API_EQUIPOS_URL}?action=estibas_ing_egr&modo=mes&meses=1`, {credentials:'same-origin'});
    const data = await res.json();
    if (data.tile_in !== undefined) {
      ingEgrTile = { in: data.tile_in, out: data.tile_out };
    }
  } catch(e) {}
}

async function precargarTileMovimientos() {
  try {
    const res  = await fetch(`${API_EQUIPOS_URL}?action=movimientos_tiempos&meses=1&tipo_carga=todos`, {credentials:'same-origin'});
    const data = await res.json();
    const nuevo = {};
    MOV_VEHICULOS.forEach(v => {
      const mesesArr = data.datos?.[v.id]?.meses || [];
      if (mesesArr.length) {
        const m = mesesArr[mesesArr.length - 1];
        const e = m.entrada_horas || 0;
        const s = m.salida_horas  || 0;
        const p = e > 0 && s > 0 ? (e + s) / 2 : (e || s);
        nuevo[v.id] = Math.round(p * 60);
      } else {
        nuevo[v.id] = 0;
      }
    });
    movTileData = nuevo;
  } catch(e) {}
}

async function precargarTileRRHH() {
  try {
    const res  = await fetch(`${API_EQUIPOS_URL}?action=rrhh_estadisticas&meses=1`, {credentials:'same-origin'});
    const data = await res.json();
    if (data.online !== undefined) {
      rrhhTileData = { online: data.online };
    }
  } catch(e) {}
}

/* ═══════════════════════════════════════════════════════════════
   PRECARGA TILE CLIENTES QUE OPERARON
   ═══════════════════════════════════════════════════════════════ */
async function precargarTileClientes() {
  try {
    const res  = await fetch(`${API_EQUIPOS_URL}?action=clientes_operaron&periodo=mes_actual`, {credentials:'same-origin'});
    const data = await res.json();
    clientesTileData = { total: data.total_clientes || 0, periodo: data.label_periodo || '—' };
    // Mantener array de nombres para compatibilidad con facturación
    clientesOperaron = (data.clientes || []).map(c => c.nombre);
  } catch(e) {}
}

/* ═══════════════════════════════════════════════════════════════
   INDICADOR: ESTIBAS INGRESADAS / EGRESADAS
   ═══════════════════════════════════════════════════════════════ */
async function renderIndicadorIngEgr() {
  setHeader('INDICADORES');
  setExpandedMode(false);
  showMetaPanel(true);
  menuGrid.className = '';
  menuGrid.innerHTML = '';

  const wrap = document.createElement('div');
  wrap.className = 'indicador-wrap';

  const header = document.createElement('div');
  header.className = 'indicador-card indicador-card-static';
  header.innerHTML = `
    <div class="indicador-card-header">
      <div class="indicador-card-title">
        <span class="indicador-badge">I/E</span>
        ESTIBAS INGRESADAS / EGRESADAS
      </div>
      <div style="display:flex;gap:8px;align-items:center">
        <select id="ingEgrPeriodo" class="pr22-input" style="padding:4px 8px;font-size:.72rem;width:auto">
          <option value="12">12 meses</option>
          <option value="6">6 meses</option>
          <option value="3">3 meses</option>
          <option value="1" selected>Mes actual</option>
        </select>
      </div>
    </div>
    <div class="inegr-totales" id="ingEgrTotales">
      <div class="ge-loading" style="padding:12px">Cargando...</div>
    </div>`;
  wrap.appendChild(header);

  const graficos = document.createElement('div');
  graficos.id = 'ingEgrGraficos';
  wrap.appendChild(graficos);

  menuGrid.appendChild(wrap);
  syncBackBtn();

  let modoActual  = 'mes';
  let mesesActual = 1;  // default: mes actual

  const renderTodo = async () => {
    document.getElementById('ingEgrTotales').innerHTML =
      '<div class="ge-loading" style="padding:12px">Cargando...</div>';
    document.getElementById('ingEgrGraficos').innerHTML = '';

    try {
      const params = modoActual === 'mes'
        ? `modo=mes&meses=${mesesActual}`
        : `modo=dia&dias=${mesesActual === 12 ? 30 : mesesActual === 6 ? 60 : 90}`;
      const res  = await fetch(`${API_EQUIPOS_URL}?action=estibas_ing_egr&${params}`, {credentials:'same-origin'});
      const data = await res.json();
      const d    = data.datos || [];

      if (modoActual === 'mes') ingEgrData    = d;
      else                      ingEgrDataDia = d;

      const totalIn  = d.reduce((s,r) => s + r.ingresadas,  0);
      const totalOut = d.reduce((s,r) => s + r.egresadas,   0);
      const totalMod = d.reduce((s,r) => s + r.modificadas, 0);
      const totalTot = totalIn + totalOut;

      document.getElementById('ingEgrTotales').innerHTML = `
        <div class="inegr-total-item">
          <span class="inegr-total-label">Ingresadas</span>
          <span class="inegr-total-val green">${totalIn.toLocaleString('es-AR')}</span>
        </div>
        <div class="inegr-total-sep"></div>
        <div class="inegr-total-item">
          <span class="inegr-total-label">Egresadas</span>
          <span class="inegr-total-val red">${totalOut.toLocaleString('es-AR')}</span>
        </div>
        <div class="inegr-total-sep"></div>
        <div class="inegr-total-item">
          <span class="inegr-total-label">Modificadas</span>
          <span class="inegr-total-val" style="color:#FACC15">${totalMod.toLocaleString('es-AR')}</span>
        </div>
        <div class="inegr-total-sep"></div>
        <div class="inegr-total-item">
          <span class="inegr-total-label">Total (I+E)</span>
          <span class="inegr-total-val" style="color:#36B0C9">${totalTot.toLocaleString('es-AR')}</span>
        </div>`;

      const grafEl = document.getElementById('ingEgrGraficos');
      grafEl.innerHTML = '';
      const charts = [
        { id:'ingEgrChIn',   title:'📦 Estibas Ingresadas',           key:'ingresadas',  color:'#00A887' },
        { id:'ingEgrChOut',  title:'📤 Estibas Egresadas',            key:'egresadas',   color:'#DC2626' },
        { id:'ingEgrChMod',  title:'✏️ Estibas Modificadas',          key:'modificadas', color:'#FACC15' },
        { id:'ingEgrChTot',  title:'📊 Estibas Totales (Ingr + Egr)', key:'total',       color:'#36B0C9' },
        { id:'ingEgrChKgIn', title:'⚖️ Kg Ingresados',                key:'kg_in',       color:'#00A887', isKg:true },
        { id:'ingEgrChKgOut',title:'⚖️ Kg Egresados',                 key:'kg_out',      color:'#DC2626', isKg:true },
      ];
      charts.forEach(cfg => {
        const sec = document.createElement('div');
        sec.className = 'indicador-mensual';
        sec.innerHTML = `
          <div class="indicador-mensual-title">${cfg.title}</div>
          <div class="inegr-chart-wrap"><canvas id="${cfg.id}"></canvas></div>`;
        grafEl.appendChild(sec);
      });

      requestAnimationFrame(() => {
        charts.forEach(cfg => ingEgrDrawBar(cfg.id, d, cfg.key, cfg.color, cfg.isKg));
      });

    } catch(e) {
      document.getElementById('ingEgrTotales').innerHTML =
        `<div style="opacity:.5;padding:12px">Error: ${e.message}</div>`;
    }
  };

  document.getElementById('ingEgrPeriodo').addEventListener('change', e => {
    mesesActual = parseInt(e.target.value);
    renderTodo();
  });

  renderTodo();
}

function ingEgrDrawBar(canvasId, data, key, color, isKg) {
  const canvas = document.getElementById(canvasId);
  if (!canvas) return;
  const wrap = canvas.parentElement;
  canvas.width  = wrap.clientWidth || 700;
  canvas.height = 200;
  const W = canvas.width, H = canvas.height;
  const PAD = { top:22, right:16, bottom:38, left:54 };
  const chartW = W - PAD.left - PAD.right;
  const chartH = H - PAD.top  - PAD.bottom;
  const ctx = canvas.getContext('2d');
  const n   = data.length;

  const vals   = data.map(d => d[key] || 0);
  const maxVal = Math.max(...vals, 1) * 1.12;
  const barW   = (chartW / n) * 0.58;
  const gap    = (chartW / n) * 0.42;

  ctx.clearRect(0, 0, W, H);

  for (let i = 0; i <= 4; i++) {
    const y = PAD.top + chartH - (i/4) * chartH;
    ctx.strokeStyle = 'rgba(255,255,255,.07)'; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(PAD.left, y); ctx.lineTo(PAD.left + chartW, y); ctx.stroke();
    ctx.fillStyle = 'rgba(255,255,255,.42)';
    ctx.font = '9px Segoe UI'; ctx.textAlign = 'right';
    const yLbl = isKg
      ? ((maxVal * i/4) >= 1e6 ? ((maxVal*i/4)/1e6).toFixed(1)+'M' : ((maxVal*i/4)/1e3).toFixed(0)+'k')
      : Math.round(maxVal * i/4).toLocaleString('es-AR');
    ctx.fillText(yLbl, PAD.left - 5, y + 3);
  }

  vals.forEach((v, i) => {
    const x      = PAD.left + i * (barW + gap) + gap/2;
    const bH     = Math.max((v / maxVal) * chartH, v > 0 ? 2 : 0);
    const y      = PAD.top + chartH - bH;
    const isLast = i === n - 1;

    ctx.fillStyle = isLast ? color : color + 'AA';
    ctx.beginPath();
    if (ctx.roundRect) ctx.roundRect(x, y, barW, bH, [3,3,0,0]);
    else ctx.rect(x, y, barW, bH);
    ctx.fill();

    if (v > 0) {
      ctx.fillStyle = isLast ? '#fff' : 'rgba(255,255,255,.7)';
      ctx.font = (isLast ? 'bold ' : '') + '9px Segoe UI';
      ctx.textAlign = 'center';
      const lbl = isKg
        ? (v >= 1e6 ? (v/1e6).toFixed(1)+'M' : (v/1e3).toFixed(0)+'k')
        : v.toLocaleString('es-AR');
      ctx.fillText(lbl, x + barW/2, y - 4);
    }

    if (n <= 15 || i % Math.ceil(n/15) === 0 || isLast) {
      ctx.fillStyle = 'rgba(255,255,255,.52)';
      ctx.font = '9px Segoe UI'; ctx.textAlign = 'center';
      ctx.fillText(data[i].label || '', x + barW/2, H - PAD.bottom + 13);
    }
  });

  const prom = vals.filter(v=>v>0).reduce((s,v)=>s+v,0) / (vals.filter(v=>v>0).length || 1);
  if (prom > 0) {
    const promY = PAD.top + chartH - (prom / maxVal) * chartH;
    ctx.strokeStyle = 'rgba(255,255,255,.3)'; ctx.lineWidth = 1.2;
    ctx.setLineDash([4,4]);
    ctx.beginPath(); ctx.moveTo(PAD.left, promY); ctx.lineTo(PAD.left + chartW, promY); ctx.stroke();
    ctx.setLineDash([]);
    const promLbl = isKg
      ? 'Prom ' + (prom >= 1e6 ? (prom/1e6).toFixed(1)+'M' : (prom/1e3).toFixed(0)+'k')
      : 'Prom ' + Math.round(prom).toLocaleString('es-AR');
    ctx.fillStyle = 'rgba(255,255,255,.55)';
    ctx.font = '9px Segoe UI'; ctx.textAlign = 'left';
    ctx.fillText(promLbl, PAD.left + 4, promY - 4);
  }
}


