// Datos simulados usados para el tile del menú (hasta que carguen los reales)
const movData = {
  vehiculos: MOV_VEHICULOS,
  meses: (() => {
    const nombres = ['Abr 24','May 24','Jun 24','Jul 24','Ago 24','Sep 24',
                     'Oct 24','Nov 24','Dic 24','Ene 25','Feb 25','Mar 25'];
    const vIds = MOV_VEHICULOS.map(v => v.id);
    let seed = 42;
    const rnd = () => { seed=(seed*1664525+1013904223)&0xffffffff; return Math.abs(seed)/0xffffffff; };
    const rv = (min,max) => +(min + rnd()*(max-min)).toFixed(1);
    return nombres.map(mes => {
      const promedios = {};
      vIds.forEach(id => {
        promedios[id] = { cargas:{ entrada:rv(1.5,6.5), salida:rv(1.2,5.8), prom:0 } };
        promedios[id].cargas.prom = +((promedios[id].cargas.entrada + promedios[id].cargas.salida)/2).toFixed(1);
        promedios[id].prom = promedios[id].cargas.prom;
      });
      return { mes, promedios };
    });
  })(),
};

async function renderIndicadorMovimientos() {
  setHeader('INDICADORES');
  setExpandedMode(false);
  showMetaPanel(true);
  menuGrid.className = '';
  menuGrid.innerHTML = '';

  const wrap = document.createElement('div');
  wrap.className = 'indicador-wrap';

  // ── Header ───────────────────────────────────────────────────
  const header = document.createElement('div');
  header.className = 'indicador-card indicador-card-static';
  header.innerHTML = `
    <div class="indicador-card-header">
      <div class="indicador-card-title">
        <span class="indicador-badge">MOV</span>
        MOVIMIENTOS — TIEMPOS DE OPERACIÓN
      </div>
      <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">
        <select id="movPeriodo" class="pr22-input" style="padding:4px 8px;font-size:.72rem;width:auto">
          <option value="12">12 meses</option>
          <option value="24">24 meses</option>
        </select>
        <span class="indicador-hint" id="movHint">Cargando...</span>
      </div>
    </div>`;
  wrap.appendChild(header);

  // ── Contenedor de gráficos ────────────────────────────────────
  const chartsWrap = document.createElement('div');
  chartsWrap.id = 'movChartsWrap';
  chartsWrap.className = 'mov-charts-outer';
  MOV_VEHICULOS.forEach(v => {
    const block = document.createElement('div');
    block.className = 'indicador-mensual mov-vehiculo-block';
    block.dataset.vid = v.id;
    block.innerHTML = `
      <div class="indicador-mensual-title mov-veh-title">
        <span class="indicador-badge" style="font-size:.68rem">${v.code}</span>
        ${v.label}
      </div>
      <div class="mov-three-charts">
        <div class="mov-chart-col">
          <div class="mov-chart-label mov-label-entrada">↓ Entradas</div>
          <div class="inegr-chart-wrap"><canvas id="mov_${v.id}_entrada"></canvas></div>
        </div>
        <div class="mov-chart-col">
          <div class="mov-chart-label mov-label-salida">↑ Salidas</div>
          <div class="inegr-chart-wrap"><canvas id="mov_${v.id}_salida"></canvas></div>
        </div>
        <div class="mov-chart-col">
          <div class="mov-chart-label mov-label-prom">⇄ Promedio</div>
          <div class="inegr-chart-wrap"><canvas id="mov_${v.id}_prom"></canvas></div>
        </div>
      </div>`;
    chartsWrap.appendChild(block);
  });
  wrap.appendChild(chartsWrap);
  menuGrid.appendChild(wrap);
  syncBackBtn();

  // ── Carga de datos ────────────────────────────────────────────
  const cargarYDibujar = async () => {
    const meses     = document.getElementById('movPeriodo')?.value || 12;
    const hint      = document.getElementById('movHint');
    if (hint) hint.textContent = 'Cargando...';

    try {
      const res  = await fetch(`${API_EQUIPOS_URL}?action=movimientos_tiempos&meses=${meses}&tipo_carga=todos`, {credentials:'same-origin'});
      const data = await res.json();
      movDataReal = data;

      if (hint) hint.textContent = 'Promedio en horas';

      requestAnimationFrame(() => {
        MOV_VEHICULOS.forEach(v => {
          const vData = data.datos[v.id];
          if (!vData || !vData.meses?.length) return;
          movDrawBar(`mov_${v.id}_entrada`, vData.meses, 'entrada_horas', '#00A887', v.id);
          movDrawBar(`mov_${v.id}_salida`,  vData.meses, 'salida_horas',  '#DC2626', v.id);
          movDrawBar(`mov_${v.id}_prom`,    vData.meses, 'prom_horas',    '#36B0C9', v.id);
        });
      });

    } catch(e) {
      const hint = document.getElementById('movHint');
      if (hint) hint.textContent = 'Error: ' + e.message;
    }
  };

  document.getElementById('movPeriodo').addEventListener('change', cargarYDibujar);

  cargarYDibujar();
}

function movDrawBar(canvasId, meses, key, color, vId) {
  const canvas = document.getElementById(canvasId);
  if (!canvas) return;
  const wrap = canvas.parentElement;
  canvas.width  = wrap.clientWidth || 280;
  canvas.height = 160;
  const W = canvas.width, H = canvas.height;
  const PAD = { top:18, right:8, bottom:32, left:34 };
  const chartW = W - PAD.left - PAD.right;
  const chartH = H - PAD.top  - PAD.bottom;
  const ctx = canvas.getContext('2d');
  const n   = meses.length;
  const barW = (chartW / n) * 0.6;
  const gap  = (chartW / n) * 0.4;

  const vals   = meses.map(m => m[key] || 0);

  // Objetivo en horas para este vehículo (MOV_OBJETIVOS está en minutos)
  const objMin  = vId ? (MOV_OBJETIVOS[vId] ?? null) : null;
  const objHoras = objMin !== null ? objMin / 60 : null;

  // El maxVal debe contemplar también el objetivo para que quepa en el gráfico
  const maxVal = Math.max(...vals, objHoras ?? 0, 0.5) * 1.18;

  ctx.clearRect(0, 0, W, H);

  // Grid
  for (let i = 0; i <= 3; i++) {
    const y = PAD.top + chartH - (i/3)*chartH;
    ctx.strokeStyle = 'rgba(255,255,255,.07)'; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(PAD.left, y); ctx.lineTo(PAD.left+chartW, y); ctx.stroke();
    ctx.fillStyle = 'rgba(255,255,255,.38)';
    ctx.font = '8px Segoe UI'; ctx.textAlign = 'right';
    ctx.fillText(((maxVal*i/3)).toFixed(1)+'h', PAD.left-3, y+3);
  }

  vals.forEach((v, i) => {
    const x      = PAD.left + i*(barW+gap) + gap/2;
    const bH     = Math.max((v/maxVal)*chartH, v > 0 ? 2 : 0);
    const y      = PAD.top + chartH - bH;
    const isLast = i === n - 1;

    ctx.fillStyle = isLast ? color : color+'99';
    ctx.beginPath();
    if (ctx.roundRect) ctx.roundRect(x, y, barW, bH, [2,2,0,0]);
    else ctx.rect(x, y, barW, bH);
    ctx.fill();

    if (v > 0) {
      ctx.fillStyle = isLast ? '#fff' : 'rgba(255,255,255,.62)';
      ctx.font = (isLast ? 'bold ' : '') + '7px Segoe UI';
      ctx.textAlign = 'center';
      ctx.fillText(v.toFixed(1)+'h', x+barW/2, y-3);
    }

    // Etiqueta mes
    ctx.fillStyle = 'rgba(255,255,255,.45)';
    ctx.font = '7px Segoe UI'; ctx.textAlign = 'center';
    const label = meses[i].label || '';
    ctx.fillText(label.split(' ')[0], x+barW/2, H-PAD.bottom+11);
  });

  // Línea de promedio (blanca punteada)
  const prom = vals.filter(v=>v>0).reduce((s,v)=>s+v,0) / (vals.filter(v=>v>0).length || 1);
  if (prom > 0) {
    const promY = PAD.top + chartH - (prom/maxVal)*chartH;
    ctx.strokeStyle = 'rgba(255,255,255,.28)'; ctx.lineWidth = 1;
    ctx.setLineDash([3,3]);
    ctx.beginPath(); ctx.moveTo(PAD.left, promY); ctx.lineTo(PAD.left+chartW, promY); ctx.stroke();
    ctx.setLineDash([]);
  }

  // Línea de objetivo (naranja punteada más gruesa)
  if (objHoras !== null && objHoras > 0) {
    const objY = PAD.top + chartH - (objHoras/maxVal)*chartH;
    ctx.strokeStyle = '#F97316'; ctx.lineWidth = 1.5;
    ctx.setLineDash([5,3]);
    ctx.beginPath(); ctx.moveTo(PAD.left, objY); ctx.lineTo(PAD.left+chartW, objY); ctx.stroke();
    ctx.setLineDash([]);
    // Etiqueta del objetivo al final de la línea
    ctx.fillStyle = '#F97316';
    ctx.font = 'bold 7px Segoe UI'; ctx.textAlign = 'right';
    ctx.fillText('obj ' + objHoras.toFixed(1) + 'h', PAD.left + chartW - 2, objY - 3);
  }
}

// Mantener drawMovBar como alias para el tile del menú (usa movData simulado)
function drawMovBar(canvasId, vId, tipo, unidad) {
  const meses  = movData.meses;
  const keyMap = { entrada:'entrada_horas', salida:'salida_horas', prom:'prom_horas' };
  const colMap = { entrada:'#00A887', salida:'#DC2626', prom:'#36B0C9' };
  const fakeMeses = meses.map(m => ({
    label: m.mes,
    entrada_horas: m.promedios[vId]?.cargas?.entrada || 0,
    salida_horas:  m.promedios[vId]?.cargas?.salida  || 0,
    prom_horas:    m.promedios[vId]?.prom            || 0,
  }));
  movDrawBar(canvasId, fakeMeses, keyMap[tipo] || 'prom_horas', colMap[tipo] || '#36B0C9');
}


