/* ═══════════════════════════════════════════════════════════════
   SCANNER QR — abre cámara, lee QR y navega a la URL detectada
   Usa jsQR (cargado desde CDN sólo cuando se necesita)
   ═══════════════════════════════════════════════════════════════ */
let _qrOverlay = null;
let _qrAnimFrame = null;
let _qrCameraStream = null; // Reusar stream para no pedir permiso cada vez

function iniciarScannerQR() {
  if (_qrOverlay) { cerrarScannerQR(); return; }

  _qrOverlay = document.createElement('div');
  _qrOverlay.id = 'qrScannerOverlay';
  _qrOverlay.innerHTML = `
    <div class="qr-scanner-backdrop"></div>
    <div class="qr-scanner-modal">
      <div class="qr-scanner-header">
        <span class="qr-scanner-title">&#9638; Escanear QR</span>
        <button class="qr-scanner-close" id="qrScannerClose">✕</button>
      </div>
      <div class="qr-scanner-viewport">
        <video id="qrVideo" autoplay playsinline muted style="width:100%;border-radius:8px;background:#000"></video>
        <canvas id="qrCanvas" style="display:none"></canvas>
        <div class="qr-scanner-frame">
          <span class="qr-corner tl"></span>
          <span class="qr-corner tr"></span>
          <span class="qr-corner bl"></span>
          <span class="qr-corner br"></span>
          <div class="qr-scan-line"></div>
        </div>
      </div>
      <div class="qr-scanner-status" id="qrStatus">Apuntá la cámara al código QR</div>
    </div>`;
  document.body.appendChild(_qrOverlay);

  document.getElementById('qrScannerClose').addEventListener('click', cerrarScannerQR);
  _qrOverlay.querySelector('.qr-scanner-backdrop').addEventListener('click', cerrarScannerQR);

  arrancarCamara();
}

async function arrancarCamara() {
  const video  = document.getElementById('qrVideo');
  const status = document.getElementById('qrStatus');
  if (!video || !status) return;

  try {
    // Reusar stream existente si está activo, si no pedir nuevo
    if (_qrCameraStream && _qrCameraStream.active) {
      video.srcObject = _qrCameraStream;
    } else {
      _qrCameraStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: { ideal: 'environment' }, width: { ideal: 1280 }, height: { ideal: 720 } }
      });
      video.srcObject = _qrCameraStream;
    }
    await video.play();

    // Estrategia 1: BarcodeDetector nativo (Chrome Android, Safari 17+)
    if ('BarcodeDetector' in window) {
      try {
        const detector = new BarcodeDetector({ formats: ['qr_code'] });
        const scanNativo = async () => {
          if (!_qrOverlay) return;
          try {
            const codes = await detector.detect(video);
            if (codes.length > 0) {
              procesarQRDetectado(codes[0].rawValue);
              return;
            }
          } catch(e) {}
          _qrAnimFrame = requestAnimationFrame(scanNativo);
        };
        _qrAnimFrame = requestAnimationFrame(scanNativo);
        status.textContent = 'Apuntá la cámara al código QR';
        return;
      } catch(e) { /* BarcodeDetector falló, usar jsQR */ }
    }

    // Estrategia 2: jsQR (fallback)
    if (typeof jsQR === 'undefined') {
      status.textContent = 'Cargando escáner...';
      await new Promise((resolve, reject) => {
        const script = document.createElement('script');
        script.src = 'https://cdn.jsdelivr.net/npm/jsqr@1.4.0/dist/jsQR.min.js';
        script.onload = resolve;
        script.onerror = () => {
          // Intentar CDN alternativo
          const s2 = document.createElement('script');
          s2.src = 'https://unpkg.com/jsqr@1.4.0/dist/jsQR.js';
          s2.onload = resolve;
          s2.onerror = reject;
          document.head.appendChild(s2);
        };
        document.head.appendChild(script);
      });
    }
    status.textContent = 'Apuntá la cámara al código QR';
    leerFrameQR(video, status);
  } catch (err) {
    status.textContent = 'Sin permiso de cámara o dispositivo no disponible.';
    console.warn('QR camera error:', err);
  }
}

function leerFrameQR(video, status) {
  const canvas = document.getElementById('qrCanvas');
  if (!canvas || !video || !_qrOverlay) return;
  const ctx = canvas.getContext('2d', { willReadFrequently: true });

  function tick() {
    if (!_qrOverlay) return;
    if (video.readyState === video.HAVE_ENOUGH_DATA) {
      canvas.width  = video.videoWidth;
      canvas.height = video.videoHeight;
      ctx.drawImage(video, 0, 0);
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const code = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: 'attemptBoth' });
      if (code && code.data) {
        procesarQRDetectado(code.data);
        return;
      }
    }
    _qrAnimFrame = requestAnimationFrame(tick);
  }
  _qrAnimFrame = requestAnimationFrame(tick);
}

// ── Procesar QR detectado: extraer estibaId y mostrar selector de modo ──
function procesarQRDetectado(rawData) {
  const url = rawData.trim();
  // Extraer estibaId del QR (puede ser URL con #estiba/ID, #estiba-intervenida/ID, ?estibaid=ID o número directo)
  let estibaId = null;
  let esIntervenida = false;
  const hashIntMatch = url.match(/#estiba-intervenida\/(\d+)/);
  const hashMatch = url.match(/#estiba\/(\d+)/);
  const queryMatch = url.match(/[?&]estibaid=(\d+)/i);
  if (hashIntMatch) { estibaId = hashIntMatch[1]; esIntervenida = true; }
  else if (hashMatch) estibaId = hashMatch[1];
  else if (queryMatch) estibaId = queryMatch[1];
  else if (/^\d+$/.test(url)) estibaId = url;

  if (!estibaId) {
    cerrarScannerQR();
    window.location.href = url;
    return;
  }

  cerrarScannerQR();

  // Determinar modo por defecto según RolID
  const rolId = perfilData?.rol_id ?? 0;
  // Roles de calidad: 9 (calidad), se puede ampliar
  const esRolCalidad = [9].includes(rolId);

  // Mostrar selector Logística / Calidad
  const selOverlay = document.createElement('div');
  selOverlay.id = 'qrModoOverlay';
  selOverlay.className = 'calidad-modal-overlay';
  document.body.appendChild(selOverlay);
  requestAnimationFrame(() => selOverlay.classList.add('calidad-modal-visible'));

  selOverlay.innerHTML = `<div class="calidad-modal" style="max-width:360px;text-align:center">
    <div class="calidad-modal-header">Estiba Escaneada <button class="chk-close" id="qrModoClose">✕</button></div>
    <div class="calidad-modal-body" style="padding:20px">
      <div style="font-size:1.4rem;font-weight:800;color:#60a5fa;margin-bottom:16px">#${estibaId}</div>
      <div style="font-size:.82rem;color:rgba(255,255,255,.5);margin-bottom:16px">¿Cómo querés abrir esta estiba?</div>
      <div style="display:flex;gap:10px">
        <button id="qrModoLog" class="mob-est-action-card" style="flex:1;${!esRolCalidad?'border:2px solid #60a5fa':''};padding:16px 10px">
          <div style="font-size:1.5rem;margin-bottom:4px">📦</div>
          <div style="font-size:.85rem;font-weight:700;color:#fff">Logística</div>
          <div style="font-size:.62rem;color:rgba(255,255,255,.4)">Ubicar, cargar, QR</div>
        </button>
        <button id="qrModoCalidad" class="mob-est-action-card" style="flex:1;${esRolCalidad?'border:2px solid #4ade80':''};padding:16px 10px">
          <div style="font-size:1.5rem;margin-bottom:4px">🔬</div>
          <div style="font-size:.85rem;font-weight:700;color:#fff">Calidad</div>
          <div style="font-size:.62rem;color:rgba(255,255,255,.4)">PR-05, temp, fotos</div>
        </button>
      </div>
    </div>
  </div>`;

  const closeSel = () => { selOverlay.classList.remove('calidad-modal-visible'); setTimeout(() => selOverlay.remove(), 200); };
  selOverlay.querySelector('#qrModoClose').onclick = closeSel;
  selOverlay.addEventListener('click', e => { if (e.target === selOverlay) closeSel(); });

  selOverlay.querySelector('#qrModoLog').onclick = () => {
    closeSel();
    historyStack.push({ __mobileRoot: true });
    if (esIntervenida) {
      renderEstibaIntervenidaMobileLanding(estibaId);
    } else {
      if (esMobile()) renderEstibaMobileLanding(estibaId);
      else renderEstibaFormulario(estibaId);
    }
  };

  selOverlay.querySelector('#qrModoCalidad').onclick = async () => {
    closeSel();
    historyStack.push({ __mobileRoot: true });
    renderEstibaCalidadMobile(estibaId, esIntervenida);
  };

  // Auto-seleccionar después de 5 segundos si no elige
  // (comentado por ahora - dejar que elija siempre)
}

function cerrarScannerQR() {
  if (_qrAnimFrame) { cancelAnimationFrame(_qrAnimFrame); _qrAnimFrame = null; }
  const video = document.getElementById('qrVideo');
  if (video) video.srcObject = null; // Desconectar video pero NO parar stream
  if (_qrOverlay) { _qrOverlay.remove(); _qrOverlay = null; }
  // Stream se mantiene vivo para reusar sin pedir permiso de nuevo
}
