// Cargar cámaras y datos iniciales desde DB, luego arrancar la app
// ── Carga todos los tiles del header en una sola llamada ──────────────────
function cargarHeaderTiles() {
  fetch(`${API_EQUIPOS_URL}?action=header_tiles`, {credentials:'same-origin'})
    .then(r => r.json())
    .then(data => {
      const setTile = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val; };
      if (data.total_planta) setTile('estibas-en-planta', data.total_planta.toLocaleString('es-AR'));
      if (data.vehiculos_planta !== undefined) setTile('vehiculos-planta', data.vehiculos_planta);
      if (data.sin_ubicacion !== undefined) {
        const elSU = document.querySelector('#sinUbicacionBox .data-number');
        if (elSU) elSU.textContent = data.sin_ubicacion.toLocaleString('es-AR');
      }
      if (data.estibas_vencidas !== undefined) {
        const elV = document.querySelector('#vencidasBox .data-number');
        if (elV) elV.textContent = data.estibas_vencidas.toLocaleString('es-AR');
      }
      if (data.estibas_por_camara) {
        dashboardLogisticaNacionalData.forEach(cam => {
          cam.estibas = data.estibas_por_camara[cam.camara_id] || cam.estibas || 0;
        });
        document.querySelectorAll('.dashboard-number').forEach((el, i) => {
          const cam = dashboardLogisticaNacionalData[i];
          if (!cam) return;
          el.textContent = cam.capacidad > 0
            ? Math.round(cam.estibas / cam.capacidad * 100) + '%'
            : '—';
        });
        document.querySelectorAll('.dashboard-sub').forEach((el, i) => {
          const cam = dashboardLogisticaNacionalData[i];
          if (!cam) return;
          el.textContent = cam.estibas + ' ESTIBAS';
        });
      }
      if (data.sin_posicion_por_camara) {
        dashboardLogisticaNacionalData.forEach(cam => {
          cam.extra = data.sin_posicion_por_camara[cam.camara_id] || 0;
        });
        document.querySelectorAll('.dashboard-card').forEach((card, i) => {
          const cam = dashboardLogisticaNacionalData[i];
          if (!cam) return;
          const el = card.querySelector('.dashboard-alert:not(.dashboard-alert-venc) .dashboard-alert-value');
          if (el) el.textContent = cam.extra;
        });
      }
      if (data.vencidas_por_camara) {
        dashboardLogisticaNacionalData.forEach(cam => {
          cam.vencidas = data.vencidas_por_camara[cam.camara_id] || 0;
        });
      }
      document.querySelectorAll('.dashboard-card').forEach((card, i) => {
        const cam = dashboardLogisticaNacionalData[i];
        if (!cam) return;
        const el = card.querySelector('.dashboard-venc-value');
        if (el) el.textContent = cam.vencidas || 0;
      });
      // Clientes con mercadería por cámara → actualizar badges
      if (data.clientes_por_camara) {
        dashboardLogisticaNacionalData.forEach(cam => {
          cam.clientes = data.clientes_por_camara[cam.camara_id] || [];
        });
        document.querySelectorAll('.dashboard-clients').forEach((el, i) => {
          const cam = dashboardLogisticaNacionalData[i];
          if (cam) el.innerHTML = buildClientSlots(cam.clientes);
        });
      }
      // Estado de puertas por cámara → actualiza 🚪 en el status row
      if (data.puertas_estado) {
        dashboardLogisticaNacionalData.forEach(cam => {
          const estado = data.puertas_estado[cam.camara_id];
          cam.puerta = estado || null; // 'Abierta' | 'Cerrada' | null
        });
        document.querySelectorAll('.dashboard-status-row').forEach((el, i) => {
          const cam = dashboardLogisticaNacionalData[i];
          if (cam) el.outerHTML = buildStatusRow(cam);
        });
      }
      const tunelesDateMap = { 2: data.tunel2_fecha, 108: data.tunel9_fecha, 109: data.tunel10_fecha };
      dashboardLogisticaNacionalData.forEach(cam => {
        if (cam.tipo === 'TUNEL' && tunelesDateMap[cam.camara_id] !== undefined)
          cam.tunel_fecha = tunelesDateMap[cam.camara_id];
      });
      document.querySelectorAll('.dashboard-tunel-fecha').forEach(el => {
        const card = el.closest('.dashboard-card');
        if (!card) return;
        const idx = [...card.parentElement.children].indexOf(card);
        const cam = dashboardLogisticaNacionalData[idx];
        if (cam?.tunel_fecha) el.textContent = cam.tunel_fecha;
      });
      window.__headerTiles = data;
      console.log('✓ Header tiles cargados');
    })
    .catch(e => console.warn('Header tiles: error', e.message));

  // ── Ocupación total para tile Dashboard Logística Nacional ────────
  fetch(`${API_EQUIPOS_URL}?action=ocupacion_total`, {credentials:'same-origin'})
    .then(r => r.json())
    .then(data => {
      if (data.pct_ocupacion !== undefined) {
        dashTileOcupacion.pct      = data.pct_ocupacion;
        dashTileOcupacion.estibas  = data.estibas_activas;
        dashTileOcupacion.totalPos = data.total_posiciones;
      }
    })
    .catch(() => {});
}

(async () => {
  await cargarPerfilDesdeDB();
  await cargarCamarasDesdeDB();
  // Cargar estado PR-6 por cámara (en paralelo, no bloquea)
  fetch(`${API_EQUIPOS_URL}?action=pr6_estado_camaras`, {credentials:'same-origin'})
    .then(r => r.json())
    .then(data => { if (Array.isArray(data)) pr6EstadoCamarasDB = data; })
    .catch(() => {});
  // Cargar espacios comunes para gestión de equipos (en paralelo, no bloquea menú)
  fetch(`${API_EQUIPOS_URL}?action=mant_espacios`, {credentials:'same-origin'})
    .then(r => r.json())
    .then(data => { if (Array.isArray(data)) mantEspaciosCache = data; })
    .catch(() => {});
  // Cargar equipos de mantenimiento ANTES de pintar el menú
  // (el tile MANTENIMIENTO GENERAL los necesita al renderizarse)
  try {
    const resMant = await fetch(`${API_EQUIPOS_URL}?action=mant_equipos_lista`, {credentials:'same-origin'});
    const datMant = await resMant.json();
    if (Array.isArray(datMant)) mantEquiposCache = datMant;
  } catch(e) { console.warn('mant_equipos_lista:', e.message); }
  // ── Cargar resumen equipos mantenimiento ANTES de pintar el menú ──────────
  // Así el tile "DASHBOARD EQUIPAMIENTO" ya tiene datos reales al renderizarse
  try {
    const resEquip = await fetch(`${API_EQUIPOS_URL}?action=mant_equipos_resumen`, {credentials:'same-origin'});
    const datEquip = await resEquip.json();
    if (datEquip.total !== undefined) {
      dashTileEquipMant.total     = datEquip.total;
      dashTileEquipMant.porEstado = datEquip.por_estado || {};
    }
  } catch(e) { console.warn('mant_equipos_resumen:', e.message); }

  // UNA sola llamada para todos los tiles del header
  cargarHeaderTiles();
  // Precargar tile de estibas ingresadas/egresadas del mes actual
  precargarTileIngEgr();
  // Precargar tile de movimientos (mes en curso)
  precargarTileMovimientos();
  // Precargar tile RRHH (usuarios online)
  precargarTileRRHH();
  // Precargar tile estibas congeladas (túneles)
  precargarTileTuneles();
  // Precargar tile clientes que operaron
  precargarTileClientes();
  // Cargar equipos industriales (autoelevadores etc.) desde DB
  fetch(`${API_EQUIPOS_URL}?action=equipos_lista`, {credentials:'same-origin'})
    .then(r => r.json())
    .then(data => {
      if (Array.isArray(data) && data.length) {
        dashboardEquipamientoData.length = 0;
        data.forEach(e => dashboardEquipamientoData.push({
          id          : parseInt(e.id),
          interno     : parseInt(e.interno),
          denominacion: e.denominacion,
          tipo        : e.tipo,
          marca       : e.marca || '',
          modelo      : e.modelo || '',
          planta      : e.planta || '',
          estado      : e.estado_actual,
          horasBase   : parseFloat(e.horometro_actual) || 0,
          horasActual : parseFloat(e.horometro_actual) || 0,
          usuario     : e.ultimo_usuario || e.usuario || '',
          año         : e.anio || 'N/D',
          icono       : e.icono || 'img/autoelevador.png',
          isImage     : true,
          fallas_abiertas: parseInt(e.fallas_abiertas) || 0,
        }));
        console.log(`✓ ${dashboardEquipamientoData.length} equipos cargados desde DB`);
      }
    })
    .catch(() => {});
  // Si hay hash en la URL → navegar directo, si no → menú principal
  const hashInicial = window.location.hash.slice(1);
  if (hashInicial) {
    await handleHashRouting();
  } else {
    renderNode(menuTree);
  }
})();

