/* ═══════════════════════════════════════════════════════════════
   UBICAR ESTIBA MÓVIL — Con formato iniciales-número de cámara
   ═══════════════════════════════════════════════════════════════ */
async function openMobileUbicarEstiba(estibaId, onSuccess, intervenida) {
  document.getElementById('calidadModalOverlay')?.remove();
  let cats;
  try {
    const r = await fetch('api_2026ia.php?action=entrada_catalogos', { credentials: 'same-origin' });
    cats = await r.json();
  } catch (e) { showToast('Error cargando cámaras'); return; }

  const camaras = cats.camaras || [];

  const overlay = document.createElement('div');
  overlay.id = 'calidadModalOverlay';
  overlay.className = 'calidad-modal-overlay';
  document.body.appendChild(overlay);
  requestAnimationFrame(() => overlay.classList.add('calidad-modal-visible'));

  overlay.innerHTML = `<div class="calidad-modal" style="width:min(400px,92vw)">
    <div class="calidad-modal-header">📍 Generar Movimiento <button class="chk-close" id="euClose">✕</button></div>
    <div class="calidad-modal-body">
      <div class="calidad-modal-field">
        <label>CÁMARA</label>
        <select id="euCam" style="font-size:1rem;padding:10px">
          ${camaras.map(c => {
            const label = c.iniciales ? `${c.iniciales}-${c.numero}` : `Cámara ${c.numero}`;
            return `<option value="${c.id}" data-calles="${c.calles}" data-filas="${c.filas}" data-niveles="${c.niveles}">${label}</option>`;
          }).join('')}
        </select>
      </div>
      <div style="display:flex;gap:8px;flex-wrap:wrap">
        <div class="calidad-modal-field" style="flex:1;min-width:70px"><label>CALLE</label><input type="number" id="euCalle" min="1" value="1" style="font-size:1rem;padding:10px;width:100%;box-sizing:border-box"></div>
        <div class="calidad-modal-field" style="flex:1;min-width:70px"><label>FILA</label><input type="number" id="euFila" min="1" value="1" style="font-size:1rem;padding:10px;width:100%;box-sizing:border-box"></div>
        <div class="calidad-modal-field" style="flex:1;min-width:70px"><label>NIVEL</label><input type="number" id="euNivel" min="1" value="1" style="font-size:1rem;padding:10px;width:100%;box-sizing:border-box"></div>
      </div>
      <div id="euPosId" style="font-size:.72rem;opacity:.5;margin-top:6px;text-align:center"></div>
    </div>
    <div class="calidad-modal-footer" style="flex-wrap:wrap">
      <button class="calidad-modal-btn calidad-modal-btn-cancel" id="euCancel">Cancelar</button>
      <button class="calidad-modal-btn calidad-modal-btn-save" id="euSave" style="font-size:1rem;padding:12px 24px;flex:1">📍 Asignar Posición</button>
    </div>
  </div>`;

  const close = () => { overlay.classList.remove('calidad-modal-visible'); setTimeout(() => overlay.remove(), 200); };
  overlay.querySelector('#euClose').onclick = close;
  overlay.querySelector('#euCancel').onclick = close;
  overlay.addEventListener('click', e => { if (e.target === overlay) close(); });
  overlay.querySelectorAll('input,select').forEach(el => { el.onkeydown = e => e.stopPropagation(); });

  const findPos = async () => {
    const camId = overlay.querySelector('#euCam').value;
    const calle = overlay.querySelector('#euCalle').value;
    const fila = overlay.querySelector('#euFila').value;
    try {
      const r = await fetch(`api_2026ia.php?action=entrada_buscar_posicion&camara_id=${camId}&calle=${calle}&fila=${fila}`, { credentials: 'same-origin' });
      const d = await r.json();
      const el = overlay.querySelector('#euPosId');
      el.textContent = d.posicion_id ? `Posición OK ✔` : '⚠ Posición no encontrada';
      el.style.color = d.posicion_id ? '#4ade80' : '#f87171';
      overlay.querySelector('#euSave').dataset.posid = d.posicion_id || '';
    } catch (e) {}
  };
  overlay.querySelector('#euCam').onchange = findPos;
  overlay.querySelector('#euCalle').oninput = findPos;
  overlay.querySelector('#euFila').oninput = findPos;
  findPos();

  overlay.querySelector('#euSave').onclick = async () => {
    const posId = overlay.querySelector('#euSave').dataset.posid;
    const nivel = +overlay.querySelector('#euNivel').value || 1;
    if (!posId) { showToast('Posición no encontrada — verificá cámara, calle y fila', 'error'); return; }
    const saveBtn = overlay.querySelector('#euSave');
    saveBtn.disabled = true; saveBtn.textContent = '⏳ Guardando...';
    try {
      const payload = { EstibaID: estibaId, PosicionID: +posId, Nivel: nivel, intervenida: !!intervenida };
      const r = await fetch('api_2026ia.php?action=entrada_ubicar_estiba', {
        method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      const d = await r.json();
      if (d.error) throw new Error(d.error);
      showToast('📍 Estiba ubicada');
      close();
      if (onSuccess) onSuccess();
    } catch (e) {
      showToast('Error al ubicar: ' + e.message, 'error');
      saveBtn.disabled = false; saveBtn.textContent = '📍 Asignar Posición';
    }
  };
}

// Formulario de carga de datos para una estiba (accedido via QR o click)
async function renderEstibaFormulario(estibaId) {
  setHeader('CARGA DE ESTIBA');
  setExpandedMode(true); showMetaPanel(true);
  menuGrid.className = '';
  menuGrid.innerHTML = '<div class="ef-wrap"><div class="ge-loading">Cargando estiba...</div></div>';
  syncBackBtn();

  let data;
  try {
    const r = await fetch(`api_2026ia.php?action=estiba_datos&estiba_id=${estibaId}`, {credentials:'same-origin'});
    data = await r.json(); if (data.error) throw new Error(data.error);
  } catch(e) { menuGrid.innerHTML = `<div class="ef-wrap"><div class="ge-empty">Error: ${e.message}</div></div>`; return; }

  const est = data.estiba, prods = data.productos||[], catalogo = data.catalogo_productos||[];
  const rango = data.rango_vencimiento||{};
  const esPre = !parseInt(est.Clasificada);
  const totalBultos = prods.reduce((s,p) => s + (parseInt(p.Cantidad)||0), 0);

  const wrap = document.createElement('div'); wrap.className = 'ef-wrap';
  menuGrid.innerHTML = ''; menuGrid.appendChild(wrap);

  // Rango visual
  const rangoHtml = rango.min ? `<div class="ef-venc-range ${rango.min===rango.max?'ef-venc-ok':'ef-venc-wide'}">
    📅 Vencimiento: <strong>${rango.min}</strong>${rango.min!==rango.max?' → <strong>'+rango.max+'</strong>':''} ${rango.min!==rango.max?'(rango múltiple)':'(fecha única)'}
  </div>` : '';

  let html = `
    <div class="ef-header">
      <span class="ed-id">#${est.CargaID}-${est.NroEstiba}</span>
      <span class="ed-badge ${esPre?'ed-badge-pre':'ed-badge-ok'}">${esPre?'Pre-Entrada':'Entrada'}</span>
      <span style="font-size:.82rem;color:rgba(255,255,255,.6)">Entrada #${est.CargaID} · ${est.cliente||''}</span>
      <span style="font-size:.75rem;opacity:.4;margin-left:auto">${est.tipo_estiba||''} · ${totalBultos} bultos</span>
    </div>

    <!-- Productos cargados -->
    <div class="ed-section">
      <div class="ed-section-title">📦 Productos en esta estiba <span class="ed-section-count">${prods.length}</span></div>
      ${prods.length ? prods.map(p => `
        <div style="background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.08);border-radius:8px;padding:10px;margin-bottom:8px">
          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">
            <span style="font-weight:700;color:#60a5fa;font-size:.82rem">${p.codigo||''} — ${p.producto||''}</span>
            ${esPre?`<button class="ed-btn ed-btn-danger" style="padding:2px 8px;font-size:.62rem" data-accion="ef-eliminar" data-prod="${p.ProductosID}" data-fechaev="${p.FechaEV}">✕</button>`:''}
          </div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:2px 12px;font-size:.72rem;color:rgba(255,255,255,.65)">
            <div><span style="color:rgba(255,255,255,.35)">Cant:</span> ${p.Cantidad}</div>
            <div><span style="color:rgba(255,255,255,.35)">Lote:</span> ${p.NroLote||'—'}</div>
            <div><span style="color:rgba(255,255,255,.35)">Elab:</span> ${p.FechaElaboracion||'—'}</div>
            <div><span style="color:rgba(255,255,255,.35)">Venc:</span> ${p.FechaVencimiento||'—'}</div>
            <div><span style="color:rgba(255,255,255,.35)">Cong:</span> ${p.FechaCongelado||'—'}</div>
            <div><span style="color:rgba(255,255,255,.35)">Tropa:</span> ${p.NroTropa||'—'}</div>
          </div>
        </div>`).join('') : '<div style="opacity:.4;text-align:center;padding:16px">Sin productos cargados aún</div>'}
      ${rangoHtml}
    </div>

    <!-- Formulario para agregar producto -->
    ${esPre ? `<div class="ed-section">
      <div class="ed-section-title">＋ Cargar Producto</div>
      <div class="ef-form-grid">
        <div class="calidad-modal-field" style="grid-column:span 2">
          <label>PRODUCTO</label>
          <select id="efProd"><option value="">— Seleccionar —</option>${catalogo.map(p=>`<option value="${p.id}" data-dias="${p.dias_vida_estandar||0}" data-req='${JSON.stringify({elab:p.RequiereFechaElaboracion,venc:p.RequiereFechaVencimiento,cong:p.RequiereFechaCongelacion,faena:p.RequiereFechaFaena,tropa:p.RequiereNroTropa,lote:p.RequiereNroLote})}'>${p.codigo||''} — ${p.nombre}</option>`).join('')}</select>
        </div>
        <div class="calidad-modal-field"><label>CANTIDAD (BULTOS)</label><input type="number" id="efCant" min="1" value="1"></div>
        <div class="calidad-modal-field"><label>LOTE</label><input type="text" id="efLote"></div>
        <div class="calidad-modal-field"><label>F. ELABORACIÓN</label><input type="date" id="efElab"></div>
        <div class="calidad-modal-field"><label>F. VENCIMIENTO</label><input type="date" id="efVenc"></div>
        <div class="calidad-modal-field"><label>F. CONGELADO</label><input type="date" id="efCong"></div>
        <div class="calidad-modal-field"><label>F. FAENA</label><input type="date" id="efFaena"></div>
        <div class="calidad-modal-field"><label>NRO TROPA</label><input type="text" id="efTropa"></div>
        <div class="calidad-modal-field"><label>NRO TAMBOR</label><input type="text" id="efTambor"></div>
      </div>
      <div class="ed-action-bar">
        <button class="ed-btn ed-btn-primary" id="efGuardar">💾 Cargar Producto</button>
        <button class="ed-btn ed-btn-secondary" id="efVolverEntrada">← Volver a Entrada #${est.CargaID}</button>
      </div>
    </div>` : `<div class="ed-action-bar"><button class="ed-btn ed-btn-secondary" id="efVolverEntrada">← Volver a Entrada #${est.CargaID}</button></div>`}`;

  wrap.innerHTML = html;
  wrap.querySelectorAll('input,select').forEach(el => { el.onkeydown = e => e.stopPropagation(); });

  // Volver a entrada
  wrap.querySelector('#efVolverEntrada')?.addEventListener('click', () => renderEntradaDetalle(est.CargaID));

  // Auto-calcular fecha de vencimiento: elaboración + dias_vida_estandar
  const autoCalcVenc = () => {
    const prodSel = wrap.querySelector('#efProd');
    const elabInput = wrap.querySelector('#efElab');
    const vencInput = wrap.querySelector('#efVenc');
    if (!prodSel || !elabInput || !vencInput) return;
    const opt = prodSel.selectedOptions[0];
    const diasStr = opt?.getAttribute('data-dias') || '0';
    const dias = parseInt(diasStr) || 0;
    const elab = elabInput.value;
    if (dias > 0 && elab && elab.includes('-')) {
      const parts = elab.split('-');
      const y = parseInt(parts[0]), m = parseInt(parts[1]) - 1, d = parseInt(parts[2]);
      const fecha = new Date(y, m, d);
      fecha.setDate(fecha.getDate() + dias);
      const fy = fecha.getFullYear();
      const fm = String(fecha.getMonth() + 1).padStart(2, '0');
      const fd = String(fecha.getDate()).padStart(2, '0');
      vencInput.value = fy + '-' + fm + '-' + fd;
    }
  };
  wrap.querySelector('#efElab')?.addEventListener('change', autoCalcVenc);
  wrap.querySelector('#efProd')?.addEventListener('change', () => {
    const elabInput = wrap.querySelector('#efElab');
    if (elabInput?.value) { wrap.querySelector('#efVenc').value = ''; autoCalcVenc(); }
  });

  // Guardar producto
  wrap.querySelector('#efGuardar')?.addEventListener('click', async () => {
    const prodId = wrap.querySelector('#efProd').value;
    if (!prodId) { showToast('Seleccioná un producto'); return; }
    const cant = +wrap.querySelector('#efCant').value;
    if (!cant || cant < 1) { showToast('Ingresá una cantidad'); return; }

    // Validaciones de fechas
    const hoy = new Date().toISOString().slice(0,10);
    const fElab = wrap.querySelector('#efElab')?.value || '';
    const fVenc = wrap.querySelector('#efVenc')?.value || '';
    const fFaena = wrap.querySelector('#efFaena')?.value || '';

    if (fElab && fElab > hoy) { showToast('⚠ La fecha de elaboración no puede ser futura'); return; }
    if (fFaena && fFaena > hoy) { showToast('⚠ La fecha de faena no puede ser futura'); return; }
    if (fVenc && fVenc <= hoy) {
      if (!confirm('⚠ La fecha de vencimiento es igual o anterior a hoy (' + fVenc + '). ¿Desea continuar?')) return;
    }
    try {
      const r = await fetch('api_2026ia.php?action=estiba_cargar_producto', {
        method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({
          EstibaID: estibaId, CargaID: est.CargaID, ProductosID: +prodId, Cantidad: cant,
          NroLote: wrap.querySelector('#efLote').value||null,
          FechaElaboracion: wrap.querySelector('#efElab').value||null,
          FechaVencimiento: wrap.querySelector('#efVenc').value||null,
          FechaCongelado: wrap.querySelector('#efCong').value||null,
          FechaFaena: wrap.querySelector('#efFaena').value||null,
          NroTropa: wrap.querySelector('#efTropa').value||null,
          nro_tambor: wrap.querySelector('#efTambor').value||null,
        })
      });
      const d = await r.json(); if (d.error) throw new Error(d.error);
      showToast('✅ Producto cargado en estiba');
      renderEstibaFormulario(estibaId);
    } catch(e) { showToast('Error: '+e.message, 'error'); }
  });

  // Eliminar producto de estiba
  wrap.querySelectorAll('[data-accion="ef-eliminar"]').forEach(btn => {
    btn.onclick = async () => {
      try {
        const r = await fetch('api_2026ia.php?action=estiba_eliminar_producto', {
          method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
          body: JSON.stringify({ CargaID: est.CargaID, ProductosID: +btn.dataset.prod, FechaEV: +btn.dataset.fechaev, EstibaID: estibaId })
        });
        const d = await r.json(); if (d.error) throw new Error(d.error);
        showToast('Producto eliminado'); renderEstibaFormulario(estibaId);
      } catch(e) { showToast('Error: '+e.message, 'error'); }
    };
  });
}

// Generación e impresión de QR para estibas
function imprimirQREstibas(estibas, cargaId) {
  const baseUrl = location.origin + location.pathname + '#estiba/';
  const win = window.open('', '_blank');
  if (!win) { showToast('Permitir popups para imprimir QR'); return; }

  const logoUrl = location.origin + '/img/cina_logo_qr.png';
  let pagesHtml = '';
  estibas.forEach(e => {
    const url = baseUrl + e.EstibaID;
    const dni = cargaId + '-' + e.NroEstiba;
    const qr = qrcode(0, 'H');
    qr.addData(url);
    qr.make();
    const qrImg = qr.createDataURL(20, 1);
    pagesHtml += `
      <div class="qr-page">
        <div class="qr-dni">${dni}</div>
        <img class="qr-code" src="${qrImg}" alt="QR ${dni}">
        <img class="qr-logo" src="${logoUrl}" alt="CINA" onerror="this.outerHTML='<div style=font-size:18px;font-weight:900;color:#1a5276>Cina</div>'">
      </div>`;
  });

  win.document.write(`<!DOCTYPE html><html><head><title>QR ${cargaId}</title>
    <style>
      * { margin:0; padding:0; box-sizing:border-box; }
      @page { margin:0; size:100mm 100mm; }
      body { font-family:'Arial Black',Arial,Helvetica,sans-serif; background:#fff; }

      .qr-page {
        width:100mm; height:100mm; margin:0 auto;
        display:flex; flex-direction:column; align-items:center; justify-content:center;
        page-break-after:always; padding:4mm;
      }
      .qr-page:last-child { page-break-after:auto; }

      .qr-dni {
        font-size:36px; font-weight:900; color:#000;
        letter-spacing:2px; text-align:center; line-height:1; margin-bottom:3mm;
      }
      .qr-code { width:72mm; height:72mm; }
      .qr-logo { height:8mm; margin-top:2mm; }

      .no-print {
        position:fixed; top:0; left:0; right:0; z-index:100;
        padding:12px 20px; background:#1a1a2e; display:flex; align-items:center; gap:16px;
      }
      .no-print button {
        padding:10px 28px; font-size:15px; cursor:pointer;
        background:#22c55e; color:#fff; border:none; border-radius:8px; font-weight:700;
      }
      .no-print span { color:#94a3b8; font-size:13px; }

      @media screen {
        .qr-page { border:1px dashed #ccc; margin:10px auto; }
      }
      @media print {
        .no-print { display:none !important; }
        .qr-page { border:none; }
      }
    </style>
  </head><body>
    <div class="no-print">
      <button onclick="window.print()">🖨 Imprimir</button>
      <span>${estibas.length} etiqueta${estibas.length!==1?'s':''} · Entrada #${cargaId}</span>
    </div>
    ${pagesHtml}
  </body></html>`);
  win.document.close();
}

// ── Imprimir etiqueta provisoria (extracción parcial) ────────────
function imprimirQREtiquetaProvisoria(etiquetas) {
  const win = window.open('', '_blank');
  if (!win) { showToast('Permitir popups para imprimir QR', 'error'); return; }

  const logoUrl = location.origin + '/img/cina_logo_qr.png';
  let pagesHtml = '';
  etiquetas.forEach(ep => {
    const qr = qrcode(0, 'H');
    qr.addData(ep.codigo_qr);
    qr.make();
    const qrImg = qr.createDataURL(20, 1);
    pagesHtml += `
      <div class="qr-page qr-provisoria">
        <div class="qr-prov-header">PROVISORIA</div>
        ${ep.PreSalidaID ? `<div class="qr-prov-presalida">Pre-Salida #${ep.PreSalidaID}</div>` : ''}
        <div class="qr-prov-origen">Origen: ${ep.CargaID}-${ep.NroEstiba || '?'}</div>
        <img class="qr-code" src="${qrImg}" alt="QR ${ep.codigo_qr}">
        <div class="qr-prov-detalle">
          <div class="qr-prov-producto">${ep.producto || ''}</div>
          <div class="qr-prov-cantidad">${ep.Cantidad} bultos</div>
        </div>
        <div class="qr-prov-codigo">${ep.codigo_qr}</div>
        <img class="qr-logo" src="${logoUrl}" alt="CINA" onerror="this.outerHTML='<div style=font-size:14px;font-weight:900;color:#1a5276>Cina</div>'">
      </div>`;
  });

  win.document.write(`<!DOCTYPE html><html><head><title>Etiquetas Provisorias</title>
    <style>
      * { margin:0; padding:0; box-sizing:border-box; }
      @page { margin:0; size:100mm 100mm; }
      body { font-family:'Arial Black',Arial,Helvetica,sans-serif; background:#fff; }

      .qr-page {
        width:100mm; height:100mm; margin:0 auto;
        display:flex; flex-direction:column; align-items:center; justify-content:center;
        page-break-after:always; padding:3mm;
      }
      .qr-page:last-child { page-break-after:auto; }
      .qr-provisoria { border:3px dashed #c2410c; }
      .qr-prov-header {
        font-size:22px; font-weight:900; color:#c2410c;
        letter-spacing:3px; text-transform:uppercase; margin-bottom:1mm;
      }
      .qr-prov-presalida { font-size:28px; font-weight:900; color:#000; letter-spacing:1px; margin-bottom:1mm; }
      .qr-prov-origen { font-size:12px; font-weight:700; color:#555; margin-bottom:2mm; }
      .qr-code { width:52mm; height:52mm; }
      .qr-prov-detalle { text-align:center; margin-top:1mm; }
      .qr-prov-producto { font-size:10px; font-weight:700; color:#333; max-width:90mm; overflow:hidden; white-space:nowrap; text-overflow:ellipsis; }
      .qr-prov-cantidad { font-size:20px; font-weight:900; color:#c2410c; }
      .qr-prov-codigo { font-size:12px; font-weight:700; color:#888; margin-top:1mm; letter-spacing:1px; }
      .qr-logo { height:6mm; margin-top:1mm; }

      .no-print {
        position:fixed; top:0; left:0; right:0; z-index:100;
        padding:12px 20px; background:#1a1a2e; display:flex; align-items:center; gap:16px;
      }
      .no-print button {
        padding:10px 28px; font-size:15px; cursor:pointer;
        background:#fb923c; color:#fff; border:none; border-radius:8px; font-weight:700;
      }
      .no-print span { color:#94a3b8; font-size:13px; }

      @media screen { .qr-page { margin:10px auto; } }
      @media print { .no-print { display:none !important; } .qr-provisoria { border-color:#c2410c; } }
    </style>
  </head><body>
    <div class="no-print">
      <button onclick="window.print()">🖨 Imprimir</button>
      <span>${etiquetas.length} etiqueta${etiquetas.length!==1?'s':''} provisoria${etiquetas.length!==1?'s':''}</span>
    </div>
    ${pagesHtml}
  </body></html>`);
  win.document.close();
}

/* ═══════════════════════════════════════════════════════════════
   DETALLE ENTRADA MÓVIL — Vista simplificada para operarios
   ═══════════════════════════════════════════════════════════════ */

function renderEntradaDetalleMobile(id, data, opts = {}) {
  const esCalidad = opts.calidad || false;
  const reg = data.registro, estibas = data.estibas || [];
  const esPre = !(parseInt(reg.Clasificada));
  const estibasInt = data.estibas_intervenidas || [];
  const soloLectura = !esCalidad && !puedeEditarModulo(esPre ? 'log_pre_entradas' : 'log_entradas');

  const wrap = document.createElement('div');
  wrap.className = 'mob-ed-wrap';
  menuGrid.innerHTML = '';
  menuGrid.appendChild(wrap);

  // ── HEADER con número, cliente y modo ──
  let html = `<div class="mob-ed-header">
    <div class="mob-ed-id">#${reg.CargaID}</div>
    <div class="mob-ed-cliente">${reg.cliente || ''}</div>
    <span class="mob-ed-badge ${esPre ? 'pre' : 'ok'}">${esPre ? 'Pre-Entrada' : 'Entrada'}</span>
    ${esCalidad ? '<span class="mob-ed-badge" style="background:rgba(168,85,247,.15);color:#a855f7">🔬 Calidad</span>' : ''}
  </div>`;

  // ── TRATAMIENTO (editable solo en logística, bloqueado en calidad) ──
  const tratCambio = reg.tratamiento_turno_id && reg.tratamiento_id && reg.tratamiento_turno_id !== reg.tratamiento_id;
  html += `<div class="mob-ed-section">
    <div class="mob-ed-section-title">Tratamiento${reg.tratamiento_turno_nombre ? ` <span style="font-size:.65rem;opacity:.5;font-weight:400">(Turno: ${reg.tratamiento_turno_nombre})</span>` : ''}</div>
    ${!esCalidad && esPre && !soloLectura && (reg.tratamientos_catalogo || []).length ? `
      <select id="mobTratamiento" class="mob-ed-select">
        <option value="">— Sin definir —</option>
        ${(reg.tratamientos_catalogo || []).map(t => `<option value="${t.id}" ${reg.tratamiento_id === t.id ? 'selected' : ''}>${t.descripcion}</option>`).join('')}
      </select>
      ${tratCambio ? `<div style="font-size:.65rem;color:#fb923c;margin-top:4px">⚠ Modificado respecto al turno (${reg.tratamiento_turno_nombre})</div>` : ''}` : `<span class="mob-ed-val">${reg.tratamiento_nombre || '—'}</span>
      ${tratCambio ? `<div style="font-size:.65rem;color:#fb923c;margin-top:4px">⚠ Modificado respecto al turno (${reg.tratamiento_turno_nombre})</div>` : ''}`}
  </div>`;

  // ── CALIDAD: PR-05 + Temperaturas ──
  if (esCalidad) {
    html += `<div class="mob-ed-section">
      <div class="mob-ed-section-title" style="color:#a855f7">Control de Calidad</div>
      <div style="display:flex;flex-direction:column;gap:8px">
        <button class="mob-ed-action-btn" id="mobPR05" style="background:rgba(168,85,247,.1);color:#a855f7;border:1px solid rgba(168,85,247,.2)">📄 PR-05 Control de Recepción</button>
        <button class="mob-ed-action-btn" id="mobAgregarTemp" style="background:rgba(54,176,201,.1);color:#36B0C9;border:1px solid rgba(54,176,201,.2)">🌡 Registrar Temperaturas</button>
      </div>
    </div>`;
  }

  // ── BOTÓN INICIAR / FINALIZAR OPERACIÓN (solo logística) ──
  if (!esCalidad && reg.carga_numero) {
    const tcEstado = reg.tc_estado;
    const tronera = reg.tronera;
    const hayBoton = (tcEstado === 'E' && tronera) || tcEstado === 'C' || tcEstado === 'F';
    const hayTiempos = reg.hora_movimiento_inicio || reg.hora_movimiento_fin;
    if (hayBoton || hayTiempos) {
      html += `<div class="mob-ed-section mob-ed-op-section">`;
      if (tcEstado === 'E' && tronera) {
        html += `<button class="mob-ed-op-btn mob-ed-op-iniciar" id="mobIniciarOp">▶ Iniciar Operación</button>`;
      } else if (tcEstado === 'C') {
        html += `<button class="mob-ed-op-btn mob-ed-op-finalizar" id="mobFinalizarOp">⏹ Finalizar Operación</button>`;
      } else if (tcEstado === 'F') {
        html += `<button class="mob-ed-op-btn" id="mobLiberarVehiculo" style="background:rgba(251,146,60,.15);color:#fb923c;border:1px solid rgba(251,146,60,.3)">🚛 Liberar Vehículo</button>`;
      }
      if (reg.hora_movimiento_inicio) html += `<span class="mob-ed-time">Inicio: ${reg.fecha_movimiento || ''} ${reg.hora_movimiento_inicio}</span>`;
      if (reg.hora_movimiento_fin) html += `<span class="mob-ed-time">Fin: ${reg.fecha_movimiento || ''} ${reg.hora_movimiento_fin}</span>`;
      html += `</div>`;
    }
  }

  // ── ACCIONES RÁPIDAS (solo logística) ──
  if (!esCalidad) {
    html += `<div class="mob-ed-actions">
      ${esPre && !soloLectura ? `<button class="mob-ed-action-btn mob-ed-crear-est" id="mobCrearEstibas">＋ Crear Estibas</button>` : ''}
      ${esPre && !soloLectura ? `<button class="mob-ed-action-btn" id="mobImportarXML" style="background:rgba(168,85,247,.12);color:#c084fc;border:1px solid rgba(168,85,247,.25)">📄 Importar XML</button>` : ''}
      ${estibas.length ? `<button class="mob-ed-action-btn mob-ed-qr-all" id="mobQRTodas">🏷 Imprimir QR Todas</button>` : ''}
    </div>`;
  }

  // ── ESTIBAS (fichas simplificadas) ──
  html += `<div class="mob-ed-section">
    <div class="mob-ed-section-title">Estibas <span class="mob-ed-count">${estibas.length}</span></div>
    <div class="mob-ed-fichas">`;

  estibas.forEach(e => {
    const prods = e.productos || [];
    const productoNombre = prods.length ? prods[0].producto : 'Vacía';
    const codigo = prods.length ? prods[0].codigo : '—';
    const fechasVenc = prods.map(p => p.FechaVencimiento).filter(Boolean);
    let vencHtml = '<span class="mob-ed-muted">—</span>';
    if (fechasVenc.length === 1) vencHtml = fechasVenc[0];
    else if (fechasVenc.length > 1) vencHtml = `${fechasVenc[0]} — ${fechasVenc[fechasVenc.length - 1]}`;
    const totalBultos = prods.reduce((s, p) => s + (parseInt(p.Cantidad) || 0), 0);

    html += `<div class="mob-ed-ficha" data-estiba-id="${e.EstibaID}" data-nro="${e.NroEstiba}">
      <div class="mob-ed-ficha-top">
        <span class="mob-ed-ficha-num">${id}-${e.NroEstiba}</span>
        ${totalBultos ? `<span class="mob-ed-ficha-bultos">${totalBultos} btos</span>` : ''}
      </div>
      <div class="mob-ed-ficha-row"><span class="mob-ed-ficha-label">Código</span><span>${codigo}</span></div>
      <div class="mob-ed-ficha-row"><span class="mob-ed-ficha-label">Producto</span><span class="mob-ed-ficha-prod">${productoNombre}${prods.length > 1 ? ` (+${prods.length - 1})` : ''}</span></div>
      <div class="mob-ed-ficha-row"><span class="mob-ed-ficha-label">Vencimiento</span><span>${vencHtml}</span></div>
      <div class="mob-ed-ficha-btns">
        ${esCalidad ? `
          <button class="mob-ed-sm-btn" data-accion="mob-temp-estiba" data-estiba="${e.EstibaID}" style="background:rgba(54,176,201,.1);color:#36B0C9">🌡 Temp</button>
          <button class="mob-ed-sm-btn" data-accion="mob-foto-estiba" data-estiba="${e.EstibaID}" data-nro="${e.NroEstiba}" style="background:rgba(168,85,247,.1);color:#a855f7">📷 Fotos</button>
          <button class="mob-ed-sm-btn" data-accion="mob-intervenir" data-estiba="${e.EstibaID}" data-nro="${e.NroEstiba}" style="background:rgba(239,68,68,.1);color:#f87171">🚫 Interv.</button>
        ` : `
          <button class="mob-ed-sm-btn" data-accion="mob-cargar" data-estiba="${e.EstibaID}">📥 Cargar</button>
          <button class="mob-ed-sm-btn" data-accion="mob-qr" data-estiba="${e.EstibaID}" data-nro="${e.NroEstiba}">🏷 QR</button>
        `}
      </div>
    </div>`;
  });
  html += `</div></div>`;

  // ── ESTIBAS INTERVENIDAS ──
  if (estibasInt.length) {
    html += `<div class="mob-ed-section">
      <div class="mob-ed-section-title" style="color:#f87171">Intervenidas <span class="mob-ed-count" style="background:rgba(239,68,68,.15);color:#f87171">${estibasInt.length}</span></div>
      <div class="mob-ed-fichas">`;
    estibasInt.forEach(ei => {
      html += `<div class="mob-ed-ficha mob-ed-ficha-int" data-estiba-id="${ei.EstibaID}" data-nro="${ei.NroEstiba}">
        <div class="mob-ed-ficha-top">
          <span class="mob-ed-ficha-num" style="color:#f87171">I-${id}-${ei.NroEstiba}</span>
        </div>
        <div class="mob-ed-ficha-row"><span class="mob-ed-ficha-label">Motivo</span><span style="color:#fca5a5">${ei.motivo_desc || '—'}</span></div>
        <div class="mob-ed-ficha-row"><span class="mob-ed-ficha-label">Causa</span><span style="color:#fca5a5">${ei.causa || '—'}</span></div>
        <div class="mob-ed-ficha-btns">
          ${esCalidad ? `
            <button class="mob-ed-sm-btn mob-ed-sm-liberar" data-accion="mob-liberar" data-estiba="${ei.EstibaID}">🔓 Liberar</button>
          ` : `
            <button class="mob-ed-sm-btn" data-accion="mob-ubicar-int" data-estiba="${ei.EstibaID}">📍 Ubicar</button>
            <button class="mob-ed-sm-btn" data-accion="mob-qr-int" data-estiba="${ei.EstibaID}" data-nro="${ei.NroEstiba}">🏷 QR</button>
            <button class="mob-ed-sm-btn mob-ed-sm-liberar" data-accion="mob-liberar" data-estiba="${ei.EstibaID}">🔓 Liberar</button>
          `}
        </div>
      </div>`;
    });
    html += `</div></div>`;
  }

  // ── ACCIONES FINALES ──
  html += `<div class="mob-ed-bottom-actions">
    ${esPre && !esCalidad && !soloLectura ? `<button class="mob-ed-action-btn mob-ed-validar" id="mobValidar">📋 Validar Ingreso</button>` : ''}
    ${esPre && !soloLectura ? `<button class="mob-ed-action-btn mob-ed-clasificar" id="mobClasificar">✅ Clasificar como Entrada</button>` : ''}
  </div>`;

  wrap.innerHTML = html;

  // ── EVENT HANDLERS ──────────────────────────────────────────────

  // Tratamiento (solo logística)
  if (!esCalidad) {
    wrap.querySelector('#mobTratamiento')?.addEventListener('change', async (ev) => {
      const trat = ev.target.value;
      if (!trat) return;
      try {
        const r = await fetch('api_2026ia.php?action=entrada_cambiar_tratamiento', { method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ CargaID: id, tratamiento_id: trat }) });
        const d = await r.json(); if (d.error) throw new Error(d.error);
        showToast(d.anterior ? `Tratamiento: ${d.anterior} → ${d.nuevo}` : `Tratamiento: ${d.nuevo}`);
      } catch (e) { showToast('Error: ' + e.message, 'error'); }
    });
  }

  // ── CALIDAD: PR-05 ──
  wrap.querySelector('#mobPR05')?.addEventListener('click', () => {
    openPR05Digital(id, true);
  });

  // ── CALIDAD: Registrar temperaturas ──
  wrap.querySelector('#mobAgregarTemp')?.addEventListener('click', () => {
    openEdAgregarTemp(id, () => renderEntradaDetalle(id, opts));
  });

  // ── CALIDAD: Temperatura por estiba ──
  wrap.querySelectorAll('[data-accion="mob-temp-estiba"]').forEach(btn => {
    btn.onclick = (e) => {
      e.stopPropagation();
      openEdAgregarTemp(id, () => renderEntradaDetalle(id, opts), btn.dataset.estiba);
    };
  });

  // ── CALIDAD: Fotos por estiba ──
  wrap.querySelectorAll('[data-accion="mob-foto-estiba"]').forEach(btn => {
    btn.onclick = (e) => {
      e.stopPropagation();
      const eId = btn.dataset.estiba;
      const nro = btn.dataset.nro;
      if (typeof openFotosEstiba === 'function') {
        openFotosEstiba(id, eId, nro, () => renderEntradaDetalle(id, opts));
      } else {
        showToast('Función de fotos no disponible');
      }
    };
  });

  // ── CALIDAD: Intervenir estiba ──
  wrap.querySelectorAll('[data-accion="mob-intervenir"]').forEach(btn => {
    btn.onclick = (e) => {
      e.stopPropagation();
      const eId = btn.dataset.estiba;
      const nro = btn.dataset.nro;
      // Modal de selección modo intervención
      const mOverlay = document.createElement('div'); mOverlay.className='calidad-modal-overlay'; mOverlay.id='qrModoOverlay';
      document.body.appendChild(mOverlay); requestAnimationFrame(()=>mOverlay.classList.add('calidad-modal-visible'));
      mOverlay.innerHTML = `<div class="calidad-modal" style="max-width:320px;text-align:center">
        <div class="calidad-modal-header">🚫 Intervenir Estiba #${id}-${nro} <button class="chk-close" id="intModoClose">✕</button></div>
        <div class="calidad-modal-body" style="padding:16px">
          <div style="display:flex;flex-direction:column;gap:10px">
            <button id="intModoCompleta" class="mob-ed-action-btn" style="background:rgba(239,68,68,.1);color:#f87171;border:1px solid rgba(239,68,68,.2);padding:14px;font-size:.9rem;font-weight:700">🚫 Estiba Completa</button>
            <button id="intModoParcial" class="mob-ed-action-btn" style="background:rgba(245,158,11,.1);color:#f59e0b;border:1px solid rgba(245,158,11,.2);padding:14px;font-size:.9rem;font-weight:700">✂ Estiba Parcial</button>
          </div>
        </div>
      </div>`;
      const closeM=()=>{mOverlay.classList.remove('calidad-modal-visible');setTimeout(()=>mOverlay.remove(),200);};
      mOverlay.querySelector('#intModoClose').onclick=closeM;
      mOverlay.addEventListener('click',ev=>{if(ev.target===mOverlay)closeM();});
      mOverlay.querySelector('#intModoCompleta').onclick=()=>{closeM();intervenirEstiba(id,eId,nro,'completa',()=>renderEntradaDetalle(id,opts));};
      mOverlay.querySelector('#intModoParcial').onclick=()=>{closeM();intervenirEstiba(id,eId,nro,'parcial',()=>renderEntradaDetalle(id,opts));};
    };
  });

  // ── LOGÍSTICA: Iniciar operación ──
  wrap.querySelector('#mobIniciarOp')?.addEventListener('click', async () => {
    const cn = reg.carga_numero;
    try {
      const res = await fetch(API_EQUIPOS_URL + '?action=carga_iniciar_operacion', {
        method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ carga_numero: parseInt(cn) })
      }).then(r => r.json()).catch(() => ({ error: 'Error de red' }));
      showToast(res.ok ? '▶ ' + (res.mensaje || 'Operación iniciada') : (res.error || 'Error'), res.ok ? 'ok' : 'error');
      if (res.ok) { renderEntradaDetalle(id, opts); if (typeof bxRefrescarDesdeExterno === 'function') bxRefrescarDesdeExterno(); }
    } catch (e) { showToast('Error: ' + e.message, 'error'); }
  });

  // ── LOGÍSTICA: Finalizar operación ──
  wrap.querySelector('#mobFinalizarOp')?.addEventListener('click', async () => {
    const cn = reg.carga_numero;
    try {
      const res = await fetch(API_EQUIPOS_URL + '?action=carga_finalizar_operacion', {
        method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ carga_numero: parseInt(cn) })
      }).then(r => r.json()).catch(() => ({ error: 'Error de red' }));
      showToast(res.ok ? '⏹ ' + (res.mensaje || 'Operación finalizada') : (res.error || 'Error'), res.ok ? 'ok' : 'error');
      if (res.ok) { renderEntradaDetalle(id, opts); if (typeof bxRefrescarDesdeExterno === 'function') bxRefrescarDesdeExterno(); }
    } catch (e) { showToast('Error: ' + e.message, 'error'); }
  });

  // ── LOGÍSTICA: Liberar vehículo ──
  wrap.querySelector('#mobLiberarVehiculo')?.addEventListener('click', async () => {
    const cn = reg.carga_numero;
    try {
      const res = await fetch(API_EQUIPOS_URL + '?action=carga_liberar_vehiculo', {
        method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ carga_numero: parseInt(cn) })
      }).then(r => r.json()).catch(() => ({ error: 'Error de red' }));
      showToast(res.ok ? '🚛 ' + (res.mensaje || 'Vehículo liberado') : (res.error || 'Error'), res.ok ? 'ok' : 'error');
      if (res.ok) { renderEntradaDetalle(id, opts); if (typeof bxRefrescarDesdeExterno === 'function') bxRefrescarDesdeExterno(); }
    } catch (e) { showToast('Error: ' + e.message, 'error'); }
  });

  // ── LOGÍSTICA: Crear estibas ──
  wrap.querySelector('#mobCrearEstibas')?.addEventListener('click', () => {
    openEdCrearEstibas(id, (result) => {
      renderEntradaDetalle(id, opts);
      if (result?.estibas?.length) {
        setTimeout(() => {
          if (confirm(`Se crearon ${result.estibas.length} estibas. ¿Imprimir QR?`)) {
            imprimirQREstibas(result.estibas, id);
          }
        }, 300);
      }
    });
  });

  // ── LOGÍSTICA: Importar XML (mobile) ──
  wrap.querySelector('#mobImportarXML')?.addEventListener('click', () => {
    openImportarXMLTwins(id, () => renderEntradaDetalle(id, opts));
  });

  // ── LOGÍSTICA: QR todas ──
  wrap.querySelector('#mobQRTodas')?.addEventListener('click', () => {
    const estibasQR = estibas.map(e => ({ EstibaID: e.EstibaID, NroEstiba: e.NroEstiba }));
    imprimirQREstibas(estibasQR, id);
  });

  // QR individual
  wrap.querySelectorAll('[data-accion="mob-qr"]').forEach(btn => {
    btn.onclick = (e) => { e.stopPropagation(); imprimirQREstibas([{ EstibaID: btn.dataset.estiba, NroEstiba: btn.dataset.nro }], id); };
  });

  // Cargar estiba
  wrap.querySelectorAll('[data-accion="mob-cargar"]').forEach(btn => {
    btn.onclick = (e) => {
      e.stopPropagation();
      historyStack.push({ title: 'ENTRADA #' + id });
      renderEstibaFormulario(btn.dataset.estiba);
    };
  });

  // QR intervenida
  wrap.querySelectorAll('[data-accion="mob-qr-int"]').forEach(btn => {
    btn.onclick = (e) => { e.stopPropagation(); imprimirQREstibasIntervenidas([{ EstibaID: btn.dataset.estiba, NroEstiba: btn.dataset.nro }], id); };
  });

  // Ubicar intervenida
  wrap.querySelectorAll('[data-accion="mob-ubicar-int"]').forEach(btn => {
    btn.onclick = (e) => {
      e.stopPropagation();
      openMobileUbicarEstiba(btn.dataset.estiba, () => renderEntradaDetalle(id, opts), true);
    };
  });

  // Liberar intervenida
  wrap.querySelectorAll('[data-accion="mob-liberar"]').forEach(btn => {
    btn.onclick = async (e) => {
      e.stopPropagation();
      if (!confirm('¿Liberar estiba intervenida?')) return;
      try {
        const r = await fetch('api_2026ia.php?action=estiba_liberar_intervenida', { method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ EstibaIntervenidaID: btn.dataset.estiba }) });
        const d = await r.json(); if (d.error) throw new Error(d.error);
        showToast('🔓 Estiba liberada'); renderEntradaDetalle(id, opts);
      } catch (e2) { showToast('Error: ' + e2.message, 'error'); }
    };
  });

  // Validar ingreso
  wrap.querySelector('#mobValidar')?.addEventListener('click', async () => {
    if (!estibas.length) { showToast('Cargá al menos una estiba antes de validar'); return; }
    try {
      const r = await fetch('api_2026ia.php?action=entrada_validar', { method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ CargaID: id }) });
      const d = await r.json(); if (d.error) throw new Error(d.error);
      showToast('📋 Ingreso validado'); renderEntradaDetalle(id, opts);
    } catch (e) { showToast('Error: ' + e.message, 'error'); }
  });

  // Clasificar
  wrap.querySelector('#mobClasificar')?.addEventListener('click', async () => {
    if (!confirm('¿Clasificar como Entrada?')) return;
    try {
      const r = await fetch('api_2026ia.php?action=entrada_clasificar', { method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ CargaID: id }) });
      const d = await r.json(); if (d.error) throw new Error(d.error);
      showToast('✅ Entrada clasificada'); renderEntradaDetalle(id, opts);
    } catch (e) { showToast('Error: ' + e.message, 'error'); }
  });
}

/* ═══════════════════════════════════════════════════════════════
   DETALLE ENTRADA (Pre-Entrada / Entrada)
   ═══════════════════════════════════════════════════════════════ */

async function renderEntradaDetalle(id, opts = {}) {
  const esCalidad = opts.calidad || false; // Si viene de calidad, puede editar temp/PR-05
  setHeader('ENTRADA #' + id);
  setExpandedMode(true); showMetaPanel(esMobile() ? false : true);
  menuGrid.className = ''; menuGrid.innerHTML = '<div class="ed-wrap"><div class="ge-loading">Cargando...</div></div>';
  syncBackBtn();

  let data;
  try {
    const r = await fetch(`api_2026ia.php?action=entrada_ver&id=${id}`, {credentials:'same-origin'});
    data = await r.json(); if (data.error) throw new Error(data.error);
  } catch(e) { menuGrid.innerHTML = `<div class="ed-wrap"><div class="ge-empty">Error: ${e.message}</div></div>`; return; }

  const reg = data.registro, prods = data.productos||[], estibas = data.estibas||[];
  const esPre = !(parseInt(reg.Clasificada));
  const esFiscal = parseInt(reg.es_fiscal);
  const soloLectura = !esCalidad && !puedeEditarModulo(esPre ? 'log_pre_entradas' : 'log_entradas');

  // ═══ VISTA MÓVIL SIMPLIFICADA ═══════════════════════════════════════
  if (esMobile()) {
    renderEntradaDetalleMobile(id, data, opts);
    return;
  }
  // ═══ FIN VISTA MÓVIL ════════════════════════════════════════════════

  const wrap = document.createElement('div'); wrap.className = 'ed-wrap';
  menuGrid.innerHTML = ''; menuGrid.appendChild(wrap);

  // HEADER
  let html = `<div class="ed-header">
    <span class="ed-id">#${reg.CargaID}</span>
    <span class="ed-cliente">${reg.cliente||''}</span>
    <span class="ed-badge ${esPre?'ed-badge-pre':'ed-badge-ok'}">${esPre?'Pre-Entrada':'Entrada'}</span>
    ${esFiscal?'<span class="ed-badge ed-badge-fiscal">Fiscal</span>':''}
  </div>`;

  // DATOS GENERALES
  html += `<div class="ed-section"><div class="ed-section-title">📋 Datos Generales</div>
    <div class="ed-info-grid">
      <div class="ed-info-item"><div class="ed-info-label">Remito</div><div class="ed-info-val">${reg.NroRemito||'—'}</div></div>
      <div class="ed-info-item"><div class="ed-info-label">Referencia</div><div class="ed-info-val">${reg.numero_referencia||'—'}</div></div>
      ${esFiscal?`<div class="ed-info-item"><div class="ed-info-label">Permiso Embarque</div><div class="ed-info-val">${reg.permiso_embarque||'—'}</div></div>`:''}
      <div class="ed-info-item"><div class="ed-info-label">Estado</div><div class="ed-info-val">${esPre?'Pendiente':reg.estado_carga==1?'Liberada':reg.estado_carga==2?'Cuarentena':'—'}</div></div>
      <div class="ed-info-item">
        <div class="ed-info-label">Tratamiento${reg.tratamiento_turno_nombre ? ` <span style="font-size:.6rem;opacity:.5;font-weight:400">(Turno: ${reg.tratamiento_turno_nombre})</span>` : ''}</div>
        <div class="ed-info-val">${esPre && !soloLectura && (reg.tratamientos_catalogo||[]).length ? `
          <select id="edTratamiento" style="background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.12);border-radius:6px;padding:4px 8px;color:#fff;font-size:.78rem">
            <option value="">— Sin definir —</option>
            ${(reg.tratamientos_catalogo||[]).map(t => `<option value="${t.id}" ${reg.tratamiento_id===t.id?'selected':''}>${t.descripcion}</option>`).join('')}
          </select>
          ${reg.tratamiento_turno_id && reg.tratamiento_id && reg.tratamiento_turno_id !== reg.tratamiento_id ? `<div style="font-size:.6rem;color:#fb923c;margin-top:2px">⚠ Modificado respecto al turno</div>` : ''}` : `<span>${reg.tratamiento_nombre||'—'}</span>
          ${reg.tratamiento_turno_id && reg.tratamiento_id && reg.tratamiento_turno_id !== reg.tratamiento_id ? `<div style="font-size:.6rem;color:#fb923c;margin-top:2px">⚠ Modificado respecto al turno</div>` : ''}`}
        </div>
      </div>
      ${reg.Observaciones?`<div class="ed-info-item" style="grid-column:span 2"><div class="ed-info-label">Observaciones</div><div class="ed-info-val">${reg.Observaciones}</div></div>`:''}
    </div>
  </div>`;

  // PRODUCTOS DE LA CARGA
  // Productos: resumen auto-calculado desde estibas
  // totales de kilos del encabezado
  const totalKilos = prods.reduce((s,p) => s + (parseFloat(p.KilosUnidad)||0), 0);
  html += `<div class="ed-section"><div class="ed-section-title">📦 Resumen de Productos <span class="ed-section-count">${prods.length} producto${prods.length!==1?'s':''} · ${prods.reduce((s,p)=>s+(parseInt(p.Cantidad)||0),0)} bultos · ${totalKilos.toLocaleString('es-AR',{maximumFractionDigits:1})} kg</span></div>
    ${prods.length ? `<table class="ed-table"><thead><tr>
      <th>Código</th><th>Producto</th><th>Bultos</th><th>Kg/Unid</th><th>Kg Total</th><th>Congelado</th><th>En estibas</th>
    </tr></thead><tbody>
    ${prods.map(p => {
      const cant = parseFloat(p.Cantidad) || 0;
      const kgTot = parseFloat(p.KilosUnidad) || 0;   // PC.KilosUnidad = total kg de la carga para ese producto
      const kgUnid = cant > 0 && kgTot > 0 ? (kgTot / cant) : 0;
      return `<tr>
        <td>${p.codigo||''}</td><td style="font-weight:600">${p.producto||''}</td>
        <td>${cant}</td>
        <td>${kgUnid > 0 ? kgUnid.toFixed(2) : '—'}</td>
        <td>${kgTot > 0 ? kgTot.toLocaleString('es-AR',{maximumFractionDigits:1}) : '—'}</td>
        <td>${p.Congelado?'❄ Sí':'No'}</td>
        <td>${p.estibado>0?'<span style="color:#4ade80">'+p.estibado+' estiba'+(p.estibado>1?'s':'')+'</span>':'<span style="opacity:.4">—</span>'}</td>
      </tr>`;
    }).join('')}
    </tbody></table>` : '<div style="opacity:.4;text-align:center;padding:12px;font-size:.8rem">Los productos se cargan desde las estibas. Creá estibas y cargá productos con el formulario de cada una.</div>'}
  </div>`;

  // ESTIBAS — tabla completa con ancho total
  const allEstibaProducts = [];
  estibas.forEach(e => {
    (e.productos||[]).forEach(p => {
      allEstibaProducts.push({...p, NroEstiba: e.NroEstiba, tipo_estiba: e.tipo_estiba, ubicacion: e.ubicacion, estibaEstibaID: e.EstibaID});
    });
    if (!(e.productos||[]).length) {
      allEstibaProducts.push({ NroEstiba: e.NroEstiba, tipo_estiba: e.tipo_estiba, ubicacion: e.ubicacion, estibaEstibaID: e.EstibaID, vacia: true });
    }
  });
  // Agregar estibas intervenidas
  const estibasInt = data.estibas_intervenidas || [];
  estibasInt.forEach(ei => {
    allEstibaProducts.push({
      NroEstiba: ei.NroEstiba, tipo_estiba: 'INTERVENIDA', ubicacion: null,
      estibaEstibaID: ei.EstibaID, intervenida: true,
      motivo_desc: ei.motivo_desc || '', causa: ei.causa || '',
      EstibaOriginalID: ei.EstibaOriginalID
    });
  });

  html += `<div class="ed-section" style="padding:14px 8px">
    <div class="ed-section-title" style="padding:0 8px">🏗 Estibas <span class="ed-section-count">${estibas.length} estibas · ${allEstibaProducts.filter(p=>!p.vacia).length} líneas</span></div>
    <div style="overflow-x:auto;margin-top:8px">
      <table class="ed-table" style="width:100%;min-width:900px">
        <thead><tr>
          <th style="width:90px">Estiba</th>
          <th style="width:70px">Código</th>
          <th>Producto</th>
          <th style="width:70px">Lote</th>
          <th style="width:75px">F.Vencimiento</th>
          <th style="width:60px;text-align:right">Kilos</th>
          <th style="width:55px;text-align:right">Bultos</th>
          <th style="width:80px">Ubicación</th>
          <th style="width:110px;text-align:center">Acciones</th>
        </tr></thead>
        <tbody>
          ${allEstibaProducts.map(p => {
            const dni = `${id}-${p.NroEstiba}`;
            if (p.intervenida) {
              return `<tr style="background:rgba(239,68,68,.06)">
                <td style="font-weight:700;color:#f87171">I-${id}-${p.NroEstiba}</td>
                <td colspan="5" style="color:#f87171;font-size:.72rem">🚫 INTERVENIDA — ${p.motivo_desc||''} ${p.causa?'· '+p.causa:''}</td>
                <td colspan="2"></td>
                <td style="text-align:center">
                  <button class="ed-btn ed-btn-blue" style="padding:1px 5px;font-size:.6rem" data-accion="ubicar-intervenida" data-estiba="${p.estibaEstibaID}" title="Ubicar">📍</button>
                  <button class="ed-btn ed-btn-secondary" style="padding:1px 5px;font-size:.6rem" data-accion="qr-intervenida" data-estiba="${p.estibaEstibaID}" data-nro="${p.NroEstiba}" title="QR Intervenida">🏷</button>
                  <button class="ed-btn ed-btn-primary" style="padding:1px 5px;font-size:.6rem" data-accion="liberar-intervenida" data-estiba="${p.estibaEstibaID}" title="Liberar">🔓</button>
                </td>
              </tr>`;
            }
            if (p.vacia) {
              return `<tr style="opacity:.4"><td style="font-weight:700">${dni}</td><td colspan="7" style="font-style:italic">Vacía</td>
                <td style="text-align:center">
                  <button class="ed-btn ed-btn-secondary" style="padding:1px 6px;font-size:.62rem" data-accion="cargar-estiba" data-estiba="${p.estibaEstibaID}">📥</button>
                  <button class="ed-btn ed-btn-secondary" style="padding:1px 6px;font-size:.62rem" data-accion="qr-estiba" data-estiba="${p.estibaEstibaID}" data-nro="${p.NroEstiba}">🏷</button>
                  ${esPre?`<button class="ed-btn ed-btn-danger" style="padding:1px 6px;font-size:.62rem" data-accion="eliminar-estiba" data-estiba="${p.estibaEstibaID}">🗑</button>`:''}
                </td></tr>`;
            }
            const kilos = p.Cantidad && p.KilosUnidad ? (parseFloat(p.Cantidad) * parseFloat(p.KilosUnidad)).toFixed(1) : '—';
            return `<tr>
              <td style="font-weight:700">${dni}</td>
              <td>${p.codigo||''}</td>
              <td style="font-weight:600">${p.producto||''}</td>
              <td>${p.NroLote||''}</td>
              <td>${p.FechaVencimiento||''}</td>
              <td style="text-align:right">${kilos}</td>
              <td style="text-align:right">${p.Cantidad||0}</td>
              <td style="font-size:.68rem">${p.ubicacion||'<span style="color:#f87171">Sin ubic.</span>'}</td>
              <td style="text-align:center;white-space:nowrap">
                <button class="ed-btn ed-btn-secondary" style="padding:1px 5px;font-size:.6rem" data-accion="cargar-estiba" data-estiba="${p.estibaEstibaID}" title="Cargar">📥</button>
                <button class="ed-btn ed-btn-secondary" style="padding:1px 5px;font-size:.6rem" data-accion="qr-estiba" data-estiba="${p.estibaEstibaID}" data-nro="${p.NroEstiba}" title="QR">🏷</button>
                ${esPre?`<button class="ed-btn ed-btn-blue" style="padding:1px 5px;font-size:.6rem" data-accion="ubicar-estiba" data-estiba="${p.estibaEstibaID}" title="Ubicar">📍</button>
                <button class="ed-btn ed-btn-danger" style="padding:1px 5px;font-size:.6rem" data-accion="eliminar-estibado" data-carga="${p.CargaID}" data-prod="${p.ProductosID}" data-fechaev="${p.FechaEV}" data-estiba="${p.EstibaID}" title="Quitar">✕</button>`:''}
                <button class="ed-btn ed-btn-danger" style="padding:1px 5px;font-size:.6rem" data-accion="intervenir-estiba" data-carga="${id}" data-estiba="${p.estibaEstibaID}" data-nro="${p.NroEstiba}" title="Intervenir">🚫</button>
              </td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>
    </div>
    ${esPre && !soloLectura?`<div class="ed-action-bar" style="padding:8px">
      <button class="ed-btn ed-btn-primary" id="edCrearEstibas">＋ Crear Estibas</button>
      <button class="ed-btn ed-btn-secondary" id="edImportarXML">📄 Importar XML</button>
      ${estibas.length?`<button class="ed-btn ed-btn-blue" id="edImprimirQR">🏷 Imprimir QR de todas</button>`:''}
    </div>`:''}
  </div>`;

  // TEMPERATURAS
  html += `<div class="ed-section">
    <div class="ed-section-title">🌡 Control de Temperaturas
      ${esCalidad ? `<button class="ed-btn ed-btn-primary" style="margin-left:auto;padding:4px 12px;font-size:.72rem" id="edAgregarTemp">＋ Nueva Medición</button>` : ''}
    </div>
    <div id="edTempBody"><div style="opacity:.4;font-size:.78rem;padding:8px">Cargando temperaturas...</div></div>
  </div>`;

  // FOTOS
  html += `<div class="ed-section">
    <div class="ed-section-title">📷 Fotos
      <label class="ed-btn ed-btn-blue" style="margin-left:auto;padding:4px 12px;font-size:.72rem;cursor:pointer">
        📷 Agregar Foto <input type="file" id="edFotoInput" accept="image/*" style="display:none" multiple>
      </label>
    </div>
    <div id="edFotosBody" style="display:flex;flex-wrap:wrap;gap:8px;padding:4px"><span style="opacity:.4;font-size:.78rem">Sin fotos</span></div>
  </div>`;

  // FORMULARIOS PR
  html += `<div class="ed-section">
    <div class="ed-section-title">📋 Formularios</div>
    <div style="display:flex;gap:8px;flex-wrap:wrap">
      <button class="ed-btn ed-btn-secondary" id="edVerPR32">📄 PR-32 Recepción</button>
      <button class="ed-btn ed-btn-secondary" id="edVerPR05">📄 PR-05 ${esCalidad?'Editar':'Ver'}</button>
      <button class="ed-btn ed-btn-secondary" id="edVerPR98">📄 PR-98 Vale Pallets</button>
    </div>
  </div>`;

  // ACCIONES
  html += `<div class="ed-action-bar" style="margin-top:8px;gap:12px">
    ${esPre && !esCalidad && !soloLectura ? `<button class="ed-btn ed-btn-blue" style="padding:10px 20px;font-size:.85rem" id="edValidar">📋 Validar Ingreso</button>` : ''}
    ${esPre && !soloLectura ? `<button class="ed-btn ed-btn-primary" style="padding:10px 20px;font-size:.85rem" id="edClasificar">✅ Clasificar como Entrada</button>` : ''}
    ${!esPre && !data.tiene_salidas ? `<button class="ed-btn ed-btn-danger" id="edDesclasificar">↩ Volver a Pre-Entrada</button>` : ''}
  </div>`;

  wrap.innerHTML = html;

  // ── EVENT HANDLERS ──
  wrap.querySelector('#edCrearEstibas')?.addEventListener('click', () => {
    openEdCrearEstibas(id, (result) => {
      renderEntradaDetalle(id);
      // Ofrecer imprimir QR de las recién creadas
      if (result?.estibas?.length) {
        setTimeout(() => {
          if (confirm(`Se crearon ${result.estibas.length} estibas. ¿Imprimir QR?`)) {
            imprimirQREstibas(result.estibas, id);
          }
        }, 300);
      }
    });
  });

  // Importar XML TWINS (desktop)
  wrap.querySelector('#edImportarXML')?.addEventListener('click', () => {
    openImportarXMLTwins(id, () => renderEntradaDetalle(id));
  });

  // Imprimir todos los QR
  wrap.querySelector('#edImprimirQR')?.addEventListener('click', () => {
    const estibasQR = estibas.map(e => ({ EstibaID: e.EstibaID, NroEstiba: e.NroEstiba }));
    imprimirQREstibas(estibasQR, id);
  });

  // Click en cargar datos de estiba
  wrap.querySelectorAll('[data-accion="cargar-estiba"]').forEach(btn => {
    btn.onclick = () => {
      historyStack.push({ title: 'ENTRADA #' + id });
      renderEstibaFormulario(btn.dataset.estiba);
    };
  });

  // QR individual
  wrap.querySelectorAll('[data-accion="qr-estiba"]').forEach(btn => {
    btn.onclick = () => imprimirQREstibas([{ EstibaID: btn.dataset.estiba, NroEstiba: btn.dataset.nro }], id);
  });

  // Validar Ingreso = guardar/confirmar datos de la pre-entrada (paso intermedio)
  // Cambio de tratamiento
  wrap.querySelector('#edTratamiento')?.addEventListener('change', async (ev) => {
    const trat = ev.target.value;
    if (!trat) return;
    try {
      const r = await fetch('api_2026ia.php?action=entrada_cambiar_tratamiento', { method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'}, body:JSON.stringify({CargaID:id, tratamiento_id:trat}) });
      const d = await r.json(); if (d.error) throw new Error(d.error);
      showToast(d.anterior ? `Tratamiento cambiado: ${d.anterior} → ${d.nuevo}` : `Tratamiento asignado: ${d.nuevo}`);
    } catch(e) { showToast('Error: '+e.message, 'error'); }
  });

  wrap.querySelector('#edValidar')?.addEventListener('click', async () => {
    if (!prods.length && !estibas.length) { showToast('Cargá al menos una estiba con productos antes de validar'); return; }
    try {
      const r = await fetch('api_2026ia.php?action=entrada_validar', { method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'}, body:JSON.stringify({CargaID:id}) });
      const d = await r.json(); if (d.error) throw new Error(d.error);
      showToast('📋 Ingreso validado correctamente'); renderEntradaDetalle(id);
    } catch(e) { showToast('Error: '+e.message, 'error'); }
  });

  // Clasificar como Entrada = paso final que bloquea todo
  wrap.querySelector('#edClasificar')?.addEventListener('click', async () => {
    if (!confirm('¿Clasificar como Entrada? Los productos y estibas quedarán bloqueados.')) return;
    try {
      const r = await fetch('api_2026ia.php?action=entrada_clasificar', { method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'}, body:JSON.stringify({CargaID:id}) });
      const d = await r.json(); if (d.error) throw new Error(d.error);
      showToast('✅ Entrada clasificada'); renderEntradaDetalle(id);
    } catch(e) { showToast('Error: '+e.message, 'error'); }
  });

  wrap.querySelector('#edDesclasificar')?.addEventListener('click', async () => {
    if (!confirm('¿Volver a Pre-Entrada? Se podrán editar los datos nuevamente.')) return;
    try {
      const r = await fetch('api_2026ia.php?action=entrada_desclasificar', { method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'}, body:JSON.stringify({CargaID:id}) });
      const d = await r.json(); if (d.error) throw new Error(d.error);
      showToast('↩ Vuelve a Pre-Entrada'); renderEntradaDetalle(id);
    } catch(e) { showToast('Error: '+e.message, 'error'); }
  });

  wrap.querySelectorAll('[data-accion="eliminar-producto"]').forEach(btn => {
    btn.onclick = async () => {
      if (!confirm('¿Eliminar este producto?')) return;
      try {
        const r = await fetch('api_2026ia.php?action=entrada_eliminar_producto', { method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'}, body:JSON.stringify({CargaID:+btn.dataset.carga, ProductosID:+btn.dataset.prod}) });
        const d = await r.json(); if (d.error) throw new Error(d.error);
        showToast('Producto eliminado'); renderEntradaDetalle(id);
      } catch(e) { showToast('Error: '+e.message, 'error'); }
    };
  });

  wrap.querySelectorAll('[data-accion="eliminar-estiba"]').forEach(btn => {
    btn.onclick = async () => {
      if (!confirm('¿Eliminar esta estiba?')) return;
      try {
        const r = await fetch('api_2026ia.php?action=entrada_eliminar_estiba', { method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'}, body:JSON.stringify({EstibaID:btn.dataset.estiba}) });
        const d = await r.json(); if (d.error) throw new Error(d.error);
        showToast('Estiba eliminada'); renderEntradaDetalle(id);
      } catch(e) { showToast('Error: '+e.message, 'error'); }
    };
  });

  wrap.querySelectorAll('[data-accion="eliminar-estibado"]').forEach(btn => {
    btn.onclick = async () => {
      try {
        const r = await fetch('api_2026ia.php?action=entrada_eliminar_estibado', { method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'}, body:JSON.stringify({CargaID:+btn.dataset.carga, ProductosID:+btn.dataset.prod, FechaEV:+btn.dataset.fechaev, EstibaID:btn.dataset.estiba}) });
        const d = await r.json(); if (d.error) throw new Error(d.error);
        showToast('Estibado eliminado'); renderEntradaDetalle(id);
      } catch(e) { showToast('Error: '+e.message, 'error'); }
    };
  });

  wrap.querySelectorAll('[data-accion="ubicar-estiba"]').forEach(btn => {
    btn.onclick = () => openEdUbicarEstiba(btn.dataset.estiba, () => renderEntradaDetalle(id));
  });

  // Cargar temperaturas existentes
  (async () => {
    try {
      const r = await fetch(`api_2026ia.php?action=entrada_temperaturas&carga_id=${id}`, {credentials:'same-origin'});
      const d = await r.json();
      const mediciones = d.mediciones || [];
      const tempBody = wrap.querySelector('#edTempBody');
      if (!mediciones.length) { tempBody.innerHTML = '<div style="opacity:.4;font-size:.78rem;padding:8px">Sin mediciones registradas</div>'; }
      else {
        // Solo mostrar temperaturas de Formulario (temp2)
        const formMeds = mediciones.filter(m => m.Observaciones === 'Formulario' && m.Temperatura);
        // Calcular promedio
        const allTemps = formMeds.map(m => parseFloat(m.Temperatura));
        const promedio = allTemps.length ? (allTemps.reduce((s,t)=>s+t,0)/allTemps.length).toFixed(2) : '—';

        // Agrupar por estiba
        const porEstiba = {};
        formMeds.forEach(m => {
          const key = m.NroEstiba ? id+'-'+m.NroEstiba : 'sin-estiba';
          if (!porEstiba[key]) porEstiba[key] = [];
          porEstiba[key].push(m);
        });

        // Mostrar por estiba, sin columna Tipo
        tempBody.innerHTML = `
          <div style="font-size:.72rem;opacity:.5;margin-bottom:6px">Promedio: <strong style="color:${parseFloat(promedio)<=-15?'#60a5fa':'#f87171'}">${promedio}°C</strong></div>
          <table class="ed-table" style="font-size:.73rem"><thead><tr><th>Estiba</th><th>Producto</th><th>Temp °C</th><th>Fecha</th></tr></thead><tbody>
          ${formMeds.map(m => `<tr>
            <td style="font-weight:700">${m.NroEstiba?id+'-'+m.NroEstiba:'—'}</td>
            <td style="font-size:.68rem">${m.producto||''}</td>
            <td style="font-weight:700;${parseFloat(m.Temperatura)<=-15?'color:#60a5fa':'color:#f87171'}">${m.Temperatura}°C</td>
            <td style="font-size:.65rem;opacity:.5">${m.FechaMedicion||''}</td>
          </tr>`).join('')}
          ${estibas.filter(e => !formMeds.find(m => m.NroEstiba == e.NroEstiba)).map(e =>
            `<tr style="opacity:.5"><td>${id}-${e.NroEstiba}</td><td colspan="2" style="font-style:italic">Sin medición — toma promedio: ${promedio}°C</td><td></td></tr>`
          ).join('')}
        </tbody></table>`;
      }
    } catch(e) {}
  })();

  // Agregar medición de temperatura
  wrap.querySelector('#edAgregarTemp')?.addEventListener('click', () => {
    document.getElementById('calidadModalOverlay')?.remove();
    const overlay = document.createElement('div'); overlay.id='calidadModalOverlay'; overlay.className='calidad-modal-overlay';
    document.body.appendChild(overlay); requestAnimationFrame(()=>overlay.classList.add('calidad-modal-visible'));

    // Generar filas para cada estiba
    const rows = estibas.map(e => `<tr>
      <td style="font-weight:700">${id}-${e.NroEstiba}</td>
      <td><input type="number" step="0.01" class="sd-qty-input temp-t1" data-estiba="${e.EstibaID}" data-nro="${e.NroEstiba}" placeholder="°C" style="width:70px"></td>
      <td><input type="number" step="0.01" class="sd-qty-input temp-t2" data-estiba="${e.EstibaID}" placeholder="°C" style="width:70px"></td>
    </tr>`).join('');

    overlay.innerHTML = `<div class="calidad-modal" style="width:min(500px,94vw);max-height:85vh;overflow-y:auto">
      <div class="calidad-modal-header">🌡 Nueva Medición de Temperatura <button class="chk-close" id="tmpClose">✕</button></div>
      <div class="calidad-modal-body">
        <div style="display:flex;gap:8px;margin-bottom:10px">
          <div class="calidad-modal-field" style="flex:1"><label>Nº TERMÓMETRO</label><input type="text" id="tmpTermometro" placeholder="Ej: 53"></div>
          <div class="calidad-modal-field" style="flex:1"><label>TRATAMIENTO</label>
            <select id="tmpTratamiento"><option value="C">Congelado</option><option value="E">Enfriado</option><option value="A">A Congelar</option><option value="S">Separadores</option></select>
          </div>
        </div>
        <table class="ed-table"><thead><tr><th>Estiba</th><th>Temp 1 (Fact.)</th><th>Temp 2 (Form.)</th></tr></thead><tbody>${rows}</tbody></table>
      </div>
      <div class="calidad-modal-footer">
        <button class="calidad-modal-btn calidad-modal-btn-cancel" id="tmpCancel">Cancelar</button>
        <button class="calidad-modal-btn calidad-modal-btn-save" id="tmpSave">💾 Registrar</button>
      </div>
    </div>`;

    const close=()=>{overlay.classList.remove('calidad-modal-visible');setTimeout(()=>overlay.remove(),200);};
    overlay.querySelector('#tmpClose').onclick=close; overlay.querySelector('#tmpCancel').onclick=close;
    overlay.addEventListener('click',e=>{if(e.target===overlay)close();}); overlay.querySelectorAll('input,select').forEach(el=>{el.onkeydown=e=>e.stopPropagation();});

    overlay.querySelector('#tmpSave').onclick = async () => {
      const mediciones = [];
      overlay.querySelectorAll('.temp-t1').forEach(inp => {
        const t1 = inp.value; const t2 = inp.closest('tr').querySelector('.temp-t2')?.value || '';
        if (t1 || t2) {
          // Buscar producto de esta estiba
          const estibaId = inp.dataset.estiba;
          const estiba = estibas.find(e => e.EstibaID == estibaId);
          const prod = estiba?.productos?.[0];
          mediciones.push({ estiba_id: estibaId, producto_id: prod?.ProductosID||0, temperatura1: t1, temperatura2: t2 });
        }
      });
      if (!mediciones.length) { showToast('Ingresá al menos una temperatura'); return; }
      try {
        const r = await fetch('api_2026ia.php?action=entrada_registrar_temperatura', {
          method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
          body: JSON.stringify({ carga_id:id, mediciones, nro_termometro: overlay.querySelector('#tmpTermometro').value, tratamiento: overlay.querySelector('#tmpTratamiento').value })
        });
        const d = await r.json(); if (d.error) throw new Error(d.error);
        showToast(`🌡 Medición #${d.nro_control} registrada — Promedio: ${d.promedio}°C`);
        close(); renderEntradaDetalle(id);
      } catch(e) { showToast('Error: '+e.message, 'error'); }
    };
  });

  // Subir fotos
  wrap.querySelector('#edFotoInput')?.addEventListener('change', async (ev) => {
    const files = ev.target.files;
    if (!files.length) return;
    // Pedir a qué estiba asociar
    const estibaId = estibas.length === 1 ? estibas[0].EstibaID : prompt('Nro de estiba (1, 2, 3...):');
    const estiba = estibas.find(e => e.NroEstiba == estibaId || e.EstibaID == estibaId);
    if (!estiba) { showToast('Estiba no encontrada'); return; }

    for (const file of files) {
      const fd = new FormData();
      fd.append('foto', file);
      fd.append('estiba_id', estiba.EstibaID);
      try {
        const r = await fetch('api_2026ia.php?action=estiba_subir_foto', { method:'POST', credentials:'same-origin', body:fd });
        const d = await r.json(); if (d.error) throw new Error(d.error);
        showToast('📷 Foto subida');
      } catch(e) { showToast('Error: '+e.message, 'error'); }
    }
    renderEntradaDetalle(id);
  });

  // Cargar fotos existentes
  (async () => {
    const fotosBody = wrap.querySelector('#edFotosBody');
    let todasFotos = [];
    for (const e of estibas) {
      try {
        const r = await fetch(`api_2026ia.php?action=estiba_fotos&estiba_id=${e.EstibaID}`, {credentials:'same-origin'});
        const d = await r.json();
        (d.fotos||[]).forEach(f => todasFotos.push({...f, nroEstiba: e.NroEstiba}));
      } catch(err) {}
    }
    if (todasFotos.length) {
      fotosBody.innerHTML = todasFotos.map(f => `
        <div style="width:100px;height:100px;border-radius:8px;overflow:hidden;border:1px solid rgba(255,255,255,.1);position:relative">
          <img src="${f.url}" style="width:100%;height:100%;object-fit:cover" alt="Foto">
          <div style="position:absolute;bottom:0;left:0;right:0;background:rgba(0,0,0,.7);padding:2px 4px;font-size:.6rem;color:#fff">#${id}-${f.nroEstiba}</div>
        </div>`).join('');
    }
  })();

  // Formularios PR
  wrap.querySelector('#edVerPR05')?.addEventListener('click', () => openPR05Digital(id, esCalidad));
  wrap.querySelector('#edVerPR32')?.addEventListener('click', () => openPR32Digital(id));
  wrap.querySelector('#edVerPR98')?.addEventListener('click', () => openPR98Digital(id));

  // Ubicar estiba intervenida
  wrap.querySelectorAll('[data-accion="ubicar-intervenida"]').forEach(btn => {
    btn.onclick = () => openEdUbicarEstiba(btn.dataset.estiba, () => renderEntradaDetalle(id, opts), true);
  });
  // QR estiba intervenida
  wrap.querySelectorAll('[data-accion="qr-intervenida"]').forEach(btn => {
    btn.onclick = () => imprimirQREstibasIntervenidas([{ EstibaID: btn.dataset.estiba, NroEstiba: btn.dataset.nro }], id);
  });
  // Liberar estiba intervenida
  wrap.querySelectorAll('[data-accion="liberar-intervenida"]').forEach(btn => {
    btn.onclick = () => liberarEstibaIntervenida(btn.dataset.estiba, () => renderEntradaDetalle(id, opts));
  });

  // Intervenir estiba
  wrap.querySelectorAll('[data-accion="intervenir-estiba"]').forEach(btn => {
    btn.onclick = () => {
      const cId = +btn.dataset.carga;
      const eId = btn.dataset.estiba;
      const nro = btn.dataset.nro;
      // Opciones: completa o parcial
      const modo = confirm('¿Intervenir la estiba COMPLETA?\n\nAceptar = Estiba completa\nCancelar = Parcial (elegir cantidad)') ? 'completa' : 'parcial';
      intervenirEstiba(cId, eId, nro, modo, () => renderEntradaDetalle(id));
    };
  });
}

// ── Modales de Entrada ───────────────────────────────────────────
async function openEdAgregarProducto(cargaId, clienteId, onSuccess) {
  document.getElementById('calidadModalOverlay')?.remove();
  let cats; try { const r = await fetch(`api_2026ia.php?action=entrada_catalogos&cliente_id=${clienteId}`,{credentials:'same-origin'}); cats = await r.json(); } catch(e) { showToast('Error catálogos'); return; }
  const overlay = document.createElement('div'); overlay.id='calidadModalOverlay'; overlay.className='calidad-modal-overlay';
  document.body.appendChild(overlay); requestAnimationFrame(()=>overlay.classList.add('calidad-modal-visible'));
  overlay.innerHTML = `<div class="calidad-modal"><div class="calidad-modal-header">＋ Agregar Producto <button class="chk-close" id="eapClose">✕</button></div>
    <div class="calidad-modal-body">
      <div class="calidad-modal-field"><label>PRODUCTO</label><select id="eapProd"><option value="">— Seleccionar —</option>${(cats.productos||[]).map(p=>`<option value="${p.id}">${p.codigo} — ${p.nombre}</option>`).join('')}</select></div>
      <div class="calidad-modal-field"><label>CANTIDAD (BULTOS)</label><input type="number" id="eapCant" min="1" value="1"></div>
      <div class="calidad-modal-field"><label>KILOS POR UNIDAD</label><input type="number" id="eapKilos" min="0" step="0.01" value="0"></div>
      <div class="calidad-modal-field"><label style="display:flex;align-items:center;gap:6px"><input type="checkbox" id="eapCong"> CONGELADO</label></div>
    </div>
    <div class="calidad-modal-footer"><button class="calidad-modal-btn calidad-modal-btn-cancel" id="eapCancel">Cancelar</button><button class="calidad-modal-btn calidad-modal-btn-save" id="eapSave">💾 Agregar</button></div></div>`;
  const close=()=>{overlay.classList.remove('calidad-modal-visible');setTimeout(()=>overlay.remove(),200);};
  overlay.querySelector('#eapClose').onclick=close; overlay.querySelector('#eapCancel').onclick=close;
  overlay.addEventListener('click',e=>{if(e.target===overlay)close();}); overlay.querySelectorAll('input,select').forEach(el=>{el.onkeydown=e=>e.stopPropagation();});
  overlay.querySelector('#eapSave').onclick = async()=>{
    const prodId=overlay.querySelector('#eapProd').value; if(!prodId){showToast('Seleccioná un producto');return;}
    try { const r=await fetch('api_2026ia.php?action=entrada_agregar_producto',{method:'POST',credentials:'same-origin',headers:{'Content-Type':'application/json'},body:JSON.stringify({CargaID:cargaId,ProductosID:+prodId,Cantidad:+overlay.querySelector('#eapCant').value,KilosUnidad:+overlay.querySelector('#eapKilos').value,Congelado:overlay.querySelector('#eapCong').checked?1:0})}); const d=await r.json(); if(d.error)throw new Error(d.error); showToast('✅ Producto agregado'); close(); if(onSuccess)onSuccess(); } catch(e){showToast('Error: '+e.message,'error');}
  };
}

