async function openImportarXMLTwins(cargaId, onSuccess) {
  document.getElementById('calidadModalOverlay')?.remove();
  const overlay = document.createElement('div'); overlay.id='calidadModalOverlay'; overlay.className='calidad-modal-overlay';
  document.body.appendChild(overlay); requestAnimationFrame(()=>overlay.classList.add('calidad-modal-visible'));
  overlay.innerHTML = `<div class="calidad-modal" style="width:min(600px,96vw)"><div class="calidad-modal-header">📄 Importar XML (InterfazTWINS) <button class="chk-close" id="ixClose">✕</button></div>
    <div class="calidad-modal-body">
      <div class="calidad-modal-field">
        <label>ARCHIVO XML</label>
        <input type="file" id="ixFile" accept=".xml" style="padding:8px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.12);border-radius:6px;color:#fff;width:100%">
      </div>
      <div id="ixPreview" style="margin-top:12px;display:none">
        <div style="font-size:.75rem;font-weight:700;color:rgba(255,255,255,.7);margin-bottom:6px">Vista previa</div>
        <div id="ixPreviewBody" style="background:rgba(0,0,0,.2);border-radius:6px;padding:10px;font-size:.72rem;max-height:300px;overflow-y:auto"></div>
      </div>
      <div id="ixStatus" style="margin-top:8px;font-size:.72rem;color:#94a3b8"></div>
    </div>
    <div class="calidad-modal-footer">
      <button class="calidad-modal-btn calidad-modal-btn-cancel" id="ixCancel">Cancelar</button>
      <button class="calidad-modal-btn calidad-modal-btn-save" id="ixImport" disabled>📥 Importar</button>
    </div></div>`;
  const close=()=>{overlay.classList.remove('calidad-modal-visible');setTimeout(()=>overlay.remove(),200);};
  overlay.querySelector('#ixClose').onclick=close; overlay.querySelector('#ixCancel').onclick=close;
  overlay.addEventListener('click',e=>{if(e.target===overlay)close();});

  let selectedFile = null;

  overlay.querySelector('#ixFile').addEventListener('change', (e) => {
    const file = e.target.files[0];
    if (!file) return;
    selectedFile = file;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const parser = new DOMParser();
        const xml = parser.parseFromString(ev.target.result, 'text/xml');
        const items = xml.querySelectorAll('GENERAL');
        const pallets = {};
        let sinPallet = 0;
        let totalPeso = 0;
        items.forEach(item => {
          const pallet = (item.querySelector('PALLET')?.textContent || '').trim();
          const peso = parseFloat(item.querySelector('PESONETO')?.textContent || '0');
          totalPeso += peso;
          if (!pallet) { sinPallet++; return; }
          if (!pallets[pallet]) pallets[pallet] = { items: 0, peso: 0, productos: {} };
          pallets[pallet].items++;
          pallets[pallet].peso += peso;
          const prod = (item.querySelector('PRODUCTO')?.textContent || '???').trim();
          pallets[pallet].productos[prod] = (pallets[pallet].productos[prod] || 0) + 1;
        });
        const nPallets = Object.keys(pallets).length;
        const conPallet = Object.values(pallets).reduce((s,p) => s + p.items, 0);
        let html = `<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:10px">
          <div style="background:rgba(74,222,128,.1);padding:8px;border-radius:6px;text-align:center">
            <div style="font-size:1.1rem;font-weight:900;color:#4ade80">${nPallets}</div>
            <div style="font-size:.65rem;color:#86efac">Pallets (Estibas)</div>
          </div>
          <div style="background:rgba(96,165,250,.1);padding:8px;border-radius:6px;text-align:center">
            <div style="font-size:1.1rem;font-weight:900;color:#60a5fa">${conPallet}</div>
            <div style="font-size:.65rem;color:#93c5fd">Items con pallet</div>
          </div>
          <div style="background:rgba(251,146,60,.1);padding:8px;border-radius:6px;text-align:center">
            <div style="font-size:1.1rem;font-weight:900;color:#fb923c">${totalPeso.toFixed(1)} kg</div>
            <div style="font-size:.65rem;color:#fdba74">Peso neto total</div>
          </div>
        </div>`;
        if (sinPallet > 0) {
          html += `<div style="background:rgba(239,68,68,.1);padding:6px 10px;border-radius:6px;margin-bottom:8px;font-size:.72rem;color:#fca5a5">⚠ ${sinPallet} items sin PALLET asignado (serán ignorados)</div>`;
        }
        if (nPallets > 0) {
          html += `<table style="width:100%;border-collapse:collapse;font-size:.7rem">
            <thead><tr style="border-bottom:1px solid rgba(255,255,255,.1)">
              <th style="text-align:left;padding:4px;color:rgba(255,255,255,.5)">Pallet</th>
              <th style="text-align:center;padding:4px;color:rgba(255,255,255,.5)">Items</th>
              <th style="text-align:right;padding:4px;color:rgba(255,255,255,.5)">Peso Neto</th>
              <th style="text-align:left;padding:4px;color:rgba(255,255,255,.5)">Productos</th>
            </tr></thead><tbody>`;
          Object.keys(pallets).sort((a,b) => +a - +b).forEach(pNum => {
            const p = pallets[pNum];
            const prodsStr = Object.entries(p.productos).map(([cod,cnt]) => `${cod} (${cnt})`).join(', ');
            html += `<tr style="border-bottom:1px solid rgba(255,255,255,.05)">
              <td style="padding:4px;font-weight:700;color:#c084fc">#${pNum}</td>
              <td style="padding:4px;text-align:center">${p.items}</td>
              <td style="padding:4px;text-align:right">${p.peso.toFixed(2)} kg</td>
              <td style="padding:4px;font-size:.65rem;color:rgba(255,255,255,.6)">${prodsStr}</td>
            </tr>`;
          });
          html += `</tbody></table>`;
        }
        overlay.querySelector('#ixPreviewBody').innerHTML = html;
        overlay.querySelector('#ixPreview').style.display = 'block';
        overlay.querySelector('#ixImport').disabled = nPallets === 0;
        if (nPallets === 0) {
          overlay.querySelector('#ixStatus').innerHTML = '<span style="color:#f87171">No se puede importar: ningún item tiene PALLET asignado</span>';
        } else {
          overlay.querySelector('#ixStatus').innerHTML = `Se crearán <b>${nPallets} estibas</b> con <b>${conPallet} items</b>`;
        }
      } catch(err) {
        overlay.querySelector('#ixPreviewBody').innerHTML = `<span style="color:#f87171">Error al leer XML: ${err.message}</span>`;
        overlay.querySelector('#ixPreview').style.display = 'block';
        overlay.querySelector('#ixImport').disabled = true;
      }
    };
    reader.readAsText(file);
  });

  overlay.querySelector('#ixImport').onclick = async () => {
    if (!selectedFile) return;
    const btn = overlay.querySelector('#ixImport');
    btn.disabled = true; btn.textContent = '⏳ Importando...';
    overlay.querySelector('#ixStatus').innerHTML = '<span style="color:#60a5fa">Procesando archivo...</span>';
    try {
      const fd = new FormData();
      fd.append('xml_file', selectedFile);
      fd.append('CargaID', cargaId);
      const r = await fetch('api_2026ia.php?action=entrada_importar_xml_twins', { method:'POST', credentials:'same-origin', body:fd });
      const d = await r.json();
      if (d.error) throw new Error(d.error);
      let msg = `✅ ${d.estibas_creadas} estibas creadas con ${d.items_procesados} items`;
      if (d.items_sin_pallet > 0) msg += ` (${d.items_sin_pallet} sin pallet ignorados)`;
      showToast(msg);
      close();
      if (onSuccess) onSuccess();
    } catch(e) {
      overlay.querySelector('#ixStatus').innerHTML = `<span style="color:#f87171">Error: ${e.message}</span>`;
      btn.disabled = false; btn.textContent = '📥 Importar';
    }
  };
}

