async function openEdUbicarEstiba(estibaId, onSuccess, intervenida) {
  document.getElementById('calidadModalOverlay')?.remove();
  let cats; try { const r=await fetch('api_2026ia.php?action=entrada_catalogos',{credentials:'same-origin'}); cats=await r.json(); } catch(e){showToast('Error');return;}
  const overlay = document.createElement('div'); overlay.id='calidadModalOverlay'; overlay.className='calidad-modal-overlay';
  document.body.appendChild(overlay); requestAnimationFrame(()=>overlay.classList.add('calidad-modal-visible'));
  const camaras = cats.camaras||[];
  overlay.innerHTML = `<div class="calidad-modal"><div class="calidad-modal-header">📍 Ubicar Estiba <button class="chk-close" id="euClose">✕</button></div>
    <div class="calidad-modal-body">
      <div class="calidad-modal-field"><label>CÁMARA</label><select id="euCam">${camaras.map(c=>{const lbl=c.iniciales?c.iniciales+'-'+c.numero:'Cámara '+c.numero;return`<option value="${c.id}" data-calles="${c.calles}" data-filas="${c.filas}" data-niveles="${c.niveles}">${lbl}</option>`;}).join('')}</select></div>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px">
        <div class="calidad-modal-field"><label>CALLE</label><input type="number" id="euCalle" min="1" value="1"></div>
        <div class="calidad-modal-field"><label>FILA</label><input type="number" id="euFila" min="1" value="1"></div>
        <div class="calidad-modal-field"><label>NIVEL</label><input type="number" id="euNivel" min="1" value="1"></div>
      </div>
      <div id="euPosId" style="font-size:.68rem;opacity:.4;margin-top:4px"></div>
    </div>
    <div class="calidad-modal-footer"><button class="calidad-modal-btn calidad-modal-btn-cancel" id="euCancel">Cancelar</button><button class="calidad-modal-btn calidad-modal-btn-save" id="euSave">💾 Asignar</button></div></div>`;
  const close=()=>{overlay.classList.remove('calidad-modal-visible');setTimeout(()=>overlay.remove(),200);};
  overlay.querySelector('#euClose').onclick=close; overlay.querySelector('#euCancel').onclick=close;
  overlay.addEventListener('click',e=>{if(e.target===overlay)close();}); overlay.querySelectorAll('input,select').forEach(el=>{el.onkeydown=e=>e.stopPropagation();});

  // Buscar PosicionID basado en cámara + calle + fila
  const findPos = async()=>{
    const camId=overlay.querySelector('#euCam').value, calle=overlay.querySelector('#euCalle').value, fila=overlay.querySelector('#euFila').value;
    try { const r=await fetch(`api_2026ia.php?action=entrada_buscar_posicion&camara_id=${camId}&calle=${calle}&fila=${fila}`,{credentials:'same-origin'}); const d=await r.json(); overlay.querySelector('#euPosId').textContent=d.posicion_id?`PosiciónID: ${d.posicion_id}`:'Posición no encontrada'; overlay.querySelector('#euSave').dataset.posid=d.posicion_id||''; } catch(e){} };
  overlay.querySelector('#euCam').onchange=findPos; overlay.querySelector('#euCalle').oninput=findPos; overlay.querySelector('#euFila').oninput=findPos;
  findPos();

  overlay.querySelector('#euSave').onclick = async()=>{
    const posId = overlay.querySelector('#euSave').dataset.posid;
    const nivel = +overlay.querySelector('#euNivel').value;
    if(!posId){showToast('Posición no encontrada');return;}
    try { const r=await fetch('api_2026ia.php?action=entrada_ubicar_estiba',{method:'POST',credentials:'same-origin',headers:{'Content-Type':'application/json'},body:JSON.stringify({EstibaID:estibaId,PosicionID:+posId,Nivel:nivel,intervenida:!!intervenida})}); const d=await r.json(); if(d.error)throw new Error(d.error); showToast('📍 Estiba ubicada'); close(); if(onSuccess)onSuccess(); } catch(e){showToast('Error: '+e.message,'error');}
  };
}

/* ═══════════════════════════════════════════════════════════════
   VERIFICACIÓN DE CARGA — Scanner QR para salidas
   ═══════════════════════════════════════════════════════════════ */

async function abrirVerificacionCarga(cargaNumero, opts = {}) {
  const presalidaId = opts.presalidaId || 0;
  document.getElementById('calidadModalOverlay')?.remove();
  const overlay = document.createElement('div');
  overlay.id = 'calidadModalOverlay';
  overlay.className = 'calidad-modal-overlay';
  document.body.appendChild(overlay);
  requestAnimationFrame(() => overlay.classList.add('calidad-modal-visible'));

  overlay.innerHTML = `<div class="calidad-modal" style="width:min(640px,96vw);max-height:92vh;overflow-y:auto">
    <div class="calidad-modal-header">
      📦 Verificación de Carga #${cargaNumero}
      <button class="chk-close" id="verifClose">✕</button>
    </div>
    <div class="calidad-modal-body" style="padding:12px">
      <!-- Barra de progreso -->
      <div id="verifProgreso" style="margin-bottom:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
          <span style="font-size:.75rem;font-weight:700;color:rgba(255,255,255,.7)">Progreso de verificación</span>
          <span id="verifPctText" style="font-size:.85rem;font-weight:900;color:#fb923c">0%</span>
        </div>
        <div style="height:8px;background:rgba(255,255,255,.08);border-radius:4px;overflow:hidden">
          <div id="verifBar" style="height:100%;width:0%;background:#fb923c;border-radius:4px;transition:width .4s ease"></div>
        </div>
        <div id="verifConteo" style="font-size:.65rem;color:#94a3b8;margin-top:3px">0 / 0 items verificados</div>
      </div>
      <!-- Scanner QR -->
      <div id="verifScanZona" style="text-align:center;padding:12px;border:1px dashed rgba(255,255,255,.15);border-radius:10px;margin-bottom:14px">
        <div style="font-size:.85rem;font-weight:700;color:rgba(255,255,255,.6);margin-bottom:8px">Escanear código QR</div>
        <div style="font-size:.7rem;color:#64748b;margin-bottom:10px">Apuntá la cámara al QR de la estiba o etiqueta provisoria</div>
        <div id="verifError" style="color:#f87171;font-size:.78rem;margin-bottom:8px;display:none"></div>
        <div id="verifOk" style="color:#22c55e;font-size:.78rem;margin-bottom:8px;display:none"></div>
        <button id="verifBtnCam" type="button" style="padding:8px 20px;background:rgba(99,179,237,.15);color:#63b3ed;border:1px solid rgba(99,179,237,.3);border-radius:8px;cursor:pointer;font-size:.82rem;font-weight:700">📷 Abrir cámara</button>
        <div id="verifCamView" style="display:none;position:relative;margin-top:10px">
          <video id="verifVideo" playsinline muted style="width:100%;max-height:280px;border-radius:10px;background:#000;display:block"></video>
          <canvas id="verifCanvas" style="display:none"></canvas>
          <div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;pointer-events:none">
            <div style="width:180px;height:180px;border:2px solid rgba(99,179,237,.8);border-radius:12px;box-shadow:0 0 0 9999px rgba(0,0,0,.45)"></div>
          </div>
          <button id="verifCerrarCam" type="button" style="position:absolute;top:6px;right:6px;background:rgba(0,0,0,.6);border:1px solid rgba(255,255,255,.3);color:#fff;border-radius:6px;padding:4px 12px;cursor:pointer;font-size:.8rem">✕</button>
        </div>
      </div>
      <!-- Lista de items -->
      <div id="verifItems" style="max-height:320px;overflow-y:auto">
        <div class="ge-loading">Cargando items...</div>
      </div>
    </div>
    <div class="calidad-modal-footer" style="flex-wrap:wrap;gap:8px">
      <button class="calidad-modal-btn calidad-modal-btn-cancel" id="verifReset" style="font-size:.72rem">🔄 Resetear</button>
      <button class="calidad-modal-btn calidad-modal-btn-cancel" id="verifCerrar">Cerrar</button>
      <button class="calidad-modal-btn calidad-modal-btn-save" id="verifFinalizar" disabled style="opacity:.5">⏹ Finalizar Operación</button>
    </div>
  </div>`;

  const close = () => { cerrarCam(); overlay.classList.remove('calidad-modal-visible'); setTimeout(() => overlay.remove(), 200); };
  overlay.querySelector('#verifClose').onclick = close;
  overlay.querySelector('#verifCerrar').onclick = close;
  overlay.addEventListener('click', e => { if (e.target === overlay) close(); });

  // ── Estado ──
  let scanStream = null, scanRafId = null;
  let estadoActual = { items: [], progreso: { total: 0, verificados: 0, porcentaje: 0 } };

  // ── UI helpers ──
  function actualizarProgreso(prog) {
    const pct = prog.porcentaje || 0;
    const color = pct >= 100 ? '#22c55e' : pct >= 50 ? '#fb923c' : '#f87171';
    overlay.querySelector('#verifBar').style.width = pct + '%';
    overlay.querySelector('#verifBar').style.background = color;
    overlay.querySelector('#verifPctText').textContent = pct + '%';
    overlay.querySelector('#verifPctText').style.color = color;
    overlay.querySelector('#verifConteo').textContent = `${prog.verificados} / ${prog.total} items verificados`;
    const btnFin = overlay.querySelector('#verifFinalizar');
    if (pct >= 100) { btnFin.disabled = false; btnFin.style.opacity = '1'; }
    else { btnFin.disabled = false; btnFin.style.opacity = '.8'; }
  }

  function renderItems(items) {
    const el = overlay.querySelector('#verifItems');
    if (!items.length) { el.innerHTML = '<div style="opacity:.4;text-align:center;padding:16px">No hay items para verificar</div>'; return; }
    el.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:.72rem">
      <thead><tr style="color:#94a3b8;text-align:left;border-bottom:1px solid rgba(255,255,255,.1)">
        <th style="padding:4px 6px">Estado</th><th style="padding:4px 6px">Producto</th><th style="padding:4px 6px">Estiba</th><th style="padding:4px 6px">Cant.</th><th style="padding:4px 6px">Tipo</th>
      </tr></thead>
      <tbody>${items.map(it => {
        const ok = it.verificado;
        const esEP = !!it.EtiquetaProvisoriaID;
        return `<tr style="border-bottom:1px solid rgba(255,255,255,.05);${ok ? 'background:rgba(34,197,94,.08)' : ''}">
          <td style="padding:5px 6px">${ok ? '<span style="color:#22c55e;font-weight:700">✔</span>' : '<span style="color:#64748b">○</span>'}</td>
          <td style="padding:5px 6px;font-weight:600">${it.producto || ''}</td>
          <td style="padding:5px 6px">#${it.NroEstiba || it.EstibaID}</td>
          <td style="padding:5px 6px">${it.Cantidad}</td>
          <td style="padding:5px 6px">${esEP ? '<span style="font-size:.6rem;padding:1px 4px;border-radius:3px;background:rgba(251,146,60,.15);color:#fb923c;font-weight:700">PROV</span>' : '<span style="font-size:.6rem;opacity:.4">Estiba</span>'}</td>
        </tr>`;
      }).join('')}</tbody></table>`;
  }

  // ── Cargar estado ──
  async function cargarEstado() {
    try {
      const r = await fetch(`api_2026ia.php?action=salida_verificacion_estado&carga_numero=${cargaNumero}&presalida_id=${presalidaId}`, { credentials: 'same-origin' });
      const d = await r.json();
      if (d.error) throw new Error(d.error);
      if (d.sin_presalidas) {
        overlay.querySelector('#verifItems').innerHTML = '<div style="opacity:.5;text-align:center;padding:20px">No hay pre-salidas vinculadas a esta carga</div>';
        return;
      }
      estadoActual = d;
      actualizarProgreso(d.progreso);
      renderItems(d.items);
    } catch(e) { overlay.querySelector('#verifItems').innerHTML = `<div style="color:#f87171;padding:12px">Error: ${e.message}</div>`; }
  }

  // ── Procesar scan ──
  async function procesarScan(codigoQR) {
    const errEl = overlay.querySelector('#verifError');
    const okEl = overlay.querySelector('#verifOk');
    errEl.style.display = 'none'; okEl.style.display = 'none';
    try {
      const r = await fetch('api_2026ia.php?action=salida_verificacion_scan', {
        method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ carga_numero: cargaNumero, presalida_id: presalidaId, codigo_qr: codigoQR })
      });
      const d = await r.json();
      if (d.error) { errEl.textContent = d.error; errEl.style.display = 'block'; return; }
      okEl.textContent = '✔ ' + (d.mensaje || 'Verificado');
      okEl.style.display = 'block';
      if (d.progreso) actualizarProgreso(d.progreso);
      await cargarEstado();
    } catch(e) { errEl.textContent = 'Error de red: ' + e.message; errEl.style.display = 'block'; }
  }

  // ── Cámara (patrón de planificacion.js) ──
  async function abrirCam() {
    const errEl = overlay.querySelector('#verifError');
    errEl.style.display = 'none';
    const btnCam = overlay.querySelector('#verifBtnCam');
    btnCam.disabled = true; btnCam.textContent = '⏳ Iniciando...';
    try {
      scanStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: { ideal: 'environment' }, width: { ideal: 1280 } }
      });
      const video = overlay.querySelector('#verifVideo');
      const canvas = overlay.querySelector('#verifCanvas');
      video.srcObject = scanStream;
      await video.play();
      overlay.querySelector('#verifCamView').style.display = '';
      overlay.querySelector('#verifScanZona').querySelector('#verifBtnCam').style.display = 'none';

      if ('BarcodeDetector' in window) {
        const detector = new BarcodeDetector({ formats: ['qr_code'] });
        async function detectLoop() {
          if (!scanStream) return;
          try {
            const codes = await detector.detect(video);
            if (codes.length > 0) {
              const raw = codes[0].rawValue;
              cerrarCam();
              procesarScan(raw);
              return;
            }
          } catch(e) {}
          scanRafId = requestAnimationFrame(detectLoop);
        }
        scanRafId = requestAnimationFrame(detectLoop);
      } else {
        const ctx = canvas.getContext('2d');
        let decoder = null;
        for (const url of ['https://cdn.jsdelivr.net/npm/jsqr@1.4.0/dist/jsQR.min.js', 'https://unpkg.com/jsqr@1.4.0/dist/jsQR.js']) {
          try { await new Promise((ok, fail) => { const s = document.createElement('script'); s.src = url; s.onload = ok; s.onerror = fail; document.head.appendChild(s); }); if (window.jsQR) { decoder = window.jsQR; break; } } catch(e) {}
        }
        if (!decoder) { cerrarCam(); errEl.textContent = 'Tu navegador no soporta lectura de QR'; errEl.style.display = 'block'; return; }
        function scanLoop() {
          if (!scanStream) return;
          if (video.readyState === video.HAVE_ENOUGH_DATA) {
            canvas.width = video.videoWidth; canvas.height = video.videoHeight;
            ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
            const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
            const decoded = decoder(imgData.data, canvas.width, canvas.height);
            if (decoded?.data) { cerrarCam(); procesarScan(decoded.data); return; }
          }
          scanRafId = requestAnimationFrame(scanLoop);
        }
        scanRafId = requestAnimationFrame(scanLoop);
      }
    } catch(e) {
      cerrarCam();
      errEl.textContent = e.name === 'NotAllowedError' ? 'Permiso de cámara denegado' : 'No se pudo abrir la cámara: ' + e.message;
      errEl.style.display = 'block';
    }
  }

  function cerrarCam() {
    if (scanRafId) { cancelAnimationFrame(scanRafId); scanRafId = null; }
    if (scanStream) { scanStream.getTracks().forEach(t => t.stop()); scanStream = null; }
    const camView = overlay.querySelector('#verifCamView');
    if (camView) camView.style.display = 'none';
    const btnCam = overlay.querySelector('#verifBtnCam');
    if (btnCam) { btnCam.style.display = ''; btnCam.disabled = false; btnCam.textContent = '📷 Abrir cámara'; }
  }

  overlay.querySelector('#verifBtnCam').addEventListener('click', abrirCam);
  overlay.querySelector('#verifCerrarCam').addEventListener('click', cerrarCam);

  // ── Finalizar ──
  overlay.querySelector('#verifFinalizar').addEventListener('click', async () => {
    const prog = estadoActual.progreso;
    const force = prog.porcentaje < 100;
    if (force && !confirm(`Verificación incompleta: ${prog.verificados} de ${prog.total} items (${prog.porcentaje}%).\n\n¿Finalizar de todas formas?`)) return;
    try {
      const r = await fetch(API_EQUIPOS_URL + '?action=carga_finalizar_operacion', {
        method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ carga_numero: cargaNumero, force })
      });
      const d = await r.json();
      if (d.requiere_confirmacion && !force) {
        if (confirm(`${d.mensaje}\n\n¿Finalizar de todas formas?`)) {
          const r2 = await fetch(API_EQUIPOS_URL + '?action=carga_finalizar_operacion', {
            method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ carga_numero: cargaNumero, force: true })
          });
          const d2 = await r2.json();
          if (d2.error) throw new Error(d2.error);
          showToast('⏹ Operación finalizada', 'ok');
        } else return;
      } else if (d.error) throw new Error(d.error);
      else showToast('⏹ ' + (d.mensaje || 'Operación finalizada'), 'ok');
      close();
      if (typeof bxRefrescarDesdeExterno === 'function') bxRefrescarDesdeExterno();
      if (opts.onFinish) opts.onFinish();
    } catch(e) { showToast('Error: ' + e.message, 'error'); }
  });

  // ── Resetear ──
  overlay.querySelector('#verifReset').addEventListener('click', async () => {
    if (!confirm('¿Resetear todas las verificaciones? Se borrará el progreso de escaneo.')) return;
    try {
      await fetch('api_2026ia.php?action=salida_verificacion_reset', {
        method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ carga_numero: cargaNumero })
      });
      showToast('Verificación reseteada', 'ok');
      await cargarEstado();
    } catch(e) { showToast('Error: ' + e.message, 'error'); }
  });

  // Cargar estado inicial
  await cargarEstado();
}

/* ═══════════════════════════════════════════════════════════════
   DETALLE SALIDA (Pre-Salida / Salida)
   ═══════════════════════════════════════════════════════════════ */

async function renderSalidaDetalle(id) {
  setHeader('SALIDA #' + id);
  setExpandedMode(true); showMetaPanel(esMobile() ? false : true);
  menuGrid.className = ''; menuGrid.innerHTML = '<div class="ed-wrap"><div class="ge-loading">Cargando...</div></div>';
  syncBackBtn();

  let data;
  try {
    const r = await fetch(`api_2026ia.php?action=salida_ver&id=${id}`, {credentials:'same-origin'});
    data = await r.json(); if (data.error) throw new Error(data.error);
  } catch(e) { menuGrid.innerHTML = `<div class="ed-wrap"><div class="ge-empty">Error: ${e.message}</div></div>`; return; }

  const reg = data.registro, seleccionados = data.seleccionados||[];
  const esPre = !(parseInt(reg.clasificada));
  const esConfirmada = esPre && parseInt(reg.confirmada||0) === 1; // Pre-Salida Confirmada (bloqueada)
  const vehiculoLiberado = reg.tc_estado === 'R' || reg.tc_estado === 'Z';
  const esBorrador = esPre && !esConfirmada && !vehiculoLiberado; // Pre-Salida borrador (editable, no si vehículo liberado)
  const clienteId = reg.ClienteID;
  const grupoId = reg.GrupoID;

  // En mobile y pre-salida confirmada → redirigir a vista mobile
  if (esConfirmada && typeof esMobile === 'function' && esMobile()) {
    renderSalidaDetalleMobile(id, data);
    return;
  }

  const wrap = document.createElement('div'); wrap.className = 'ed-wrap';
  menuGrid.innerHTML = ''; menuGrid.appendChild(wrap);

  let html = `<div class="ed-header">
    <span class="ed-id">#${reg.PreSalidaID}</span>
    <span class="ed-cliente">${reg.cliente||''}</span>
    <span class="ed-badge ${vehiculoLiberado?'ed-badge-ok':esConfirmada?'ed-badge-warn':esBorrador?'ed-badge-pre':'ed-badge-ok'}">${vehiculoLiberado?'Vehículo Liberado':esConfirmada?'Pre-Salida Confirmada':esBorrador?'Pre-Salida':'Salida Confirmada'}</span>
    ${parseInt(reg.es_fiscal)?'<span class="ed-badge ed-badge-fiscal">Fiscal</span>':''}
  </div>`;

  html += `<div class="ed-section"><div class="ed-section-title">📋 Datos Generales</div>
    <div class="ed-info-grid">
      <div class="ed-info-item"><div class="ed-info-label">Remito</div><div class="ed-info-val">${reg.Remito||'—'}</div></div>
      <div class="ed-info-item"><div class="ed-info-label">Destino</div><div class="ed-info-val">${reg.destino||'—'}</div></div>
      <div class="ed-info-item"><div class="ed-info-label">Contrato</div><div class="ed-info-val">${reg.ContratoNro||'—'}</div></div>
      <div class="ed-info-item"><div class="ed-info-label">Referencia</div><div class="ed-info-val">${reg.numero_referencia||'—'}</div></div>
      ${reg.Observaciones?`<div class="ed-info-item" style="grid-column:span 2"><div class="ed-info-label">Observaciones</div><div class="ed-info-val">${reg.Observaciones}</div></div>`:''}
    </div>
  </div>`;

  // Productos seleccionados
  html += `<div class="ed-section"><div class="ed-section-title">📦 Productos Seleccionados <span class="ed-section-count">${seleccionados.length}</span></div>
    ${seleccionados.length ? `<div class="sd-table-scroll"><table class="ed-table"><thead><tr><th>Sub</th><th>Código</th><th>Producto</th><th>Estiba</th><th>Cantidad</th><th>Entrada</th><th>Etiqueta</th></tr></thead><tbody>
      ${seleccionados.map(s => {
        const esParcial = s.stock_disponible && parseInt(s.Cantidad) < parseInt(s.stock_disponible);
        const tieneEtiqueta = !!s.EtiquetaProvisoriaID;
        const etiqCol = tieneEtiqueta
          ? `<span style="font-size:.65rem;padding:2px 6px;border-radius:4px;background:rgba(251,146,60,.15);color:#fb923c;font-weight:700;cursor:pointer" class="ep-print-btn" data-ep-id="${s.EtiquetaProvisoriaID}" data-ep-qr="${s.etiqueta_qr||''}" data-ep-estiba="${s.NroEstiba||''}" data-ep-carga="${s.CargaID}" data-ep-producto="${(s.producto||'').replace(/"/g,'&quot;')}" data-ep-cantidad="${s.Cantidad}">${s.etiqueta_qr||'EP-'+s.EtiquetaProvisoriaID} 🖨</span>`
          : (esPre && esParcial
            ? `<button class="ed-btn" style="font-size:.6rem;padding:2px 6px;background:rgba(251,146,60,.12);color:#fb923c;border:1px solid rgba(251,146,60,.3)" data-gen-ep data-presalida="${reg.PreSalidaID}" data-estiba="${s.EstibaID}" data-carga="${s.CargaID}" data-producto="${s.ProductosID}" data-fechaev="${s.FechaEV}" data-cantidad="${s.Cantidad}">Generar</button>`
            : `<span style="opacity:.3;font-size:.6rem">${esPre ? 'Completa' : '—'}</span>`);
        return `<tr><td>${s.SubSalidaID}</td><td>${s.codigo||''}</td><td style="font-weight:600">${s.producto||''}</td><td>#${s.NroEstiba||s.EstibaID}</td><td>${s.Cantidad}</td><td>${s.CargaID}</td><td>${etiqCol}</td></tr>`;
      }).join('')}
    </tbody></table></div>` : '<div style="opacity:.4;text-align:center;padding:20px">Sin productos seleccionados</div>'}
  </div>`;

  // Stock disponible (solo para pre-salidas)
  // Stock disponible (solo para borrador, no confirmada)
  if (esBorrador) {
    html += `<div class="ed-section"><div class="ed-section-title">🏪 Stock Disponible</div>
      <div class="sd-filtros">
        <div class="sd-filtro sd-filtro-grow">
          <label class="sd-filtro-label">PRODUCTO</label>
          <select id="sdProducto" class="sd-filtro-input">
            <option value="">— Todos los productos —</option>
          </select>
        </div>
        <div class="sd-filtro">
          <label class="sd-filtro-label">ELABORACIÓN HASTA</label>
          <input type="date" id="sdFechaLimite" class="sd-filtro-input">
        </div>
        <div class="sd-filtro">
          <label class="sd-filtro-label">BUSCAR TEXTO</label>
          <input type="text" id="sdBusq" placeholder="Código, nombre..." class="sd-filtro-input">
        </div>
        <div class="sd-filtro" style="justify-content:flex-end">
          <button class="ed-btn ed-btn-blue" id="sdBuscar" style="padding:6px 16px;width:100%">🔍 Buscar</button>
        </div>
      </div>
      <div id="sdStockBody"><div style="opacity:.4;text-align:center;padding:20px">Seleccioná un producto o presioná Buscar</div></div>
      <div class="ed-action-bar" style="margin-top:10px">
        <button class="ed-btn ed-btn-primary" id="sdGuardarSeleccion" style="display:none">💾 Guardar Selección</button>
      </div>
    </div>`;
  }

  // ── Botones Iniciar / Finalizar / Liberar operación ──
  if (reg.carga_numero) {
    const tcEstado = reg.tc_estado;
    const tronera = reg.tronera;
    const hayBoton = (tcEstado === 'E' && tronera) || tcEstado === 'C' || tcEstado === 'F';
    const hayTiempos = reg.hora_movimiento_inicio || reg.hora_movimiento_fin;
    if (hayBoton || hayTiempos || tcEstado === 'R') {
      html += `<div class="ed-section" style="display:flex;flex-direction:column;gap:8px;align-items:stretch">
        <div class="ed-section-title">🚛 Operación de Transporte${tcEstado ? ` <span style="font-size:.68rem;opacity:.5">(${
          {P:'Planificado',E:'En Planta',D:'Demorado',C:'Cargando',F:'Finalizado',R:'Retirado'}[tcEstado]||tcEstado
        })</span>` : ''}</div>
        ${tcEstado === 'E' && tronera
          ? `<button class="ed-btn" style="padding:12px 20px;font-size:.88rem;background:rgba(74,222,128,.15);color:#4ade80;border:1px solid rgba(74,222,128,.3);width:100%" id="sdIniciarOp">▶ Iniciar Operación</button>`
          : tcEstado === 'C'
            ? `<button class="ed-btn" style="padding:12px 20px;font-size:.88rem;background:rgba(239,68,68,.12);color:#f87171;border:1px solid rgba(239,68,68,.3);width:100%" id="sdFinalizarOp">⏹ Finalizar Operación</button>`
            : tcEstado === 'F'
              ? `<button class="ed-btn" style="padding:12px 20px;font-size:.88rem;background:rgba(251,146,60,.15);color:#fb923c;border:1px solid rgba(251,146,60,.3);width:100%" id="sdLiberarVehiculo">🚛 Liberar Vehículo</button>`
              : tcEstado === 'R'
                ? `<span style="font-size:.78rem;color:#94a3b8;text-align:center">✔ Vehículo liberado</span>`
                : ''}
        ${reg.hora_movimiento_inicio ? `<span style="font-size:.72rem;color:#94a3b8">Inicio: ${reg.fecha_movimiento||''} ${reg.hora_movimiento_inicio}</span>` : ''}
        ${reg.hora_movimiento_fin ? `<span style="font-size:.72rem;color:#94a3b8">Fin: ${reg.fecha_movimiento||''} ${reg.hora_movimiento_fin}</span>` : ''}
      </div>`;
    }
  }

  // Acciones según estado
  if (esConfirmada) {
    // Pre-Salida Confirmada: imprimir etiquetas, no se puede editar stock
    html += `<div class="ed-action-bar" style="margin-top:8px;display:flex;gap:8px;flex-wrap:wrap">
      <button class="ed-btn" style="padding:10px 20px;font-size:.82rem;background:rgba(251,146,60,.12);color:#fb923c;border:1px solid rgba(251,146,60,.3)" id="sdImprimirTodas">🖨 Imprimir Todas las Etiquetas</button>
      <button class="ed-btn" style="padding:10px 20px;font-size:.82rem;background:rgba(99,179,237,.12);color:#63b3ed;border:1px solid rgba(99,179,237,.3)" id="sdAbrirVerificacion">📦 Verificar Carga</button>
    </div>`;
  } else if (esBorrador) {
    html += `<div class="ed-action-bar" style="margin-top:8px">
      <button class="ed-btn ed-btn-primary" style="padding:10px 24px;font-size:.88rem" id="sdConfirmarPre">✅ Confirmar Pre-Salida</button>
    </div>`;
  }

  wrap.innerHTML = html;

  // ── Handlers etiqueta provisoria ──
  wrap.querySelectorAll('[data-gen-ep]').forEach(btn => {
    btn.onclick = async () => {
      btn.disabled = true; btn.textContent = '...';
      try {
        const r = await fetch('api_2026ia.php?action=salida_generar_etiqueta_provisoria', {
          method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
          body: JSON.stringify({
            PreSalidaID: parseInt(btn.dataset.presalida),
            EstibaID: btn.dataset.estiba,
            CargaID: parseInt(btn.dataset.carga),
            ProductosID: parseInt(btn.dataset.producto),
            FechaEV: parseInt(btn.dataset.fechaev),
            Cantidad: parseInt(btn.dataset.cantidad)
          })
        });
        const d = await r.json();
        if (d.error) throw new Error(d.error);
        showToast('Etiqueta provisoria generada: ' + d.etiqueta.codigo_qr, 'ok');
        imprimirQREtiquetaProvisoria([d.etiqueta]);
        renderSalidaDetalle(id);
      } catch(e) { showToast('Error: '+e.message, 'error'); btn.disabled = false; btn.textContent = 'Generar'; }
    };
  });
  wrap.querySelectorAll('.ep-print-btn').forEach(btn => {
    btn.onclick = () => {
      imprimirQREtiquetaProvisoria([{
        EtiquetaProvisoriaID: btn.dataset.epId,
        codigo_qr: btn.dataset.epQr,
        NroEstiba: btn.dataset.epEstiba,
        CargaID: btn.dataset.epCarga,
        producto: btn.dataset.epProducto,
        Cantidad: btn.dataset.epCantidad,
        PreSalidaID: reg.PreSalidaID
      }]);
    };
  });

  // Cargar stock si es pre-salida
  if (esPre) {
    // Cargar catálogo de productos para el dropdown (filtrado por cliente o grupo)
    (async () => {
      try {
        const qs = new URLSearchParams();
        if (grupoId) qs.set('grupo_id', grupoId);
        else if (clienteId) qs.set('cliente_id', clienteId);
        const r = await fetch(`api_2026ia.php?action=salida_productos_catalogo&${qs}`, {credentials:'same-origin'});
        const d = await r.json();
        const sel = wrap.querySelector('#sdProducto');
        (d.productos||[]).forEach(p => {
          const opt = document.createElement('option');
          opt.value = p.ProductosID;
          opt.textContent = `${p.codigo||''} — ${p.producto} (${p.stock_total} bultos)`;
          sel.appendChild(opt);
        });
      } catch(e) {}
    })();

    // Prevenir propagación de teclas en inputs
    wrap.querySelectorAll('#sdBusq, #sdFechaLimite, #sdProducto').forEach(el => {
      el.onkeydown = e => e.stopPropagation();
    });

    let ultimoStock = [];
    const cargarStock = async () => {
      const stockBody = wrap.querySelector('#sdStockBody');
      stockBody.innerHTML = '<div class="ge-loading">Buscando stock...</div>';
      const qs = new URLSearchParams();
      // Filtrar por grupo (prioridad) o cliente
      if (grupoId) qs.set('grupo_id', grupoId);
      else if (clienteId) qs.set('cliente_id', clienteId);
      const productoSel = wrap.querySelector('#sdProducto')?.value;
      const fechaLim = wrap.querySelector('#sdFechaLimite')?.value;
      const busq = wrap.querySelector('#sdBusq')?.value;
      if (productoSel) qs.set('producto_id', productoSel);
      if (fechaLim) qs.set('fecha_limite', fechaLim);
      if (busq) qs.set('q', busq);
      qs.set('presalida_id', id); // para excluir esta pre-salida del cálculo de afectados
      try {
        const r = await fetch(`api_2026ia.php?action=salida_stock_cliente&${qs}`, {credentials:'same-origin'});
        const d = await r.json(); if (d.error) throw new Error(d.error);
        const stock = d.stock||[];
        ultimoStock = stock;
        if (!stock.length) { stockBody.innerHTML = '<div style="opacity:.4;text-align:center;padding:16px">Sin stock disponible con esos filtros</div>'; wrap.querySelector('#sdGuardarSeleccion').style.display='none'; return; }

        // Calcular totales por producto
        const totalBultos = stock.reduce((sum, s) => sum + parseInt(s.Cantidad||0), 0);

        stockBody.innerHTML = `
          <div style="font-size:.68rem;color:#94a3b8;margin-bottom:6px">${stock.length} registros · ${totalBultos} bultos totales</div>
          <div class="sd-table-scroll" style="max-height:400px;overflow-y:auto">
          <table class="ed-table" style="font-size:.72rem"><thead><tr>
            <th style="width:28px">Sel</th>
            <th>Producto</th>
            <th>Estiba</th>
            <th>Entrada</th>
            <th>Ubicación</th>
            <th>F.Elabor.</th>
            <th>F.Venc.</th>
            <th>Stock</th>
            <th title="Disponible real: stock menos lo afectado en otras pre-salidas pendientes">Disp. Real</th>
            <th style="width:70px">Agregar</th>
          </tr></thead><tbody>
          ${stock.map((s,i) => {
            const dispReal = s.disponible_real ?? s.Cantidad;
            const afectado = s.cantidad_afectada || 0;
            const sinDisp = dispReal <= 0;
            return `<tr style="${sinDisp ? 'opacity:.4' : ''}">
            <td><input type="checkbox" class="sd-chk" data-idx="${i}" ${sinDisp ? 'disabled' : ''}></td>
            <td style="font-weight:600;font-size:.7rem;max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${s.producto||''}">${s.producto||''}</td>
            <td style="font-weight:700;color:#38bdf8">#${s.NroEstiba||''}</td>
            <td style="opacity:.6">${s.CargaID}</td>
            <td style="font-size:.65rem;opacity:.7">${s.ubicacion||'—'}</td>
            <td style="font-size:.65rem">${s.FechaElaboracion||'—'}</td>
            <td style="font-size:.65rem">${s.FechaVencimiento||'—'}</td>
            <td style="font-weight:700">${s.Cantidad}</td>
            <td style="font-weight:700;${afectado > 0 ? 'color:#fb923c' : 'color:#4ade80'}">${dispReal}${afectado > 0 ? ` <span style="font-size:.6rem;opacity:.6">(-${afectado})</span>` : ''}</td>
            <td><input type="number" class="sd-qty-input" data-idx="${i}" min="0" max="${dispReal}" value="0" ${sinDisp ? 'disabled' : ''} style="width:60px;background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.15);border-radius:4px;padding:3px 5px;color:#fff;font-size:.72rem;text-align:center"></td>
          </tr>`; }).join('')}</tbody></table></div>`;
        wrap.querySelector('#sdGuardarSeleccion').style.display = 'inline-flex';

        // Guardar selección
        wrap.querySelector('#sdGuardarSeleccion').onclick = async () => {
          const items = [];
          stock.forEach((s,i) => {
            const chk = stockBody.querySelector(`.sd-chk[data-idx="${i}"]`);
            const qty = stockBody.querySelector(`.sd-qty-input[data-idx="${i}"]`);
            if (chk?.checked && +qty?.value > 0) {
              items.push({ CargaID:s.CargaID, ProductosID:s.ProductosID, FechaEV:s.FechaEV, EstibaID:s.EstibaID, Cantidad:+qty.value, SubSalidaID:1 });
            }
          });
          if (!items.length) { showToast('Seleccioná al menos un producto y definí la cantidad'); return; }
          try {
            const r = await fetch('api_2026ia.php?action=salida_seleccionar', { method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'}, body:JSON.stringify({PreSalidaID:id, items}) });
            const d = await r.json(); if (d.error) throw new Error(d.error);
            showToast('✅ Selección guardada'); renderSalidaDetalle(id);
          } catch(e) { showToast('Error: '+e.message, 'error'); }
        };

        // Al tildar checkbox, autocompletar cantidad con disponible
        stockBody.querySelectorAll('.sd-chk').forEach(chk => {
          chk.onchange = () => {
            const qty = stockBody.querySelector(`.sd-qty-input[data-idx="${chk.dataset.idx}"]`);
            if (chk.checked && +qty.value === 0) qty.value = stock[+chk.dataset.idx].Cantidad;
            if (!chk.checked) qty.value = 0;
          };
        });
        // Al cambiar cantidad > 0, auto-tildar
        stockBody.querySelectorAll('.sd-qty-input').forEach(inp => {
          inp.oninput = () => {
            const chk = stockBody.querySelector(`.sd-chk[data-idx="${inp.dataset.idx}"]`);
            if (+inp.value > 0 && chk) chk.checked = true;
            if (+inp.value === 0 && chk) chk.checked = false;
          };
        });
      } catch(e) { stockBody.innerHTML = `<div class="ge-empty">Error: ${e.message}</div>`; }
    };

    wrap.querySelector('#sdBuscar')?.addEventListener('click', cargarStock);
    wrap.querySelector('#sdBusq')?.addEventListener('keydown', e => { if(e.key==='Enter') cargarStock(); });
    wrap.querySelector('#sdProducto')?.addEventListener('change', cargarStock);
    wrap.querySelector('#sdFechaLimite')?.addEventListener('change', cargarStock);

    // Confirmar Pre-Salida (bloquea selección, genera etiquetas provisorias)
    wrap.querySelector('#sdConfirmarPre')?.addEventListener('click', async () => {
      if (!confirm('¿Confirmar esta pre-salida? Se bloquearán los productos seleccionados y se generarán etiquetas provisorias para las extracciones parciales.')) return;
      try {
        const r = await fetch('api_2026ia.php?action=salida_confirmar_presalida', { method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'}, body:JSON.stringify({PreSalidaID:id}) });
        const d = await r.json(); if (d.error) throw new Error(d.error);
        showToast('✅ ' + d.mensaje);
        // Imprimir etiquetas provisorias generadas automáticamente
        if (d.etiquetas && d.etiquetas.length > 0) {
          imprimirQREtiquetaProvisoria(d.etiquetas);
        }
        renderSalidaDetalle(id);
      } catch(e) { showToast('Error: '+e.message, 'error'); }
    });
  }

  // ── Handlers operación de transporte ──
  wrap.querySelector('#sdIniciarOp')?.addEventListener('click', async () => {
    const btn = wrap.querySelector('#sdIniciarOp');
    btn.disabled = true; btn.textContent = '⏳ Iniciando...';
    try {
      const res = await fetch(API_EQUIPOS_URL + '?action=carga_iniciar_operacion', {
        method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({ carga_numero: parseInt(reg.carga_numero) })
      }).then(r=>r.json()).catch(()=>({error:'Error de red'}));
      showToast(res.ok ? '▶ ' + (res.mensaje||'Operación iniciada') : (res.error||'Error'), res.ok?'ok':'error');
      if (res.ok) { renderSalidaDetalle(id); if (typeof bxRefrescarDesdeExterno === 'function') bxRefrescarDesdeExterno(); }
    } catch(err) { showToast('Error: '+err.message,'error'); btn.disabled = false; btn.textContent = '▶ Iniciar Operación'; }
  });
  wrap.querySelector('#sdFinalizarOp')?.addEventListener('click', async () => {
    const btn = wrap.querySelector('#sdFinalizarOp');
    btn.disabled = true; btn.textContent = '⏳ Finalizando...';
    try {
      const res = await fetch(API_EQUIPOS_URL + '?action=carga_finalizar_operacion', {
        method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({ carga_numero: parseInt(reg.carga_numero) })
      }).then(r=>r.json()).catch(()=>({error:'Error de red'}));
      showToast(res.ok ? '⏹ ' + (res.mensaje||'Operación finalizada') : (res.error||'Error'), res.ok?'ok':'error');
      if (res.ok) { renderSalidaDetalle(id); if (typeof bxRefrescarDesdeExterno === 'function') bxRefrescarDesdeExterno(); }
    } catch(err) { showToast('Error: '+err.message,'error'); btn.disabled = false; btn.textContent = '⏹ Finalizar Operación'; }
  });
  wrap.querySelector('#sdLiberarVehiculo')?.addEventListener('click', async () => {
    const btn = wrap.querySelector('#sdLiberarVehiculo');
    btn.disabled = true; btn.textContent = '⏳ Liberando...';
    try {
      const res = await fetch(API_EQUIPOS_URL + '?action=carga_liberar_vehiculo', {
        method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({ carga_numero: parseInt(reg.carga_numero) })
      }).then(r=>r.json()).catch(()=>({error:'Error de red'}));
      showToast(res.ok ? '🚛 ' + (res.mensaje||'Vehículo liberado') : (res.error||'Error'), res.ok?'ok':'error');
      if (res.ok) { renderSalidaDetalle(id); if (typeof bxRefrescarDesdeExterno === 'function') bxRefrescarDesdeExterno(); }
    } catch(err) { showToast('Error: '+err.message,'error'); btn.disabled = false; btn.textContent = '🚛 Liberar Vehículo'; }
  });

  // ── Handlers para Pre-Salida Confirmada ──
  // Imprimir todas las etiquetas (provisorias + estibas completas)
  wrap.querySelector('#sdImprimirTodas')?.addEventListener('click', () => {
    const provisorias = seleccionados.filter(s => s.EtiquetaProvisoriaID);
    const completas = seleccionados.filter(s => !s.EtiquetaProvisoriaID);
    if (provisorias.length) {
      imprimirQREtiquetaProvisoria(provisorias.map(s => ({
        EtiquetaProvisoriaID: s.EtiquetaProvisoriaID,
        codigo_qr: s.etiqueta_qr || 'EP-'+s.EtiquetaProvisoriaID,
        NroEstiba: s.NroEstiba, CargaID: s.CargaID,
        producto: s.producto, Cantidad: s.Cantidad,
        PreSalidaID: reg.PreSalidaID
      })));
    }
    if (completas.length) {
      imprimirQREstibas(completas.map(s => ({ EstibaID: s.EstibaID, NroEstiba: s.NroEstiba })), completas[0]?.CargaID || '');
    }
    if (!provisorias.length && !completas.length) showToast('No hay etiquetas para imprimir');
  });

  // Abrir verificación desde desktop
  wrap.querySelector('#sdAbrirVerificacion')?.addEventListener('click', () => {
    abrirVerificacionCarga(reg.carga_numero || 0, {
      presalidaId: id,
      onFinish: () => renderSalidaDetalle(id)
    });
  });
}

/* ═══════════════════════════════════════════════════════════════
   DETALLE SALIDA MOBILE — Vista para operarios
   ═══════════════════════════════════════════════════════════════ */

async function renderSalidaDetalleMobile(id, data) {
  setHeader('SALIDA #' + id);
  setExpandedMode(true); showMetaPanel(false);
  syncBackBtn();

  const reg = data.registro, seleccionados = data.seleccionados || [];
  const wrap = document.createElement('div');
  wrap.className = 'ed-wrap';
  wrap.style.cssText = 'padding:8px;max-width:100%';
  menuGrid.className = ''; menuGrid.innerHTML = '';
  menuGrid.appendChild(wrap);

  // Estado de verificación
  let verificacion = { items: [], progreso: { total: 0, verificados: 0, porcentaje: 0 } };

  // Cargar estado de verificación
  async function cargarVerificacion() {
    try {
      const r = await fetch(`api_2026ia.php?action=salida_verificacion_estado&presalida_id=${id}`, { credentials: 'same-origin' });
      const d = await r.json();
      if (d.ok) verificacion = d;
    } catch(e) {}
  }

  await cargarVerificacion();

  // Crear mapa de items verificados
  const scanMap = {};
  verificacion.items.forEach(it => {
    const key = it.EtiquetaProvisoriaID ? 'ep-'+it.EtiquetaProvisoriaID : it.EstibaID+'-'+it.ProductosID+'-'+it.FechaEV;
    scanMap[key] = it.verificado;
  });

  function renderMobile() {
    const prog = verificacion.progreso;
    const pct = prog.porcentaje || 0;
    const pctColor = pct >= 100 ? '#22c55e' : pct >= 50 ? '#fb923c' : '#f87171';

    let html = `
    <div style="padding:10px 12px;background:rgba(255,255,255,.04);border-radius:10px;margin-bottom:10px">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
        <span style="font-size:.95rem;font-weight:800;color:#fff">#${reg.PreSalidaID}</span>
        <span style="font-size:.7rem;padding:3px 8px;border-radius:5px;background:rgba(251,146,60,.15);color:#fb923c;font-weight:700">Pre-Salida Confirmada</span>
      </div>
      <div style="font-size:.75rem;color:#94a3b8">${reg.cliente||''}</div>
      <div style="font-size:.68rem;color:#64748b;margin-top:2px">Remito: ${reg.Remito||'—'} · Destino: ${reg.destino||'—'}</div>
    </div>

    <!-- Barra de progreso -->
    <div style="padding:8px 12px;background:rgba(255,255,255,.04);border-radius:8px;margin-bottom:10px">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
        <span style="font-size:.7rem;font-weight:700;color:rgba(255,255,255,.6)">Progreso de carga</span>
        <span style="font-size:.85rem;font-weight:900;color:${pctColor}">${pct}%</span>
      </div>
      <div style="height:6px;background:rgba(255,255,255,.08);border-radius:3px;overflow:hidden">
        <div style="height:100%;width:${pct}%;background:${pctColor};border-radius:3px;transition:width .4s"></div>
      </div>
      <div style="font-size:.6rem;color:#94a3b8;margin-top:2px">${prog.verificados}/${prog.total} items verificados</div>
    </div>

    <!-- Lista de items -->
    <div style="margin-bottom:10px">
      <div style="font-size:.72rem;font-weight:700;color:rgba(255,255,255,.7);margin-bottom:6px;padding:0 4px">📦 Items de la carga</div>
      ${seleccionados.map((s, i) => {
        const key = s.EtiquetaProvisoriaID ? 'ep-'+s.EtiquetaProvisoriaID : s.EstibaID+'-'+s.ProductosID+'-'+s.FechaEV;
        const vItem = verificacion.items.find(v =>
          (s.EtiquetaProvisoriaID && v.EtiquetaProvisoriaID == s.EtiquetaProvisoriaID) ||
          (!s.EtiquetaProvisoriaID && v.EstibaID == s.EstibaID && v.ProductosID == s.ProductosID && v.FechaEV == s.FechaEV)
        );
        const verificado = vItem?.verificado || false;
        const esEP = !!s.EtiquetaProvisoriaID;
        return `<div class="mob-sal-item" data-idx="${i}" style="padding:10px;margin-bottom:6px;border-radius:8px;border:1px solid ${verificado ? 'rgba(34,197,94,.3)' : 'rgba(255,255,255,.08)'};background:${verificado ? 'rgba(34,197,94,.06)' : 'rgba(255,255,255,.03)'};cursor:pointer">
          <div style="display:flex;justify-content:space-between;align-items:center">
            <div style="flex:1;min-width:0">
              <div style="font-size:.78rem;font-weight:700;color:#fff;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${s.producto||''}</div>
              <div style="font-size:.65rem;color:#94a3b8;margin-top:2px">
                Estiba #${s.NroEstiba||s.EstibaID} · ${s.Cantidad} bultos
                ${esEP ? '<span style="color:#fb923c;font-weight:700"> · PROVISORIA</span>' : ''}
              </div>
            </div>
            <div style="text-align:right;margin-left:8px">
              ${verificado ? '<span style="font-size:1.1rem">✅</span>' : '<span style="font-size:1.1rem;opacity:.2">○</span>'}
            </div>
          </div>
          <div style="display:flex;gap:6px;margin-top:6px">
            <button class="mob-sal-reemplazar" data-idx="${i}" style="flex:1;padding:4px;font-size:.6rem;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.12);border-radius:5px;color:#94a3b8;cursor:pointer" onclick="event.stopPropagation()">🔄 Modificar Estiba</button>
            ${esEP ? `<button class="mob-sal-imprimir" data-idx="${i}" style="flex:1;padding:4px;font-size:.6rem;background:rgba(251,146,60,.1);border:1px solid rgba(251,146,60,.2);border-radius:5px;color:#fb923c;cursor:pointer" onclick="event.stopPropagation()">🖨 Imprimir</button>` : ''}
          </div>
        </div>`;
      }).join('')}
    </div>

    <!-- Operación de transporte -->
    ${reg.carga_numero ? (() => {
      const _tc = reg.tc_estado, _tr = reg.tronera;
      if (_tc === 'E' && _tr) return `<div style="padding:0 4px;margin-bottom:8px"><button id="mobSalIniciarOp" style="width:100%;padding:12px;font-size:.88rem;font-weight:800;background:rgba(74,222,128,.15);color:#4ade80;border:1px solid rgba(74,222,128,.3);border-radius:10px;cursor:pointer">▶ Iniciar Operación</button></div>`;
      if (_tc === 'C') return `<div style="padding:0 4px;margin-bottom:8px"><button id="mobSalFinalizarOp" style="width:100%;padding:12px;font-size:.88rem;font-weight:800;background:rgba(239,68,68,.12);color:#f87171;border:1px solid rgba(239,68,68,.3);border-radius:10px;cursor:pointer">⏹ Finalizar Operación</button></div>`;
      if (_tc === 'F') return `<div style="padding:0 4px;margin-bottom:8px"><button id="mobSalLiberarVeh" style="width:100%;padding:12px;font-size:.88rem;font-weight:800;background:rgba(251,146,60,.15);color:#fb923c;border:1px solid rgba(251,146,60,.3);border-radius:10px;cursor:pointer">🚛 Liberar Vehículo</button></div>`;
      if (_tc === 'R') return `<div style="padding:0 4px;margin-bottom:8px;text-align:center"><span style="font-size:.78rem;color:#94a3b8">✔ Vehículo liberado</span></div>`;
      return '';
    })() : ''}
    ${reg.hora_movimiento_inicio || reg.hora_movimiento_fin ? `<div style="padding:0 8px;margin-bottom:8px;font-size:.68rem;color:#94a3b8;display:flex;gap:12px">${reg.hora_movimiento_inicio?`<span>Inicio: ${reg.hora_movimiento_inicio}</span>`:''}${reg.hora_movimiento_fin?`<span>Fin: ${reg.hora_movimiento_fin}</span>`:''}</div>` : ''}

    <!-- Botones de acción -->
    <div style="display:flex;flex-direction:column;gap:8px;padding:0 4px">
      <button id="mobInformarCarga" style="width:100%;padding:12px;font-size:.88rem;font-weight:800;background:rgba(99,179,237,.15);color:#63b3ed;border:1px solid rgba(99,179,237,.3);border-radius:10px;cursor:pointer">📦 Informar Carga (Escanear)</button>
      ${pct >= 100 ? `<button id="mobConfirmarSalida" style="width:100%;padding:12px;font-size:.88rem;font-weight:800;background:rgba(34,197,94,.15);color:#22c55e;border:1px solid rgba(34,197,94,.3);border-radius:10px;cursor:pointer">✅ Confirmar Salida</button>` : ''}
      <button id="mobCancelarScans" style="width:100%;padding:8px;font-size:.72rem;font-weight:600;background:rgba(239,68,68,.08);color:#f87171;border:1px solid rgba(239,68,68,.15);border-radius:8px;cursor:pointer">✕ Cancelar verificación</button>
    </div>`;

    wrap.innerHTML = html;

    // ── Handlers ──

    // Imprimir etiqueta individual
    wrap.querySelectorAll('.mob-sal-imprimir').forEach(btn => {
      btn.onclick = (e) => {
        e.stopPropagation();
        const s = seleccionados[+btn.dataset.idx];
        if (s.EtiquetaProvisoriaID) {
          imprimirQREtiquetaProvisoria([{
            EtiquetaProvisoriaID: s.EtiquetaProvisoriaID,
            codigo_qr: s.etiqueta_qr || 'EP-'+s.EtiquetaProvisoriaID,
            NroEstiba: s.NroEstiba, CargaID: s.CargaID,
            producto: s.producto, Cantidad: s.Cantidad,
            PreSalidaID: reg.PreSalidaID
          }]);
        }
      };
    });

    // Modificar estiba
    wrap.querySelectorAll('.mob-sal-reemplazar').forEach(btn => {
      btn.onclick = async (e) => {
        e.stopPropagation();
        const s = seleccionados[+btn.dataset.idx];
        openReemplazarEstiba(id, s, () => renderSalidaDetalle(id));
      };
    });

    // Informar Carga (abre scanner)
    wrap.querySelector('#mobInformarCarga')?.addEventListener('click', () => {
      abrirVerificacionCarga(reg.carga_numero || 0, {
        presalidaId: id,
        onFinish: async () => {
          await cargarVerificacion();
          renderMobile();
        }
      });
    });

    // Confirmar Salida (descuenta stock)
    wrap.querySelector('#mobConfirmarSalida')?.addEventListener('click', async () => {
      if (!confirm('¿Confirmar esta salida? El stock será descontado permanentemente.')) return;
      try {
        const r = await fetch('api_2026ia.php?action=salida_confirmar', {
          method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ PreSalidaID: id })
        });
        const d = await r.json();
        if (d.error) throw new Error(d.error);
        showToast('✅ ' + d.mensaje);
        renderSalidaDetalle(id);
      } catch(e) { showToast('Error: '+e.message, 'error'); }
    });

    // Operación de transporte (mobile)
    wrap.querySelector('#mobSalIniciarOp')?.addEventListener('click', async () => {
      const btn = wrap.querySelector('#mobSalIniciarOp');
      btn.disabled = true; btn.textContent = '⏳ Iniciando...';
      try {
        const res = await fetch(API_EQUIPOS_URL + '?action=carga_iniciar_operacion', {
          method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
          body: JSON.stringify({ carga_numero: parseInt(reg.carga_numero) })
        }).then(r=>r.json()).catch(()=>({error:'Error de red'}));
        showToast(res.ok ? '▶ ' + (res.mensaje||'Operación iniciada') : (res.error||'Error'), res.ok?'ok':'error');
        if (res.ok) renderSalidaDetalle(id);
      } catch(err) { showToast('Error: '+err.message,'error'); btn.disabled = false; btn.textContent = '▶ Iniciar Operación'; }
    });
    wrap.querySelector('#mobSalFinalizarOp')?.addEventListener('click', async () => {
      const btn = wrap.querySelector('#mobSalFinalizarOp');
      btn.disabled = true; btn.textContent = '⏳ Finalizando...';
      try {
        const res = await fetch(API_EQUIPOS_URL + '?action=carga_finalizar_operacion', {
          method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
          body: JSON.stringify({ carga_numero: parseInt(reg.carga_numero) })
        }).then(r=>r.json()).catch(()=>({error:'Error de red'}));
        showToast(res.ok ? '⏹ ' + (res.mensaje||'Operación finalizada') : (res.error||'Error'), res.ok?'ok':'error');
        if (res.ok) renderSalidaDetalle(id);
      } catch(err) { showToast('Error: '+err.message,'error'); btn.disabled = false; btn.textContent = '⏹ Finalizar Operación'; }
    });
    wrap.querySelector('#mobSalLiberarVeh')?.addEventListener('click', async () => {
      const btn = wrap.querySelector('#mobSalLiberarVeh');
      btn.disabled = true; btn.textContent = '⏳ Liberando...';
      try {
        const res = await fetch(API_EQUIPOS_URL + '?action=carga_liberar_vehiculo', {
          method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
          body: JSON.stringify({ carga_numero: parseInt(reg.carga_numero) })
        }).then(r=>r.json()).catch(()=>({error:'Error de red'}));
        showToast(res.ok ? '🚛 ' + (res.mensaje||'Vehículo liberado') : (res.error||'Error'), res.ok?'ok':'error');
        if (res.ok) renderSalidaDetalle(id);
      } catch(err) { showToast('Error: '+err.message,'error'); btn.disabled = false; btn.textContent = '🚛 Liberar Vehículo'; }
    });

    // Cancelar verificación
    wrap.querySelector('#mobCancelarScans')?.addEventListener('click', async () => {
      if (!confirm('¿Cancelar la verificación? Se borrarán todos los escaneos realizados.')) return;
      try {
        await fetch('api_2026ia.php?action=salida_verificacion_reset', {
          method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ carga_numero: reg.carga_numero || 0 })
        });
        showToast('Verificación cancelada');
        await cargarVerificacion();
        renderMobile();
      } catch(e) { showToast('Error: '+e.message, 'error'); }
    });
  }

  renderMobile();
}

// Modal para reemplazar estiba
async function openReemplazarEstiba(presalidaId, item, onSuccess) {
  document.getElementById('calidadModalOverlay')?.remove();
  const overlay = document.createElement('div');
  overlay.id = 'calidadModalOverlay'; overlay.className = 'calidad-modal-overlay';
  document.body.appendChild(overlay);
  requestAnimationFrame(() => overlay.classList.add('calidad-modal-visible'));

  overlay.innerHTML = `<div class="calidad-modal" style="width:min(520px,95vw)">
    <div class="calidad-modal-header">🔄 Reemplazar Estiba <button class="chk-close" id="reClose">✕</button></div>
    <div class="calidad-modal-body">
      <div style="padding:8px;background:rgba(255,255,255,.04);border-radius:6px;margin-bottom:10px;font-size:.75rem">
        <div><strong>Producto:</strong> ${item.producto||''}</div>
        <div><strong>Estiba actual:</strong> #${item.NroEstiba||item.EstibaID} · ${item.Cantidad} bultos</div>
      </div>
      <div style="font-size:.7rem;font-weight:700;color:rgba(255,255,255,.6);margin-bottom:6px">Estibas disponibles del mismo producto:</div>
      <div id="reEstibas"><div class="ge-loading">Cargando...</div></div>
    </div>
    <div class="calidad-modal-footer">
      <button class="calidad-modal-btn calidad-modal-btn-cancel" id="reCancel">Cancelar</button>
      <button class="calidad-modal-btn calidad-modal-btn-save" id="reSave" disabled>💾 Confirmar Reemplazo</button>
    </div>
  </div>`;

  const close = () => { overlay.classList.remove('calidad-modal-visible'); setTimeout(() => overlay.remove(), 200); };
  overlay.querySelector('#reClose').onclick = close;
  overlay.querySelector('#reCancel').onclick = close;
  overlay.addEventListener('click', e => { if (e.target === overlay) close(); });

  // Cargar estibas alternativas
  try {
    const r = await fetch(`api_2026ia.php?action=salida_estibas_alternativas&producto_id=${item.ProductosID}&estiba_excluir=${item.EstibaID}`, { credentials: 'same-origin' });
    const d = await r.json();
    if (d.error) throw new Error(d.error);
    const estibas = d.estibas || [];
    const cantidadNecesaria = parseInt(item.Cantidad);
    const elEstibas = overlay.querySelector('#reEstibas');

    if (!estibas.length) {
      elEstibas.innerHTML = '<div style="opacity:.4;text-align:center;padding:16px">No hay estibas alternativas disponibles</div>';
      return;
    }

    elEstibas.innerHTML = `<div style="max-height:250px;overflow-y:auto">
      ${estibas.map((e, i) => `<div style="display:flex;align-items:center;gap:8px;padding:6px;border-bottom:1px solid rgba(255,255,255,.05);font-size:.72rem">
        <input type="checkbox" class="re-chk" data-idx="${i}">
        <div style="flex:1">
          <span style="font-weight:700;color:#38bdf8">#${e.NroEstiba}</span>
          <span style="opacity:.6;margin-left:4px">${e.ubicacion||''}</span>
          <span style="opacity:.5;margin-left:4px">Disp: ${e.Cantidad}</span>
        </div>
        <input type="number" class="re-qty" data-idx="${i}" min="0" max="${e.Cantidad}" value="0"
          style="width:55px;background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.12);border-radius:4px;padding:3px;color:#fff;font-size:.72rem;text-align:center">
      </div>`).join('')}
    </div>
    <div id="reSuma" style="font-size:.7rem;color:#94a3b8;margin-top:6px;text-align:right">Necesario: ${cantidadNecesaria} bultos · Seleccionado: 0</div>`;

    const actualizarSuma = () => {
      let suma = 0;
      elEstibas.querySelectorAll('.re-qty').forEach(q => { suma += parseInt(q.value) || 0; });
      elEstibas.querySelector('#reSuma').innerHTML = `Necesario: <strong>${cantidadNecesaria}</strong> bultos · Seleccionado: <strong style="color:${suma === cantidadNecesaria ? '#22c55e' : '#f87171'}">${suma}</strong>`;
      overlay.querySelector('#reSave').disabled = (suma !== cantidadNecesaria);
    };

    elEstibas.querySelectorAll('.re-chk').forEach(chk => {
      chk.onchange = () => {
        const qty = elEstibas.querySelector(`.re-qty[data-idx="${chk.dataset.idx}"]`);
        if (chk.checked && +qty.value === 0) qty.value = Math.min(parseInt(estibas[+chk.dataset.idx].Cantidad), cantidadNecesaria);
        if (!chk.checked) qty.value = 0;
        actualizarSuma();
      };
    });
    elEstibas.querySelectorAll('.re-qty').forEach(q => { q.oninput = actualizarSuma; });

    overlay.querySelector('#reSave').onclick = async () => {
      const itemsNuevos = [];
      elEstibas.querySelectorAll('.re-chk').forEach((chk, i) => {
        const qty = parseInt(elEstibas.querySelector(`.re-qty[data-idx="${i}"]`).value) || 0;
        if (chk.checked && qty > 0) {
          itemsNuevos.push({ EstibaID: estibas[i].EstibaID, Cantidad: qty });
        }
      });
      try {
        const r = await fetch('api_2026ia.php?action=salida_reemplazar_estiba', {
          method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            PreSalidaID: presalidaId, EstibaID_original: item.EstibaID,
            ProductosID: item.ProductosID, FechaEV: item.FechaEV, CargaID: item.CargaID,
            items_nuevos: itemsNuevos
          })
        });
        const d = await r.json();
        if (d.error) throw new Error(d.error);
        showToast('✅ Estiba reemplazada');
        close();
        if (onSuccess) onSuccess();
      } catch(e) { showToast('Error: '+e.message, 'error'); }
    };
  } catch(e) {
    overlay.querySelector('#reEstibas').innerHTML = `<div style="color:#f87171;padding:10px">Error: ${e.message}</div>`;
  }
}

/* ═══════════════════════════════════════════════════════════════
   MÓDULO TRANSPORTE: CRUD Aseguradoras, Empresas, Conductores,
   Vehículos, Acoplados
   ═══════════════════════════════════════════════════════════════ */

const _transpLabels = {
  aseguradoras: { titulo:'ASEGURADORAS', columnas:['nombre','cuit','domicilio','localidad','telefono','email'],
    form:['nombre','cuit','domicilio','localidad','telefono','email'] },
  empresas: { titulo:'EMPRESAS DE TRANSPORTE', columnas:['nombre','cuit','domicilio','localidad','telefono','email'],
    form:['razon_social','cuit','domicilio','localidad','codigo_postal','telefono','email'] },
  conductores: { titulo:'CONDUCTORES', columnas:['nombre','documento','celular','carnet','carnet_vencimiento'],
    form:['apellido','nombre','documento_numero','fecha_nacimiento','carnet_conducir','carnet_vencimiento','numero_celular'] },
  vehiculos: { titulo:'VEHÍCULOS', columnas:['patente','habilitacion_senasa','habilitacion_vencimiento','vtv_vencimiento','aseguradora_vencimiento'],
    form:['patente','patente_vencimiento','vtv_vencimiento','ruta_vencimiento','habilitacion_senasa','habilitacion_clase','habilitacion_vencimiento'] },
  acoplados: { titulo:'ACOPLADOS', columnas:['patente','habilitacion_senasa','habilitacion_vencimiento','vtv_vencimiento','aseguradora_vencimiento'],
    form:['patente','patente_vencimiento','vtv_vencimiento','ruta_vencimiento','habilitacion_senasa','habilitacion_clase','habilitacion_vencimiento'] },
};

async function renderTransporteEntidad(entidad) {
  const cfg = _transpLabels[entidad];
  setHeader(cfg.titulo);
  setExpandedMode(false);
  showMetaPanel(true);
  menuGrid.className = '';
  menuGrid.innerHTML = '';
  syncBackBtn();

  const wrap = document.createElement('div');
  wrap.className = 'logmod-wrap';
  menuGrid.appendChild(wrap);

  let filtros = { q:'', activos:1 };

  const render = async () => {
    const qs = new URLSearchParams({ action:'transporte_lista', entidad, activos:filtros.activos, q:filtros.q });
    wrap.innerHTML = '<div class="ge-loading" style="padding:40px;text-align:center">Cargando...</div>';
    let data;
    try {
      const r = await fetch(`api_2026ia.php?${qs}`, { credentials:'same-origin' });
      data = await r.json();
      if (data.error) throw new Error(data.error);
    } catch(e) { wrap.innerHTML = `<div class="ge-empty">Error: ${e.message}</div>`; return; }

    const rows = data.registros || [];
    const cols = cfg.columnas;
    const trHtml = rows.map(r => `
      <tr class="logmod-row" style="cursor:pointer" data-id="${r.id}">
        ${cols.map(c => `<td class="logmod-text-sm">${r[c]??''}</td>`).join('')}
        <td style="text-align:center">
          <span class="logmod-cal-chip ${r.activo?'completo':'pendiente'}">${r.activo?'Activo':'Inactivo'}</span>
        </td>
      </tr>`).join('');

    wrap.innerHTML = `
      <div class="logmod-toolbar">
        <div class="logmod-filter-group">
          <span class="logmod-filter-label">Buscar</span>
          <div class="logmod-search-row">
            <input type="text" class="logmod-input-search" id="trBusq" value="${filtros.q}" placeholder="Nombre, patente, CUIT...">
            <button class="logmod-search-btn" id="trBuscarBtn">🔍</button>
          </div>
        </div>
        <div class="logmod-filter-group">
          <label style="display:flex;align-items:center;gap:6px;font-size:.75rem;color:rgba(255,255,255,.5);cursor:pointer">
            <input type="checkbox" id="trActivos" ${filtros.activos?'checked':''}>Solo activos
          </label>
        </div>
        <div class="logmod-filter-group" style="margin-left:auto">
          <button class="logmod-search-btn calidad-modal-btn-save" id="trNuevo">＋ Nuevo</button>
        </div>
      </div>
      <div class="logmod-table-wrap">
        <table class="logmod-table">
          <thead><tr>
            ${cols.map(c => `<th>${c.replace(/_/g,' ').toUpperCase()}</th>`).join('')}
            <th style="width:80px;text-align:center">Estado</th>
          </tr></thead>
          <tbody>${rows.length ? trHtml : '<tr><td colspan="'+(cols.length+1)+'" class="logmod-empty">Sin registros</td></tr>'}</tbody>
        </table>
      </div>
      <div class="logmod-footer">${rows.length} registro${rows.length!==1?'s':''}</div>`;

    const busqI = wrap.querySelector('#trBusq');
    busqI.onkeydown = e => { e.stopPropagation(); if(e.key==='Enter'){ filtros.q=busqI.value; render(); } };
    wrap.querySelector('#trBuscarBtn').onclick = () => { filtros.q=busqI.value; render(); };
    wrap.querySelector('#trActivos').onchange = e => { filtros.activos = e.target.checked?1:0; render(); };
    wrap.querySelector('#trNuevo').onclick = () => openTransporteForm(entidad, 0, render);

    wrap.querySelectorAll('[data-id]').forEach(tr => {
      tr.onclick = () => openTransporteForm(entidad, +tr.dataset.id, render);
    });
  };
  render();
}

async function openTransporteForm(entidad, id, onSave) {
  const cfg = _transpLabels[entidad];
  document.getElementById('calidadModalOverlay')?.remove();

  let registro = {};
  if (id > 0) {
    try {
      const r = await fetch(`api_2026ia.php?action=transporte_ver&entidad=${entidad}&id=${id}`, { credentials:'same-origin' });
      const d = await r.json();
      if (d.error) throw new Error(d.error);
      registro = d.registro;
    } catch(e) { showToast('Error: '+e.message); return; }
  }

  const overlay = document.createElement('div');
  overlay.id = 'calidadModalOverlay';
  overlay.className = 'calidad-modal-overlay';
  document.body.appendChild(overlay);
  requestAnimationFrame(() => overlay.classList.add('calidad-modal-visible'));

  const fields = cfg.form;
  const fieldsHtml = fields.map(f => {
    const isDate = f.includes('vencimiento') || f.includes('nacimiento');
    const val = registro[f] ?? '';
    return `<div class="calidad-modal-field">
      <label>${f.replace(/_/g,' ').toUpperCase()}</label>
      <input type="${isDate?'date':'text'}" name="${f}" value="${val}" />
    </div>`;
  }).join('');

  overlay.innerHTML = `<div class="calidad-modal" style="max-height:90vh;overflow-y:auto">
    <div class="calidad-modal-header">${id?'✏️ Editar':'＋ Nuevo'} ${cfg.titulo.slice(0,-1)} <button class="chk-close" id="trClose">✕</button></div>
    <div class="calidad-modal-body">${fieldsHtml}
      <div class="calidad-modal-field">
        <label>ACTIVO</label>
        <select name="activo"><option value="1" ${(registro.activo??1)==1?'selected':''}>Sí</option><option value="0" ${registro.activo==0?'selected':''}>No</option></select>
      </div>
    </div>
    <div class="calidad-modal-footer">
      <button class="calidad-modal-btn calidad-modal-btn-cancel" id="trCancelar">Cancelar</button>
      <button class="calidad-modal-btn calidad-modal-btn-save" id="trGuardar">💾 Guardar</button>
    </div>
  </div>`;

  const close = () => { overlay.classList.remove('calidad-modal-visible'); setTimeout(()=>overlay.remove(),200); };
  overlay.querySelector('#trClose').onclick = close;
  overlay.querySelector('#trCancelar').onclick = close;
  overlay.addEventListener('click', e => { if(e.target===overlay) close(); });
  overlay.querySelectorAll('input,select').forEach(el => { el.onkeydown = e => e.stopPropagation(); });

  overlay.querySelector('#trGuardar').onclick = async () => {
    const campos = {};
    overlay.querySelectorAll('[name]').forEach(el => { campos[el.name] = el.value; });
    campos.activo = parseInt(campos.activo);
    try {
      const r = await fetch('api_2026ia.php?action=transporte_guardar', {
        method:'POST', credentials:'same-origin',
        headers:{'Content-Type':'application/json'},
        body: JSON.stringify({ entidad, id, campos })
      });
      const d = await r.json();
      if (d.error) throw new Error(d.error);
      showToast('💾 Guardado correctamente');
      close();
      if (onSave) onSave();
    } catch(e) { showToast('Error: '+e.message, 'error'); }
  };
}

