async function renderReporteStock() {
  setHeader('REPORTE DE STOCK');
  setExpandedMode(false);
  showMetaPanel(true);
  menuGrid.className = '';
  menuGrid.innerHTML = '';
  syncBackBtn();

  const wrap = document.createElement('div');
  wrap.className = 'logmod-wrap';
  menuGrid.appendChild(wrap);

  let detalleClienteId = null;

  const renderResumen = async () => {
    wrap.innerHTML = '<div class="ge-loading" style="padding:40px;text-align:center">Cargando stock...</div>';
    let data;
    try {
      const r = await fetch('api_2026ia.php?action=reporte_stock', { credentials:'same-origin' });
      data = await r.json();
      if (data.error) throw new Error(data.error);
    } catch(e) { wrap.innerHTML = `<div class="ge-empty">Error: ${e.message}</div>`; return; }

    const rows = data.registros || [];
    const tot = data.totales || {};

    wrap.innerHTML = `
      <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:16px">
        <div class="calidad-detail-section" style="text-align:center">
          <div style="font-size:1.8rem;font-weight:800;color:#4ade80">${(tot.bultos||0).toLocaleString()}</div>
          <div style="font-size:.7rem;opacity:.4;text-transform:uppercase;margin-top:2px">Bultos totales</div>
        </div>
        <div class="calidad-detail-section" style="text-align:center">
          <div style="font-size:1.8rem;font-weight:800;color:#60a5fa">${(tot.kilos||0).toLocaleString()} kg</div>
          <div style="font-size:.7rem;opacity:.4;text-transform:uppercase;margin-top:2px">Kilos totales</div>
        </div>
        <div class="calidad-detail-section" style="text-align:center">
          <div style="font-size:1.8rem;font-weight:800;color:#facc15">${(tot.posiciones||0).toLocaleString()}</div>
          <div style="font-size:.7rem;opacity:.4;text-transform:uppercase;margin-top:2px">Posiciones</div>
        </div>
      </div>
      <div class="logmod-table-wrap">
        <table class="logmod-table">
          <thead><tr>
            <th>Cliente</th>
            <th style="width:100px;text-align:right">Bultos</th>
            <th style="width:100px;text-align:right">Kilos</th>
            <th style="width:100px;text-align:right">Posiciones</th>
            <th style="width:60px;text-align:center">Ver</th>
          </tr></thead>
          <tbody>${rows.length ? rows.map(r => `
            <tr class="logmod-row">
              <td style="font-weight:700">${r.cliente||''}</td>
              <td style="text-align:right">${(r.bultos||0).toLocaleString()}</td>
              <td style="text-align:right">${(r.kilos||0).toLocaleString()}</td>
              <td style="text-align:right">${(r.posiciones||0).toLocaleString()}</td>
              <td style="text-align:center"><button class="logmod-acc-icon stk-det" data-cid="${r.ClienteID}" data-nombre="${r.cliente}">👁</button></td>
            </tr>`).join('') : '<tr><td colspan="5" class="logmod-empty">Sin stock</td></tr>'}
          </tbody>
          ${rows.length ? `<tfoot><tr style="font-weight:800;border-top:2px solid rgba(255,255,255,.15)">
            <td>TOTAL</td>
            <td style="text-align:right">${(tot.bultos||0).toLocaleString()}</td>
            <td style="text-align:right">${(tot.kilos||0).toLocaleString()}</td>
            <td style="text-align:right">${(tot.posiciones||0).toLocaleString()}</td>
            <td></td>
          </tr></tfoot>` : ''}
        </table>
      </div>
      <div class="logmod-footer">${rows.length} cliente${rows.length!==1?'s':''} con stock</div>`;

    wrap.querySelectorAll('.stk-det').forEach(btn => {
      btn.onclick = () => renderDetalle(+btn.dataset.cid, btn.dataset.nombre);
    });
  };

  const renderDetalle = async (clienteId, clienteNombre) => {
    wrap.innerHTML = '<div class="ge-loading" style="padding:40px;text-align:center">Cargando detalle...</div>';
    let data;
    try {
      const r = await fetch(`api_2026ia.php?action=reporte_stock_detalle&cliente_id=${clienteId}`, { credentials:'same-origin' });
      data = await r.json();
      if (data.error) throw new Error(data.error);
    } catch(e) { wrap.innerHTML = `<div class="ge-empty">Error: ${e.message}</div>`; return; }

    const rows = data.registros || [];
    wrap.innerHTML = `
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:14px">
        <button class="logmod-search-btn" id="stkVolver">← Volver al resumen</button>
        <span style="font-weight:800;font-size:.95rem">${clienteNombre}</span>
        <span style="font-size:.72rem;opacity:.4">${rows.length} producto${rows.length!==1?'s':''}</span>
      </div>
      <div class="logmod-table-wrap">
        <table class="logmod-table">
          <thead><tr>
            <th style="width:80px">Código</th><th>Producto</th>
            <th style="width:90px;text-align:right">Bultos</th>
            <th style="width:90px;text-align:right">Kilos</th>
            <th style="width:80px;text-align:right">Posiciones</th>
            <th style="width:90px">F.Elab. mín</th>
            <th style="width:90px">F.Venc. máx</th>
          </tr></thead>
          <tbody>${rows.map(r => `
            <tr class="logmod-row">
              <td class="logmod-text-sm">${r.codigo||''}</td>
              <td style="font-weight:600">${r.producto||''}</td>
              <td style="text-align:right">${(r.bultos||0).toLocaleString()}</td>
              <td style="text-align:right">${(r.kilos||0).toLocaleString()}</td>
              <td style="text-align:right">${r.posiciones||0}</td>
              <td class="logmod-text-muted">${r.fecha_elab_min||''}</td>
              <td class="logmod-text-muted">${r.fecha_venc_max||''}</td>
            </tr>`).join('')}
          </tbody>
        </table>
      </div>`;

    wrap.querySelector('#stkVolver').onclick = renderResumen;
  };

  renderResumen();
}

