/* ═══════════════════════════════════════════════════════════════
   CHECKLIST: EQUIPO EN MARCHA
   ═══════════════════════════════════════════════════════════════ */



/* ═══════════════════════════════════════════════════════════════
   MODAL: CAMBIO DE ESTADO DE EQUIPO (En marcha ↔ Falla / Cargando)
   ═══════════════════════════════════════════════════════════════ */


/* ═══════════════════════════════════════════════════════════════
   CHECKLIST: EQUIPO EN MARCHA (estado Cargando → En marcha)
   2 pasos: ítems 1-9 → continuar → ítems 10-18 + horas iniciales
   ═══════════════════════════════════════════════════════════════ */
const CHECKLIST_ITEMS = [
  'Extinguidores 1 Kg.',
  'Espejos retrovisores',
  'Cinturón de seguridad',
  'Luz delantera',
  'Bocina',
  'Luz trasera – baliza',
  'Alarma acústica de retroceso',
  'Luz electroboscópica de retroceso',
  'Frenos en condiciones',
  'Dirección',
  'Mástil movimiento vertical',
  'Mástil movimiento en ángulo',
  'Apertura de uñas',
  'Desplazamiento lateral de horquilla',
  'Cadena del mástil',
  'Mangueras hidráulicas',
  'Asiento en condiciones',
  'Jaula y mallas de protección',
];

function openChecklistEnMarcha(index) {
  document.getElementById('checklistModal')?.remove();
  const item = dashboardEquipamientoData[index];
  const now  = new Date();
  const horaStr = now.getHours().toString().padStart(2,'0') + ':' + now.getMinutes().toString().padStart(2,'0');
  const checks  = {};
  CHECKLIST_ITEMS.forEach((_, i) => { checks[i] = null; });
  let paso = 1;          // paso 1: ítems 0-8 | paso 2: ítems 9-17 + horas
  let horasIniVal = String(item.horasActual || item.horasBase || ''); // pre-cargado con horómetro actual

  const modal = document.createElement('div');
  modal.id = 'checklistModal';
  modal.className = 'chk-overlay';
  document.body.appendChild(modal);
  requestAnimationFrame(() => modal.classList.add('chk-visible'));

  const render = () => {
    const start    = paso === 1 ? 0 : 9;
    const end      = paso === 1 ? 9 : 18;
    const items    = CHECKLIST_ITEMS.slice(start, end);
    const respondidos = Object.values(checks).filter(v => v !== null).length;
    const stepDone = items.every((_, i) => checks[start + i] !== null);
    const hayFalla = Object.values(checks).some(v => v === 'no');
    const horasOk  = paso === 2 ? horasIniVal.trim() !== '' : true;
    const puedeRetirar = paso === 2 && stepDone && horasOk;

    const rows = items.map((elem, i) => {
      const idx = start + i;
      return `<tr class="chk-row ${checks[idx]!==null?'chk-row-done':''} ${checks[idx]==='no'?'chk-row-falla':''}">
        <td class="chk-td-elem">${elem}</td>
        <td class="chk-td-opt"><button class="chk-opt-btn ${checks[idx]==='si'?'chk-sel-si':''}" data-idx="${idx}" data-val="si">✓</button></td>
        <td class="chk-td-opt"><button class="chk-opt-btn ${checks[idx]==='no'?'chk-sel-no':''}" data-idx="${idx}" data-val="no">✗</button></td>
      </tr>`;
    }).join('');

    modal.innerHTML = `
      <div class="chk-modal">
        <div class="chk-header">
          <div class="chk-header-info">
            <span class="chk-equip-badge">${item.tipo}</span>
            <span class="chk-equip-denom">${item.denominacion}</span>
            <span class="chk-paso-label">Paso ${paso} de 2</span>
          </div>
          <button class="chk-close" id="chkClose">✕</button>
        </div>

        <div class="chk-datos-grid">
          <div class="chk-dato"><span class="chk-dato-label">Equipo</span><span class="chk-dato-val">${item.denominacion}</span></div>
          <div class="chk-dato"><span class="chk-dato-label">Usuario</span><span class="chk-dato-val">${perfilData.usuario || item.usuario}</span></div>
          <div class="chk-dato"><span class="chk-dato-label">Hora inicio</span><span class="chk-dato-val">${horaStr}</span></div>
          ${paso === 2 ? `
          <div class="chk-dato">
            <span class="chk-dato-label">Horómetro inicio <span style="color:#f87171">*</span></span>
            <input class="chk-input" type="number" id="chkHorasIni" value="${horasIniVal}" placeholder="${item.horasActual||item.horasBase}">
          </div>` : `<div class="chk-dato"></div>`}
          <div class="chk-dato chk-progress-inline">
            <span class="chk-dato-label">${respondidos}/18 completados</span>
            <div class="chk-progress-bar-bg">
              <div class="chk-progress-bar-fill" style="width:${Math.round(respondidos/18*100)}%"></div>
            </div>
          </div>
        </div>

        <div class="chk-list-wrap">
          <table class="chk-table">
            <thead><tr>
              <th class="chk-th-elem">Elemento (${paso === 1 ? '1–9' : '10–18'})</th>
              <th class="chk-th-si">SI</th>
              <th class="chk-th-no">NO</th>
            </tr></thead>
            <tbody>${rows}</tbody>
          </table>
        </div>

        ${hayFalla ? '<div class="chk-alerta-falla">⚠️ Hay elementos con falla detectada</div>' : ''}

        <div class="chk-footer">
          <button class="chk-btn chk-btn-rechazar" id="chkRechazar">🚫 Rechazar uso</button>
          <button class="chk-btn chk-btn-falla"    id="chkFalla">⚠️ Informar falla</button>
          ${paso === 1
            ? `<button class="chk-btn chk-btn-retirar ${!stepDone?'chk-disabled':''}" id="chkContinuar" ${!stepDone?'disabled':''}>Continuar →</button>`
            : `<button class="chk-btn chk-btn-retirar ${!puedeRetirar?'chk-disabled':''}" id="chkRetirar" ${!puedeRetirar?'disabled':''}>✅ Retirar equipo</button>`
          }
        </div>
      </div>`;

    // Eventos botones de checklist
    modal.querySelectorAll('.chk-opt-btn').forEach(btn => {
      btn.onclick = e => {
        e.stopPropagation();
        const i = +btn.dataset.idx, v = btn.dataset.val;
        checks[i] = checks[i] === v ? null : v;
        if (paso === 2) horasIniVal = modal.querySelector('#chkHorasIni')?.value || horasIniVal;
        render();
      };
    });

    modal.querySelector('#chkClose').onclick    = close;
    modal.querySelector('#chkRechazar').onclick = () => { close(); showToast('🚫 Uso rechazado — ' + item.denominacion); };
    modal.querySelector('#chkFalla').onclick    = () => {
      const motivoChk = (prompt('Descripción de la falla (obligatorio):') || '').trim();
      if (!motivoChk) { showToast('⚠️ Ingresá una descripción de la falla'); return; }
      dashboardEquipamientoData[index].estado = 'Falla';
      close(); renderDashboardEquipamiento();
      showToast('⚠️ Falla informada — ' + item.denominacion);
      apiEquipos('cambio_estado', {
        interno      : item.interno,
        estado_nuevo : 'Falla',
        usuario      : perfilData.usuario,
        horometro    : item.horasActual || item.horasBase,
        motivo       : motivoChk,
      });
    };

    if (paso === 1) {
      modal.querySelector('#chkContinuar').onclick = () => { if (!stepDone) return; paso = 2; render(); };
    } else {
      const ini = modal.querySelector('#chkHorasIni');
      ini.oninput   = e => { horasIniVal = e.target.value; };
      ini.onkeydown = e => e.stopPropagation();
      modal.querySelector('#chkRetirar').onclick = () => {
        if (!puedeRetirar) { ini.classList.add('chk-required-err'); ini.focus(); return; }
        const horasNum = parseInt(horasIniVal) || dashboardEquipamientoData[index].horasActual;
        dashboardEquipamientoData[index].estado = 'En marcha';
        dashboardEquipamientoData[index].horasActual = horasNum;
        // Convertir checks a array de 18 ítems (1=si, 0=no, null=sin responder)
        const itemsArr = CHECKLIST_ITEMS.map((_, i) =>
          checks[i] === 'si' ? 1 : checks[i] === 'no' ? 0 : null
        );
        close(); renderDashboardEquipamiento();
        showToast('✅ Equipo en marcha — ' + item.denominacion);
        // Grabar cambio de estado En marcha
        apiEquipos('cambio_estado', {
          interno      : item.interno,
          estado_nuevo : 'En marcha',
          usuario      : perfilData.usuario,
          horometro    : horasNum,
          motivo       : null,
        }).then(r => {
          if (r?.ok) {
            // Grabar checklist
            apiEquipos('checklist', {
              interno          : item.interno,
              usuario          : perfilData.usuario,
              horometro_inicio : horasNum,
              items            : itemsArr,
              observaciones    : null,
            }).then(c => { if (c?.ok) console.log('Checklist grabado:', c.resultado); });
          }
        });
      };
    }
  };

  render();
  function close() { modal.classList.remove('chk-visible'); setTimeout(() => modal.remove(), 220); }
  modal.addEventListener('click', e => { if (e.target === modal) close(); });
}

/* ═══════════════════════════════════════════════════════════════
   MODAL: CAMBIO DE ESTADO (En marcha / Falla → otro estado)
   Pide horas finales obligatorias
   ═══════════════════════════════════════════════════════════════ */
function openCambioEstadoEquipo(index) {
  document.getElementById('estadoEquipModal')?.remove();
  const item    = dashboardEquipamientoData[index];
  const esFalla = item.estado === 'Falla';
  const esMarcha= item.estado === 'En marcha';

  const modal = document.createElement('div');
  modal.id    = 'estadoEquipModal';
  modal.className = 'chk-overlay';
  document.body.appendChild(modal);

  let horasFinVal = '';
  let errMsg = '';

  const opciones = esFalla
    ? [{ val:'Cargando', label:'🔋 Pasar a Cargando', cls:'estado-btn-cargando' }]
    : esMarcha
    ? [
        { val:'Falla',    label:'⚠️ Informar falla',   cls:'estado-btn-falla'    },
        { val:'Cargando', label:'🔋 Pasar a Cargando', cls:'estado-btn-cargando' },
      ]
    : [];

  const badgeCls = item.estado === 'En marcha' ? 'state-running' : item.estado === 'Falla' ? 'state-falla' : 'state-cargando';

  const render = () => {
    modal.innerHTML = `
      <div class="chk-modal" style="height:auto;max-height:min(460px,90dvh)">
        <div class="chk-header">
          <div class="chk-header-info">
            <span class="chk-equip-badge">${item.tipo}</span>
            <span class="chk-equip-denom">${item.denominacion}</span>
          </div>
          <button class="chk-close" id="estClose">✕</button>
        </div>
        <div style="padding:14px 20px;display:flex;flex-direction:column;gap:12px;overflow-y:auto">
          <div style="display:flex;align-items:center;gap:10px">
            <span style="font-size:.65rem;font-weight:800;color:rgba(255,255,255,.4);text-transform:uppercase">Estado actual</span>
            <span class="estado-equip-badge ${badgeCls}">${item.estado}</span>
            <span style="font-size:.72rem;color:rgba(255,255,255,.45);margin-left:4px">· ${perfilData.usuario}</span>
          </div>
          <div class="chk-dato">
            <span class="chk-dato-label">Horómetro final <span style="color:#f87171">*</span></span>
            <input class="chk-input ${errMsg?'chk-required-err':''}" type="number" id="estHorasFin" value="${horasFinVal}" placeholder="${item.horasActual||item.horasBase}" />
            ${errMsg ? `<span style="font-size:.6rem;color:#f87171;font-weight:800;margin-top:2px">${errMsg}</span>` : ''}
          </div>
          <p style="font-size:.72rem;color:rgba(255,255,255,.42);margin:0;line-height:1.45">
            ${esFalla ? 'El equipo está en falla. Registrá las horas finales antes de cambiar el estado.' : 'Registrá las horas finales antes de cambiar el estado del equipo.'}
          </p>
          <div style="display:flex;flex-direction:column;gap:7px">
            ${opciones.map(o => `<button class="chk-btn ${o.cls}" data-val="${o.val}">${o.label}</button>`).join('')}
            <button class="chk-btn" style="background:rgba(107,114,128,.15);border-color:rgba(107,114,128,.28);color:rgba(255,255,255,.55)" id="estCancelar">Cancelar</button>
          </div>
        </div>
      </div>`;

    const inp = modal.querySelector('#estHorasFin');
    inp.oninput   = e => { horasFinVal = e.target.value; };
    inp.onkeydown = e => e.stopPropagation();
    setTimeout(() => inp.focus(), 80);

    modal.querySelector('#estClose').onclick    = close;
    modal.querySelector('#estCancelar').onclick = close;
    modal.addEventListener('click', e => { if (e.target === modal) close(); });

    modal.querySelectorAll('[data-val]').forEach(btn => {
      btn.onclick = () => {
        horasFinVal = modal.querySelector('#estHorasFin').value.trim();
        if (!horasFinVal) { errMsg = 'Campo obligatorio'; render(); return; }
        const numFin     = parseInt(horasFinVal);
        const estadoNuevo = btn.dataset.val;
        const motivoFalla = estadoNuevo === 'Falla'
          ? (prompt('Descripción de la falla (obligatorio):') || '').trim()
          : null;
        if (estadoNuevo === 'Falla' && !motivoFalla) {
          showToast('⚠️ Ingresá una descripción de la falla'); return;
        }
        dashboardEquipamientoData[index].estado = estadoNuevo;
        if (!isNaN(numFin)) dashboardEquipamientoData[index].horasActual = numFin;
        close(); renderDashboardEquipamiento();
        showToast(`✓ ${item.denominacion} → ${estadoNuevo}`);
        // Grabar en base de datos (no bloquea la UI)
        apiEquipos('cambio_estado', {
          interno      : item.interno,
          estado_nuevo : estadoNuevo,
          usuario      : perfilData.usuario,
          horometro    : !isNaN(numFin) ? numFin : (item.horasActual || item.horasBase),
          motivo       : motivoFalla,
        }).then(r => {
          if (r?.ok) console.log('Estado grabado en DB:', r);
        });
      };
    });
  };

  render();
  requestAnimationFrame(() => modal.classList.add('chk-visible'));
  function close() { modal.classList.remove('chk-visible'); setTimeout(() => modal.remove(), 220); }
}

/* ═══════════════════════════════════════════════════════════════
   URL ROUTING — hash-based deep links
   ═══════════════════════════════════════════════════════════════

   TABLA DE RUTAS:
   #dashboard-nacional              → Dashboard Logística Nacional
   #dashboard-equipamiento          → Dashboard Equipamiento (autoelevadores, etc.)
   #gestion                         → Gestión de Equipos (lista de sectores)
   #gestion/{sector}                → Detalle de sector (categorías)
   #gestion/{sector}/{categoria}    → Lista de equipos de esa categoría
   #equipo-ind/{denominacion}       → Modal de equipo industrial (SIL-1520, etc.)
   #equipo-mant/{id}                → Ficha de equipo de mantenimiento
   #camara/{id}                     → Sector de cámara en gestión (por CamaraID)
   #sector/{nombre}                 → Espacio común en gestión (por nombre)
   #ia                              → Asistente IA

   NOTA: {sector} y {categoria} van URL-encoded.
         {id} es numérico. {denominacion} y {nombre} son texto.
   ═══════════════════════════════════════════════════════════════ */

// ── Helpers de hash ───────────────────────────────────────────

function setHash(hash) {
  history.replaceState(null, '', hash ? '#' + hash : window.location.pathname + window.location.search);
}

function clearHash() {
  history.replaceState(null, '', window.location.pathname + window.location.search);
}

// Encode para usar en URL: espacios → %20 (legible en barra)
function hashEncode(str) { return encodeURIComponent(str); }
function hashDecode(str) { return decodeURIComponent(str); }

// ── Helpers de espera de datos ────────────────────────────────

async function esperarDatos(getter, loader, intentos = 15, espera = 200) {
  for (let i = 0; i < intentos; i++) {
    const val = getter();
    if (val && (Array.isArray(val) ? val.length > 0 : true)) return val;
    if (i === 0) await loader();
    else await new Promise(r => setTimeout(r, espera));
  }
  return getter();
}

// ── Navegadores ───────────────────────────────────────────────

// #dashboard-nacional
async function navigateToDashboardNacional() {
  await esperarDatos(() => dashboardLogisticaNacionalData, cargarCamarasDesdeDB);
  historyStack.length = 0;
  historyStack.push(menuTree);
  renderDashboardLogisticaNacional();
}

// #dashboard-equipamiento
async function navigateToDashboardEquipamiento() {
  await esperarDatos(
    () => dashboardEquipamientoData,
    () => fetch(`${API_EQUIPOS_URL}?action=equipos_lista`, {credentials:'same-origin'}).then(r=>r.json()).then(data => {
      if (Array.isArray(data) && data.length) {
        dashboardEquipamientoData.length = 0;
        data.forEach(e => dashboardEquipamientoData.push({
          id: parseInt(e.id), interno: parseInt(e.interno),
          denominacion: e.denominacion, tipo: e.tipo,
          marca: e.marca||'', modelo: e.modelo||'', planta: e.planta||'',
          estado: e.estado_actual, horasBase: parseFloat(e.horometro_actual)||0,
          horasActual: parseFloat(e.horometro_actual)||0,
          usuario: e.ultimo_usuario||e.usuario||'', año: e.anio||'N/D',
          icono: e.icono||'img/autoelevador.png', isImage: true,
          fallas_abiertas: parseInt(e.fallas_abiertas)||0,
        }));
      }
    }).catch(()=>{})
  );
  historyStack.length = 0;
  historyStack.push(menuTree);
  renderDashboardEquipamiento();
}

// #gestion
async function navigateToGestion() {
  await _cargarDatosGestion();
  historyStack.length = 0;
  historyStack.push(menuTree);
  renderGestionEquipos();
}

// #gestion/{sector}
async function navigateToGestionSector(sector) {
  await _cargarDatosGestion();
  historyStack.length = 0;
  historyStack.push(menuTree);
  historyStack.push({ title: 'GESTIÓN DE EQUIPOS', __custom: 'ge_sectores_root' });
  renderDetalleSector(sector);
}

// #gestion/{sector}/{categoria}
async function navigateToGestionLista(sector, categoriaId) {
  await _cargarDatosGestion();
  historyStack.length = 0;
  historyStack.push(menuTree);
  historyStack.push({ title: 'GESTIÓN DE EQUIPOS', __custom: 'ge_sectores_root' });
  historyStack.push({ __custom: 'ge_sectores' }); // para que back vuelva al sector
  renderListaEquipos(sector, categoriaId);
}

// #equipo-ind/{denominacion}  (equipos industriales: autoelevadores, robot, etc.)
async function navigateToEquipoInd(denominacion) {
  await navigateToDashboardEquipamiento();
  const idx = dashboardEquipamientoData.findIndex(e => e.denominacion === denominacion);
  if (idx === -1) { showToast('Equipo no encontrado: ' + denominacion); return; }
  const item = dashboardEquipamientoData[idx];
  setTimeout(() => {
    if (item.estado === 'Cargando')                           openChecklistEnMarcha(idx);
    else if (item.estado === 'Falla' || item.estado === 'En marcha') openCambioEstadoEquipo(idx);
  }, 80);
}

// #equipo-mant/{id}  (equipos de mantenimiento por ID numérico)
async function navigateToEquipoMant(equipoId) {
  await _cargarDatosGestion();
  historyStack.length = 0;
  historyStack.push(menuTree);
  historyStack.push({ __custom: 'ge_sectores' });
  renderFichaEquipo(equipoId, '', null);
}

// #camara/{id}  (sector de cámara en gestión, por CamaraID numérico)
async function navigateToCamara(camaraId) {
  await _cargarDatosGestion();
  const cam = camarasDB.find(c => parseInt(c.CamaraID) === camaraId || parseInt(c.CamaraNumero) === camaraId);
  if (!cam) { console.warn('Cámara no encontrada:', camaraId); showToast('Cámara no encontrada'); return; }
  historyStack.length = 0;
  historyStack.push(menuTree);
  historyStack.push({ title: 'GESTIÓN DE EQUIPOS', __custom: 'ge_sectores_root' });
  renderDetalleSector(cam.nombre_display);
}

// #sector/{nombre}  (espacio común en gestión, por nombre URL-encoded)
async function navigateToSector(nombre) {
  await _cargarDatosGestion();
  historyStack.length = 0;
  historyStack.push(menuTree);
  historyStack.push({ title: 'GESTIÓN DE EQUIPOS', __custom: 'ge_sectores_root' });
  renderDetalleSector(nombre);
}

// #ia
function navigateToIA() {
  historyStack.length = 0;
  historyStack.push(menuTree);
  renderAsistenteIA();
}

// ── Carga de datos de gestión (equipos + espacios + cámaras) ──

async function _cargarDatosGestion() {
  const promesas = [];
  if (!camarasDB.length)       promesas.push(cargarCamarasDesdeDB());
  if (!mantEquiposCache.length) promesas.push(
    fetch(`${API_EQUIPOS_URL}?action=mant_equipos_lista`, {credentials:'same-origin'}).then(r=>r.json())
      .then(d => { if (Array.isArray(d)) mantEquiposCache = d; }).catch(()=>{})
  );
  if (!mantEspaciosCache.length) promesas.push(
    fetch(`${API_EQUIPOS_URL}?action=mant_espacios`, {credentials:'same-origin'}).then(r=>r.json())
      .then(d => { if (Array.isArray(d)) mantEspaciosCache = d; }).catch(()=>{})
  );
  if (promesas.length) await Promise.all(promesas);
}

// ── Router principal ──────────────────────────────────────────

async function handleHashRouting() {
  const hash = window.location.hash.slice(1); // quitar el #
  if (!hash) return;

  const partes = hash.split('/');
  const ruta   = partes[0];

  switch (ruta) {

    case 'dashboard-nacional':
      await navigateToDashboardNacional();
      break;

    case 'dashboard-equipamiento':
      await navigateToDashboardEquipamiento();
      break;

    case 'gestion':
      if (partes.length === 1) {
        await navigateToGestion();
      } else if (partes.length === 2) {
        await navigateToGestionSector(hashDecode(partes[1]));
      } else if (partes.length >= 3) {
        await navigateToGestionLista(hashDecode(partes[1]), hashDecode(partes[2]));
      }
      break;

    case 'equipo-ind':
      if (partes[1]) await navigateToEquipoInd(hashDecode(partes.slice(1).join('/')));
      break;

    // Alias legacy: #equipo/ sigue funcionando igual que #equipo-ind/
    case 'equipo':
      if (partes[1]) await navigateToEquipoInd(hashDecode(partes.slice(1).join('/')));
      break;

    case 'equipo-mant': {
      const id = parseInt(partes[1]);
      if (!isNaN(id)) await navigateToEquipoMant(id);
      break;
    }

    case 'camara': {
      const id = parseInt(partes[1]);
      if (!isNaN(id)) await navigateToCamara(id);
      break;
    }

    case 'sector':
      if (partes[1]) await navigateToSector(hashDecode(partes.slice(1).join('/')));
      break;

    case 'ia':
      navigateToIA();
      break;

    case 'estiba':
      if (partes[1]) {
        if (esMobile()) renderEstibaMobileLanding(partes[1]);
        else renderEstibaFormulario(partes[1]);
      }
      break;

    case 'estiba-intervenida':
      if (partes[1]) renderEstibaIntervenidaMobileLanding(partes[1]);
      break;

    default:
      console.warn('Hash no reconocido:', hash);
  }
}

// ── Actualizar hash al navegar (para que la URL refleje dónde estás) ──

function setEquipoHash(denominacion) {
  setHash('equipo-ind/' + hashEncode(denominacion));
}

function clearEquipoHash() {
  clearHash();
}

// Hook: al abrir modal de equipo industrial → actualizar hash
(function patchCardClicks() {
  document.addEventListener('click', function(e) {
    const card = e.target.closest('.equipment-card');
    if (!card) return;
    if (e.target.closest('.equipment-edit-btn')) return;
    const idx = Array.from(card.parentElement.children).indexOf(card);
    if (idx >= 0 && dashboardEquipamientoData[idx]) {
      setEquipoHash(dashboardEquipamientoData[idx].denominacion);
    }
  });
  // Limpiar hash al cerrar modal
  document.addEventListener('click', function(e) {
    if (e.target.id === 'checklistModal' || e.target.id === 'estadoEquipModal') clearHash();
    if (e.target.id === 'chkClose'       || e.target.id === 'estClose')         clearHash();
  });
})();

// ── Inicialización ────────────────────────────────────────────
// hashchange cubre navegación con back/forward del browser
window.addEventListener('hashchange', handleHashRouting);

/* ═══════════════════════════════════════════════════════════
   PR-6 CONTRASTE DE TERMÓMETROS
   ═══════════════════════════════════════════════════════════ */

/* ── PR-22 LIMPIEZA DE TANQUES ─────────────────────── */
let pr22Registros = [];
let pr100Registros = [];
let pr6EstadoCamarasDB = []; // estado por cámara desde DB

// Lista dinámica — se reemplaza al cargar desde MySQL
// Se carga desde la base de datos al iniciar — no modificar
let PR6_CAMARAS = [];
// Datos completos de cámaras desde DB (CamaraID, numero, calles, filas, etc.)
let camarasDB = [];
let PR100_CAMARAS = []; // cámaras TiposCamaraID=2 para descongelado

// Maquinistas — se carga desde tabla persona al iniciar
let PR6_MAQUINISTAS = [];

/* Array mutable de registros guardados */
let pr6Registros = [];

function renderPR6Contraste() {
  const now = new Date();
  const fechaStr = now.toLocaleDateString('es-AR',{day:'2-digit',month:'2-digit',year:'numeric'});
  const horaStr  = now.toLocaleTimeString('es-AR',{hour:'2-digit',minute:'2-digit'});
  const isoFecha = now.toISOString().split('T')[0];

  setExpandedMode(true);
  showMetaPanel(false);
  syncBackBtn();
  menuGrid.className = 'menu-grid';
  menuGrid.innerHTML = `
    <div class="pr6-wrap">

      <div class="pr6-topbar">
        <div class="pr6-topbar-center">
          <span class="pr6-badge-sm">PR-6</span>
          <span class="pr6-topbar-title">Contraste de Termómetros</span>
        </div>
        <button class="pr6-hist-trigger" id="pr6HistorialBtn">📋 Historial</button>
      </div>

      <div class="pr6-meta-row">
        <div class="pr6-meta-item">
          <div class="pr6-meta-label">📅 Fecha</div>
          <div class="pr6-meta-val" id="pr6FechaDisp">${fechaStr}</div>
          <input type="hidden" id="pr6Fecha" value="${isoFecha}">
        </div>
        <div class="pr6-meta-item">
          <div class="pr6-meta-label">🕐 Hora</div>
          <div class="pr6-meta-val" id="pr6HoraDisp">${horaStr}</div>
          <input type="hidden" id="pr6Hora" value="${horaStr}">
        </div>
        <div class="pr6-meta-item pr6-meta-grow">
          <div class="pr6-meta-label">👤 Maquinista</div>
          <div class="pr6-meta-val pr6-meta-usuario">${perfilData.usuario}</div>
          <input type="hidden" id="pr6Maquinista" value="${perfilData.usuario}">
        </div>
      </div>

      <div class="pr6-section">
        <div class="pr6-section-title"><span>❄️</span> Seleccioná las cámaras a contrastar</div>
        <div class="pr6-camara-chips" id="pr6CamaraChips">
          ${PR6_CAMARAS.map(c => {
            const label = c.replace(/^CÁMARA /, 'C').replace('ANTECÁMARA','ANTEC').replace('SALA DE MÁQUINAS','S.MÁQ').replace('EXTERIOR','EXT').replace(/^TÚNEL /, 'TUN ');
            // Buscar estado en DB para colorear el chip
            const camaraObj = camarasDB.find(x => x.nombre_display === c);
            const camaraNum = camaraObj ? camaraObj.CamaraNumero : null;
            let chipClass = 'pr6-chip';
            let chipTitle = c;
            if (pr6EstadoCamarasDB.length && camaraNum) {
              const dbRow = pr6EstadoCamarasDB.find(r => parseInt(r.camara_numero ?? r.camara) === camaraNum);
              if (dbRow) {
                const dias = parseInt(dbRow.dias_desde_ultimo);
                chipClass += dias <= 30 ? ' pr6-chip-ok' : ' pr6-chip-vencido';
                chipTitle = `${c}: último contraste hace ${dias} días (${dbRow.ultima_fecha})`;
              } else {
                chipClass += ' pr6-chip-sin-dato';
                chipTitle = `${c}: sin registros`;
              }
            }
            return `<button class="${chipClass}" data-camara="${c}" title="${chipTitle}">${label}</button>`;
          }).join('')}
        </div>
      </div>

      <div class="pr6-section">
        <div class="pr6-section-title"><span>🌡️</span> Datos de contraste</div>
        <div class="pr6-tabla-wrap">
          <div class="pr6-tabla-head">
            <div class="pr6-th pr6-th-cam">Cámara</div>
            <div class="pr6-th pr6-th-num">Ptr N°1</div>
            <div class="pr6-th pr6-th-num">Ptr N°2</div>
            <div class="pr6-th pr6-th-num">Temp PLC</div>
            <div class="pr6-th pr6-th-num">T. Puesta</div>
            <div class="pr6-th pr6-th-num">T. Alcanz.</div>
            <div class="pr6-th pr6-th-obs">Observaciones</div>
            <div class="pr6-th pr6-th-del"></div>
          </div>
          <div id="pr6Filas" class="pr6-filas-body"></div>
        </div>
        <div class="pr6-tabla-footer">
          <button class="pr6-add-row-btn" id="pr6AgregarBtn">＋ Agregar fila manual</button>
        </div>
      </div>

      <div class="pr6-actions">
        <button class="pr6-guardar-btn" id="pr6GuardarBtn">💾 Guardar Registro</button>
      </div>

    </div>
  `;

  document.getElementById('pr6CamaraChips').addEventListener('click', e => {
    const chip = e.target.closest('[data-camara]');
    if (!chip) return;
    const camara = chip.dataset.camara;
    chip.classList.toggle('active');
    if (chip.classList.contains('active')) {
      pr6AgregarFila(camara);
    } else {
      pr6EliminarFilaPorCamara(camara);
    }
  });

  document.getElementById('pr6AgregarBtn').addEventListener('click', () => pr6AgregarFila(''));

  // Toggle +/- en celdas numéricas
  document.getElementById('pr6Filas').addEventListener('click', e => {
    const btn = e.target.closest('.pr6-sign-btn');
    if (!btn) return;
    const wrap = btn.closest('.pr6-num-wrap');
    wrap.querySelector('.pr6-sign-neg').classList.toggle('active', btn.classList.contains('pr6-sign-neg'));
    wrap.querySelector('.pr6-sign-pos').classList.toggle('active', btn.classList.contains('pr6-sign-pos'));
  });
  document.getElementById('pr6GuardarBtn').addEventListener('click', pr6GuardarRegistro);
  document.getElementById('pr6HistorialBtn').addEventListener('click', pr6MostrarHistorial);
}

function pr6NumCell() {
  return `<div class="pr6-num-wrap">
    <button type="button" class="pr6-sign-btn pr6-sign-neg active" title="Negativo">−</button>
    <input type="number" class="pr6-num-inp" placeholder="0.0" step="0.1" min="0">
    <button type="button" class="pr6-sign-btn pr6-sign-pos" title="Positivo">+</button>
  </div>`;
}

function pr6AgregarFila(camaraVal) {
  const contenedor = document.getElementById('pr6Filas');
  const id = 'pr6f_' + Date.now() + '_' + Math.random().toString(36).slice(2,5);
  const div = document.createElement('div');
  div.className = 'pr6-row';
  div.id = id;
  div.dataset.camara = camaraVal || '';
  const camaraCell = camaraVal
    ? `<div class="pr6-td pr6-td-cam"><span class="pr6-cam-tag">${camaraVal}</span></div>`
    : `<div class="pr6-td pr6-td-cam"><select class="pr6-sel-inline pr6-sel-camara">${['<option value="">— Cámara —</option>',...PR6_CAMARAS.map(c=>`<option value="${c}">${c}</option>`)].join('')}</select></div>`;
  div.innerHTML = `
    ${camaraCell}
    <div class="pr6-td pr6-td-num">${pr6NumCell()}</div>
    <div class="pr6-td pr6-td-num">${pr6NumCell()}</div>
    <div class="pr6-td pr6-td-num">${pr6NumCell()}</div>
    <div class="pr6-td pr6-td-num">${pr6NumCell()}</div>
    <div class="pr6-td pr6-td-num">${pr6NumCell()}</div>
    <div class="pr6-td pr6-td-obs"><textarea class="pr6-obs-inp" placeholder="—" rows="1"></textarea></div>
    <div class="pr6-td pr6-td-del">
      <button class="pr6-del-btn" onclick="pr6EliminarFila('${id}','${(camaraVal||'').replace(/'/g,"\\'")}')">✕</button>
    </div>
  `;
  contenedor.appendChild(div);
  const ta = div.querySelector('textarea');
  ta.addEventListener('input', () => { ta.style.height='auto'; ta.style.height=ta.scrollHeight+'px'; });
}

function pr6EliminarFila(id, camaraVal) {
  const el = document.getElementById(id);
  if (el) {
    el.style.cssText += 'opacity:0;transform:translateX(10px);transition:all .18s;';
    setTimeout(() => el.remove(), 200);
  }
  if (camaraVal) {
    const chip = document.querySelector('.pr6-chip[data-camara="'+camaraVal+'"]');
    if (chip) chip.classList.remove('active');
  }
}

function pr6EliminarFilaPorCamara(camara) {
  const fila = document.querySelector('#pr6Filas .pr6-row[data-camara="'+camara+'"]');
  if (fila) {
    fila.style.cssText += 'opacity:0;transform:translateX(10px);transition:all .18s;';
    setTimeout(() => fila.remove(), 200);
  }
}

function pr6GuardarRegistro() {
  const maquinista = document.getElementById('pr6Maquinista').value;
  const fecha      = document.getElementById('pr6Fecha').value;
  const hora       = document.getElementById('pr6Hora').value;
  if (!maquinista) { pr6MostrarToast('Error: no hay usuario activo', 'error'); return; }

  const filas = [...document.querySelectorAll('#pr6Filas .pr6-row')];
  if (!filas.length) { pr6MostrarToast('Agregá al menos una cámara', 'error'); return; }

  // Construir detalles con número de cámara desde camarasDB
  const detalles = filas.map(f => {
    const camaraNombre = f.dataset.camara || f.querySelector('.pr6-sel-camara')?.value || '';
    // Buscar número de cámara en camarasDB
    const camaraObj = camarasDB.find(c => c.nombre_display === camaraNombre);
    const camaraNum = camaraObj ? camaraObj.CamaraNumero : null;

    const wraps = [...f.querySelectorAll('.pr6-num-wrap')];
    const leerValor = (wrap) => {
      if (!wrap) return null;
      const val = wrap.querySelector('.pr6-num-inp').value;
      if (val === '' || val === null) return null;
      const isNeg = wrap.querySelector('.pr6-sign-neg').classList.contains('active');
      return isNeg ? -Math.abs(parseFloat(val)) : Math.abs(parseFloat(val));
    };

    return {
      camara_nombre: camaraNombre,
      camara_num   : camaraNum,
      ptr1         : leerValor(wraps[0]),
      ptr2         : leerValor(wraps[1]),
      plc          : leerValor(wraps[2]),
      puerta       : leerValor(wraps[3]),
      alcohol      : leerValor(wraps[4]),
      obs          : f.querySelector('textarea')?.value || '',
    };
  });

  if (detalles.some(d => !d.camara_nombre)) {
    pr6MostrarToast('Hay filas sin cámara seleccionada', 'error'); return;
  }

  // Guardar en memoria (respaldo local)
  pr6Registros.push({ maquinista, fecha, hora, detalles, ts: new Date().toLocaleString('es-AR') });

  // Deshabilitar botón mientras guarda
  const btn = document.getElementById('pr6GuardarBtn');
  if (btn) { btn.disabled = true; btn.textContent = 'Guardando...'; }

  // Enviar a la base de datos
  fetch(`${API_EQUIPOS_URL}?action=pr6_guardar`, {
      credentials: 'same-origin',
    credentials: 'same-origin',
    method : 'POST',
    headers: { 'Content-Type': 'application/json' },
    body   : JSON.stringify({
      fecha, hora, maquinista, detalles
    })
  })
  .then(r => r.json())
  .then(data => {
    if (data.ok) {
      showToast('✅ Formulario PR-06 enviado correctamente');
      setTimeout(() => renderSalaMaquinas(), 1200);
    } else {
      pr6MostrarToast('⚠️ Error: ' + (data.error || ''), 'error');
    }
  })
  .catch(() => {
    pr6MostrarToast('✗ Sin conexión con el servidor', 'error');
  });
}

function pr6MostrarHistorial() {
  // Mostrar modal con spinner mientras carga
  const overlay = document.createElement('div');
  overlay.className = 'pr6-hist-overlay';
  overlay.innerHTML = `
    <div class="pr6-hist-modal">
      <div class="pr6-hist-header">
        <span>📋 Historial PR-6 — Contraste de Termómetros</span>
        <button class="pr6-hist-close" id="pr6HClose">✕</button>
      </div>
      <div class="pr6-hist-body" id="pr6HistBody">
        <div style="text-align:center;padding:32px;color:rgba(255,255,255,.5)">Cargando registros...</div>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  overlay.addEventListener('click', e => { if (e.target===overlay) overlay.remove(); });
  document.getElementById('pr6HClose').addEventListener('click', () => overlay.remove());

  // Cargar desde DB
  fetch(`${API_EQUIPOS_URL}?action=pr6_historial&limit=30`, {credentials:'same-origin'})
  .then(r => { if (!r.ok) throw new Error(`HTTP ${r.status}`); return r.json(); })
  .then(registros => {
    const body = document.getElementById('pr6HistBody');
    if (!body) return;

    if (!Array.isArray(registros)) {
      const msg = registros?.error || JSON.stringify(registros);
      body.innerHTML = `<div style="text-align:center;padding:32px;color:#f87171">Error de API: ${msg}</div>`;
      return;
    }
    if (!registros.length) {
      body.innerHTML = '<div style="text-align:center;padding:32px;color:rgba(255,255,255,.5)">No hay registros en la base de datos aún.</div>';
      return;
    }

    body.innerHTML = registros.map(r => `
      <div class="pr6-hist-card">
        <div class="pr6-hist-card-header">
          <span class="pr6-hist-maq">${r.maquinista_nombre || '—'}</span>
          <span class="pr6-hist-fecha">${r.fecha} ${r.hora?.slice(0,5) || ''}</span>
          <span style="margin-left:auto;font-size:.7rem;color:rgba(255,255,255,.35)">${r.camaras_registradas} cámaras</span>
          <button class="pr6-ver-detalle-btn" data-id="${r.id}" style="
            background:rgba(54,176,201,.15);border:1px solid rgba(54,176,201,.3);
            color:#7dd3fc;border-radius:6px;padding:3px 10px;font-size:.72rem;
            font-weight:700;cursor:pointer;white-space:nowrap;margin-left:8px
          ">Ver detalle</button>
        </div>
      </div>`).join('');

    // Botones ver detalle
    body.querySelectorAll('.pr6-ver-detalle-btn').forEach(btn => {
      btn.addEventListener('click', () => pr6VerDetalle(btn.dataset.id, body));
    });
  })
  .catch(err => {
    console.error('PR6 historial error:', err);
    // Fallback a registros en memoria
    const body = document.getElementById('pr6HistBody');
    if (!body) return;
    if (!pr6Registros.length) {
      body.innerHTML = '<div style="text-align:center;padding:32px;color:rgba(255,255,255,.5)">Sin conexión a DB y sin registros locales.</div>';
      return;
    }
    body.innerHTML = pr6Registros.slice().reverse().map(r => `
      <div class="pr6-hist-card">
        <div class="pr6-hist-card-header">
          <span class="pr6-hist-maq">${r.maquinista}</span>
          <span class="pr6-hist-fecha">${r.fecha} ${r.hora}</span>
        </div>
        <table class="pr6-hist-table"><thead><tr>
          <th>Cámara</th><th>Ptr 1</th><th>Ptr 2</th><th>PLC</th><th>Puerta</th><th>Alcohol</th><th>Obs.</th>
        </tr></thead><tbody>
          ${r.detalles.map(d=>`<tr>
            <td>${d.camara_nombre||d.camara||'—'}</td>
            <td>${d.ptr1??'—'}</td><td>${d.ptr2??'—'}</td><td>${d.plc??'—'}</td>
            <td>${d.puerta??'—'}</td><td>${d.alcohol??'—'}</td>
            <td class="pr6-td-obs">${d.obs||'—'}</td>
          </tr>`).join('')}
        </tbody></table>
        <div class="pr6-hist-footer">Guardado localmente: ${r.ts}</div>
      </div>`).join('');
  });
}

async function pr6VerDetalle(id, container) {
  // Reemplazar contenido con spinner
  container.innerHTML = `
    <button style="background:none;border:none;color:rgba(255,255,255,.5);cursor:pointer;font-size:.8rem;padding:8px 0;margin-bottom:8px"
      id="pr6VolvHistorial">← Volver al listado</button>
    <div style="text-align:center;padding:32px;color:rgba(255,255,255,.5)">Cargando detalle...</div>`;
  document.getElementById('pr6VolvHistorial').addEventListener('click', () => pr6MostrarHistorialEnBody(container));

  try {
    const res  = await fetch(`${API_EQUIPOS_URL}?action=pr6_detalle&id=${id}`, {credentials:'same-origin'});
    const data = await res.json();
    const { cabecera, detalles } = data;

    container.innerHTML = `
      <button style="background:none;border:none;color:rgba(255,255,255,.5);cursor:pointer;font-size:.8rem;padding:8px 0;margin-bottom:12px"
        id="pr6VolvHistorial2">← Volver al listado</button>
      <div class="pr6-hist-card">
        <div class="pr6-hist-card-header">
          <span class="pr6-hist-maq">${cabecera.maquinista_nombre}</span>
          <span class="pr6-hist-fecha">${cabecera.fecha} ${cabecera.hora?.slice(0,5)}</span>
        </div>
        <table class="pr6-hist-table">
          <thead><tr>
            <th>Cámara</th><th>Ptr N°1</th><th>Ptr N°2</th><th>Temp PLC</th>
            <th>T. Puerta</th><th>T. Alcohol</th>
            <th>Dif PLC</th><th>Dif Puerta</th><th>Dif Alc.</th><th>Dif Máx</th>
            <th style="text-align:left">Observaciones</th>
          </tr></thead>
          <tbody>
            ${detalles.map(d => {
              const difColor = (v) => {
                if (v === null || v === undefined) return '';
                const n = parseFloat(v);
                if (Math.abs(n) > 2) return 'color:#fca5a5';
                if (Math.abs(n) > 1) return 'color:#fde68a';
                return 'color:#86efac';
              };
              return `<tr>
                <td style="font-weight:800">${d.camara_nombre || 'Cámara ' + d.camara}</td>
                <td>${d.temp_patron_n1??'—'}</td>
                <td>${d.temp_patron_n2??'—'}</td>
                <td>${d.temp_plc??'—'}</td>
                <td>${d.temp_puerta??'—'}</td>
                <td>${d.temp_alcohol??'—'}</td>
                <td style="${difColor(d.dif_temp_plc)}">${d.dif_temp_plc??'—'}</td>
                <td style="${difColor(d.dif_temp_puerta)}">${d.dif_temp_puerta??'—'}</td>
                <td style="${difColor(d.dif_temp_alcohol)}">${d.dif_temp_alcohol??'—'}</td>
                <td style="${difColor(d.dif_temp_max)};font-weight:800">${d.dif_temp_max??'—'}</td>
                <td class="pr6-td-obs">${d.observaciones||'—'}</td>
              </tr>`;
            }).join('')}
          </tbody>
        </table>
      </div>`;
    document.getElementById('pr6VolvHistorial2').addEventListener('click', () => pr6MostrarHistorialEnBody(container));
  } catch(e) {
    container.innerHTML = '<div style="color:#fca5a5;padding:16px">Error al cargar el detalle.</div>';
  }
}

function pr6MostrarHistorialEnBody(container) {
  // Re-cargar el listado en el body existente sin cerrar el modal
  fetch(`${API_EQUIPOS_URL}?action=pr6_historial&limit=30`, {credentials:'same-origin'})
  .then(r => r.json())
  .then(registros => {
    container.innerHTML = registros.map(r => `
      <div class="pr6-hist-card">
        <div class="pr6-hist-card-header">
          <span class="pr6-hist-maq">${r.maquinista_nombre||'—'}</span>
          <span class="pr6-hist-fecha">${r.fecha} ${r.hora?.slice(0,5)||''}</span>
          <span style="margin-left:auto;font-size:.7rem;color:rgba(255,255,255,.35)">${r.camaras_registradas} cámaras</span>
          <button class="pr6-ver-detalle-btn" data-id="${r.id}" style="
            background:rgba(54,176,201,.15);border:1px solid rgba(54,176,201,.3);
            color:#7dd3fc;border-radius:6px;padding:3px 10px;font-size:.72rem;
            font-weight:700;cursor:pointer;white-space:nowrap;margin-left:8px
          ">Ver detalle</button>
        </div>
      </div>`).join('');
    container.querySelectorAll('.pr6-ver-detalle-btn').forEach(btn => {
      btn.addEventListener('click', () => pr6VerDetalle(btn.dataset.id, container));
    });
  });
}

async function pr6CargarDetalle(regId) {
  const cont = document.getElementById('pr6HistDet_' + regId);
  if (!cont) return;
  cont.innerHTML = '<div style="font-size:.72rem;color:rgba(255,255,255,.4);padding:4px 0">Cargando...</div>';
  try {
    const res  = await fetch(`${API_EQUIPOS_URL}?action=pr6_detalle&id=${regId}`, {credentials:'same-origin'});
    const rows = await res.json();
    if (!rows.length) { cont.innerHTML = '<div style="font-size:.72rem;color:rgba(255,255,255,.4);">Sin detalles</div>'; return; }
    cont.innerHTML = `
      <table class="pr6-hist-table">
        <thead><tr>
          <th>Cámara</th><th>Ptr 1</th><th>Ptr 2</th><th>PLC</th><th>Puerta</th><th>Alcohol</th>
          <th>Δ PLC</th><th>Δ Puerta</th><th>Δ Alcohol</th><th>Δ Max</th><th style="text-align:left">Obs.</th>
        </tr></thead>
        <tbody>
          ${rows.map(d => {
            const difColor = v => {
              if (v === null || v === undefined) return '';
              const n = parseFloat(v);
              if (Math.abs(n) > 1.5) return 'color:#fca5a5';
              if (Math.abs(n) > 0.5) return 'color:#fbbf24';
              return 'color:#86efac';
            };
            return `<tr>
              <td><strong>C${d.camara_num}</strong></td>
              <td>${d.ptr1??'—'}</td><td>${d.ptr2??'—'}</td>
              <td>${d.plc??'—'}</td><td>${d.puerta??'—'}</td><td>${d.alcohol??'—'}</td>
              <td style="${difColor(d.dif_temp_plc)}">${d.dif_temp_plc??'—'}</td>
              <td style="${difColor(d.dif_temp_puerta)}">${d.dif_temp_puerta??'—'}</td>
              <td style="${difColor(d.dif_temp_alcohol)}">${d.dif_temp_alcohol??'—'}</td>
              <td style="${difColor(d.dif_temp_max)};font-weight:800">${d.dif_temp_max??'—'}</td>
              <td style="text-align:left;font-size:.72rem">${d.observaciones||'—'}</td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>`;
  } catch(e) {
    cont.innerHTML = '<div style="font-size:.72rem;color:#fca5a5">Error al cargar detalle</div>';
  }
}

function pr6MostrarToast(msg, tipo='ok') {
  let t = document.querySelector('.pr6-toast');
  if (!t) { t = document.createElement('div'); t.className='pr6-toast'; document.body.appendChild(t); }
  t.textContent = msg;
  t.className = 'pr6-toast pr6-toast-'+tipo+' pr6-toast-show';
  clearTimeout(t._timer);
  t._timer = setTimeout(() => t.classList.remove('pr6-toast-show'), 2800);
}

/* ═══════════════════════════════════════════════════════
   PR-22 LIMPIEZA DE TANQUES
   ═══════════════════════════════════════════════════════ */

function renderPR22Limpieza() {
  const now      = new Date();
  const fechaStr = now.toLocaleDateString('es-AR',{day:'2-digit',month:'2-digit',year:'numeric'});
  const horaStr  = now.toLocaleTimeString('es-AR',{hour:'2-digit',minute:'2-digit'});
  const isoFecha = now.toISOString().split('T')[0];

  setExpandedMode(true);
  showMetaPanel(false);
  syncBackBtn();
  menuGrid.className = 'menu-grid';
  menuGrid.innerHTML = `
    <div class="pr6-wrap">

      <div class="pr6-topbar">
        <div class="pr6-topbar-center">
          <span class="pr6-badge-sm">PR-22</span>
          <span class="pr6-topbar-title">Limpieza y Desinfección de Tanques</span>
        </div>
        <button class="pr6-hist-trigger" id="pr22HistorialBtn">📋 Historial</button>
      </div>

      <!-- META: usuario / fecha / hora automáticos -->
      <div class="pr6-meta-row">
        <div class="pr6-meta-item pr6-meta-grow">
          <div class="pr6-meta-label">👤 Responsable</div>
          <div class="pr6-meta-val">${perfilData.usuario}</div>
          <input type="hidden" id="pr22Maquinista" value="${perfilData.usuario}">
        </div>
        <div class="pr6-meta-item">
          <div class="pr6-meta-label">📅 Fecha</div>
          <div class="pr6-meta-val">${fechaStr}</div>
          <input type="hidden" id="pr22Fecha" value="${isoFecha}">
        </div>
        <div class="pr6-meta-item">
          <div class="pr6-meta-label">🕐 Hora</div>
          <div class="pr6-meta-val">${horaStr}</div>
          <input type="hidden" id="pr22Hora" value="${horaStr}">
        </div>
      </div>

      <!-- TANQUES -->
      <div class="pr6-section">
        <div class="pr6-section-title"><span>🛢️</span> Tanques</div>
        <div class="pr22-tanques-row">

          <div class="pr22-tanque-card" id="pr22CardNorte">
            <div class="pr22-tanque-header">
              <div class="pr22-tanque-check" id="pr22CheckNorte">
                <div class="pr22-checkbox" id="pr22CbNorte"></div>
                <span>Tanque Norte</span>
              </div>
              <span class="pr22-tanque-badge" id="pr22BadgeNorte">Pendiente</span>
            </div>
            <div class="pr22-tanque-body">
              <div class="pr22-field">
                <label class="pr22-label">Nº de Precinto</label>
                <input type="text" class="pr22-input" id="pr22PrecintoNorte" placeholder="Ingresá el número...">
              </div>
            </div>
          </div>

          <div class="pr22-tanque-card" id="pr22CardSur">
            <div class="pr22-tanque-header">
              <div class="pr22-tanque-check" id="pr22CheckSur">
                <div class="pr22-checkbox" id="pr22CbSur"></div>
                <span>Tanque Sur</span>
              </div>
              <span class="pr22-tanque-badge" id="pr22BadgeSur">Pendiente</span>
            </div>
            <div class="pr22-tanque-body">
              <div class="pr22-field">
                <label class="pr22-label">Nº de Precinto</label>
                <input type="text" class="pr22-input" id="pr22PrecintoSur" placeholder="Ingresá el número...">
              </div>
            </div>
          </div>

        </div>
      </div>

      <!-- COMENTARIOS -->
      <div class="pr6-section">
        <div class="pr6-section-title"><span>💬</span> Comentarios</div>
        <textarea class="pr22-textarea" id="pr22Comentarios" placeholder="Observaciones generales del procedimiento..." rows="3"></textarea>
      </div>

      <!-- GUARDAR -->
      <div class="pr6-actions">
        <button class="pr6-guardar-btn" id="pr22GuardarBtn">💾 Guardar Registro</button>
      </div>

    </div>
  `;

  // Toggle Tanque Norte
  document.getElementById('pr22CheckNorte').addEventListener('click', () => pr22ToggleTanque('Norte'));
  // Toggle Tanque Sur
  document.getElementById('pr22CheckSur').addEventListener('click', () => pr22ToggleTanque('Sur'));

  document.getElementById('pr22GuardarBtn').addEventListener('click', pr22Guardar);
  document.getElementById('pr22HistorialBtn').addEventListener('click', pr22MostrarHistorial);
}

function pr22ToggleTanque(cual) {
  const cb    = document.getElementById('pr22Cb'    + cual);
  const badge = document.getElementById('pr22Badge' + cual);
  const card  = document.getElementById('pr22Card'  + cual);
  const activo = cb.classList.toggle('checked');
  badge.textContent = activo ? 'Realizado' : 'Pendiente';
  badge.className   = 'pr22-tanque-badge' + (activo ? ' pr22-badge-ok' : '');
  card.classList.toggle('pr22-card-active', activo);
}

function pr22Guardar() {
  const maquinista = document.getElementById('pr22Maquinista').value;
  const fecha      = document.getElementById('pr22Fecha').value;
  const hora       = document.getElementById('pr22Hora').value;
  const norte      = document.getElementById('pr22CbNorte').classList.contains('checked');
  const sur        = document.getElementById('pr22CbSur').classList.contains('checked');
  const preNorte   = document.getElementById('pr22PrecintoNorte')?.value.trim() || '';
  const preSur     = document.getElementById('pr22PrecintoSur')?.value.trim() || '';
  const comentarios= document.getElementById('pr22Comentarios').value.trim();

  if (!norte && !sur) {
    pr6MostrarToast('Marcá al menos un tanque', 'error'); return;
  }
  if (norte && !preNorte) {
    pr6MostrarToast('Ingresá el Nº de precinto del Tanque Norte', 'error'); return;
  }
  if (sur && !preSur) {
    pr6MostrarToast('Ingresá el Nº de precinto del Tanque Sur', 'error'); return;
  }

  // Guardar en memoria (respaldo local)
  pr22Registros.push({
    maquinista, fecha, hora, comentarios,
    tanques: {
      norte: norte ? { precinto: preNorte } : null,
      sur:   sur   ? { precinto: preSur   } : null,
    },
    ts: new Date().toLocaleString('es-AR')
  });

  // Deshabilitar botón mientras guarda
  const btn22 = document.getElementById('pr22GuardarBtn');
  if (btn22) { btn22.disabled = true; btn22.textContent = 'Guardando...'; }

  // Enviar a la base de datos
  fetch(`${API_EQUIPOS_URL}?action=pr22_guardar`, {
      credentials: 'same-origin',
    credentials: 'same-origin',
    method : 'POST',
    headers: { 'Content-Type': 'application/json' },
    body   : JSON.stringify({
      fecha, hora, maquinista,
      tanque_norte   : norte ? 1 : 0,
      tanque_sur     : sur   ? 1 : 0,
      precinto_norte : preNorte,
      precinto_sur   : preSur,
      comentarios,
    })
  })
  .then(r => r.json())
  .then(data => {
    if (data.ok) {
      showToast('✅ Formulario PR-22 enviado correctamente');
      setTimeout(() => renderSalaMaquinas(), 1200);
    } else {
      pr6MostrarToast('⚠️ Error: ' + (data.error || ''), 'error');
    }
  })
  .catch(() => {
    pr6MostrarToast('✗ Sin conexión con el servidor', 'error');
  });
}

function pr22MostrarHistorial() {
  const overlay = document.createElement('div');
  overlay.className = 'pr6-hist-overlay';
  overlay.innerHTML = `
    <div class="pr6-hist-modal">
      <div class="pr6-hist-header">
        <span>📋 Historial — PR-22 Limpieza de Tanques</span>
        <button class="pr6-hist-close" id="pr22HClose">✕</button>
      </div>
      <div class="pr6-hist-body" id="pr22HistBody">
        <div style="text-align:center;padding:32px;color:rgba(255,255,255,.5)">Cargando registros...</div>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
  document.getElementById('pr22HClose').addEventListener('click', () => overlay.remove());

  // Cargar desde DB
  fetch(`${API_EQUIPOS_URL}?action=pr22_historial&limite=20`, {credentials:'same-origin'})
  .then(r => { if (!r.ok) throw new Error(`HTTP ${r.status}`); return r.json(); })
  .then(rows => {
    const body = document.getElementById('pr22HistBody');
    if (!body) return;
    if (!Array.isArray(rows)) {
      const msg = rows?.error || JSON.stringify(rows);
      body.innerHTML = `<div style="text-align:center;padding:32px;color:#f87171">Error de API: ${msg}</div>`;
      return;
    }
    if (!rows.length) {
      body.innerHTML = '<div style="text-align:center;padding:32px;color:rgba(255,255,255,.5)">Sin registros aún</div>';
      return;
    }
    body.innerHTML = rows.map(r => {
      const norte = parseInt(r.tanque_norte) === 1;
      const sur   = parseInt(r.tanque_sur)   === 1;
      // Parsear presintos del texto
      const lineas = (r.presinto || '').split('\n');
      const txtNorte = lineas.find(l => l.includes('Norte'))?.replace('Tanque Norte:','').trim() || '—';
      const txtSur   = lineas.find(l => l.includes('Sur'))?.replace('Tanque Sur:','').trim() || '—';
      const obs      = lineas.find(l => l.startsWith('Obs:'))?.replace('Obs:','').trim() || '';
      return `
        <div class="pr6-hist-card">
          <div class="pr6-hist-card-header">
            <span class="pr6-hist-maq">${r.maquinista || '—'}</span>
            <span class="pr6-hist-fecha">${r.fecha} ${r.hora}</span>
          </div>
          <div style="padding:12px 14px;display:flex;flex-direction:column;gap:8px;">
            ${norte ? `<div class="pr22-hist-tanque">
              <span class="pr22-hist-tag pr22-hist-norte">Tanque Norte</span>
              <span>Precinto: <strong>${txtNorte}</strong></span>
            </div>` : ''}
            ${sur ? `<div class="pr22-hist-tanque">
              <span class="pr22-hist-tag pr22-hist-sur">Tanque Sur</span>
              <span>Precinto: <strong>${txtSur}</strong></span>
            </div>` : ''}
            ${obs ? `<div style="font-size:.78rem;color:rgba(255,255,255,.6);font-style:italic">"${obs}"</div>` : ''}
          </div>
          <div class="pr6-hist-footer">Registro #${r.id}</div>
        </div>`;
    }).join('');
  })
  .catch(err => {
    console.error('PR22 historial error:', err);
    // Fallback a registros locales
    const body = document.getElementById('pr22HistBody');
    if (!body) return;
    if (!pr22Registros.length) {
      body.innerHTML = `<div style="text-align:center;padding:32px;color:#f87171">Error: ${err.message}</div>`;
      return;
    }
    body.innerHTML = pr22Registros.slice().reverse().map(r => `
      <div class="pr6-hist-card">
        <div class="pr6-hist-card-header">
          <span class="pr6-hist-maq">${r.maquinista}</span>
          <span class="pr6-hist-fecha">${r.fecha} ${r.hora}</span>
        </div>
        <div class="pr6-hist-footer">Local — ${r.ts}</div>
      </div>`).join('');
  });
  document.getElementById('pr22HClose').addEventListener('click', () => overlay.remove());
}

/* ═══════════════════════════════════════════════════════
   PR-100 DESCONGELADO DE CÁMARAS
   ═══════════════════════════════════════════════════════ */

function renderPR100Descongelado() {
  // PR-100 es ahora una vista de consulta: va directo al historial con gráfico
  renderPR100ConsultaGrafico();
}

let _pr100FiltroDesde = new Date(Date.now() - 30*864e5).toISOString().split('T')[0];
let _pr100FiltroHasta = new Date().toISOString().split('T')[0];
let _pr100CamSelId    = null;

async function renderPR100ConsultaGrafico() {
  setHeader('PR-100 — Descongelado de Cámaras');
  menuGrid.className = 'menu-grid';
  syncBackBtn();

  const hoy   = new Date().toISOString().split('T')[0];
  const hace30= new Date(Date.now()-30*864e5).toISOString().split('T')[0];

  menuGrid.innerHTML = `
    <div class="pr6-wrap" id="pr100ConsultaWrap">

      <div class="pr6-topbar">
        <div class="pr6-topbar-center">
          <span class="pr6-badge-sm">PR-100</span>
          <span class="pr6-topbar-title">Descongelado de Cámaras — Consulta</span>
        </div>
      </div>

      <!-- FILTRO: período + cámara -->
      <div class="pr6-section">
        <div class="pr100-consult-filtros">
          <div class="deshelo-filt-group">
            <label class="deshelo-filt-label">Desde</label>
            <input type="date" id="pr100CDesde" class="deshelo-filt-input" value="${hace30}" />
          </div>
          <div class="deshelo-filt-group">
            <label class="deshelo-filt-label">Hasta</label>
            <input type="date" id="pr100CHasta" class="deshelo-filt-input" value="${hoy}" />
          </div>
          <button class="deshelo-buscar-btn" id="pr100CBuscarBtn">🔍 Buscar</button>
        </div>

        <!-- Chips de cámara -->
        <div class="pr6-camara-chips" id="pr100CChips" style="margin-top:12px">
          ${PR100_CAMARAS.map(c => {
            const label = c.nombre.replace(/^CÁMARA /,'C').replace(/^TÚNEL /,'T');
            return `<button class="pr6-chip" data-id="${c.id}" data-nombre="${c.nombre}" title="${c.nombre}">${label}</button>`;
          }).join('')}
        </div>
      </div>

      <!-- RESUMEN GLOBAL (cuando no hay cámara seleccionada) -->
      <div class="pr6-section" id="pr100GlobalSection">
        <div class="pr6-section-title"><span>📊</span> Resumen por cámara — últimos 30 días</div>
        <div id="pr100GlobalBars">
          <div class="ge-loading" style="padding:10px;font-size:.8rem">Cargando...</div>
        </div>
      </div>

      <!-- GRÁFICO POR CÁMARA (cuando se selecciona una) -->
      <div class="pr6-section" id="pr100CamSection" style="display:none">
        <div class="pr6-section-title" id="pr100CamTitulo"><span>❄️</span> —</div>
        <div id="pr100CamChartArea" class="pr100-cam-chart-wrap" style="height:280px">
          <div class="ge-loading" style="padding:16px;font-size:.8rem">Seleccioná una cámara</div>
        </div>
        <div id="pr100CamPeriodos" style="margin-top:12px"></div>
      </div>

    </div>`;

  // Cargar resumen global
  pr100CargarGlobalBars(hace30, hoy);

  // Click en chip de cámara
  document.getElementById('pr100CChips').addEventListener('click', e => {
    const chip = e.target.closest('[data-id]');
    if (!chip) return;
    document.querySelectorAll('#pr100CChips .pr6-chip').forEach(c => c.classList.remove('active'));
    chip.classList.add('active');
    _pr100CamSelId = parseInt(chip.dataset.id);
    const desde = document.getElementById('pr100CDesde').value;
    const hasta  = document.getElementById('pr100CHasta').value;
    document.getElementById('pr100GlobalSection').style.display = 'none';
    document.getElementById('pr100CamSection').style.display    = '';
    document.getElementById('pr100CamTitulo').innerHTML = '<span>❄️</span> ' + chip.dataset.nombre;
    pr100CargarGraficoCamara(_pr100CamSelId, desde, hasta, 'pr100CamChartArea');
    pr100CargarPeriodosTabla(_pr100CamSelId, desde, hasta);
  });

  // Botón buscar
  document.getElementById('pr100CBuscarBtn').addEventListener('click', () => {
    const desde = document.getElementById('pr100CDesde').value;
    const hasta  = document.getElementById('pr100CHasta').value;
    if (_pr100CamSelId) {
      pr100CargarGraficoCamara(_pr100CamSelId, desde, hasta, 'pr100CamChartArea');
      pr100CargarPeriodosTabla(_pr100CamSelId, desde, hasta);
    } else {
      pr100CargarGlobalBars(desde, hasta);
    }
  });
}

async function pr100CargarPeriodosTabla(camaraId, desde, hasta) {
  const el = document.getElementById('pr100CamPeriodos');
  if (!el) return;
  el.innerHTML = '<div class="ge-loading" style="padding:8px;font-size:.78rem">Cargando períodos...</div>';

  try {
    const r    = await fetch(API_EQUIPOS_URL + '?action=pr100_deshelo_historial&camara_id=' + camaraId + '&desde=' + desde + '&hasta=' + hasta, {credentials:'same-origin'});
    const data = await r.json();
    const list = data.periodos || [];

    if (!list.length) {
      el.innerHTML = '<div style="font-size:.75rem;color:rgba(255,255,255,.3);padding:4px">Sin períodos de deshelo en el período.</div>';
      return;
    }

    const fmtD = (fecha, hora) => {
      if (!fecha) return '—';
      const p = String(fecha).split('-');
      const f = p.length === 3 ? p[2]+'/'+p[1]+'/'+p[0].slice(2) : fecha;
      return f + (hora ? ' ' + String(hora).substring(0,5) : '');
    };
    const fmtDur = min => {
      if (!min || min < 1) return '< 1 min';
      if (min < 60) return min + ' min';
      return Math.floor(min/60) + 'h ' + (min%60 > 0 ? (min%60)+'min':'');
    };

    el.innerHTML =
      '<div style="font-size:.72rem;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:rgba(255,255,255,.35);margin:10px 0 6px">Períodos en deshelo (' + list.length + ')</div>'
      + '<div style="overflow-x:auto">'
      + '<table class="deshelo-table">'
      + '<thead><tr><th>Inicio</th><th>Fin</th><th>Duración</th><th>T° mín</th><th>T° máx</th><th>Lecturas</th></tr></thead>'
      + '<tbody>'
      + list.map(p =>
          '<tr>'
          + '<td style="white-space:nowrap">' + fmtD(p.fecha_inicio, p.hora_inicio) + '</td>'
          + '<td style="white-space:nowrap">' + fmtD(p.fecha_fin, p.hora_fin) + '</td>'
          + '<td style="color:#facc15;font-weight:700">' + fmtDur(p.duracion_min) + '</td>'
          + '<td>' + (p.temp_min !== null ? parseFloat(p.temp_min).toFixed(1)+'°C' : '—') + '</td>'
          + '<td>' + (p.temp_max !== null ? parseFloat(p.temp_max).toFixed(1)+'°C' : '—') + '</td>'
          + '<td style="color:rgba(255,255,255,.4)">' + p.lecturas + '</td>'
          + '</tr>'
        ).join('')
      + '</tbody></table></div>';
  } catch(e) {
    el.innerHTML = '';
  }
}


async function pr100CargarGlobalBars(desde, hasta) {
  const el = document.getElementById('pr100GlobalBars');
  if (!el) return;
  el.innerHTML = '<div class="ge-loading" style="padding:10px;font-size:.8rem">Cargando...</div>';
  try {
    const r    = await fetch(API_EQUIPOS_URL + '?action=pr100_deshelo_historial&desde=' + desde + '&hasta=' + hasta, {credentials:'same-origin'});
    const data = await r.json();
    const list = data.periodos || [];
    if (!list.length) {
      el.innerHTML = '<div style="font-size:.78rem;color:rgba(255,255,255,.35);padding:6px">Sin períodos de deshelo en el período seleccionado.</div>';
      return;
    }
    const fmtDur = min => {
      if (!min || min < 1) return '< 1 min';
      if (min < 60) return min + ' min';
      return Math.floor(min/60) + 'h ' + (min%60 > 0 ? (min%60)+'min' : '');
    };
    const grupos = {};
    list.forEach(p => {
      if (!grupos[p.camara_id]) grupos[p.camara_id] = { nombre: p.camara_nombre, count: 0, durTot: 0 };
      grupos[p.camara_id].count++;
      grupos[p.camara_id].durTot += p.duracion_min || 0;
    });
    const sorted  = Object.values(grupos).sort((a,b) => b.count - a.count);
    const maxCount = sorted[0]?.count || 1;
    el.innerHTML = '<div class="pr100-stats-global">'
      + sorted.map(g => {
          const pct = Math.round(g.count / maxCount * 100);
          return '<div class="pr100-stats-bar-row">'
            + '<span class="pr100-stats-bar-nombre">' + g.nombre.replace('Cámara ','C').replace('Túnel ','T') + '</span>'
            + '<div class="pr100-stats-bar-wrap"><div class="pr100-stats-bar" style="width:' + pct + '%"></div></div>'
            + '<span class="pr100-stats-bar-val">' + g.count + ' período' + (g.count!==1?'s':'')
            + ' <span style="opacity:.4">(' + fmtDur(Math.round(g.durTot/g.count)) + ' prom)</span></span>'
            + '</div>';
        }).join('')
      + '</div>';
  } catch(e) {
    el.innerHTML = '<div style="font-size:.75rem;color:rgba(255,255,255,.35)">Error al cargar.</div>';
  }
}


async function pr100CargarStats(camaraId) {
  const el = document.getElementById('pr100Stats');
  if (!el) return;

  if (!camaraId) {
    // Vista global: barras por cámara
    el.innerHTML = '<div class="ge-loading" style="padding:10px 0;font-size:.8rem">Cargando...</div>';
    const hasta = new Date().toISOString().split('T')[0];
    const desde = new Date(Date.now() - 30*864e5).toISOString().split('T')[0];
    try {
      const r    = await fetch(API_EQUIPOS_URL + '?action=pr100_deshelo_historial&desde=' + desde + '&hasta=' + hasta, {credentials:'same-origin'});
      const data = await r.json();
      const list = data.periodos || [];

      if (!list.length) {
        el.innerHTML = '<div style="font-size:.78rem;color:rgba(255,255,255,.35);padding:6px 0">Sin períodos de deshelo en los últimos 30 días.</div>';
        return;
      }

      const fmtDur = min => {
        if (!min || min < 1) return '< 1 min';
        if (min < 60) return min + ' min';
        return Math.floor(min/60) + 'h ' + (min%60 > 0 ? (min%60)+'min' : '');
      };

      const grupos = {};
      list.forEach(p => {
        const k = p.camara_id;
        if (!grupos[k]) grupos[k] = { nombre: p.camara_nombre, count: 0, durTot: 0 };
        grupos[k].count++;
        grupos[k].durTot += p.duracion_min || 0;
      });
      const sorted = Object.values(grupos).sort((a,b) => b.count - a.count);
      const maxCount = sorted[0]?.count || 1;

      el.innerHTML = '<div class="pr100-stats-global">'
        + sorted.map(g => {
            const pct = Math.round(g.count / maxCount * 100);
            return '<div class="pr100-stats-bar-row">'
              + '<span class="pr100-stats-bar-nombre">' + g.nombre.replace('Cámara ','C').replace('Túnel ','T') + '</span>'
              + '<div class="pr100-stats-bar-wrap"><div class="pr100-stats-bar" style="width:' + pct + '%"></div></div>'
              + '<span class="pr100-stats-bar-val">' + g.count + ' <span style="opacity:.4">(' + fmtDur(Math.round(g.durTot/g.count)) + ' prom)</span></span>'
              + '</div>';
          }).join('')
        + '</div>';
    } catch(e) {
      el.innerHTML = '<div style="font-size:.75rem;color:rgba(255,255,255,.35)">Sin datos disponibles.</div>';
    }
    return;
  }

  // Vista por cámara seleccionada: filtros + gráfico combinado
  el.innerHTML =
    '<div class="pr100-cam-filtros">'
    + '<div class="deshelo-filt-group"><label class="deshelo-filt-label">Desde</label>'
    + '<input type="date" id="pr100StatDesde" class="deshelo-filt-input" value="' + _pr100FiltroDesde + '"/></div>'
    + '<div class="deshelo-filt-group"><label class="deshelo-filt-label">Hasta</label>'
    + '<input type="date" id="pr100StatHasta" class="deshelo-filt-input" value="' + _pr100FiltroHasta + '"/></div>'
    + '<button class="deshelo-buscar-btn" id="pr100StatBuscar">🔍 Buscar</button>'
    + '</div>'
    + '<div id="pr100CamChart" class="pr100-cam-chart-wrap">'
    + '<div class="ge-loading" style="padding:16px;font-size:.8rem">Cargando gráfico...</div>'
    + '</div>';

  document.getElementById('pr100StatBuscar')?.addEventListener('click', () => {
    _pr100FiltroDesde = document.getElementById('pr100StatDesde').value;
    _pr100FiltroHasta = document.getElementById('pr100StatHasta').value;
    pr100CargarGraficoCamara(camaraId, _pr100FiltroDesde, _pr100FiltroHasta);
  });

  pr100CargarGraficoCamara(camaraId, _pr100FiltroDesde, _pr100FiltroHasta);
}

async function pr100CargarGraficoCamara(camaraId, desde, hasta, wrapId) {
  const chartWrap = document.getElementById(wrapId || 'pr100CamChart');
  if (!chartWrap) return;
  chartWrap.innerHTML = '<div class="ge-loading" style="padding:16px;font-size:.8rem">Cargando datos...</div>';

  try {
    await cargarChartJS();
    const r    = await fetch(API_EQUIPOS_URL + '?action=pr100_cam_detalle&camara_id=' + camaraId + '&desde=' + desde + '&hasta=' + hasta, {credentials:'same-origin'});
    const data = await r.json();

    const estados   = data.estados   || [];
    const presiones = data.presiones || [];

    if (!estados.length) {
      chartWrap.innerHTML = '<div style="font-size:.78rem;color:rgba(255,255,255,.35);padding:8px">Sin datos de estado en el período.</div>';
      return;
    }

    // ── Construir etiquetas de tiempo unificadas (fecha+hora) ──
    const allTs = new Set();
    estados.forEach(e   => allTs.add(e.fecha + ' ' + e.hora.slice(0,5)));
    presiones.forEach(p => allTs.add(p.fecha + ' ' + p.hora.slice(0,5)));
    const labels = [...allTs].sort();

    // ── Dataset 1: estado deshelo (1 si en deshelo, 0 si no) ──
    const desheloMap = {};
    estados.forEach(e => {
      const k = e.fecha + ' ' + e.hora.slice(0,5);
      const est = (e.estado||'');
      const estL = est.toLowerCase().replace(/[áàäâ]/g,'a').replace(/[éèëê]/g,'e').replace(/[íìïî]/g,'i').replace(/[óòöô]/g,'o').replace(/[úùüû]/g,'u');
      desheloMap[k] = (estL.includes('eshel') || estL.includes('escongelad')) ? 1 : 0;
    });

    // ── Dataset 2: Temperatura ──
    const tempMap = {};
    estados.forEach(e => { tempMap[e.fecha + ' ' + e.hora.slice(0,5)] = parseFloat(e.temperatura); });

    // ── Datasets 3,4,5: Presiones ──
    const ps30Map = {}, ps40Map = {}, pdMap = {};
    presiones.forEach(p => {
      const k = p.fecha + ' ' + p.hora.slice(0,5);
      if (p.pres_succ_30 !== null) ps30Map[k] = parseFloat(p.pres_succ_30);
      if (p.pres_succ_40 !== null) ps40Map[k] = parseFloat(p.pres_succ_40);
      if (p.pres_desc    !== null) pdMap[k]   = parseFloat(p.pres_desc);
    });

    const hasPresiones = presiones.length > 0;

    // ── Calcular cortes en deshelo para colorear fondo ──
    const bgColors = labels.map(l => {
      const d = desheloMap[l];
      return d === 1 ? 'rgba(250,204,21,0.18)' : 'rgba(34,197,94,0.06)';
    });

    const bgPlugin = {
      id: 'pr100Bg',
      beforeDraw(chart) {
        const { ctx, chartArea: { left, right, top, bottom } } = chart;
        if (!chart.scales.x) return;
        ctx.save();
        const n = bgColors.length;
        if (n < 2) { ctx.restore(); return; }
        const step = (right - left) / n;
        bgColors.forEach((color, i) => {
          ctx.fillStyle = color;
          ctx.fillRect(left + i * step, top, step + 1, bottom - top);
        });
        ctx.restore();
      }
    };

    // ── Formatear labels para mostrar ──
    const shortLabel = l => {
      // Si hay varios días, mostrar dia+hora; si es un día, solo hora
      const [fecha, hora] = l.split(' ');
      return fecha.slice(5).replace('-','/') + ' ' + hora;
    };

    chartWrap.innerHTML =
      '<div class="pr100-cam-chart-leyenda">'
      + '<span class="gcomb-ley-item"><span class="gcomb-ley-dot" style="background:#facc15;opacity:.8;border-radius:2px"></span>Período en deshelo</span>'
      + '<span class="gcomb-ley-item"><span class="gcomb-ley-dot" style="background:#38bdf8"></span>Temperatura (°C)</span>'
      + (hasPresiones
        ? '<span class="gcomb-ley-item"><span class="gcomb-ley-dot" style="background:#a78bfa"></span>P. Succ 30</span>'
          + '<span class="gcomb-ley-item"><span class="gcomb-ley-dot" style="background:#f472b6"></span>P. Succ 40</span>'
          + '<span class="gcomb-ley-item"><span class="gcomb-ley-dot" style="background:#fb923c"></span>P. Desc.</span>'
        : '')
      + '</div>'
      + '<canvas id="pr100CamCanvas"></canvas>';

    const ctx    = document.getElementById('pr100CamCanvas').getContext('2d');
    const lCount = labels.length;
    const maxPts = 200;
    // Decimar si hay demasiados puntos
    const step   = Math.max(1, Math.floor(lCount / maxPts));
    const filtIdx = labels.map((_,i) => i).filter(i => i % step === 0);
    const fLabels = filtIdx.map(i => shortLabel(labels[i]));

    const ds = [
      {
        label: 'Temperatura (°C)',
        data: filtIdx.map(i => tempMap[labels[i]] ?? null),
        borderColor: '#38bdf8', backgroundColor: '#38bdf815',
        borderWidth: 2, pointRadius: lCount > 50 ? 0 : 2,
        tension: 0.3, fill: true, yAxisID: 'yTemp', order: 2,
      },
    ];

    if (hasPresiones) {
      ds.push({
        label: 'Pres. Succ. 30',
        data: filtIdx.map(i => ps30Map[labels[i]] ?? null),
        borderColor: '#a78bfa', borderWidth: 1.5,
        pointRadius: 0, tension: 0.3,
        spanGaps: true, yAxisID: 'yPres', order: 3,
      });
      ds.push({
        label: 'Pres. Succ. 40',
        data: filtIdx.map(i => ps40Map[labels[i]] ?? null),
        borderColor: '#f472b6', borderWidth: 1.5,
        pointRadius: 0, tension: 0.3,
        spanGaps: true, yAxisID: 'yPres', order: 4,
      });
      ds.push({
        label: 'Pres. Desc.',
        data: filtIdx.map(i => pdMap[labels[i]] ?? null),
        borderColor: '#fb923c', borderWidth: 1.5,
        pointRadius: 0, tension: 0.3,
        spanGaps: true, yAxisID: 'yPres', order: 5,
      });
    }

    if (window._pr100Chart) { window._pr100Chart.destroy(); window._pr100Chart = null; }

    window._pr100Chart = new Chart(ctx, {
      type: 'line',
      plugins: [bgPlugin],
      data: { labels: fLabels, datasets: ds },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        interaction: { mode: 'index', intersect: false },
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              label: c => c.dataset.label + ': ' + (c.parsed.y !== null ? c.parsed.y.toFixed(1) : '—')
            }
          }
        },
        scales: {
          x: {
            ticks: { color: 'rgba(255,255,255,.4)', font:{size:9}, maxTicksLimit:12, maxRotation:45 },
            grid:  { color: 'rgba(255,255,255,.06)' }
          },
          yTemp: {
            type: 'linear', position: 'left',
            ticks: { color: '#38bdf8', font:{size:10}, callback: v => v+'°C' },
            grid:  { color: 'rgba(255,255,255,.07)' },
            title: { display: true, text: 'Temperatura', color: '#38bdf8aa', font:{size:10} }
          },
          ...(hasPresiones ? {
            yPres: {
              type: 'linear', position: 'right',
              ticks: { color: '#a78bfa', font:{size:10}, callback: v => v+' bar' },
              grid:  { drawOnChartArea: false },
              title: { display: true, text: 'Presión', color: '#a78bfaaa', font:{size:10} }
            }
          } : {})
        }
      }
    });

  } catch(e) {
    if (chartWrap) chartWrap.innerHTML = '<div style="font-size:.75rem;color:#f87171;padding:8px">Error: ' + e.message + '</div>';
  }
}


function pr100Guardar() {
  const maquinista = document.getElementById('pr100Maquinista').value;
  const fecha      = document.getElementById('pr100Fecha').value;
  const camara     = document.getElementById('pr100Camara').value;
  const horaInicio = document.getElementById('pr100HoraInicio').value;
  const horaFin    = document.getElementById('pr100HoraFin').value;
  const frecuencia = document.getElementById('pr100Frecuencia').value;
  const presDesc   = document.getElementById('pr100PresDesc').value;
  const presAsp    = document.getElementById('pr100PresAsp').value;
  const obs        = document.getElementById('pr100Obs').value.trim();

  if (!camara)     { pr6MostrarToast('Seleccioná una cámara', 'error'); return; }
  if (!horaInicio) { pr6MostrarToast('Ingresá la hora de inicio', 'error'); return; }
  if (!horaFin)    { pr6MostrarToast('Ingresá la hora de fin', 'error'); return; }

  pr100Registros.push({ maquinista, fecha, camara, horaInicio, horaFin, frecuencia, presDesc, presAsp, obs, ts: new Date().toLocaleString('es-AR') });
  pr6MostrarToast('✓ Registro guardado correctamente', 'ok');
  setTimeout(() => renderPR100Descongelado(), 1400);
}

