async function cargarDesheloHistorial(desde, hasta, camaraId) {
  const resEl = document.getElementById('desheloResultados');
  if (!resEl) return;
  resEl.innerHTML = '<div class="deshelo-loading"><div class="cam-spin"></div><span>Cargando registros...</span></div>';

  let url = `${API_EQUIPOS_URL}?action=pr100_deshelo_historial&desde=${desde}&hasta=${hasta}`;
  if (camaraId) url += `&camara_id=${camaraId}`;

  try {
    const r    = await fetch(url, { credentials: 'same-origin' });
    const data = await r.json();
    const list = data.periodos || [];

    if (!list.length) {
      resEl.innerHTML = '<div class="deshelo-empty">Sin períodos de deshelo en el rango seleccionado.</div>';
      return;
    }

    // Agrupar por cámara
    const grupos = {};
    list.forEach(p => {
      const k = p.camara_nombre;
      if (!grupos[k]) grupos[k] = { nombre: p.camara_nombre, numero: p.camara_numero, periodos: [] };
      grupos[k].periodos.push(p);
    });

    const fmtDt = (fecha, hora) => {
      if (!fecha) return '—';
      // Format directly from strings to avoid timezone issues
      const partes = String(fecha).split('-');
      const fechaFmt = partes.length === 3 ? partes[2] + '/' + partes[1] + '/' + partes[0].slice(2) : fecha;
      return fechaFmt + (hora ? ' ' + String(hora).substring(0,5) : '');
    };

    const fmtDur = (min) => {
      if (!min || min < 1) return '< 1 min';
      if (min < 60) return min + ' min';
      const h = Math.floor(min / 60);
      const m = min % 60;
      return h + 'h' + (m > 0 ? ' ' + m + 'min' : '');
    };

    resEl.innerHTML = '<div class="deshelo-resumen">Total: <strong>' + list.length
      + '</strong> período' + (list.length !== 1 ? 's' : '')
      + ' en <strong>' + Object.keys(grupos).length + '</strong> cámara'
      + (Object.keys(grupos).length !== 1 ? 's' : '')
      + ' — ' + desde + ' al ' + hasta
      + '</div>'
      + Object.values(grupos).sort((a,b) => a.numero - b.numero).map(g => `
        <div class="deshelo-cam-group">
          <div class="deshelo-cam-header">
            <span class="deshelo-cam-nombre">❄️ ${g.nombre}</span>
            <span class="deshelo-cam-count">${g.periodos.length} período${g.periodos.length !== 1 ? 's' : ''}</span>
          </div>
          <div class="deshelo-table-wrap">
            <table class="deshelo-table">
              <thead>
                <tr>
                  <th>Inicio</th>
                  <th>Fin</th>
                  <th>Duración</th>
                  <th>Temp. mín.</th>
                  <th>Temp. máx.</th>
                  <th>Estado</th>
                  <th>Lecturas</th>
                </tr>
              </thead>
              <tbody>
                ${g.periodos.map(p => `
                  <tr>
                    <td style="white-space:nowrap">${fmtDt(p.fecha_inicio, p.hora_inicio)}</td>
                    <td style="white-space:nowrap">${fmtDt(p.fecha_fin, p.hora_fin)}</td>
                    <td style="color:#facc15;font-weight:700">${fmtDur(p.duracion_min)}</td>
                    <td>${p.temp_min !== null ? parseFloat(p.temp_min).toFixed(1) + '°C' : '—'}</td>
                    <td>${p.temp_max !== null ? parseFloat(p.temp_max).toFixed(1) + '°C' : '—'}</td>
                    <td style="font-size:.7rem;color:rgba(255,255,255,.55)">${p.estado}</td>
                    <td style="color:rgba(255,255,255,.4);font-size:.72rem">${p.lecturas}</td>
                  </tr>`).join('')}
              </tbody>
            </table>
          </div>
        </div>`).join('');

  } catch(e) {
    resEl.innerHTML = '<div class="deshelo-empty">Error al cargar: ' + e.message + '</div>';
  }
}

function pr100MostrarHistorial() {
  if (!pr100Registros.length) { pr6MostrarToast('No hay registros guardados aún', 'info'); return; }
  const overlay = document.createElement('div');
  overlay.className = 'pr6-hist-overlay';
  overlay.innerHTML = `
    <div class="pr6-hist-modal">
      <div class="pr6-hist-header">
        <span>📋 Historial — PR-100 Descongelado</span>
        <button class="pr6-hist-close" id="pr100HClose">✕</button>
      </div>
      <div class="pr6-hist-body">
        ${pr100Registros.slice().reverse().map(r => `
          <div class="pr6-hist-card">
            <div class="pr6-hist-card-header">
              <span class="pr6-hist-maq">${r.maquinista}</span>
              <span class="pr22-hist-tag pr22-hist-norte">${r.camara}</span>
              <span class="pr6-hist-fecha">${r.fecha}</span>
            </div>
            <div style="padding:12px 14px;">
              <table class="pr6-hist-table">
                <thead><tr>
                  <th>H. Inicio</th><th>H. Fin</th><th>Frec.</th><th>Pres. Desc.</th><th>Pres. Asp.</th><th style="text-align:left">Observaciones</th>
                </tr></thead>
                <tbody><tr>
                  <td>${r.horaInicio||'—'}</td>
                  <td>${r.horaFin||'—'}</td>
                  <td>${r.frecuencia||'—'}</td>
                  <td>${r.presDesc||'—'}</td>
                  <td>${r.presAsp||'—'}</td>
                  <td style="text-align:left">${r.obs||'—'}</td>
                </tr></tbody>
              </table>
            </div>
            <div class="pr6-hist-footer">Guardado: ${r.ts}</div>
          </div>`).join('')}
      </div>
    </div>`;
  document.body.appendChild(overlay);
  overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
  document.getElementById('pr100HClose').addEventListener('click', () => overlay.remove());
}

