let clientesCache       = [];   // lista paginada actual
let clientesBusqueda    = '';
let clientesFiscal      = 0;    // 0=Nacional, 1=Fiscal
let clientesPagina      = 1;
let clientesTotalPags   = 1;
let clienteDetalle      = null; // cliente abierto en ficha

/* ── Entrada al módulo ──────────────────────────────────────── */
