/* ── Utilidad: escapar HTML ───────────────────────────────────── */
function _pr24Esc(s) {
  return String(s || '')
    .replace(/&/g, '&amp;')
    .replace(/"/g, '&quot;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}
/* ══════════════════════════════════════════════════════════════════════
   PR-30 — CONTROL SALA DE MÁQUINAS
   ══════════════════════════════════════════════════════════════════════
   Integrar en app.js:
   - Reemplazar la línea:
       case 'pr30': openModule('https://...'); break;
     por:
       case 'pr30': historyStack.push({__sdmBack:true}); renderPR30Guardia(); break;
   - Agregar en renderNode (junto a los demás ifs de PR):
       if (item.title === 'PR 30 LIBRO DE GUARDIA') { historyStack.push(node); renderPR30Guardia(); return; }
   ══════════════════════════════════════════════════════════════════════ */

let _pr30FiltroFecha = '';
let _pr30FormDatos   = null;  // cache de cámaras + última presión

/* ══════════════════════════════════════════════════════════════════
   VISTA PRINCIPAL — GRILLA DE TURNOS DEL DÍA
   ══════════════════════════════════════════════════════════════════ */
/* ── Helpers: turno y control número actual según hora ─────── */
function _pr30TurnoActual() {
  const h = new Date().getHours();
  if (h >= 6  && h < 14) return 'MAÑANA';
  if (h >= 14 && h < 22) return 'TARDE';
  return 'NOCHE';
}
function _pr30ControlActual() {
  const h = new Date().getHours();
  const m = new Date().getMinutes();
  const mins = h * 60 + m;
  // MAÑANA: 06:30, 10:00, 13:30 | TARDE: 14:30, 18:00, 21:30 | NOCHE: 22:30, 02:00, 05:30
  const horarios = {
    MAÑANA: [[6,30],[10,0],[13,30]],
    TARDE:  [[14,30],[18,0],[21,30]],
    NOCHE:  [[22,30],[26,0],[29,30]], // 26:00 = 02:00 next day
  };
  const turno = _pr30TurnoActual();
  const slots = horarios[turno];
  // Retornar el control más próximo (el que está activo o el siguiente)
  for (let i = 0; i < slots.length; i++) {
    const slotMins = slots[i][0] * 60 + slots[i][1];
    if (mins < slotMins + 120) return i + 1; // dentro de las 2hs siguientes
  }
  return 3; // fallback al último
}

async function renderPR30Guardia() {
  setHeader('PR-30 — Control Sala de Máquinas');
  setExpandedMode(true);
  showMetaPanel(false);
  menuGrid.className = 'menu-grid';
  menuGrid.innerHTML = `<div style="padding:32px;text-align:center;color:rgba(255,255,255,.4)">Cargando...</div>`;
  syncBackBtn();

  if (!_pr30FiltroFecha) {
    _pr30FiltroFecha = new Date().toISOString().split('T')[0];
  }
  await _pr30RenderGrilla();
}

async function _pr30RenderGrilla() {
  let rows = [];
  try {
    const res = await fetch(`${API_EQUIPOS_URL}?action=pr30_grilla&fecha=${_pr30FiltroFecha}`, { credentials: 'same-origin' });
    if (res.status === 401) { showToast('Sesión expirada', 'error'); return; }
    rows = await res.json();
    if (!Array.isArray(rows)) rows = [];
  } catch(e) { rows = []; }

  // Fecha display
  const [y,m,d] = _pr30FiltroFecha.split('-');
  const fechaDisplay = `${d}-${m}-${y}`;

  // Agrupar por turno para separadores visuales
  const turnos = ['MAÑANA','TARDE','NOCHE'];
  let tbody = '';
  let prevTurno = null;
  for (const r of rows) {
    if (r.turno !== prevTurno) {
      if (prevTurno !== null) tbody += `<tr><td colspan="7" class="pr30-sep-turno"></td></tr>`;
      prevTurno = r.turno;
    }
    const turnoLabel = `${fechaDisplay} ${r.turno}`;
    const horaReal   = r.hora_real || '';
    const maq        = r.maquinista_nombre ? _pr30Esc(r.maquinista_nombre) : '';
    const verif      = r.verificado ? '<span style="color:#22c55e;font-weight:700">Si</span>'
                                    : '<span style="color:rgba(255,255,255,.3)">—</span>';
    const accion = r.tiene_registro
      ? `<button class="pr30-btn-ver"  data-id="${r.id}">👁 Ver</button>
         <button class="pr30-btn-edit" data-id="${r.id}" data-turno="${r.turno}" data-num="${r.control_num}">✏️</button>`
      : `<button class="pr30-btn-nuevo" data-turno="${r.turno}" data-num="${r.control_num}">+ Control</button>`;

    tbody += `<tr>
      <td>${turnoLabel}</td>
      <td style="text-align:center">${r.control_num}</td>
      <td style="text-align:center">${r.hora_prevista}</td>
      <td style="text-align:center">${horaReal}</td>
      <td>${maq}</td>
      <td style="text-align:center">${verif}</td>
      <td style="text-align:right">${accion}</td>
    </tr>`;
  }
  if (!tbody) tbody = `<tr><td colspan="7" style="text-align:center;padding:32px;color:rgba(255,255,255,.35)">Sin datos para esta fecha</td></tr>`;

  menuGrid.innerHTML = `
    <div class="pr24-wrap">
      <div class="pr24-topbar">
        <div class="pr24-topbar-title">
          <span class="pr24-badge">PR-30</span>
          Control Sala de Máquinas
        </div>
        <div class="pr24-topbar-actions">
          <input type="date" class="pr24-filtro-fecha" id="pr30FFecha" value="${_pr30FiltroFecha}">
          <button class="pr24-btn-buscar" id="pr30BIr">🔍 Ir</button>
          <button class="pr24-btn-pdf"    id="pr30BPDF" title="Imprimir PR-30">PR30 📄</button>
        </div>
      </div>

      <div class="pr24-tabla-wrap">
        <table class="pr24-tabla">
          <thead>
            <tr>
              <th>Turno</th>
              <th style="text-align:center">Control</th>
              <th style="text-align:center">Hora Prevista</th>
              <th style="text-align:center">Hora Real</th>
              <th>Maquinista</th>
              <th style="text-align:center">Verificado</th>
              <th></th>
            </tr>
          </thead>
          <tbody id="pr30Tbody">${tbody}</tbody>
        </table>
      </div>
    </div>`;

  // Eventos
  document.getElementById('pr30BIr').addEventListener('click', () => {
    _pr30FiltroFecha = document.getElementById('pr30FFecha').value || new Date().toISOString().split('T')[0];
    _pr30RenderGrilla();
  });
  document.getElementById('pr30FFecha').addEventListener('change', e => {
    _pr30FiltroFecha = e.target.value;
    _pr30RenderGrilla();
  });
  document.getElementById('pr30BPDF').addEventListener('click', () => pr30ImprimirPDF());

  document.querySelectorAll('.pr30-btn-nuevo').forEach(btn => {
    btn.addEventListener('click', () => pr30AbrirFormulario(null, btn.dataset.turno, parseInt(btn.dataset.num)));
  });
  document.querySelectorAll('.pr30-btn-edit').forEach(btn => {
    btn.addEventListener('click', () => pr30AbrirFormulario(parseInt(btn.dataset.id), btn.dataset.turno, parseInt(btn.dataset.num)));
  });
  document.querySelectorAll('.pr30-btn-ver').forEach(btn => {
    btn.addEventListener('click', () => pr30VerDetalle(parseInt(btn.dataset.id)));
  });
}

/* ══════════════════════════════════════════════════════════════════
   FORMULARIO DE CARGA
   ══════════════════════════════════════════════════════════════════ */
async function pr30AbrirFormulario(id, turno, controlNum) {
  setExpandedMode(true);
  syncBackBtn();
  menuGrid.innerHTML = `<div style="padding:32px;text-align:center;color:rgba(255,255,255,.4)">Cargando datos...</div>`;

  // Cargar datos del formulario (cámaras + presión)
  if (!_pr30FormDatos) {
    try {
      const res = await fetch(`${API_EQUIPOS_URL}?action=pr30_form_datos`, { credentials: 'same-origin' });
      _pr30FormDatos = await res.json();
    } catch(e) { _pr30FormDatos = { camaras: [], presion: null }; }
  }

  // Cargar registro existente si es edición
  let reg = null;
  if (id) {
    try {
      const res = await fetch(`${API_EQUIPOS_URL}?action=pr30_detalle&id=${id}`, { credentials: 'same-origin' });
      reg = await res.json();
    } catch(e) {}
  }

  const isNuevo = !id;
  const ahora   = new Date();
  const hhNow   = String(ahora.getHours()).padStart(2,'0');
  const mmNow   = String(ahora.getMinutes()).padStart(2,'0');
  const horaReal= reg?.cabecera?.hora_real ? reg.cabecera.hora_real.substring(0,5) : `${hhNow}:${mmNow}`;
  const [hhV, mmV] = horaReal.split(':');

  // ── MAQUINISTA: bloqueado al usuario actual para nuevos ──────
  const maqActualId  = perfilData.persona_id;
  const maqActualNom = perfilData.usuario || perfilData.nombre || '—';

  let maqField;
  if (isNuevo) {
    maqField = `
      <div class="pr24-form-group" style="flex:1;min-width:220px">
        <label class="pr24-form-label">Maquinista</label>
        <div style="padding:9px 12px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.12);
          border-radius:9px;font-size:.88rem;color:rgba(255,255,255,.7);font-weight:600">
          👤 ${_pr30Esc(maqActualNom)}
        </div>
        <input type="hidden" id="pr30FMaq" value="${maqActualId || ''}">
      </div>`;
  } else {
    const optMaq = PR6_MAQUINISTAS.map(m => {
      const sel = reg?.cabecera?.maquinista_id == m.persona_id ? 'selected' : '';
      return `<option value="${m.persona_id}" ${sel}>${_pr30Esc((m.apellido||'') + ', ' + (m.nombre||''))}</option>`;
    }).join('');
    maqField = `
      <div class="pr24-form-group" style="flex:1;min-width:220px">
        <label class="pr24-form-label">Maquinista</label>
        <select class="pr24-form-select" id="pr30FMaq">
          <option value="">— Seleccioná —</option>
          ${optMaq}
        </select>
      </div>`;
  }

  // ── HORA: bloqueada para nuevos ──────────────────────────────
  const horaField = isNuevo
    ? `<div class="pr24-form-group">
        <label class="pr24-form-label">Hora Real</label>
        <div style="padding:9px 12px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.12);
          border-radius:9px;font-size:.88rem;color:rgba(255,255,255,.7);min-width:80px">
          🕐 ${hhV}:${mmV}
        </div>
        <input type="hidden" id="pr30FHH" value="${hhV}">
        <input type="hidden" id="pr30FMM" value="${mmV}">
      </div>`
    : `<div class="pr24-form-group">
        <label class="pr24-form-label">Hora Real</label>
        <div style="display:flex;gap:6px;align-items:center">
          <select class="pr24-form-select pr24-hora-sel" id="pr30FHH">
            ${Array.from({length:24},(_,i)=>{const v=String(i).padStart(2,'0'); return `<option value="${v}" ${v===hhV?'selected':''}>${v}</option>`;}).join('')}
          </select>
          <span style="color:rgba(255,255,255,.5);font-weight:900">:</span>
          <select class="pr24-form-select pr24-hora-sel" id="pr30FMM">
            ${Array.from({length:60},(_,i)=>{const v=String(i).padStart(2,'0'); return `<option value="${v}" ${v===mmV?'selected':''}>${v}</option>`;}).join('')}
          </select>
        </div>
      </div>`;

  // ── CÁMARAS: con estado por defecto en observaciones ─────────
  const camaraMap = {};
  (reg?.camaras || []).forEach(c => { camaraMap[c.camara_id] = c; });

  const ESTADOS_CAM = ['Normal','Inyectando','Descongelando','Con hielo','Sin inyección','Fuera de servicio','Mantenimiento'];
  const camarasHTML = (_pr30FormDatos.camaras || []).map(cam => {
    const saved   = camaraMap[cam.CamaraID] || {};
    const tempVal = saved.temperatura !== undefined && saved.temperatura !== null ? saved.temperatura : '';
    // Observación: si hay guardado usar eso, sino usar el estado SCADA actual
    const estadoScada = (cam.temp_estado || '').trim();
    const obsDefault  = saved.observaciones || estadoScada || '';
    const setpStr = cam.setpoint != null ? Number(cam.setpoint).toFixed(2) + ' °C' : '—';
    const optsObs = ESTADOS_CAM.map(e =>
      `<option value="${e}" ${obsDefault === e ? 'selected' : ''}>${e}</option>`
    ).join('');
    return `
      <tr class="pr30-cam-row" data-camara-id="${cam.CamaraID}">
        <td class="pr30-cam-nombre">${_pr30Esc(cam.nombre_display)}</td>
        <td class="pr30-cam-setpoint" style="color:#36B0C9;font-weight:700">${setpStr}</td>
        <td class="pr30-cam-setpoint">${setpStr}</td>
        <td class="pr30-cam-setpoint">${setpStr}</td>
        <td>
          <div style="display:flex;align-items:center;gap:4px">
            <input type="number" class="pr30-temp-input" data-camara-id="${cam.CamaraID}"
              value="${_pr30Esc(String(tempVal))}" placeholder="—" step="0.1" style="width:80px">
            <span style="font-size:.72rem;color:rgba(255,255,255,.4)">°C</span>
          </div>
        </td>
        <td>
          <select class="pr30-obs-select" data-camara-id="${cam.CamaraID}">
            <option value=""></option>
            ${optsObs}
          </select>
        </td>
      </tr>`;
  }).join('');

  // ── PRESIONES ────────────────────────────────────────────────
  const pMap = {};
  (reg?.presiones || []).forEach(p => { pMap[p.sistema] = p; });
  const presDB = _pr30FormDatos.presion || {};
  const presSCADA = {
    '-30': { asp: presDB.pres_succ_30 ?? '', desc: presDB.pres_desc ?? '' },
    '-40': { asp: presDB.pres_succ_40 ?? '', desc: presDB.pres_desc ?? '' },
    '-10': { asp: '', desc: '' },
  };
  const presHTML = ['-10','-30','-40'].map(sis => {
    const saved = pMap[sis];
    const aspVal  = saved ? (saved.aspiracion ?? '') : (presSCADA[sis]?.asp ?? '');
    const descVal = saved ? (saved.descarga   ?? '') : (presSCADA[sis]?.desc ?? '');
    return `
      <tr>
        <td style="font-size:.82rem;font-weight:700;color:rgba(255,255,255,.6)">Sistema ${sis}</td>
        <td><input type="number" class="pr30-pres-input" data-sistema="${sis}" data-tipo="asp"
          value="${aspVal}" placeholder="—" step="0.01" style="width:90px"></td>
        <td><input type="number" class="pr30-pres-input" data-sistema="${sis}" data-tipo="desc"
          value="${descVal}" placeholder="—" step="0.01" style="width:90px"></td>
      </tr>`;
  }).join('');

  // ── EQUIPOS DESDE mantEquiposCache ──────────────────────────
  // Condensadores: subcategoria = 'condensador'
  const equipCondensadores = mantEquiposCache.filter(e =>
    e.activo != 0 && (e.subcategoria || '').toLowerCase().includes('condensador') &&
    !(e.subcategoria || '').toLowerCase().includes('parte')
  ).sort((a,b) => a.nombre.localeCompare(b.nombre));

  // Partes de condensadores: subcategoria = 'partes_condensadores'
  const equipPartesCond = mantEquiposCache.filter(e =>
    e.activo != 0 && (e.subcategoria || '').toLowerCase().replace(/\s/g,'_').includes('partes')
  ).sort((a,b) => a.nombre.localeCompare(b.nombre));

  // Compresores: subcategoria = 'compresor' o 'compresores'
  const equipCompresores = mantEquiposCache.filter(e =>
    e.activo != 0 && (e.subcategoria || '').toLowerCase().includes('compresor')
  ).sort((a,b) => a.nombre.localeCompare(b.nombre));

  // Fallback fijo si no hay datos de DB todavía
  const condensadoresFijos = equipCondensadores.length > 0
    ? equipCondensadores
    : [{ id:'c1', nombre:'Condensador 01' }, { id:'c2', nombre:'Condensador 02' }, { id:'c3', nombre:'Condensador 03' }];

  const bombasVentFijos = equipPartesCond.length > 0
    ? equipPartesCond
    : [
        { id:'b1', nombre:'Bomba 1' }, { id:'b2', nombre:'Bomba 2' },
        { id:'v1', nombre:'Vent. Grupo 1' }, { id:'v2', nombre:'Vent. Grupo 2' }
      ];

  const compresoresFijos = equipCompresores.length > 0
    ? equipCompresores
    : [
        { id:'f1', nombre:'Frick 01' }, { id:'f2', nombre:'Frick 02' },
        { id:'g1', nombre:'Gram 01' },  { id:'g2', nombre:'Gram 02' },
        { id:'l1', nombre:'Luciano' }
      ];

  // Tabla condensadores: filas = condensadores, columnas = bombas+ventiladores
  const condMap = {};
  (reg?.condensadores || []).forEach(c => { condMap[c.numero] = c; });

  // Usar ID del equipo como clave, guardado en data-num
  const partesLabels = bombasVentFijos.map(p => `<th style="text-align:center;white-space:nowrap">${_pr30Esc(p.nombre)}</th>`).join('');
  const condHTML = condensadoresFijos.map((cond, idx) => {
    const num = idx + 1;
    const cSaved = condMap[num] || {};
    const partesCells = bombasVentFijos.map((parte, pi) => {
      const fieldKey = `parte_${pi}`;
      const checked  = cSaved[fieldKey] == 1 ? 'checked' : '';
      return `<td style="text-align:center">
        <input type="checkbox" class="pr30-cond-cb" data-num="${num}" data-field="${fieldKey}" ${checked}>
      </td>`;
    }).join('');
    return `<tr>
      <td style="font-size:.82rem;color:rgba(255,255,255,.7);white-space:nowrap">${_pr30Esc(cond.nombre)}</td>
      ${partesCells}
    </tr>`;
  }).join('');

  // Tabla compresores
  const COMP_COLS = ['Horas','Potencia KW.','Consumo Amp.','Consumo %','Capacidad %','Presión Aceite','Dif. Aceite'];
  const compMap = {};
  (reg?.compresores || []).forEach(c => { compMap[c.equipo_id] = c; });
  const compHTML = compresoresFijos.map(comp => {
    const c = compMap[comp.id] || {};
    return `<tr class="pr30-comp-row" data-comp-id="${comp.id}">
      <td style="font-size:.82rem;color:rgba(255,255,255,.7);white-space:nowrap">${_pr30Esc(comp.nombre)}</td>
      ${COMP_COLS.map((col, ci) => {
        const fieldKey = `col${ci}`;
        return `<td><input type="number" class="pr30-comp-input" data-comp-id="${comp.id}" data-col="${ci}"
          value="${c[fieldKey] !== undefined ? c[fieldKey] : ''}" placeholder="—"
          step="any" style="width:80px"></td>`;
      }).join('')}
    </tr>`;
  }).join('');

  const verificado = reg?.cabecera?.verificado == 1;
  const turnoLabel = `${turno} — Control ${controlNum}`;

  menuGrid.innerHTML = `
    <div class="pr24-wrap">
      <div class="pr24-topbar">
        <div class="pr24-topbar-title">
          <span class="pr24-badge">PR-30</span>
          ${id ? 'Editar' : 'Nuevo'} Control — ${_pr30FiltroFecha.split('-').reverse().join('/')} ${turnoLabel}
        </div>
        <button class="pr24-btn-volver" id="pr30BVolver">← Volver</button>
      </div>

      <div class="pr24-form-scroll">
        <div style="display:flex;flex-direction:column;gap:18px;max-width:1100px">

          <!-- Meta: maquinista + hora + verificado -->
          <div class="pr24-form-card" style="flex-direction:row;flex-wrap:wrap;gap:18px">
            ${maqField}
            ${horaField}
            <div class="pr24-form-group" style="justify-content:center">
              <label class="pr24-form-label">Verificado</label>
              <label class="pr24-check-label" style="padding-top:6px">
                <input type="checkbox" id="pr30FVerif" ${verificado ? 'checked' : ''}>
                Conforme
              </label>
            </div>
          </div>

          <!-- CÁMARAS -->
          <div style="background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.14);border-radius:14px;overflow:hidden">
            <div style="padding:13px 18px;border-bottom:1px solid rgba(255,255,255,.1);font-size:.82rem;font-weight:800;color:rgba(255,255,255,.6);text-transform:uppercase;letter-spacing:.5px">❄️ Temperaturas de Cámaras</div>
            <div style="overflow-x:auto">
              <table class="pr24-tabla" style="min-width:700px">
                <thead><tr><th>Cámara</th><th>Set Point</th><th>Req. Logística</th><th>Control HACCP</th><th>Temperatura</th><th>Observaciones</th></tr></thead>
                <tbody>${camarasHTML}</tbody>
              </table>
            </div>
          </div>

          <!-- PRESIONES -->
          <div style="background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.14);border-radius:14px;overflow:hidden">
            <div style="padding:13px 18px;border-bottom:1px solid rgba(255,255,255,.1);font-size:.82rem;font-weight:800;color:rgba(255,255,255,.6);text-transform:uppercase;letter-spacing:.5px">🔩 Presiones</div>
            <div style="overflow-x:auto;padding:12px 18px">
              <table class="pr24-tabla" style="min-width:400px">
                <thead><tr><th>Sistema</th><th>Aspiración</th><th>Descarga</th></tr></thead>
                <tbody>${presHTML}</tbody>
              </table>
              ${presDB.fecha ? `<div style="font-size:.68rem;color:rgba(255,255,255,.3);margin-top:8px">Último dato SCADA: ${presDB.fecha} ${(presDB.hora||'').substring(0,5)}</div>` : ''}
            </div>
          </div>

          <!-- CONDENSADORES -->
          <div style="background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.14);border-radius:14px;overflow:hidden">
            <div style="padding:13px 18px;border-bottom:1px solid rgba(255,255,255,.1);font-size:.82rem;font-weight:800;color:rgba(255,255,255,.6);text-transform:uppercase;letter-spacing:.5px">🌀 Condensadores</div>
            <div style="overflow-x:auto">
              <table class="pr24-tabla" style="min-width:500px">
                <thead><tr><th>Condensador</th>${partesLabels}</tr></thead>
                <tbody>${condHTML}</tbody>
              </table>
            </div>
          </div>

          <!-- COMPRESORES -->
          <div style="background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.14);border-radius:14px;overflow:hidden">
            <div style="padding:13px 18px;border-bottom:1px solid rgba(255,255,255,.1);font-size:.82rem;font-weight:800;color:rgba(255,255,255,.6);text-transform:uppercase;letter-spacing:.5px">⚙️ Compresores</div>
            <div style="overflow-x:auto">
              <table class="pr24-tabla" style="min-width:800px">
                <thead><tr><th>Compresor</th>${COMP_COLS.map(c=>`<th>${_pr30Esc(c)}</th>`).join('')}</tr></thead>
                <tbody>${compHTML}</tbody>
              </table>
            </div>
          </div>

          <!-- Observaciones generales -->
          <div class="pr24-form-card">
            <label class="pr24-form-label">Observaciones generales del control</label>
            <textarea class="pr24-form-textarea" id="pr30FObs" rows="3"
              placeholder="Observaciones adicionales del turno...">${_pr30Esc(reg?.cabecera?.observaciones || '')}</textarea>
          </div>

          <div id="pr30FMsg" style="min-height:18px;font-size:.84rem;color:#f87171"></div>

          <div class="pr6-actions" style="padding-bottom:24px">
            <button class="pr6-guardar-btn" id="pr30FSave">💾 Guardar Control</button>
          </div>

        </div>
      </div>
    </div>`;

  document.getElementById('pr30BVolver').addEventListener('click', () => _pr30RenderGrilla());
  document.getElementById('pr30FSave').addEventListener('click',  () => _pr30Guardar(id, turno, controlNum));
}

/* ── Guardar ──────────────────────────────────────────────────── */
async function _pr30Guardar(id, turno, controlNum) {
  const maquinistaId = document.getElementById('pr30FMaq').value;
  const hh           = document.getElementById('pr30FHH').value;
  const mm           = document.getElementById('pr30FMM').value;
  const verificado   = document.getElementById('pr30FVerif').checked ? 1 : 0;
  const observaciones= document.getElementById('pr30FObs').value.trim();
  const msgEl        = document.getElementById('pr30FMsg');

  if (!maquinistaId) { msgEl.textContent = '⚠ Seleccioná el maquinista.'; return; }

  // Leer cámaras
  const camaras = [];
  document.querySelectorAll('.pr30-cam-row').forEach(row => {
    const camaraId = parseInt(row.dataset.camaraId);
    const temp     = row.querySelector('.pr30-temp-input')?.value ?? '';
    const obs      = row.querySelector('.pr30-obs-select')?.value ?? '';
    camaras.push({ camara_id: camaraId, temperatura: temp !== '' ? temp : null, observaciones: obs || null });
  });

  // Leer presiones
  const presMap = {};
  document.querySelectorAll('.pr30-pres-input').forEach(inp => {
    const sis  = inp.dataset.sistema;
    const tipo = inp.dataset.tipo;
    if (!presMap[sis]) presMap[sis] = { sistema: sis };
    presMap[sis][tipo === 'asp' ? 'aspiracion' : 'descarga'] = inp.value !== '' ? inp.value : null;
  });
  const presiones = Object.values(presMap);

  // Leer condensadores (campos dinámicos parte_N)
  const condMap = {};
  document.querySelectorAll('.pr30-cond-cb').forEach(cb => {
    const num   = parseInt(cb.dataset.num);
    const field = cb.dataset.field;
    if (!condMap[num]) condMap[num] = { numero: num };
    condMap[num][field] = cb.checked ? 1 : 0;
  });
  const condensadores = Object.values(condMap);

  // Leer compresores
  const compMapG = {};
  document.querySelectorAll('.pr30-comp-input').forEach(inp => {
    const cid = inp.dataset.compId;
    const col = `col${inp.dataset.col}`;
    if (!compMapG[cid]) compMapG[cid] = { equipo_id: cid };
    compMapG[cid][col] = inp.value !== '' ? inp.value : null;
  });
  const compresores = Object.values(compMapG);

  const btn = document.getElementById('pr30FSave');
  btn.disabled = true; btn.textContent = 'Guardando...';

  try {
    const res = await fetch(`${API_EQUIPOS_URL}?action=pr30_guardar`, {
      method: 'POST', credentials: 'same-origin',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        id: id || null,
        fecha: _pr30FiltroFecha, turno, control_num: controlNum,
        hora_real: `${hh}:${mm}`,
        maquinista_id: maquinistaId, verificado, observaciones,
        camaras, presiones, condensadores, compresores,
      })
    });
    const data = await res.json();
    if (data.ok) {
      showToast('✅ Formulario PR-30 enviado correctamente');
      setTimeout(() => renderSalaMaquinas(), 1200);
    } else {
      msgEl.textContent = '✗ ' + (data.error || 'Error al guardar');
      btn.disabled = false; btn.textContent = '💾 Guardar Control';
    }
  } catch(e) {
    msgEl.textContent = '✗ Sin conexión con el servidor';
    btn.disabled = false; btn.textContent = '💾 Guardar Control';
  }
}

/* ══════════════════════════════════════════════════════════════════
   VER DETALLE
   ══════════════════════════════════════════════════════════════════ */
async function pr30VerDetalle(id) {
  let data = null;
  try {
    const res = await fetch(`${API_EQUIPOS_URL}?action=pr30_detalle&id=${id}`, { credentials: 'same-origin' });
    data = await res.json();
    if (data.error) { pr6MostrarToast('Error al cargar', 'error'); return; }
  } catch(e) { pr6MostrarToast('Sin conexión', 'error'); return; }

  const cab   = data.cabecera;
  const fecha = (cab.fecha || '').split('-').reverse().join('/');
  const hora  = (cab.hora_real || '').substring(0, 5);

  const camarasHTML = (data.camaras || []).map(c => {
    const temp = c.temperatura !== null && c.temperatura !== undefined
      ? Number(c.temperatura).toFixed(1) + ' °C' : '—';
    return `<tr>
      <td>${_pr30Esc(c.nombre_display)}</td>
      <td style="text-align:center">${c.setpoint !== null ? Number(c.setpoint).toFixed(2)+' °C' : '—'}</td>
      <td style="text-align:center;font-weight:700;color:#36B0C9">${temp}</td>
      <td style="color:rgba(255,255,255,.55)">${_pr30Esc(c.observaciones || '')}</td>
    </tr>`;
  }).join('');

  const presMap = {};
  (data.presiones || []).forEach(p => { presMap[p.sistema] = p; });
  const presHTML = ['-10','-30','-40'].map(sis => {
    const p = presMap[sis] || {};
    return `<tr>
      <td>Sistema ${sis}</td>
      <td style="text-align:center">${p.aspiracion ?? '—'}</td>
      <td style="text-align:center">${p.descarga   ?? '—'}</td>
    </tr>`;
  }).join('');

  const condMap = {};
  (data.condensadores || []).forEach(c => { condMap[c.numero] = c; });
  const condHTML = [1,2,3].map(num => {
    const c = condMap[num] || {};
    const dot = v => v == 1
      ? '<span style="color:#22c55e;font-size:1rem">✔</span>'
      : '<span style="color:rgba(255,255,255,.2);font-size:1rem">—</span>';
    return `<tr>
      <td>Condensador ${String(num).padStart(2,'0')}</td>
      <td style="text-align:center">${dot(c.bomba1)}</td>
      <td style="text-align:center">${dot(c.bomba2)}</td>
      <td style="text-align:center">${dot(c.vent_grupo1)}</td>
      <td style="text-align:center">${dot(c.vent_grupo2)}</td>
    </tr>`;
  }).join('');

  const overlay = document.createElement('div');
  overlay.className = 'pr24-ver-overlay';
  overlay.innerHTML = `
    <div class="pr24-ver-card" style="max-width:680px">
      <div class="pr24-ver-header">
        <div class="pr24-ver-title"><span class="pr24-badge">PR-30</span> Control ${cab.turno} — #${id}</div>
        <button class="pr24-ver-close" id="pr30VClose">✕ Cerrar</button>
      </div>
      <hr class="pr24-divider">
      <div style="display:flex;gap:24px;flex-wrap:wrap;margin-bottom:14px">
        <div><div style="font-size:.66rem;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:.5px">Fecha</div><div style="font-weight:700;color:#36B0C9">${fecha}</div></div>
        <div><div style="font-size:.66rem;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:.5px">Turno</div><div style="font-weight:700">${cab.turno} — Control ${cab.control_num}</div></div>
        <div><div style="font-size:.66rem;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:.5px">Hora Real</div><div style="font-weight:700">${hora}</div></div>
        <div><div style="font-size:.66rem;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:.5px">Maquinista</div><div style="font-weight:700">${_pr30Esc(cab.maquinista_nombre || '—')}</div></div>
        <div><div style="font-size:.66rem;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:.5px">Verificado</div>
          <div style="font-weight:700;color:${cab.verificado ? '#22c55e' : 'rgba(255,255,255,.35)'}">${cab.verificado ? 'Sí' : 'No'}</div></div>
      </div>

      ${camarasHTML ? `
      <div style="font-size:.72rem;font-weight:800;color:rgba(255,255,255,.45);text-transform:uppercase;letter-spacing:.5px;margin:14px 0 8px">❄️ Cámaras</div>
      <div style="overflow-x:auto">
        <table class="pr24-tabla" style="font-size:.78rem">
          <thead><tr><th>Cámara</th><th>Set Point</th><th>Temp. Medida</th><th>Obs.</th></tr></thead>
          <tbody>${camarasHTML}</tbody>
        </table>
      </div>` : ''}

      <div style="font-size:.72rem;font-weight:800;color:rgba(255,255,255,.45);text-transform:uppercase;letter-spacing:.5px;margin:14px 0 8px">🔩 Presiones</div>
      <table class="pr24-tabla" style="font-size:.78rem">
        <thead><tr><th>Sistema</th><th style="text-align:center">Aspiración</th><th style="text-align:center">Descarga</th></tr></thead>
        <tbody>${presHTML}</tbody>
      </table>

      <div style="font-size:.72rem;font-weight:800;color:rgba(255,255,255,.45);text-transform:uppercase;letter-spacing:.5px;margin:14px 0 8px">🌀 Condensadores</div>
      <table class="pr24-tabla" style="font-size:.78rem">
        <thead><tr><th>Condensador</th><th style="text-align:center">B1</th><th style="text-align:center">B2</th><th style="text-align:center">VG1</th><th style="text-align:center">VG2</th></tr></thead>
        <tbody>${condHTML}</tbody>
      </table>

      ${cab.observaciones ? `<hr class="pr24-divider"><div style="font-size:.8rem;color:rgba(255,255,255,.6)">💬 ${_pr30Esc(cab.observaciones)}</div>` : ''}

      <div style="display:flex;justify-content:flex-end;margin-top:16px">
        <button class="pr24-btn-volver" style="font-size:.8rem"
          onclick="this.closest('.pr24-ver-overlay').remove(); pr30AbrirFormulario(${id}, '${cab.turno}', ${cab.control_num})">✏️ Editar</button>
      </div>
    </div>`;

  document.body.appendChild(overlay);
  overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
  document.getElementById('pr30VClose').addEventListener('click', () => overlay.remove());
}

/* ══════════════════════════════════════════════════════════════════
   PDF
   ══════════════════════════════════════════════════════════════════ */
async function pr30ImprimirPDF() {
  let rows = [];
  try {
    const res = await fetch(`${API_EQUIPOS_URL}?action=pr30_grilla&fecha=${_pr30FiltroFecha}`, { credentials: 'same-origin' });
    rows = await res.json();
    if (!Array.isArray(rows)) rows = [];
  } catch(e) { pr6MostrarToast('Error al cargar datos', 'error'); return; }

  const [y,m,d] = _pr30FiltroFecha.split('-');
  const fechaDisplay = `${d}/${m}/${y}`;
  const fechaImpresion = new Date().toLocaleDateString('es-AR',{day:'2-digit',month:'2-digit',year:'numeric'});

  const filas = rows.map(r => {
    const hr  = r.hora_real ? `<td>${r.hora_real}</td>` : '<td></td>';
    const maq = r.maquinista_nombre ? r.maquinista_nombre.toUpperCase() : '';
    const ver = r.verificado ? '✔' : '';
    return `<tr>
      <td>${fechaDisplay} ${r.turno}</td>
      <td style="text-align:center">${r.control_num}</td>
      <td style="text-align:center">${r.hora_prevista}</td>
      ${hr}
      <td>${maq}</td>
      <td style="text-align:center">${ver}</td>
    </tr>`;
  }).join('');

  const html = `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="utf-8">
  <title>PR-30 Control Sala de Máquinas — ${fechaDisplay}</title>
  <style>
    * { box-sizing:border-box; margin:0; padding:0; }
    body { font-family:Arial,sans-serif; font-size:11px; color:#000; background:#fff; padding:20px 28px; }
    .header-table { width:100%; border-collapse:collapse; margin-bottom:20px; }
    .header-table td { border:1px solid #000; padding:5px 10px; vertical-align:middle; }
    .logo-cell { font-size:22px; font-weight:900; text-align:center; width:160px; }
    .title-cell { text-align:center; font-size:13px; font-weight:600; }
    .title-cell .subtitle { font-size:12px; font-weight:700; margin-top:4px; }
    .meta-cell { font-size:10px; }
    .meta-cell .meta-label { color:#555; }
    .meta-cell .meta-val   { font-weight:700; float:right; }
    .data-table { width:100%; border-collapse:collapse; }
    .data-table th { border:1px solid #000; background:#f0f0f0; padding:6px 8px; font-size:10px; font-weight:700; text-align:center; }
    .data-table td { border:1px solid #000; padding:6px 8px; font-size:10px; vertical-align:middle; }
    @media print { .no-print { display:none !important; } }
  </style>
</head>
<body>
  <div class="no-print" style="margin-bottom:14px;display:flex;gap:10px">
    <button onclick="window.print()" style="background:#0C2554;color:#fff;border:none;border-radius:7px;padding:9px 22px;font-size:12px;font-weight:700;cursor:pointer">🖨️ Imprimir / PDF</button>
    <button onclick="window.close()" style="background:#eee;color:#333;border:1px solid #ccc;border-radius:7px;padding:9px 18px;font-size:12px;cursor:pointer">✕ Cerrar</button>
  </div>
  <table class="header-table">
    <tr>
      <td class="logo-cell" rowspan="2">CINA S.R.L</td>
      <td class="title-cell" rowspan="2">Planilla de Registros<div class="subtitle">Control Sala de Máquinas</div></td>
      <td class="meta-cell"><span class="meta-label">Documento</span><span class="meta-val">PR-30</span></td>
    </tr>
    <tr>
      <td class="meta-cell"><span class="meta-label">Revisión</span><span class="meta-val">1</span></td>
    </tr>
    <tr>
      <td class="logo-cell" style="font-size:11px;font-weight:400">SENASA ESTAB. N° 3540</td>
      <td class="title-cell">Libro de Guardia</td>
      <td class="meta-cell"><span class="meta-label">Fecha Revisión</span><span class="meta-val">Jul-20</span></td>
    </tr>
    <tr>
      <td colspan="2" style="font-size:10px;padding:4px 10px">
        <span style="color:#555">Fecha:</span> <strong>${fechaDisplay}</strong>
        &nbsp;&nbsp;&nbsp;
        <span style="color:#555">Fecha de Impresión:</span> <strong>${fechaImpresion}</strong>
      </td>
      <td class="meta-cell"><span class="meta-label">Página</span><span class="meta-val">1 de 1</span></td>
    </tr>
  </table>
  <table class="data-table">
    <thead>
      <tr>
        <th>Turno</th>
        <th>Control</th>
        <th>Hora Prevista</th>
        <th>Hora Real</th>
        <th>Maquinista</th>
        <th>Verificado</th>
      </tr>
    </thead>
    <tbody>${filas}</tbody>
  </table>
</body>
</html>`;

  const win = window.open('', '_blank', 'width=900,height=700');
  if (!win) { pr6MostrarToast('Habilitá los pop-ups para imprimir', 'error'); return; }
  win.document.write(html);
  win.document.close();
}

/* ── Helper ───────────────────────────────────────────────────── */
function _pr30Esc(s) {
  return String(s||'').replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

/* ══════════════════════════════════════════════════════════════
   MÓDULO: PRODUCTOS
   Lista + edición inline de cajas_por_pallet y datos básicos
   ══════════════════════════════════════════════════════════════ */
function renderProductos(crearNuevo = false) {
  if (typeof setHeader       === 'function') setHeader('ADMINISTRACION');
  if (typeof setExpandedMode === 'function') setExpandedMode(false);
  if (typeof showMetaPanel   === 'function') showMetaPanel(true);
  if (typeof syncBackBtn     === 'function') syncBackBtn();

  const menuGrid = document.getElementById('menuGrid');
  menuGrid.className = '';
  menuGrid.innerHTML = '';

  let pagina = 1, porPag = 50, totalPags = 1;
  let buscarTimer = null;

  const wrap = document.createElement('div');
  wrap.style.cssText = 'padding:18px 22px;max-width:1100px';
  wrap.innerHTML = `
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;flex-wrap:wrap;gap:10px">
      <div style="font-size:1.05rem;font-weight:800;letter-spacing:.04em;color:#fff;display:flex;align-items:center;gap:10px">
        <span style="background:rgba(54,176,201,.2);color:#36B0C9;border:1px solid rgba(54,176,201,.35);
               border-radius:6px;padding:2px 10px;font-size:.72rem">PROD</span>
        PRODUCTOS
      </div>
      <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">
        <input id="prodBuscar" type="text" placeholder="🔍 Buscar producto..."
          style="background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.12);border-radius:8px;
                 color:#fff;font-size:.85rem;padding:7px 12px;outline:none;width:240px">
        <label style="font-size:.75rem;color:rgba(255,255,255,.5);display:flex;align-items:center;gap:5px">
          <input id="prodSoloActivos" type="checkbox" checked> Solo activos
        </label>
        <button id="prodBtnNuevo"
          style="background:linear-gradient(135deg,#36B0C9,#0e7a94);border:none;border-radius:8px;
                 color:#fff;font-size:.8rem;font-weight:800;padding:7px 16px;cursor:pointer;
                 box-shadow:0 3px 12px rgba(54,176,201,.3);white-space:nowrap">
          ＋ Nuevo producto
        </button>
      </div>
    </div>

    <div id="prodTablaWrap">
      <div class="ge-loading">Cargando productos...</div>
    </div>
    <div id="prodPager" style="margin-top:12px;display:flex;gap:8px;align-items:center;justify-content:center"></div>
    <div id="prodFormOverlay"></div>
  `;
  menuGrid.appendChild(wrap);

  const tablaWrap = wrap.querySelector('#prodTablaWrap');
  const pagerEl   = wrap.querySelector('#prodPager');
  const formOv    = wrap.querySelector('#prodFormOverlay');

  const cargar = async () => {
    const buscar     = wrap.querySelector('#prodBuscar').value.trim();
    const soloActivos= wrap.querySelector('#prodSoloActivos').checked ? 1 : 0;
    tablaWrap.innerHTML = '<div class="ge-loading">Cargando...</div>';
    try {
      const r = await fetch(
        `${API_EQUIPOS_URL}?action=productos_lista&buscar=${encodeURIComponent(buscar)}&pagina=${pagina}&por_pagina=${porPag}&activos=${soloActivos}`,
        { credentials: 'same-origin' }
      );
      const d = await r.json();
      if (d.error) throw new Error(d.error);
      totalPags = d.paginas || 1;
      renderTabla(d.productos || [], d.total || 0);
      renderPager();
    } catch(e) {
      tablaWrap.innerHTML = `<div class="ge-empty">Error: ${e.message}</div>`;
    }
  };

  const renderTabla = (prods, total) => {
    if (!prods.length) {
      tablaWrap.innerHTML = '<div class="ge-empty">Sin productos encontrados</div>';
      return;
    }
    tablaWrap.innerHTML = `
      <div style="font-size:.7rem;opacity:.4;margin-bottom:8px">${total} producto${total !== 1 ? 's' : ''} encontrado${total !== 1 ? 's' : ''}</div>
      <div style="overflow-x:auto">
        <table style="width:100%;border-collapse:collapse;font-size:.78rem">
          <thead>
            <tr style="border-bottom:1px solid rgba(255,255,255,.1)">
              <th style="text-align:left;padding:8px 10px;opacity:.4;font-size:.65rem;text-transform:uppercase;white-space:nowrap">ID</th>
              <th style="text-align:left;padding:8px 10px;opacity:.4;font-size:.65rem;text-transform:uppercase">Código</th>
              <th style="text-align:left;padding:8px 10px;opacity:.4;font-size:.65rem;text-transform:uppercase">Descripción</th>
              <th style="text-align:left;padding:8px 10px;opacity:.4;font-size:.65rem;text-transform:uppercase">Marca</th>
              <th style="text-align:right;padding:8px 10px;opacity:.4;font-size:.65rem;text-transform:uppercase;white-space:nowrap">Peso std.</th>
              <th style="text-align:right;padding:8px 10px;opacity:.4;font-size:.65rem;text-transform:uppercase;white-space:nowrap">Caj/Pallet</th>
              <th style="text-align:center;padding:8px 10px;opacity:.4;font-size:.65rem;text-transform:uppercase">Estado</th>
              <th style="padding:8px 10px"></th>
            </tr>
          </thead>
          <tbody id="prodTbody">
            ${prods.map(p => `
              <tr data-id="${p.ProductosID}" style="border-bottom:1px solid rgba(255,255,255,.05);transition:background .1s">
                <td style="padding:8px 10px;opacity:.4;font-size:.7rem">${p.ProductosID}</td>
                <td style="padding:8px 10px;font-family:monospace;font-size:.72rem;opacity:.7">${p.CodigoProducto||'—'}</td>
                <td style="padding:8px 10px;font-weight:600;max-width:280px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap"
                    title="${p.Descripcion1||''}">${p.Descripcion1||'—'}</td>
                <td style="padding:8px 10px;opacity:.7">${p.Marca||'—'}</td>
                <td style="padding:8px 10px;text-align:right;font-variant-numeric:tabular-nums">${p.peso_estandar > 0 ? parseFloat(p.peso_estandar).toLocaleString('es-AR',{minimumFractionDigits:2}) + ' kg' : '—'}</td>
                <td style="padding:8px 10px;text-align:right">
                  ${parseInt(p.cajas_por_pallet) > 0
                    ? `<span style="background:rgba(54,176,201,.15);color:#36B0C9;border-radius:4px;padding:2px 8px;font-size:.72rem;font-weight:700">${p.cajas_por_pallet}</span>`
                    : `<span style="opacity:.3;font-size:.72rem">sin definir</span>`}
                </td>
                <td style="padding:8px 10px;text-align:center">
                  ${p.Activo ? '<span style="color:#86efac;font-size:.7rem">●</span>' : '<span style="color:#fca5a5;font-size:.7rem">●</span>'}
                </td>
                <td style="padding:8px 10px;text-align:right">
                  <button class="prod-edit-btn" data-id="${p.ProductosID}"
                    style="background:rgba(54,176,201,.15);border:1px solid rgba(54,176,201,.3);
                           border-radius:5px;color:#36B0C9;font-size:.65rem;font-weight:700;
                           padding:3px 9px;cursor:pointer;white-space:nowrap">✏️ Editar</button>
                </td>
              </tr>`).join('')}
          </tbody>
        </table>
      </div>`;

    tablaWrap.querySelectorAll('.prod-edit-btn').forEach(btn => {
      btn.addEventListener('click', () => abrirFormProducto(parseInt(btn.dataset.id)));
    });
  };

  const renderPager = () => {
    if (totalPags <= 1) { pagerEl.innerHTML = ''; return; }
    pagerEl.innerHTML = `
      <button id="prodPrev" ${pagina <= 1 ? 'disabled' : ''}
        style="background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.12);border-radius:6px;
               color:rgba(255,255,255,.7);font-size:.75rem;padding:5px 12px;cursor:pointer;
               opacity:${pagina<=1?.4:1}">← Ant</button>
      <span style="font-size:.75rem;color:rgba(255,255,255,.4)">${pagina} / ${totalPags}</span>
      <button id="prodNext" ${pagina >= totalPags ? 'disabled' : ''}
        style="background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.12);border-radius:6px;
               color:rgba(255,255,255,.7);font-size:.75rem;padding:5px 12px;cursor:pointer;
               opacity:${pagina>=totalPags?.4:1}">Sig →</button>`;
    pagerEl.querySelector('#prodPrev')?.addEventListener('click', () => { if(pagina>1){pagina--;cargar();} });
    pagerEl.querySelector('#prodNext')?.addEventListener('click', () => { if(pagina<totalPags){pagina++;cargar();} });
  };

  // Botón Nuevo Producto
  wrap.querySelector('#prodBtnNuevo').addEventListener('click', () => abrirFormNuevoProducto());

  const abrirFormNuevoProducto = () => {
    formOv.innerHTML = `
      <div style="position:fixed;inset:0;background:rgba(0,0,0,.72);z-index:9800;display:flex;
                  align-items:center;justify-content:center;padding:20px" id="prodNuevoOverlay">
        <div style="background:#0d1b35;border:1px solid rgba(255,255,255,.12);border-radius:16px;
                    width:100%;max-width:600px;max-height:90vh;overflow-y:auto;
                    box-shadow:0 24px 60px rgba(0,0,0,.7);padding:24px 28px">

          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:18px">
            <div style="font-size:.95rem;font-weight:800;color:#fff">＋ Crear nuevo producto</div>
            <button id="prodNuevoCerrar"
              style="background:rgba(239,68,68,.12);border:1px solid rgba(239,68,68,.25);border-radius:6px;
                     color:#EF4444;font-size:.75rem;font-weight:700;padding:5px 12px;cursor:pointer">✕ Cerrar</button>
          </div>

          <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px">
            ${prodFld('Código producto', 'n_CodigoProducto', '', 'text')}
            ${prodFld('Marca', 'n_Marca', '', 'text')}
          </div>
          <div style="margin-bottom:12px">
            ${prodFld('Descripción 1 *', 'n_Descripcion1', '', 'text', true)}
          </div>
          <div style="margin-bottom:12px">
            ${prodFld('Descripción 2', 'n_Descripcion2', '', 'text', true)}
          </div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:20px">
            ${prodFld('Peso estándar (kg)', 'n_peso_estandar', '0', 'number')}
            ${prodFld('Cajas por pallet', 'n_cajas_por_pallet', '0', 'number', false, '0 = sin clasificar')}
          </div>

          <div style="display:flex;gap:10px;align-items:center">
            <button id="prodNuevoGuardar"
              style="background:linear-gradient(135deg,#36B0C9,#0e7a94);border:none;border-radius:9px;
                     color:#fff;font-size:.85rem;font-weight:800;padding:10px 24px;cursor:pointer;
                     box-shadow:0 4px 14px rgba(54,176,201,.3)">
              💾 Crear producto
            </button>
            <span id="prodNuevoMsg" style="font-size:.75rem;opacity:.6"></span>
          </div>
        </div>
      </div>`;

    document.getElementById('prodNuevoCerrar').addEventListener('click', () => { formOv.innerHTML = ''; });
    document.getElementById('prodNuevoOverlay').addEventListener('click', e => {
      if (e.target.id === 'prodNuevoOverlay') formOv.innerHTML = '';
    });

    document.getElementById('prodNuevoGuardar').addEventListener('click', async () => {
      const btn = document.getElementById('prodNuevoGuardar');
      const msg = document.getElementById('prodNuevoMsg');
      const payload = {
        CodigoProducto   : formOv.querySelector('[name="n_CodigoProducto"]').value.trim(),
        Descripcion1     : formOv.querySelector('[name="n_Descripcion1"]').value.trim(),
        Descripcion2     : formOv.querySelector('[name="n_Descripcion2"]').value.trim(),
        Marca            : formOv.querySelector('[name="n_Marca"]').value.trim(),
        peso_estandar    : parseFloat(formOv.querySelector('[name="n_peso_estandar"]').value)    || 0,
        cajas_por_pallet : parseInt(formOv.querySelector('[name="n_cajas_por_pallet"]').value)   || 0,
        Activo           : 1,
      };
      if (!payload.Descripcion1) { msg.textContent = 'La descripción 1 es requerida'; msg.style.color='#fca5a5'; return; }
      btn.disabled = true;
      msg.textContent = 'Creando...';
      msg.style.color = 'rgba(255,255,255,.5)';
      try {
        const r = await fetch(`${API_EQUIPOS_URL}?action=productos_crear`, {
          method: 'POST', credentials: 'same-origin',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload),
        });
        const result = await r.json();
        if (result.error) throw new Error(result.error);
        msg.textContent = '✓ Producto creado';
        msg.style.color = '#86efac';
        setTimeout(() => { formOv.innerHTML = ''; cargar(); }, 900);
      } catch(e) {
        msg.textContent = 'Error: ' + e.message;
        msg.style.color = '#fca5a5';
        btn.disabled = false;
      }
    });
  };

  const abrirFormProducto = async (id) => {
    formOv.innerHTML = '<div style="position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9800;display:flex;align-items:center;justify-content:center"><div class="ge-loading">Cargando...</div></div>';
    try {
      const r = await fetch(`${API_EQUIPOS_URL}?action=productos_ficha&id=${id}`, { credentials: 'same-origin' });
      const p = await r.json();
      if (p.error) throw new Error(p.error);

      formOv.innerHTML = `
        <div style="position:fixed;inset:0;background:rgba(0,0,0,.72);z-index:9800;display:flex;
                    align-items:center;justify-content:center;padding:20px" id="prodFichaOverlay">
          <div style="background:#0d1b35;border:1px solid rgba(255,255,255,.12);border-radius:16px;
                      width:100%;max-width:600px;max-height:90vh;overflow-y:auto;
                      box-shadow:0 24px 60px rgba(0,0,0,.7);padding:24px 28px">

            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:18px">
              <div style="font-size:.95rem;font-weight:800;color:#fff">
                ✏️ Editar producto <span style="font-size:.72rem;opacity:.4;margin-left:6px">#${p.ProductosID}</span>
              </div>
              <button id="prodFichaCerrar"
                style="background:rgba(239,68,68,.12);border:1px solid rgba(239,68,68,.25);border-radius:6px;
                       color:#EF4444;font-size:.75rem;font-weight:700;padding:5px 12px;cursor:pointer">✕ Cerrar</button>
            </div>

            <!-- campos -->
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px">
              ${prodFld('Código producto', 'CodigoProducto', p.CodigoProducto, 'text')}
              ${prodFld('Marca', 'Marca', p.Marca, 'text')}
            </div>
            <div style="margin-bottom:12px">
              ${prodFld('Descripción 1', 'Descripcion1', p.Descripcion1, 'text', true)}
            </div>
            <div style="margin-bottom:12px">
              ${prodFld('Descripción 2', 'Descripcion2', p.Descripcion2, 'text', true)}
            </div>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px">
              ${prodFld('Peso estándar (kg)', 'peso_estandar', p.peso_estandar, 'number')}
              ${prodFld('Cajas por pallet', 'cajas_por_pallet', p.cajas_por_pallet, 'number', false, 'Define el umbral pallet vs picking. 0 = sin clasificar.')}
            </div>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px">
              ${prodFld('Días vida estándar', 'dias_vida_estandar', p.dias_vida_estandar||0, 'number', false, 'Auto-calcula F.Vencimiento al cargar estibas')}
              ${prodFld('Días vida comercial', 'dias_vida_comercial', p.dias_vida_comercial||0, 'number', false, 'Vida útil comercial del producto')}
            </div>
            <div style="margin-bottom:20px">
              <label style="display:flex;align-items:center;gap:10px;cursor:pointer">
                <input id="prodActivoChk" type="checkbox" ${p.Activo ? 'checked' : ''}
                  style="width:16px;height:16px;accent-color:#36B0C9">
                <span style="font-size:.82rem;color:rgba(255,255,255,.8)">Producto activo</span>
              </label>
            </div>

            <!-- Clientes asignados -->
            <div style="border-top:1px solid rgba(255,255,255,.08);padding-top:16px;margin-bottom:16px">
              <div style="font-size:.82rem;font-weight:700;color:#fff;margin-bottom:10px;display:flex;align-items:center;gap:8px">
                👥 Clientes habilitados
                <span style="font-size:.65rem;opacity:.4" id="prodClienteCount">${(p.clientes_asignados||[]).length}</span>
              </div>
              <div id="prodClientesLista" style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:10px">
                ${(p.clientes_asignados||[]).map(c => `
                  <span style="display:inline-flex;align-items:center;gap:4px;padding:3px 10px;border-radius:6px;
                    font-size:.72rem;font-weight:600;background:rgba(74,222,128,.1);color:#4ade80;border:1px solid rgba(74,222,128,.2)">
                    ${c.ClienteNombre}
                    <button class="prod-desasignar-cli" data-cid="${c.ClienteID}" style="background:none;border:none;color:#f87171;cursor:pointer;font-size:.8rem;padding:0 2px" title="Quitar">✕</button>
                  </span>`).join('') || '<span style="font-size:.72rem;opacity:.35">Sin clientes asignados</span>'}
              </div>
              <div style="display:flex;gap:6px;align-items:center">
                <select id="prodClienteSelect" style="flex:1;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.12);
                  border-radius:6px;padding:6px 8px;color:#fff;font-size:.78rem">
                  <option value="">— Agregar cliente —</option>
                  ${(p.clientes_disponibles||[]).filter(c => !(p.clientes_asignados||[]).find(a => a.ClienteID == c.ClienteID)).map(c =>
                    `<option value="${c.ClienteID}">${c.ClienteNombre}</option>`).join('')}
                </select>
                <button id="prodClienteAgregar" style="padding:6px 12px;border-radius:6px;border:1px solid rgba(74,222,128,.3);
                  background:rgba(74,222,128,.1);color:#4ade80;font-weight:700;font-size:.75rem;cursor:pointer;white-space:nowrap">＋ Agregar</button>
              </div>
            </div>

            <div style="display:flex;gap:10px;align-items:center">
              <button id="prodFichaGuardar"
                style="background:linear-gradient(135deg,#36B0C9,#0e7a94);border:none;border-radius:9px;
                       color:#fff;font-size:.85rem;font-weight:800;padding:10px 24px;cursor:pointer;
                       box-shadow:0 4px 14px rgba(54,176,201,.3)">
                💾 Guardar cambios
              </button>
              <span id="prodFichaMsg" style="font-size:.75rem;opacity:.6"></span>
            </div>
          </div>
        </div>`;

      document.getElementById('prodFichaCerrar').addEventListener('click', () => { formOv.innerHTML = ''; });
      document.getElementById('prodFichaOverlay').addEventListener('click', e => {
        if (e.target.id === 'prodFichaOverlay') formOv.innerHTML = '';
      });

      // Asignar cliente al producto
      document.getElementById('prodClienteAgregar').addEventListener('click', async () => {
        const sel = document.getElementById('prodClienteSelect');
        const cid = sel.value;
        if (!cid) { return; }
        try {
          const r = await fetch(`${API_EQUIPOS_URL}?action=producto_asignar_cliente`, {
            method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
            body: JSON.stringify({ ProductosID: id, ClienteID: +cid })
          });
          const d = await r.json();
          if (d.error) throw new Error(d.error);
          showToast('✅ Cliente asignado');
          abrirFormProducto(id); // Recargar formulario
        } catch(e) { showToast('Error: '+e.message, 'error'); }
      });
      // Desasignar cliente
      formOv.querySelectorAll('.prod-desasignar-cli').forEach(btn => {
        btn.addEventListener('click', async (ev) => {
          ev.stopPropagation();
          const cid = btn.dataset.cid;
          if (!confirm('¿Quitar este cliente del producto?')) return;
          try {
            const r = await fetch(`${API_EQUIPOS_URL}?action=producto_desasignar_cliente`, {
              method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
              body: JSON.stringify({ ProductosID: id, ClienteID: +cid })
            });
            const d = await r.json();
            if (d.error) throw new Error(d.error);
            showToast('Cliente removido');
            abrirFormProducto(id);
          } catch(e) { showToast('Error: '+e.message, 'error'); }
        });
      });

      document.getElementById('prodFichaGuardar').addEventListener('click', async () => {
        const btn = document.getElementById('prodFichaGuardar');
        const msg = document.getElementById('prodFichaMsg');
        const payload = {
          ProductosID      : id,
          CodigoProducto   : formOv.querySelector('[name="CodigoProducto"]').value.trim(),
          Descripcion1     : formOv.querySelector('[name="Descripcion1"]').value.trim(),
          Descripcion2     : formOv.querySelector('[name="Descripcion2"]').value.trim(),
          Marca            : formOv.querySelector('[name="Marca"]').value.trim(),
          peso_estandar    : parseFloat(formOv.querySelector('[name="peso_estandar"]').value)    || 0,
          cajas_por_pallet    : parseInt(formOv.querySelector('[name="cajas_por_pallet"]').value)   || 0,
          dias_vida_estandar  : parseInt(formOv.querySelector('[name="dias_vida_estandar"]')?.value)  || 0,
          dias_vida_comercial : parseInt(formOv.querySelector('[name="dias_vida_comercial"]')?.value) || 0,
          Activo              : document.getElementById('prodActivoChk').checked ? 1 : 0,
        };
        if (!payload.Descripcion1) { msg.textContent = 'La descripción es requerida'; msg.style.color='#fca5a5'; return; }
        btn.disabled = true;
        msg.textContent = 'Guardando...';
        msg.style.color = 'rgba(255,255,255,.5)';
        try {
          const r = await fetch(`${API_EQUIPOS_URL}?action=productos_editar`, {
            method: 'POST', credentials: 'same-origin',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
          });
          const result = await r.json();
          if (result.error) throw new Error(result.error);
          msg.textContent = '✓ Guardado';
          msg.style.color = '#86efac';
          setTimeout(() => { formOv.innerHTML = ''; cargar(); }, 800);
        } catch(e) {
          msg.textContent = 'Error: ' + e.message;
          msg.style.color = '#fca5a5';
          btn.disabled = false;
        }
      });

    } catch(e) {
      formOv.innerHTML = '';
      alert('Error al cargar producto: ' + e.message);
    }
  };

  // helper campo de formulario
  function prodFld(label, name, val, type = 'text', full = false, hint = '') {
    return `<div style="${full ? 'grid-column:1/-1;' : ''}display:flex;flex-direction:column;gap:3px">
      <label style="font-size:.62rem;opacity:.45;text-transform:uppercase;letter-spacing:.05em">${label}
        ${hint ? `<span style="font-size:.58rem;opacity:.6;text-transform:none;margin-left:4px">${hint}</span>` : ''}
      </label>
      <input name="${name}" type="${type}" ${type === 'number' ? 'step="0.01" min="0"' : ''} value="${String(val||'').replace(/"/g,'&quot;')}"
        style="background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.14);border-radius:7px;
               color:#fff;font-size:.82rem;padding:7px 10px;outline:none;width:100%;box-sizing:border-box">
    </div>`;
  }

  // Buscar con debounce
  wrap.querySelector('#prodBuscar').addEventListener('input', () => {
    clearTimeout(buscarTimer);
    buscarTimer = setTimeout(() => { pagina = 1; cargar(); }, 350);
  });
  wrap.querySelector('#prodSoloActivos').addEventListener('change', () => { pagina = 1; cargar(); });

  cargar();
  if (crearNuevo) setTimeout(() => abrirFormNuevoProducto(), 200);
}

