/* ═══════════════════════════════════════════════════════════════
   ESTIBAS INTERVENIDAS — Tabla separada + QR con prefijo I
   ═══════════════════════════════════════════════════════════════ */

async function intervenirEstiba(cargaId, estibaId, nroEstiba, modo, onSuccess) {
  // modo: 'completa' | 'parcial' | 'carga_completa'
  document.getElementById('calidadModalOverlay')?.remove();

  const overlay = document.createElement('div');
  overlay.id = 'calidadModalOverlay';
  overlay.className = 'calidad-modal-overlay';
  document.body.appendChild(overlay);
  requestAnimationFrame(() => overlay.classList.add('calidad-modal-visible'));

  let catalogos;
  try { catalogos = await calidadGetCatalogos(); } catch(e) { showToast('Error catálogos'); overlay.remove(); return; }

  // Obtener bultos máximos de la estiba para limitar cantidad parcial
  let maxBultos = 999;
  try {
    const rd = await fetch(`api_2026ia.php?action=estiba_datos&estiba_id=${estibaId}`, {credentials:'same-origin'});
    const dd = await rd.json();
    if (dd.productos) maxBultos = dd.productos.reduce((s,p) => s + (parseInt(p.Cantidad)||0), 0);
  } catch(e) {}

  const esParcial = modo === 'parcial';
  const titulo = modo === 'carga_completa' ? '🚫 Intervenir Carga Completa' : modo === 'completa' ? '🚫 Intervenir Estiba Completa' : '🚫 Intervenir Parcial';

  overlay.innerHTML = `<div class="calidad-modal" style="width:min(500px,94vw)">
    <div class="calidad-modal-header">${titulo} <button class="chk-close" id="eiClose">✕</button></div>
    <div class="calidad-modal-body">
      <div style="font-size:.78rem;opacity:.5;margin-bottom:8px">Estiba #${cargaId}-${nroEstiba}${maxBultos < 999 ? ' · '+maxBultos+' bultos' : ''}</div>
      ${esParcial ? `<div class="calidad-modal-field"><label>CANTIDAD A INTERVENIR (máx ${maxBultos})</label><input type="number" id="eiCant" min="1" max="${maxBultos}" value="1"></div>` : ''}
      <div class="calidad-modal-field"><label>MOTIVO DE INTERVENCIÓN</label>
        <select id="eiMotivo"><option value="">— Seleccionar —</option>${(catalogos.motivos_intervencion||[]).map(m=>`<option value="${m.id}">${m.descripcion}</option>`).join('')}</select>
      </div>
      <div class="calidad-modal-field"><label>DESCRIPCIÓN / CAUSA</label><textarea id="eiCausa" rows="3"></textarea></div>
    </div>
    <div class="calidad-modal-footer">
      <button class="calidad-modal-btn calidad-modal-btn-cancel" id="eiCancel">Cancelar</button>
      <button class="calidad-modal-btn calidad-modal-btn-danger" id="eiConfirm">🚫 Confirmar Intervención</button>
    </div>
  </div>`;

  const close = () => { overlay.classList.remove('calidad-modal-visible'); setTimeout(()=>overlay.remove(),200); };
  overlay.querySelector('#eiClose').onclick = close;
  overlay.querySelector('#eiCancel').onclick = close;
  overlay.addEventListener('click', e => { if(e.target===overlay) close(); });
  overlay.querySelectorAll('input,select,textarea').forEach(el => { el.onkeydown = e => e.stopPropagation(); });

  overlay.querySelector('#eiConfirm').onclick = async () => {
    const motivo = overlay.querySelector('#eiMotivo').value;
    if (!motivo) { showToast('Seleccioná un motivo'); return; }
    const causa = overlay.querySelector('#eiCausa').value.trim();
    const cant = esParcial ? +(overlay.querySelector('#eiCant')?.value||0) : 0;
    if (esParcial && cant < 1) { showToast('Ingresá una cantidad'); return; }
    if (esParcial && cant > maxBultos) { showToast(`Máximo ${maxBultos} bultos`); return; }

    try {
      const r = await fetch('api_2026ia.php?action=estiba_intervenir', {
        method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({ CargaID:cargaId, EstibaID:estibaId, modo, cantidad:cant, motivo_intervencion:+motivo, causa })
      });
      const d = await r.json();
      if (d.error) throw new Error(d.error);
      showToast('🚫 Intervención registrada');
      close();

      if (onSuccess) onSuccess();

      // Imprimir QR de estiba intervenida (después de refresh)
      if (d.estiba_intervenida) {
        const ei = d.estiba_intervenida;
        setTimeout(() => {
          imprimirQREstibasIntervenidas([ei], cargaId);
          showToast('🏷 Etiqueta I-' + cargaId + '-' + ei.NroEstiba + ' generada');
        }, 500);
      }
    } catch(e) { showToast('Error: '+e.message, 'error'); }
  };
}

/* ═══════════════════════════════════════════════════════════════
   AGREGAR TEMPERATURA — Modal móvil reutilizable
   ═══════════════════════════════════════════════════════════════ */
async function openEdAgregarTemp(cargaId, onSuccess, filtroEstibaId) {
  document.getElementById('calidadModalOverlay')?.remove();
  // Obtener estibas de la entrada
  let data;
  try {
    const r = await fetch(`api_2026ia.php?action=entrada_ver&id=${cargaId}`, { credentials:'same-origin' });
    data = await r.json(); if (data.error) throw new Error(data.error);
  } catch(e) { showToast('Error: ' + e.message, 'error'); return; }
  let estibas = data.estibas || [];
  // Si viene filtro, mostrar solo esa estiba
  if (filtroEstibaId) estibas = estibas.filter(e => e.EstibaID == filtroEstibaId);
  if (!estibas.length) { showToast('No hay estibas para medir'); return; }

  const overlay = document.createElement('div'); overlay.id='calidadModalOverlay'; overlay.className='calidad-modal-overlay';
  document.body.appendChild(overlay); requestAnimationFrame(()=>overlay.classList.add('calidad-modal-visible'));

  const rows = estibas.map(e => `<tr>
    <td style="font-weight:700;font-size:.78rem;padding:6px 4px">${cargaId}-${e.NroEstiba}</td>
    <td style="padding:4px"><input type="number" step="0.01" class="temp-t1" data-estiba="${e.EstibaID}" placeholder="°C" style="width:100%;padding:8px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.12);border-radius:6px;color:#fff;font-size:.85rem"></td>
    <td style="padding:4px"><input type="number" step="0.01" class="temp-t2" data-estiba="${e.EstibaID}" placeholder="°C" style="width:100%;padding:8px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.12);border-radius:6px;color:#fff;font-size:.85rem"></td>
  </tr>`).join('');

  overlay.innerHTML = `<div class="calidad-modal" style="width:min(480px,94vw);max-height:85vh;overflow-y:auto">
    <div class="calidad-modal-header">🌡 Nueva Medición <button class="chk-close" id="tmpClose">✕</button></div>
    <div class="calidad-modal-body">
      <div style="display:flex;gap:8px;margin-bottom:10px;flex-wrap:wrap">
        <div class="calidad-modal-field" style="flex:1;min-width:120px"><label>Nº TERMÓMETRO</label><input type="text" id="tmpTermometro" placeholder="Ej: 53" style="padding:10px;font-size:.9rem"></div>
        <div class="calidad-modal-field" style="flex:1;min-width:120px"><label>TRATAMIENTO</label>
          <select id="tmpTratamiento" style="padding:10px;font-size:.9rem"><option value="C">Congelado</option><option value="E">Enfriado</option><option value="A">A Congelar</option><option value="S">Separadores</option></select>
        </div>
      </div>
      <table style="width:100%;border-collapse:collapse"><thead><tr>
        <th style="text-align:left;font-size:.65rem;color:rgba(255,255,255,.4);padding:4px">Estiba</th>
        <th style="text-align:left;font-size:.65rem;color:rgba(255,255,255,.4);padding:4px">T1 (Fact.)</th>
        <th style="text-align:left;font-size:.65rem;color:rgba(255,255,255,.4);padding:4px">T2 (Form.)</th>
      </tr></thead><tbody>${rows}</tbody></table>
    </div>
    <div class="calidad-modal-footer">
      <button class="calidad-modal-btn calidad-modal-btn-cancel" id="tmpCancel">Cancelar</button>
      <button class="calidad-modal-btn calidad-modal-btn-save" id="tmpSave" style="padding:12px 20px;font-size:.9rem">💾 Registrar</button>
    </div>
  </div>`;

  const close=()=>{overlay.classList.remove('calidad-modal-visible');setTimeout(()=>overlay.remove(),200);};
  overlay.querySelector('#tmpClose').onclick=close; overlay.querySelector('#tmpCancel').onclick=close;
  overlay.addEventListener('click',e=>{if(e.target===overlay)close();}); overlay.querySelectorAll('input,select').forEach(el=>{el.onkeydown=e=>e.stopPropagation();});

  overlay.querySelector('#tmpSave').onclick = async () => {
    const mediciones = [];
    overlay.querySelectorAll('.temp-t1').forEach(inp => {
      const t1 = inp.value; const t2 = inp.closest('tr').querySelector('.temp-t2')?.value || '';
      if (t1 || t2) {
        const estibaId = inp.dataset.estiba;
        const estiba = estibas.find(e => e.EstibaID == estibaId);
        const prod = estiba?.productos?.[0];
        mediciones.push({ estiba_id: estibaId, producto_id: prod?.ProductosID||0, temperatura1: t1, temperatura2: t2 });
      }
    });
    if (!mediciones.length) { showToast('Ingresá al menos una temperatura'); return; }
    try {
      const r = await fetch('api_2026ia.php?action=entrada_registrar_temperatura', {
        method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({ carga_id:cargaId, mediciones, nro_termometro: overlay.querySelector('#tmpTermometro').value, tratamiento: overlay.querySelector('#tmpTratamiento').value })
      });
      const d = await r.json(); if (d.error) throw new Error(d.error);
      showToast(`🌡 Medición registrada — Promedio: ${d.promedio||'—'}°C`);
      close(); if (onSuccess) onSuccess();
    } catch(e) { showToast('Error: '+e.message, 'error'); }
  };
}

/* ═══════════════════════════════════════════════════════════════
   FOTOS ESTIBA — Modal móvil con cámara y archivo
   ═══════════════════════════════════════════════════════════════ */
function openFotosEstiba(cargaId, estibaId, nroEstiba, onSuccess) {
  document.getElementById('calidadModalOverlay')?.remove();
  const overlay = document.createElement('div'); overlay.id='calidadModalOverlay'; overlay.className='calidad-modal-overlay';
  document.body.appendChild(overlay); requestAnimationFrame(()=>overlay.classList.add('calidad-modal-visible'));

  overlay.innerHTML = `<div class="calidad-modal" style="width:min(440px,94vw);max-height:85vh;overflow-y:auto">
    <div class="calidad-modal-header">📷 Fotos Estiba #${cargaId}-${nroEstiba} <button class="chk-close" id="fotoClose">✕</button></div>
    <div class="calidad-modal-body">
      <div id="fotoGaleria" style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:12px"><div style="color:rgba(255,255,255,.3);font-size:.75rem">Cargando...</div></div>
      <div style="display:flex;gap:8px;flex-wrap:wrap">
        <label style="flex:1;min-width:120px;display:flex;align-items:center;justify-content:center;gap:6px;padding:14px;border-radius:10px;background:rgba(168,85,247,.1);border:1px solid rgba(168,85,247,.2);color:#a855f7;font-weight:700;font-size:.85rem;cursor:pointer">
          📷 Cámara <input type="file" accept="image/*" capture="environment" id="fotoCam" style="display:none">
        </label>
        <label style="flex:1;min-width:120px;display:flex;align-items:center;justify-content:center;gap:6px;padding:14px;border-radius:10px;background:rgba(96,165,250,.1);border:1px solid rgba(96,165,250,.2);color:#60a5fa;font-weight:700;font-size:.85rem;cursor:pointer">
          📁 Archivo <input type="file" accept="image/*" multiple id="fotoFile" style="display:none">
        </label>
      </div>
    </div>
  </div>`;

  const close=()=>{overlay.classList.remove('calidad-modal-visible');setTimeout(()=>overlay.remove(),200);};
  overlay.querySelector('#fotoClose').onclick=close;
  overlay.addEventListener('click',e=>{if(e.target===overlay)close();});

  // Cargar fotos existentes
  (async () => {
    try {
      const r = await fetch(`api_2026ia.php?action=estiba_fotos&estiba_id=${estibaId}`, {credentials:'same-origin'});
      const d = await r.json();
      const fotos = d.fotos || [];
      const galeria = overlay.querySelector('#fotoGaleria');
      if (fotos.length) {
        galeria.innerHTML = fotos.map(f => `
          <div style="width:80px;height:80px;border-radius:8px;overflow:hidden;border:1px solid rgba(255,255,255,.1)">
            <img src="${f.url}" style="width:100%;height:100%;object-fit:cover" alt="Foto">
          </div>`).join('');
      } else {
        galeria.innerHTML = '<div style="color:rgba(255,255,255,.3);font-size:.75rem">Sin fotos aún</div>';
      }
    } catch(e) { overlay.querySelector('#fotoGaleria').innerHTML = '<div style="color:#f87171;font-size:.75rem">Error al cargar</div>'; }
  })();

  // Subir foto
  const subirFoto = async (file) => {
    const fd = new FormData();
    fd.append('foto', file);
    fd.append('estiba_id', estibaId);
    try {
      const r = await fetch('api_2026ia.php?action=estiba_subir_foto', { method:'POST', credentials:'same-origin', body:fd });
      const d = await r.json(); if (d.error) throw new Error(d.error);
      showToast('📷 Foto subida');
      // Recargar galería
      close();
      openFotosEstiba(cargaId, estibaId, nroEstiba, onSuccess);
    } catch(e) { showToast('Error: '+e.message, 'error'); }
  };

  overlay.querySelector('#fotoCam').onchange = (ev) => { if (ev.target.files[0]) subirFoto(ev.target.files[0]); };
  overlay.querySelector('#fotoFile').onchange = (ev) => { Array.from(ev.target.files).forEach(f => subirFoto(f)); };
}

function imprimirQREstibasIntervenidas(estibas, cargaId) {
  const baseUrl = location.origin + location.pathname + '#estiba-intervenida/';
  const win = window.open('', '_blank');
  if (!win) { showToast('Permitir popups'); return; }

  const logoUrl = location.origin + '/img/cina_logo_qr.png';
  let pagesHtml = '';
  estibas.forEach(e => {
    const url = baseUrl + e.EstibaID;
    const dni = 'I-' + cargaId + '-' + e.NroEstiba;
    const qr = qrcode(0, 'H'); qr.addData(url); qr.make();
    const qrImg = qr.createDataURL(20, 1);
    pagesHtml += `<div class="qr-page">
      <div class="qr-dni" style="background:#dc2626">${dni}</div>
      <img class="qr-code" src="${qrImg}" alt="QR ${dni}">
      <img class="qr-logo" src="${logoUrl}" alt="CINA" onerror="this.outerHTML='<div style=font-size:18px;font-weight:900;color:#dc2626>INTERVENIDA</div>'">
    </div>`;
  });

  win.document.write(`<!DOCTYPE html><html><head><title>QR Intervenida ${cargaId}</title>
    <style>
      *{margin:0;padding:0;box-sizing:border-box}
      @page{margin:0;size:100mm 100mm}
      body{font-family:'Arial Black',Arial,sans-serif;background:#fff}
      .qr-page{width:100mm;height:100mm;margin:0 auto;display:flex;flex-direction:column;align-items:center;justify-content:center;page-break-after:always;padding:4mm;border:2px solid #dc2626}
      .qr-page:last-child{page-break-after:auto}
      .qr-dni{font-size:28px;font-weight:900;color:#fff;background:#dc2626;padding:4px 20px;border-radius:8px;margin-bottom:3mm;letter-spacing:2px}
      .qr-code{width:72mm;height:72mm}
      .qr-logo{height:8mm;margin-top:2mm}
      .no-print{position:fixed;top:0;left:0;right:0;z-index:100;padding:12px 20px;background:#7f1d1d;display:flex;align-items:center;gap:16px}
      .no-print button{padding:10px 28px;font-size:15px;cursor:pointer;background:#dc2626;color:#fff;border:none;border-radius:8px;font-weight:700}
      .no-print span{color:#fca5a5;font-size:13px}
      @media screen{.qr-page{margin:10px auto}}
      @media print{.no-print{display:none!important}.qr-page{border:2px solid #dc2626}}
    </style>
  </head><body>
    <div class="no-print"><button onclick="window.print()">🖨 Imprimir</button><span>ESTIBA INTERVENIDA</span></div>
    ${pagesHtml}
  </body></html>`);
  win.document.close();
}

async function liberarEstibaIntervenida(estibaIntervenidaId, onSuccess) {
  if (!confirm('¿Liberar esta estiba intervenida? Los productos volverán a la estiba original.')) return;
  try {
    const r = await fetch('api_2026ia.php?action=estiba_liberar_intervenida', {
      method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({ EstibaIntervenidaID: estibaIntervenidaId })
    });
    const d = await r.json();
    if (d.error) throw new Error(d.error);
    showToast('🔓 Estiba liberada — productos devueltos a estiba original');
    if (onSuccess) onSuccess();
  } catch(e) { showToast('Error: '+e.message, 'error'); }
}

