async function openPR32Digital(cargaId) {
  // PR-32: Registro de Recepción de Mercadería
  let data;
  try {
    const r = await fetch(`api_2026ia.php?action=entrada_pr05&carga_id=${cargaId}`, {credentials:'same-origin'});
    data = await r.json(); if (data.error) throw new Error(data.error);
  } catch(e) { showToast('Error: '+e.message); return; }

  const d = data.datos||{}, prods = data.productos||[], certs = data.certificados||[];
  const win = window.open('', '_blank');
  if (!win) { showToast('Permitir popups'); return; }

  const prodsHtml = prods.map((p,i) => `<tr><td>${i+1}</td><td>${p.codigo} - ${p.producto}</td><td style="text-align:right">${p.estibas}</td><td style="text-align:right">${p.bultos}</td><td style="text-align:right">${p.kilos} Kg.</td><td style="text-align:right">${p.bultos>0?(p.kilos/p.bultos).toFixed(3):0} Kg.</td></tr>`).join('');
  const totBultos = prods.reduce((s,p)=>s+(+p.bultos||0),0);
  const totKilos = prods.reduce((s,p)=>s+(+p.kilos||0),0);

  win.document.write(`<!DOCTYPE html><html><head><title>PR-32 Entrada #${cargaId}</title>
    <style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:Arial,sans-serif;font-size:11px;padding:20px}
    table{width:100%;border-collapse:collapse;margin-bottom:10px}td,th{border:1px solid #000;padding:4px 6px}
    .hdr{font-weight:700}.no-border{border:none}.right{text-align:right}
    h2{font-size:14px;margin:0}@media print{.no-print{display:none}}</style>
  </head><body>
    <div class="no-print" style="margin-bottom:10px"><button onclick="window.print()" style="padding:8px 20px;cursor:pointer">🖨 Imprimir / PDF</button></div>
    <table><tr><td rowspan="2" class="hdr" style="width:25%">CINA S.R.L<br>SENASA ESTAB. Nro. OF. 3540</td><td rowspan="2" style="width:30%">Planilla de Registros<br>Registro de Recepción de Mercadería</td><td>Documento</td><td class="hdr">PR-32</td></tr>
    <tr><td>Revisión</td><td>1</td></tr></table>
    <table>
      <tr><td class="hdr">Entrada: ${cargaId}</td><td>Fecha: ${d.fecha_movimiento||''}</td></tr>
      <tr><td class="hdr">Cliente: ${d.cliente||''}</td><td>Remito Nro.: ${d.NroRemito||''}</td></tr>
      <tr><td>Dirección: ${d.direccion||''}</td><td>Localidad: ${d.localidad||''}</td></tr>
      <tr><td colspan="2">CUIT: ${d.cuit||''}</td></tr>
      <tr><td>Horario Comienzo: ${d.hora_movimiento_inicio||''}</td><td>Horario Terminación: ${d.hora_movimiento_fin||''}</td></tr>
      <tr><td>Transporte: ${d.transporte_nombre||''}</td><td>Patente: ${d.vehiculo_patente||''} / ${d.acoplado_patente||''}</td></tr>
      <tr><td>Conductor: ${d.conductor_nombre||''}</td><td>Documento: ${d.conductor_doc||''}</td></tr>
      <tr><td colspan="2">Habilitación Senasa: ${d.habilitacion_senasa||''}</td></tr>
      <tr><td colspan="2">Certificado/s Nro: ${certs.join(' , ')}</td></tr>
    </table>
    <table><thead><tr><th>Item</th><th>Descripción</th><th>Estibas</th><th>Bultos</th><th>Kilos</th><th>Kilos Promedio</th></tr></thead>
    <tbody>${prodsHtml}
    <tr class="hdr"><td colspan="2" style="text-align:right">TOTALES:</td><td style="text-align:right">${prods.reduce((s,p)=>s+(+p.estibas||0),0)}</td><td style="text-align:right">${totBultos}</td><td style="text-align:right">${totKilos.toFixed(2)} Kg.</td><td style="text-align:right">${totBultos>0?(totKilos/totBultos).toFixed(2):0} Kg.</td></tr>
    </tbody></table>
    <p style="margin-top:20px"><strong>Firma Supervisor</strong></p>
  </body></html>`);
  win.document.close();
}

async function openPR05Digital(cargaId, editable = false) {
  let data;
  try {
    const r = await fetch(`api_2026ia.php?action=entrada_pr05&carga_id=${cargaId}`, {credentials:'same-origin'});
    data = await r.json(); if (data.error) throw new Error(data.error);
  } catch(e) { showToast('Error: '+e.message); return; }

  const d = data.datos||{}, pr = data.pr05||{}, certs = data.certificados||[], tempsForm = data.temperaturas_formulario||[];
  if (!pr || !pr.ControlCalidadID) {
    if (editable) {
      openPR05Formulario(cargaId, d, certs, tempsForm);
    } else {
      showToast('PR-05 no completado aún. Editarlo desde el módulo de Calidad.');
    }
    return;
  }
  const win = window.open('', '_blank');
  if (!win) { showToast('Permitir popups'); return; }

  const chkRow = (label, val, okVal, okLabel, badLabel) => `<tr><td>${label}</td><td style="font-weight:${val===okVal?'700':'400'}">${val===okVal?okLabel:''}</td><td style="font-weight:${val!==okVal?'700':'400'}">${val!==okVal?badLabel:''}</td></tr>`;

  win.document.write(`<!DOCTYPE html><html><head><title>PR-05 Entrada #${cargaId}</title>
    <style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:Arial,sans-serif;font-size:11px;padding:20px}
    table{width:100%;border-collapse:collapse;margin-bottom:10px}td,th{border:1px solid #000;padding:4px 6px}
    .hdr{font-weight:700}@media print{.no-print{display:none}}</style>
  </head><body>
    <div class="no-print" style="margin-bottom:10px"><button onclick="window.print()">🖨 Imprimir / PDF</button>
      <button onclick="window.opener?.openPR05Formulario?.(${cargaId})" style="margin-left:8px">✏ Editar</button></div>
    <table><tr><td rowspan="2" class="hdr">CINA S.R.L<br>SENASA ESTAB. Nº OF. 3540</td><td rowspan="2">Registro de Control de Recepción y Despacho de Mercadería</td><td>Documento</td><td class="hdr">PR-05</td></tr>
    <tr><td>Revisión</td><td>14</td></tr></table>
    <table>
      <tr><td>Fecha: ${d.fecha_movimiento||''}</td><td>Transporte: ${d.transporte_nombre||''}</td></tr>
      <tr><td>Cliente: ${d.cliente||''}</td><td>Patente: ${d.vehiculo_patente||''} / ${d.acoplado_patente||''}</td></tr>
      <tr><td>Cert nº: ${certs.join(' , ')}</td><td>Carga: ${d.carga_numero||''}</td></tr>
      <tr><td>Remito nº: ${d.NroRemito||''}</td><td></td></tr>
      <tr><td>Entrada: ${cargaId}</td><td></td></tr>
      <tr><td>Horario comienzo: ${d.hora_movimiento_inicio||''}</td><td>Horario fin: ${d.hora_movimiento_fin||''}</td></tr>
    </table>
    <table>
      <tr><td>Temperatura</td><td>Muestra 1<br>${pr.Temperatura1||0}°C</td><td>Muestra 2<br>${pr.Temperatura2||0}°C</td><td>Muestra 3<br>${pr.Temperatura3||0}°C</td></tr>
      <tr><td>Termómetro nº: ${pr.NroTermometro||''}</td><td colspan="3"></td></tr>
    </table>
    <table>
      ${chkRow('Cond. de Transporte', pr.CondicionTransporte, 'B', 'Aceptable', 'Inaceptable')}
      ${chkRow('Exámen Organoléptico', pr.Organoleptico, 'N', 'Aceptable', 'Inaceptable')}
      ${chkRow('Estado de los Envases', pr.EstadoEnvases, 'B', 'Aceptable', 'Inaceptable')}
      ${chkRow('Estado de las Tarimas', pr.EstadoTarimas, 'B', 'Aceptable', 'Inaceptable')}
      ${chkRow('Estado Sanitario', pr.EstadoSanitario, 'B', 'Aceptable', 'Inaceptable')}
      ${chkRow('Paredes, Piso y Techo', pr.EstadoParedesPisoTecho, 'B', 'Aceptable', 'Inaceptable')}
      ${chkRow('Equipo de Frío', pr.EquipoFrio, 'F', 'En funcionamiento', 'Fuera de servicio')}
      ${chkRow('Set Point vs. Carga', pr.setpoint_equipo_frio, 'F', 'Correcto', 'Incorrecto')}
    </table>
    <p>Observaciones: ${pr.Observaciones||''}</p>
    <div style="margin-top:40px;display:flex;justify-content:space-between">
      <div style="text-align:center;width:30%"><hr>Firma Transportista</div>
      <div style="text-align:center;width:30%"><hr>Firma Encargado de Carga</div>
      <div style="text-align:center;width:30%"><hr>Firma Control Calidad</div>
    </div>
  </body></html>`);
  win.document.close();
}

function openPR05Formulario(cargaId, datos, certs, tempsForm) {
  tempsForm = tempsForm || [];
  document.getElementById('calidadModalOverlay')?.remove();
  const overlay = document.createElement('div'); overlay.id='calidadModalOverlay'; overlay.className='calidad-modal-overlay';
  document.body.appendChild(overlay); requestAnimationFrame(()=>overlay.classList.add('calidad-modal-visible'));

  const chkField = (id, label, defVal, okLabel, badLabel, okVal, badVal) =>
    `<div style="display:flex;justify-content:space-between;align-items:center;padding:4px 0;border-bottom:1px solid rgba(255,255,255,.06);font-size:.78rem">
      <span>${label}</span>
      <div style="display:flex;gap:8px">
        <label style="display:flex;align-items:center;gap:3px;cursor:pointer"><input type="radio" name="${id}" value="${okVal}" ${defVal===okVal?'checked':''}> ${okLabel}</label>
        <label style="display:flex;align-items:center;gap:3px;cursor:pointer"><input type="radio" name="${id}" value="${badVal}" ${defVal===badVal?'checked':''}> ${badLabel}</label>
      </div>
    </div>`;

  overlay.innerHTML = `<div class="calidad-modal" style="width:min(580px,94vw);max-height:90vh;overflow-y:auto">
    <div class="calidad-modal-header">📋 PR-05 Control de Recepción <button class="chk-close" id="pr05Close">✕</button></div>
    <div class="calidad-modal-body">
      <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:12px">
        <div class="calidad-modal-field" style="flex:1;min-width:80px"><label>TEMP 1 °C</label><input type="number" step="0.01" id="pr05T1" value="${tempsForm[0]||0}"></div>
        <div class="calidad-modal-field" style="flex:1;min-width:80px"><label>TEMP 2 °C</label><input type="number" step="0.01" id="pr05T2" value="${tempsForm[1]||0}"></div>
        <div class="calidad-modal-field" style="flex:1;min-width:80px"><label>TEMP 3 °C</label><input type="number" step="0.01" id="pr05T3" value="${tempsForm[2]||0}"></div>
      </div>
      ${tempsForm.length ? `<div style="font-size:.65rem;color:rgba(255,255,255,.4);margin:-8px 0 8px;text-align:center">Auto-completado: 3 valores más altos de TEMP FACT</div>` : ''}
      <div class="calidad-modal-field" style="margin-bottom:12px"><label>Nº TERMÓMETRO</label><input type="text" id="pr05Term"></div>
      ${chkField('pr05CT','Cond. de Transporte','B','Aceptable','Inaceptable','B','M')}
      ${chkField('pr05OL','Exámen Organoléptico','N','Aceptable','Inaceptable','N','A')}
      ${chkField('pr05EE','Estado de Envases','B','Aceptable','Inaceptable','B','M')}
      ${chkField('pr05ET','Estado de Tarimas','B','Aceptable','Inaceptable','B','M')}
      ${chkField('pr05ES','Estado Sanitario','B','Aceptable','Inaceptable','B','M')}
      ${chkField('pr05EP','Paredes/Piso/Techo','B','Aceptable','Inaceptable','B','M')}
      ${chkField('pr05EF','Equipo de Frío','F','En funcionamiento','Fuera de servicio','F','N')}
      ${chkField('pr05SP','Set Point vs. Carga','F','Correcto','Incorrecto','F','N')}
      <div class="calidad-modal-field" style="margin-top:10px"><label>OBSERVACIONES</label><textarea id="pr05Obs" rows="2"></textarea></div>
    </div>
    <div class="calidad-modal-footer">
      <button class="calidad-modal-btn calidad-modal-btn-cancel" id="pr05Cancel">Cancelar</button>
      <button class="calidad-modal-btn calidad-modal-btn-save" id="pr05Save">💾 Guardar PR-05</button>
    </div>
  </div>`;

  const close=()=>{overlay.classList.remove('calidad-modal-visible');setTimeout(()=>overlay.remove(),200);};
  overlay.querySelector('#pr05Close').onclick=close; overlay.querySelector('#pr05Cancel').onclick=close;
  overlay.addEventListener('click',e=>{if(e.target===overlay)close();}); overlay.querySelectorAll('input,select,textarea').forEach(el=>{el.onkeydown=e=>e.stopPropagation();});

  overlay.querySelector('#pr05Save').onclick = async () => {
    const getRadio = (name) => overlay.querySelector(`input[name="${name}"]:checked`)?.value || '';
    try {
      const r = await fetch('api_2026ia.php?action=entrada_guardar_pr05', {
        method:'POST', credentials:'same-origin', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({
          carga_id: cargaId,
          Temperatura1: +overlay.querySelector('#pr05T1').value,
          Temperatura2: +overlay.querySelector('#pr05T2').value,
          Temperatura3: +overlay.querySelector('#pr05T3').value,
          NroTermometro: overlay.querySelector('#pr05Term').value,
          CondicionTransporte: getRadio('pr05CT'), Organoleptico: getRadio('pr05OL'),
          EstadoEnvases: getRadio('pr05EE'), EstadoTarimas: getRadio('pr05ET'),
          EstadoSanitario: getRadio('pr05ES'), EstadoParedesPisoTecho: getRadio('pr05EP'),
          EquipoFrio: getRadio('pr05EF'), setpoint_equipo_frio: getRadio('pr05SP'),
          Observaciones: overlay.querySelector('#pr05Obs').value,
        })
      });
      const d = await r.json(); if (d.error) throw new Error(d.error);
      showToast('✅ PR-05 guardado'); close();
    } catch(e) { showToast('Error: '+e.message, 'error'); }
  };
}

